with new_qas(youtube_id, doctor_slug, question, answer, meta, keywords) as (
  values
    ('aix5AhlXk2s', 'kimjongsik', '경락 마사지 효과 금방 사라지는데 오래가는 리프팅 방법 없나요?', '레비나스 리프팅은 경락보다 훨씬 깊은 근막층을 체외충격파로 자극해 붓기 제거와 리프팅 효과가 오래 유지됩니다. 경락 마사지는 효과 지속기간이 너무 짧아서 매번 받기 어렵지만, 레비나스는 처음에 2-3주 간격으로 2-3번 받은 뒤 3개월에서 6개월 간격으로 한 번씩만 유지하면 됩니다. 근막보다 깊은 층을 두드려주기 때문에 림프순환이 촉진되면서 노폐물이 배출되고 얼굴 전체가 슬림해지는 원리예요. 단순히 붓기만 빠지는 게 아니라 혈색과 안색까지 좋아져서 받은 분들이 건강하게 리프팅되는 느낌이라고 표현합니다. 시술 후 바로 일상생활이 가능하고 거울을 보면 즉각적으로 달라진 느낌이 확 나요. 반복 시술할수록 운동으로 근육이 붙듯이 효과 지속 기간이 늘어나서 나중에는 자주 받지 않아도 좋은 윤곽을 유지할 수 있게 됩니다. 직장인분들이 점심시간에 잠깐 마사지 받듯 다녀올 수 있을 정도로 간편합니다.', '경락보다 오래가는 레비나스 리프팅의 원리와 유지 주기를 피부과 전문의 김종식이 설명합니다.', array['레비나스', '리프팅', '붓기', '림프순환', '경락', '체외충격파', '근막']::text[]),
    ('aix5AhlXk2s', 'kimjongsik', '레비나스가 울쎄라만큼 효과 있다는 게 진짜예요?', '네, 레비나스를 잘 받으면 울쎄라 효과가 그대로 나고, 심지어 더 빠르고 즉각적으로 좋은 결과가 나오는 분들도 있습니다. 특히 전체적으로 붓기가 많아서 동그랗고 살이 많은 분, 옆쪽으로 붓기가 있는 분들이 받으면 효과가 아주 좋아요. 나이가 젊고 처짐이 심하지 않은 분들은 울쎄라를 레비나스로 대체해서 윤곽을 먼저 잡으면, 울쎄라 900샷 받을 것을 600샷만 받아도 비용은 줄이고 더 좋은 효과를 누릴 수 있습니다. 울쎄라와 병합하면 효과가 훨씬 드라마틱한데, 레비나스는 즉각적으로 나타나고 울쎄라는 시간이 걸리기 때문에 서로 보완이 됩니다. 스킨보톡스나 윤곽보톡스처럼 얼굴을 축소시켜주는 시술들과도 궁합이 좋아요. 가장 큰 장점은 마취크림 없이 진행할 정도로 전혀 아프지 않다는 점입니다. 마사지 받을 때 약간 아픈데 더 받고 싶은 그 정도의 둔탁한 압력감만 느껴집니다.', '레비나스와 울쎄라의 효과 비교 및 병합 시술 장점을 피부과 전문의 김종식이 안내합니다.', array['레비나스', '울쎄라', '리프팅', '윤곽보톡스', '스킨보톡스', '붓기', '통증']::text[]),
    ('aix5AhlXk2s', 'kimjongsik', '여드름 흉터 때문에 얼굴이 울퉁불퉁한데 레비나스가 도움 돼요?', '네, 여드름 흉터가 많거나 시술을 많이 받아서 얼굴에 유착이 심한 분들에게 레비나스가 특히 효과적입니다. 피부 조직이 안쪽에서 여기저기 유착되면서 얼기설기 붙어있으면 피부가 울퉁불퉁해 보이고, 표정 지을 때 찌그러져 보이거나 비대칭이 생기게 돼요. 레비나스는 이런 유착을 전반적으로 풀어주면서 피부가 자연스럽게 움직일 수 있도록 만들어줍니다. 얼굴이 조화롭게 움직이다 보니 부드러운 인상과 리프팅된 형태가 자연스럽게 나타나는 거죠. 시술 후에는 얼굴 전체 조직이 부드러워져서 자연스러운 미소를 짓는 데도 큰 도움이 됩니다. 그래서 결혼식이나 상견례, 미팅처럼 많이 웃어야 하는 중요한 일 전에 받으시면 딱 좋아요. 한쪽은 덜 웃고 반대쪽은 많이 웃는 비대칭 현상도 개선할 수 있습니다.', '여드름 흉터로 인한 유착과 표정 비대칭에 레비나스가 효과적인 이유를 피부과 전문의 김종식이 설명합니다.', array['레비나스', '여드름흉터', '유착', '비대칭', '리프팅', '표정', '결혼식']::text[]),
    ('aix5AhlXk2s', 'kimjongsik', '레비나스 시술 통증이 걱정되는데 진짜 안 아파요?', '마취크림도 바르지 않고 하는 시술인데 정말 하나도 안 아프다고 자신 있게 말씀드릴 수 있습니다. 느낌을 표현하자면 마사지 받을 때 손으로 누르는 것 같은 살짝 둔탁한 압력, 약간 아픈데 더 받았으면 좋겠다는 느낌이에요. 치아 근처를 지나갈 때 살짝 시린 느낌이 나기도 하고, 어떤 부위는 시원하게 안마받는 것 같은 느낌이 납니다. 정형외과에서 쓰는 체외충격파는 아파서 소리 지르며 맞을 정도이지만, 레비나스는 얼굴 전용으로 만든 장비라 전혀 다릅니다. 피부 속 깊은 근막을 두드려서 시원하게 풀어주는 느낌이라고 생각하면 딱 맞아요. 주의사항도 거의 없어서 직장인분들이 점심시간에 잠깐 쉬다 가는 느낌으로 받고 가시기도 합니다. 시술 직후 바로 일상생활이 가능하고 다운타임이 없는 게 큰 장점입니다.', '레비나스 시술의 실제 통증 정도와 체외충격파와의 차이를 피부과 전문의 김종식이 안내합니다.', array['레비나스', '통증', '체외충격파', '마취', '다운타임', '리프팅', '직장인']::text[]),
    ('zNfS-qfGo-k', 'gohyerim', '예민한 피부인데 각질 제거 스크럽 써도 괜찮나요?', '아니요, 예민한 피부에 알갱이 스크럽이나 닦아내는 토너 패드, 전동 브러쉬 같은 물리적 각질 제거 제품은 자극이 너무 커서 절대 쓰면 안 됩니다. 대신 PHA(폴리히드록시산) 성분이 소량 들어간 기초 제품을 세안 후 매일 발라주는 방법이 훨씬 안전해요. PHA는 입자가 크기 때문에 피부 속까지 들어가지 못하고 겉에 있는 각질만 부드럽게 녹여주는 원리입니다. 게다가 물을 끌어당기는 작용이 있어서 필링 후에도 피부가 건조하지 않고 촉촉하게 유지돼요. AHA나 BHA가 각질 관리는 더 잘 되지만 예민한 피부에는 자극이 심하고 따갑고 건조해질 수 있거든요. PHA가 들어간 기초 제품을 바르면 각질 정리와 함께 보습, 진정, 장벽 강화 효과까지 한 번에 챙길 수 있습니다. 다만 얼굴이 붉고 가려운 날이나 따가움이 느껴지는 날은 사용을 쉬고 피부 컨디션을 보면서 쓰는 게 중요해요.', '예민한 피부가 스크럽 대신 PHA로 안전하게 각질 관리하는 방법을 피부과 전문의 고혜림이 안내합니다.', array['각질제거', 'PHA', '예민피부', '민감성피부', '스크럽', '보습', '피부장벽']::text[]),
    ('zNfS-qfGo-k', 'gohyerim', '예민한 피부도 효소 세안제로 각질 관리해도 돼요?', '네, 효소 세안제는 파파인이나 브로멜라인 같은 천연 효소가 단백질을 부드럽게 녹여주는 방식이라 예민한 피부도 사용할 수 있습니다. 한 번 사용한다고 각질이 확 없어지지는 않지만 꾸준히 쓰면 피부결이 훨씬 정돈되는 느낌을 받을 수 있어요. 사용할 때는 1차 세안 후 손에 약간의 물기가 있는 상태에서 가루를 충분히 녹여 거품을 내고, 그 거품으로 10-15초 이내로 가볍게 롤링한 뒤 헹궈내세요. 알갱이를 제대로 녹이지 않고 바로 얼굴에 문지르면 자극이 될 수 있으니 주의하셔야 합니다. 빈도는 여름철에는 일주일에 2회, 겨울에는 일주일에 1회 정도가 적당해요. 효소 특유의 냄새를 잡기 위해 향료가 들어간 제품들이 있으니, 민감하신 분들은 향료가 없는 제품을 선택하시는 게 좋습니다. 성분 검색 앱을 활용해 알레르기 주의 성분이 없는지 확인해보시길 추천드려요.', '예민한 피부의 효소 세안제 사용법과 빈도 및 주의사항을 피부과 전문의 고혜림이 정리합니다.', array['효소세안제', '각질관리', '예민피부', '파파인', '브로멜라인', '민감성피부', '클렌징']::text[]),
    ('zNfS-qfGo-k', 'gohyerim', '각질 관리 후에 꼭 챙겨야 할 게 뭔가요?', '각질 관리를 한 뒤에는 보습과 자외선 차단을 반드시 챙겨야 합니다. 각질이 정리되면 피부 표면이 매끈해지지만 그만큼 자외선에 더 민감해져서, 얇아진 피부에 햇빛이 바로 닿으면 붉어지고 색소침착과 잔주름이 생기기 쉬워요. 선크림은 아침 출근할 때 한 번, 점심쯤 한 번 더, 퇴근 전 4-5시쯤 한 번 더 덧바르면 좋습니다. 예민해서 선크림을 못 바르겠다는 분들은 무기자차를 선택하시면 되는데, 약간의 백탁이 있을 수 있다는 점은 참고하세요. 보습 앰플은 평소에는 비타민C나 나이아신아마이드가 든 제품을 쓰되, 얼굴이 붉고 간질간질한 날에는 판테놀이 든 앰플로 바꿔 쓰는 게 좋아요. 판테놀은 보습과 장벽 강화, 붉은기 완화, 진정 역할을 하는 성분으로 아기 기저귀 발진에 쓰이는 비판텐에도 들어가 있습니다. 계절이나 피부 상태에 따라 제품을 나눠 사용하는 게 핵심이에요.', '각질 관리 후 필수인 보습과 자외선 차단 방법을 피부과 전문의 고혜림이 설명합니다.', array['각질관리', '선크림', '보습', '판테놀', '비타민C', '자외선차단', '무기자차', '예민피부']::text[]),
    ('zNfS-qfGo-k', 'gohyerim', '환절기에 피부가 뒤집어졌을 때는 어떻게 해야 돼요?', '환절기에 피부가 와장창 무너져서 건들기만 해도 따갑고 뭘 발라도 화끈거릴 때는 그냥 아무것도 하지 마세요. 그때는 각질 관리고 뭐고 일단 피부가 회복하는 게 먼저입니다. 피부가 진짜 따갑고 뒤집어졌을 때는 스테로이드 연고를 바르고 그 위에 에스트라 MD크림이나 제로이드 인텐시브 MD크림을 발라주면 됩니다. 건조하고 당길 때마다 수시로 덧바르는 게 포인트예요. 다만 스테로이드는 반드시 전문의와 상의 후 사용해야 합니다. 예민한 피부는 얼마나 비싸고 좋은 제품을 쓰는지가 중요한 게 아니라, 본인에게 맞는 제품으로 피부 컨디션을 보면서 어떤 걸 바르느냐가 제일 중요해요. 평소에는 병원에서 한 달에 1-2회 정도 LDM 보습 진정 관리나 PHA 관리를 받으면 피부 유지에 도움이 됩니다.', '환절기 피부 뒤집힘 시 대처법과 병원 관리 주기를 피부과 전문의 고혜림이 안내합니다.', array['환절기', '민감성피부', '스테로이드', '재생크림', '피부장벽', 'LDM', '진정']::text[]),
    ('mHH3CpGKX5E', 'kwonsuhyun', '땅콩형 얼굴인데 볼륨 채우려면 필러랑 스컬트라 중 뭐가 나아요?', '시간이 급하지 않고 자연스럽게 예뻐지고 싶다면 스컬트라가 더 좋고, 2주 내로 중요한 일정이 있다면 필러가 적합합니다. 필러는 넣자마자 모양이 바로 형성되어 즉각적인 효과를 볼 수 있고, 의사가 환자와 소통하며 원하는 만큼 조절할 수 있다는 게 장점이에요. 반면 스컬트라는 장기적으로 볼 때 필러보다 자연스럽게 탄탄하게 올라오지만, 완전히 차오르려면 반 년 정도 걸립니다. 꺼진 부위를 채워주면 단순히 볼록해지는 게 아니라 리프팅되는 효과까지 나타나요. 젊을수록 스컬트라의 반응이 잘 일어나서 20대는 확실히 효과가 더 좋고, 60대 이상은 같은 양을 해도 올라오는 게 적은 편입니다. 결혼식처럼 급한 일정이 있어서 애플존이 예뻐지고 싶다면 필러로 즉각적인 효과를 보는 게 맞습니다. 미리미리 관리하실 수 있다면 스컬트라를 추천드려요.', '땅콩형 얼굴의 스컬트라와 필러 선택 기준을 피부과 전문의 권수현이 정리합니다.', array['스컬트라', '필러', '땅콩형얼굴', '볼륨', '애플존', '리프팅', '콜라겐']::text[]),
    ('mHH3CpGKX5E', 'jeonghanmi', '동그란 얼굴 보톡스만으로 갸름하게 만들 수 있나요?', '보톡스로 상당히 줄일 수 있지만, 사각턱만 맞아서는 부족하고 턱 아래부터 귀 밑까지 근육 전체를 줄여야 얼굴 라인이 정리됩니다. 근육이 턱 끝에서 귀 밑까지 발달되어 있기 때문에, 뼈를 제외한 전체 구간에 보톡스를 맞아야 실질적으로 라인이 줄어들어요. 여기에 턱이 짧은 분들은 이중턱도 함께 있는 경우가 많은데, 윤곽주사부터 브이올렛까지 병행하면 효과가 좋습니다. 그리고 침샘이 큰 분들은 침샘 보톡스로 턱 라인을 더 깔끔하게 만들 수 있어요. 보톡스로 라인을 줄인 뒤 울쎄라로 다듬어 놓으면 덜렁덜렁하던 지방층이 몇 주 뒤에 확 달라붙는 효과가 나타납니다. 남은 지방은 지방 분해 주사로 처리해서 더 매끈한 라인을 만들 수 있어요. 칼을 대지 않고도 열심히 빚어나가면 충분히 브이라인에 가까워질 수 있습니다.', '동그란 얼굴형을 보톡스와 병행 시술로 갸름하게 만드는 방법을 피부과 전문의 정한미가 설명합니다.', array['보톡스', '사각턱', '이중턱', '윤곽주사', '울쎄라', '브이라인', '침샘보톡스']::text[]),
    ('mHH3CpGKX5E', 'jeonghanmi', '얼굴형이 이목구비보다 정말 그렇게 중요한가요?', '네, 이목구비가 아무리 예뻐도 얼굴형이 거기에 맞지 않으면 예쁜 게 하나도 안 보이게 됩니다. 눈, 코, 입을 따로 보면 예쁜데 얼굴형 때문에 전혀 살아나지 않는 경우가 실제로 흔해요. 요즘은 눈코입이 뚜렷한 것보다 분위기 미녀를 추구하는 분들이 많은데, 이것도 결국 얼굴형이 예뻐야 가능한 거죠. 코로나 때 마스크를 쓰면 눈만 보이고 얼굴형이 가려지니까 더 예뻐 보였던 경험 하신 분들 많으실 거예요. 본인이 가진 얼굴형에서 너무 많은 변형을 하려고 하기보다, 깎아야 할 사람은 조각하듯 다듬고 채워야 할 사람은 볼륨을 넣어서 가꿔나가는 접근이 중요합니다. 둥근 얼굴은 보톡스와 윤곽 시술로 깎고, 긴 얼굴은 스컬트라나 필러로 채우는 식으로 각자 다른 전략이 필요해요. 본인의 얼굴형에서 조금 더 예뻐질 수 있는 현실적인 방법을 찾는 게 핵심입니다.', '이목구비보다 얼굴형이 중요한 이유와 타입별 교정 전략을 피부과 전문의 정한미가 안내합니다.', array['얼굴형', '이목구비', '윤곽', '보톡스', '필러', '스컬트라', '브이라인']::text[]),
    ('mHH3CpGKX5E', 'kwonsuhyun', '볼이 꺼져서 너무 길어 보이는데 경락으로도 개선이 돼요?', '경락 마사지로 튀어나온 라인을 다듬는 효과는 있지만, 꺼진 볼륨을 채우는 것은 의학적인 힘을 빌려야 합니다. 경락을 꾸준히 받으면 튀어나온 부위가 들어가면서 라인이 다듬어지는 부위가 분명히 있어요. 하지만 꺼진 곳을 채우거나 볼륨을 만드는 것은 경락으로 해결이 안 됩니다. 살이 빠지면 얼굴도 같이 빠지면서 땅콩형 얼굴로 금방 변하는 분들은 주기적으로 볼륨 시술을 해줘야 해요. 스컬트라로 꺼진 광대 아래쪽을 채워주면 단순히 볼록해지는 게 아니라 리프팅되는 효과를 줄 수 있습니다. 시술을 2년 정도 아무것도 안 하면 다시 없어 보이고 길어 보이기 때문에 유지 관리가 중요해요. 본인 얼굴의 밸런스에 맞게 자연스럽게 채우면 주변에서 알아채지 못할 정도로 자연스러운 변화가 가능합니다.', '꺼진 볼을 경락과 볼륨 시술로 개선하는 방법의 차이를 피부과 전문의 권수현이 정리합니다.', array['경락', '땅콩형얼굴', '스컬트라', '볼륨', '리프팅', '광대', '꺼짐']::text[]),
    ('9oI0Gt75ar8', 'kimsoohyung', 'PHA가 각질도 제거하면서 보습도 된다는 게 사실이에요?', '네, PHA는 피부 표면의 죽은 각질 세포를 정리하면서 동시에 큰 분자가 수분을 끌어당겨 보습막을 씌워주는 역할을 합니다. 산 성분이라 피지와 노폐물을 녹여 제거하는 원리인데, 분자 크기가 크기 때문에 피부 깊숙이 들어가지 못하고 표면에서 부드럽게 작용해요. 그래서 각질을 녹이면서도 피부가 촉촉해지고 광이 나는 효과까지 얻을 수 있습니다. 스크럽처럼 문질러서 물리적으로 벗기는 게 아니라 화학적으로 녹이는 방식이라 피부 손상이 적어요. 민감성이나 건성 피부가 부담 없이 각질 관리를 할 수 있는 거의 유일한 성분이라고 보시면 됩니다. 피부과에서 PHA 필링 관리를 받으면 귀티 나는 물광 피부가 되는데, 집에서도 PHA가 들어간 제품을 쓰면 비슷한 결 정리 효과를 볼 수 있어요. 주 2-3회 정도 사용하시는 걸 권장합니다.', 'PHA가 각질 제거와 보습을 동시에 하는 원리와 사용 빈도를 피부과 전문의 김수형이 설명합니다.', array['PHA', '각질제거', '보습', '글루코노락톤', '민감성피부', '건성피부', '물광']::text[]),
    ('9oI0Gt75ar8', 'kimsoohyung', 'AHA, BHA, PHA 뭐가 다른 건지 모르겠어요', '세 가지 모두 산 성분으로 각질과 노폐물을 제거하지만, 분자 크기와 성질이 달라서 맞는 피부 타입이 다릅니다. AHA는 분자가 아주 작고 물을 좋아해서 피부 표면의 잔 각질을 빠르게 정리하는 데 가장 좋은데, 그만큼 자극감이 있을 수 있어요. BHA는 기름에 녹는 성분이라 블랙헤드나 모공 깊숙한 피지를 제거하는 데 효과적이고, AHA보다도 더 자극적입니다. PHA는 셋 중 가장 순하면서 각질 제거는 좀 덜 되더라도 보습감을 줄 수 있는 성분이에요. 여드름 피부나 지성 피부에는 BHA, 건성이나 민감성 피부에는 PHA가 적합합니다. BHA를 쓰고 싶은 민감성 분들은 코 주위 블랙헤드에만 부분적으로 사용하시는 게 안전해요. AHA는 2-10%가 화장품 일반 농도이고, 10% 이상은 필링 개념으로 자극이 강할 수 있습니다.', 'AHA와 BHA와 PHA의 차이점 및 피부 타입별 선택법을 피부과 전문의 김수형이 안내합니다.', array['AHA', 'BHA', 'PHA', '각질제거', '블랙헤드', '민감성피부', '지성피부', '여드름']::text[]),
    ('9oI0Gt75ar8', 'kimsoohyung', '집에서 바르는 PHA 제품이랑 피부과 관리 차이가 얼마나 나요?', '피부과 PHA 필링에 쓰는 제품은 PHA가 14% 들어있어서 집에서 쓰는 10% 제품보다 약 1.5배 높은 농도이고, LDM 장비로 흡수까지 시켜줘서 효과가 확실히 더 좋습니다. 집에서 쓰는 제품도 꾸준히 사용하면 피부결 정리와 광 효과를 볼 수 있지만, 중요한 일이 있어서 얼굴에 확실한 광이 필요하다면 2-3일 전에 피부과에서 PHA 필링 한번 받으시면 차원이 달라요. 피부과 관리용 제품은 물처럼 흐르는 제형에 쿨링감이 강한데 14%임에도 따갑지는 않습니다. 집에서는 마몽드 리퀴드 마스크 같은 10% PHA 제품으로 먼저 시작해서 본인 피부에 PHA가 잘 맞는지 확인해보세요. 잘 맞으면 P-TIOX 같은 펩타이드와 PHA가 함께 들어간 제품으로 넘어가도 좋습니다. 리퀴드 마스크를 냉장고에 뒀다가 쓰면 피부과 관리 제품의 쿨링감과 비슷한 느낌을 낼 수 있어요. 펩타이드와 PHA는 시너지가 매우 좋은 조합입니다.', '집에서 쓰는 PHA 제품과 피부과 관리의 농도 및 효과 차이를 피부과 전문의 김수형이 비교합니다.', array['PHA', '필링', 'P-TIOX', '펩타이드', 'LDM', '피부과관리', '피부결']::text[]),
    ('9oI0Gt75ar8', 'kimsoohyung', 'PHA 제품 쓸 때 같이 쓰면 안 되는 성분이 있나요?', '네, 비타민C나 레티놀 같은 성분은 PHA를 포함한 산 성분과 같은 날 쓰면 피부 자극이 커질 수 있어서 피해주셔야 합니다. AHA, BHA, PHA 모두 산이기 때문에 너무 자주 사용하면 피부 장벽이 무너질 수 있고, 그럴 때는 잠시 중단하고 판테놀 같은 재생 성분이 든 크림을 자주 발라주세요. 요일별로 다르게 어떤 날은 각질 제거, 어떤 날은 비타민C 이런 식으로 번갈아 사용하는 게 좋습니다. 반대로 같이 쓰면 좋은 성분도 있는데, 판테놀은 재생을, 히알루론산은 수분 충전을, 펩타이드는 재생을, 세라마이드는 장벽 강화를 도와줘요. 또한 AHA와 BHA는 햇빛에 예민하게 만드는 광과민성이 있어서 아침에는 꼭 선크림을 잘 발라야 합니다. 집에서 쓰는 제품에 기기를 사용하거나 다른 각질 제거제를 겹쳐 쓰면 피부 장벽이 무너져 오히려 악영향을 줄 수 있으니 주의하세요. 주 2-3회가 가장 적절한 사용 빈도입니다.', 'PHA와 함께 쓰면 안 되는 성분과 좋은 성분 조합을 피부과 전문의 김수형이 정리합니다.', array['PHA', '비타민C', '레티놀', '판테놀', '세라마이드', '피부장벽', '각질관리']::text[]),
    ('e2LsuwIAZHY', 'kwonsuhyun', '지성 피부면 피부과 의사도 필링젤이나 닦토를 쓰나요?', '지성 피부라면 필링젤, 효소 세안제, 닦아내는 토너 전부 써도 됩니다. 보통 피부과 의사들이 이런 제품을 쓰지 말라고 하지만 그건 민감하거나 건조한 피부 기준이에요. 기름이 1시간에 한 번씩 닦아야 할 정도로 많은데 따갑거나 가려운 증상이 없는 튼튼한 지성 피부라면 오히려 해야 피부가 좋아지고 여드름도 안 생기고 화장도 잘 먹습니다. 필링젤은 여름철 기준 일주일에 1-2회 사용하면 적당하고, 알갱이가 너무 큰 자극적인 제품은 피하세요. 효소 세안제는 여름 7-8월에는 매일 메인으로 사용해도 되고, 닦토는 AHA와 BHA가 들어있는 스케일링 토너로 매일 쓸 수 있어요. 다만 이렇게 작업을 많이 한 다음 날 아침에는 순한 약산성 세안제를 써서 피부 장벽을 지켜주는 게 중요합니다. 건성 피부는 절대 따라하면 안 되는 루틴이니 본인 피부 타입을 정확히 아는 게 먼저예요.', '지성 피부의 필링젤과 닦토 사용 여부 및 올바른 빈도를 피부과 전문의 권수현이 안내합니다.', array['필링젤', '닦토', '지성피부', '효소세안제', '피지', '각질제거', '스케일링토너']::text[]),
    ('e2LsuwIAZHY', 'kwonsuhyun', '지성인데 여드름은 별로 없어도 여드름용 클렌저를 써야 하나요?', '네, 지성인데 굳이 여드름이 많이 나지 않더라도 피지 관리를 안 하면 트러블이 나는 피부라면 여드름성 클렌저나 토너를 쓰는 게 맞습니다. 많은 분들이 여드름이 없으니까 순한 약산성 클렌저나 수분 토너만 쓰시는데, 그러면 피지가 해결이 안 돼서 오히려 트러블이 생기거든요. BHA가 들어있는 약산성 여드름용 클렌저를 쓰면 피부 장벽은 지켜주면서 피지와 노폐물을 날려줄 수 있어요. 클렌징 워터는 지성 피부에게 최악인데, 물 제형이라 피지가 제대로 안 닦여서 뾰루지가 많이 생길 수 있습니다. 기름은 기름으로 씻어야 하니까 1차 세안은 클렌징 오일이나 밀크로 하고, 2차로 BHA 성분의 폼클렌저를 쓰는 게 효과적이에요. 겨울에는 세정력이 강한 제품이 건조할 수 있으니 더 순한 약산성 클렌저로 바꿔주세요. 지성 피부에게 이런 여드름용 제품을 권하면 의아해하시는 분이 많은데 효과가 확실히 다릅니다.', '지성 피부가 여드름용 클렌저를 써야 하는 이유와 세안 순서를 피부과 전문의 권수현이 설명합니다.', array['지성피부', '여드름', '클렌저', 'BHA', '피지', '클렌징오일', '약산성']::text[]),
    ('e2LsuwIAZHY', 'jeonghanmi', '건성 피부는 클렌징 순서랑 제품을 뭐로 해야 돼요?', '건성 피부는 클렌징 밀크로 1차 세안하고 약산성 폼클렌저로 2차 세안하면 충분합니다. 클렌징 밀크가 부드럽고 순해서 피부 자극 없이 화장을 지울 수 있는데, 화장을 진하게 한 날은 밀크만으로 깨끗하게 안 닦일 수 있어서 그때는 오일 클렌징으로 대체하면 됩니다. 여름에는 유분기가 약간 있으니 세럼 하나에 선크림만 발라도 충분하고, 겨울에는 크림을 두 겹 정도 바를 정도로 보습을 강화해야 해요. 토너나 스킨은 있으면 쓰고 없으면 안 써도 되는데, 닦아내는 목적이 아니라 보습 목적으로 사용하는 게 포인트입니다. 각질이 일어날 때는 효소 세안제를 2주에 1회 정도 가볍게 사용하고, 약산성 스케일링 토너도 가끔 써주면 좋아요. 겨울에는 세정력 있는 클렌저가 건조할 수 있으니 더 순한 제품으로 바꿔야 합니다. 건성 피부는 지성과 완전히 다른 접근이 필요하니 절대 따라하지 마세요.', '건성 피부의 계절별 클렌징 방법과 보습 루틴을 피부과 전문의 정한미가 안내합니다.', array['건성피부', '클렌징밀크', '약산성', '보습', '세안', '효소세안제', '스킨케어']::text[]),
    ('e2LsuwIAZHY', 'kwonsuhyun', '지성 피부는 써마지 안 해도 되는 게 진짜예요?', '네, 지성 피부는 필링젤과 효소 세안제, 닦토로 스케일링만 제대로 해도 써마지 받은 것 같은 뽀송하고 탄탄한 느낌을 낼 수 있습니다. 오일 클렌징 후 필링젤로 모공의 피지와 각질을 밀어내고, 효소 세안제로 한 꺼풀 더 벗긴 뒤, 닦토로 마무리하면 매끈하고 화장이 착 붙는 피부가 돼요. 이렇게 하면 고주파 시술 받은 것처럼 뽀송한 느낌이 나서 200만원짜리 써마지를 아낄 수 있는 셈입니다. 다만 이 뽀송한 효과는 하룻밤 자는 동안 다시 피지가 쌓여서 매일 아침에 리셋되기 때문에 꾸준히 해줘야 해요. 중요한 건 이 루틴은 기름이 많으면서 피부가 튼튼한 사람만 해야 한다는 점입니다. 따갑거나 가려운 증상이 있는 분, 건성이나 민감성 분들이 따라하면 피부 장벽이 무너지니 절대 금물이에요. 지성 피부에게는 스케일링이 가장 가성비 좋은 피부 관리법입니다.', '지성 피부가 써마지 없이 스케일링만으로 관리하는 방법을 피부과 전문의 권수현이 정리합니다.', array['지성피부', '써마지', '필링젤', '효소세안제', '피지', '스케일링', '모공']::text[]),
    ('cKe0vgatOmU', 'leedoyoung', '동안 얼굴의 비밀이 그냥 볼륨 채우는 거라고요?', '동안 얼굴의 핵심은 끊김 없이 부드럽게 이어지는 윤곽과 적절한 볼륨 유지입니다. 나이가 들면 지방층 볼륨이 줄어들고 탄력이 떨어져 중력에 의해 처지면서 얼굴 곳곳에서 라인의 연속성이 끊기게 됩니다. 아기 얼굴처럼 모든 부위에 볼륨감이 있고 라인이 매끄럽게 이어져야 생기 있고 젊어 보이는 거예요. 한국인과 서양인은 볼륨 포인트가 다른데, 서양인은 광대나 턱뼈처럼 수평적 볼륨을 선호하는 반면 한국인은 이마와 볼 같은 수직적 볼륨을 중요시합니다. 한국인 얼굴 뼈가 넓고 짧으며 평면적이기 때문에 가운데 쪽 볼륨을 살려주는 게 핵심이에요. 처진 부위는 써마지나 울쎄라 같은 리프팅 기기로 줄일 수 있지만, 꺼진 부위는 채워 넣어야 하므로 필러가 기본적인 해법이 됩니다. 결국 단순히 채우고 당기는 게 아니라 윤곽 라인을 연결하고 입체감을 살리는 접근이 진짜 동안을 만드는 방식이에요.', '동안 얼굴의 비밀은 끊김 없이 이어지는 윤곽과 볼륨입니다. 한국인 얼굴형에 맞는 수직적 볼륨 포인트와 필러 활용법을 피부과 전문의 이도영이 설명합니다.', array['동안', '필러', '리프팅', '볼륨', '윤곽', '써마지', '울쎄라']::text[]),
    ('cKe0vgatOmU', 'leedoyoung', '필러 맞으면 몸에 평생 남는다는데 사실인가요?', '아니요, 히알루론산 필러는 우리 몸에 있는 효소에 의해 자연스럽게 녹아 없어집니다. 일반적으로 필러라고 하면 히알루론산 필러를 말하는데, 몸속에 히알루론산을 분해하는 효소가 있어서 시간이 지나면 저절로 사라져요. 재미있는 건 움직임이 많은 부위일수록 더 빨리 녹는다는 점입니다. 밀가루 반죽을 엄지로 누르면 가장자리에 크랙이 생기고 마르기 시작하듯이, 필러도 움직임으로 찌그러지면서 크랙이 발생해 빨리 분해돼요. 그래서 팔자주름처럼 움직임이 많은 곳은 빨리 사라지고, 턱이나 관자처럼 움직임이 적은 곳은 상대적으로 오래 갑니다. 혹시 마음에 안 들면 히알루로니다제라는 효소로 녹여드릴 수도 있어서 피부에 넣는 것 중 가장 안전한 축에 속합니다. 이물질이 몸에 영구히 남는 게 아니니 안심하셔도 돼요.', '히알루론산 필러는 몸속 효소에 의해 자연 분해되어 영구히 남지 않습니다. 부위별 유지 기간 차이와 히알루로니다제 녹임 시술까지 피부과 전문의 이도영이 안내합니다.', array['필러', '히알루론산', '분해', '안전성', '팔자주름', '히알루로니다제']::text[]),
    ('cKe0vgatOmU', 'leedoyoung', '필러 녹으면 오히려 얼굴이 더 처지는 거 아닌가요?', '필러가 사라져도 얼굴이 더 처지지는 않습니다. 필러가 피부 안에 들어가면 공간을 차지하면서 섬유모세포를 자극하는데, 이 세포는 쭉쭉 늘어나는 자극을 받으면 콜라겐을 많이 만들어냅니다. 이렇게 생성된 콜라겐은 우리 몸이 직접 만든 것이기 때문에 필러가 없어져도 남아 있어요. 그래서 필러 시술 전 사진과 비교하면 절대로 더 처지지 않고, 오히려 이전보다 확실히 좋아져 있습니다. 다만 필러로 볼륨이 좋았던 상태를 기억하고 있다가 꺼지면 심리적으로 허전해서 더 처졌다고 느끼실 수는 있어요. 그건 착시일 뿐 실제로는 콜라겐 생성 효과가 유지되고 있는 겁니다. 필러에 대한 두려움이 있으시다면 이 점을 기억해 주세요.', '필러가 녹아도 섬유모세포가 만든 콜라겐은 남아 오히려 시술 전보다 좋아집니다. 필러 후 처짐이 생기지 않는 과학적 이유를 피부과 전문의 이도영이 정리합니다.', array['필러', '콜라겐', '섬유모세포', '처짐', '볼륨', '노화방지']::text[]),
    ('cKe0vgatOmU', 'leedoyoung', '필러 맞고 울퉁불퉁해지는 건 어떻게 막나요?', '필러를 깊은 층에 먼저 주입해 밑바닥을 탄탄하게 다진 후 그 위에 얕게 살짝 놓으면 울퉁불퉁함이 거의 발생하지 않습니다. 쉽게 비유하면, 얇은 여름 이불 밑에 공을 넣으면 눈에 두드러지게 보이지만, 두꺼운 겨울 이불 밑에 넣으면 약간의 윤곽 변화만 느껴지는 것과 같은 원리예요. 피부의 얕은 층에 놓으면 적은 양으로도 주름 개선 효과는 크지만 울퉁불퉁함을 느낄 수 있습니다. 그래서 깊은 층에 볼륨을 넣어 토대를 만들고 표면은 소량만 보완하는 이중 접근이 핵심입니다. 이물감이 걱정되는 분에게는 PDRN(연어 주사) 성분과 히알루론산 필러를 섞어 스킨부스터 형식으로 시술하기도 해요. 이렇게 하면 성상이 묽어져서 일반 필러보다 자연스럽고 이물감이 덜하면서 세포 재생 효과까지 얻을 수 있습니다. 적재적소에 적당량을 넣는 것이 부자연스러움을 막는 핵심이에요.', '깊은 층에 먼저 토대를 만들고 표면은 소량만 보완하면 울퉁불퉁함이 없습니다. PDRN 혼합 주입법과 자연스러운 필러 시술 원칙을 피부과 전문의 이도영이 안내합니다.', array['필러', '울퉁불퉁', '스킨부스터', 'PDRN', '리쥬란', '이물감', '자연스러운시술']::text[]),
    ('QcOfVF3tRSM', 'kwonsuhyun', 'EGF 크림은 어떤 효과가 있고 누구한테 추천하나요?', 'EGF 크림은 피부 재생과 안티에이징을 동시에 잡고 싶은 분들께 추천드려요. EGF는 Epidermal Growth Factor의 약자로 성장인자라는 단백질 성분인데, 원래는 상처 회복이나 피부 재생용 연고 제형으로 많이 쓰였어요. 최근에는 콜라겐 생성을 돕고 잔주름을 줄여준다는 보고들이 많아 안티에이징용 화장품으로도 활발히 출시되고 있어요. 피부가 지치고 거칠거칠할 때 밤에 발라두면 다음날 아침 한결 쌩쌩해진 느낌이 들어요. 레티놀이나 비타민C 앰플이 자극감으로 쓰기 어려운 분들도 EGF는 자극이 거의 없어 부담 없이 쓰기 좋아요. 보습이 되면서 수분 증발도 막아줘 건성·민감성 피부에 특히 잘 맞습니다. 피부가 좋은 날엔 레티놀로 관리하고 민감한 날엔 EGF로 진정·안티에이징을 함께 챙기는 식으로 번갈아 쓰시면 좋아요.', 'EGF 크림의 재생·안티에이징 효과와 추천 대상을 피부과 전문의 권수현이 정리합니다.', array['EGF', '안티에이징', '피부재생', '콜라겐', '잔주름', '보습크림', '민감성']::text[]),
    ('QcOfVF3tRSM', 'kwonsuhyun', 'EGF 크림은 어떤 단계에서 어떻게 발라야 하나요?', 'EGF 크림은 스킨케어 마무리 단계에서 보습크림 위에 얇게 덧발라주시는 게 좋아요. 저는 아토베리어 크림 같은 베이스 보습 제품을 먼저 바르고 그 위에 EGF 크림을 추가로 올리는 방식으로 사용해요. 건조함이 심한 분은 이렇게 두 겹으로 발라야 다음날 당김 없이 촉촉함이 유지돼요. 다만 제형이 꾸덕한 편이라 지성이거나 베이스 크림만으로 충분한 분은 얼굴 전체보다는 눈가나 잔주름이 시작되는 부위에만 부분적으로 쓰시는 걸 추천드려요. 아이크림 제형과 비슷해서 눈가 안티에이징용으로도 활용도가 좋아요. 레이저 시술 후 화끈거리고 거칠한 피부에 하루 얹어두고 자면 회복이 한결 빨라집니다. 평상시 안티에이징 목적과 시술 후 회복 목적 두 가지로 모두 활용 가능합니다.', 'EGF 크림을 보습크림 위에 덧바르는 마무리 사용법을 피부과 전문의 권수현이 안내합니다.', array['EGF', '사용법', '스킨케어', '눈가관리', '레이저후관리', '잔주름', '보습']::text[]),
    ('QcOfVF3tRSM', 'kwonsuhyun', 'EGF 화장품을 고를 때 어떤 점을 봐야 하나요?', 'EGF 화장품은 안정화 기술과 함량, 보조 성분 세 가지를 함께 보고 고르시는 게 좋아요. EGF는 단백질이라 열·빛 같은 외부 환경에 매우 취약해서 계란 흰자가 익으면 되돌릴 수 없듯 변성되면 효과가 사라져요. 그래서 빛 차단이 잘 되는 용기에 담겨 있거나, 자체 안정화 기술로 EGF를 보호하는 제품을 고르시는 게 좋아요. 함량은 무조건 높을수록 좋은 게 아니라 피부 수용체가 받아들일 수 있는 적정 농도면 충분합니다. 너무 고함량은 오히려 자극이 될 수 있어요. 보조 성분으로 판테놀, 히알루론산, 나이아신아마이드, B5, FGF 등이 함께 들어 있으면 재생·보습·미백 시너지가 좋아요. 본인 피부 고민에 맞춰 함께 들어 있는 유효 성분을 확인해 선택하시면 됩니다.', 'EGF 화장품을 고를 때 안정화·함량·보조 성분 보는 법을 피부과 전문의 권수현이 설명합니다.', array['EGF', '화장품선택', '안정화', '판테놀', '히알루론산', '나이아신아마이드', 'FGF']::text[]),
    ('QcOfVF3tRSM', 'kwonsuhyun', 'EGF 크림을 쓸 때 부작용이나 주의할 점이 있나요?', 'EGF 자체는 비교적 안전한 성분이지만 함께 들어 있는 보조 성분 때문에 자극 반응이 생길 수 있으니 주의해서 쓰셔야 해요. 일부 분들은 바른 직후 따갑거나 가려운 증상을 느낄 수 있는데, 이는 EGF가 아니라 화장품에 같이 섞여 있는 향료나 보존제 때문일 가능성이 높아요. 처음 쓰실 땐 귀 뒤나 턱 아래에 패치 테스트를 해보고 이상이 없으면 얼굴에 쓰시는 게 안전해요. 제형이 꾸덕한 EGF 크림은 지성 피부나 여드름성 피부가 두껍게 바르면 다음날 뾰루지가 올라올 수 있어 얇게 펴 발라주세요. 앰플 제형은 산뜻해서 지성 피부에 더 잘 맞아요. 보관도 중요해서 직사광선을 피하고 서늘한 곳이나 냉장고에 두면 단백질 안정성이 더 잘 유지돼요. 자극이 지속되면 사용을 중단하고 진료를 받아보세요.', 'EGF 크림 사용 시 자극 반응과 보관·패치 테스트 주의점을 피부과 전문의 권수현이 안내합니다.', array['EGF', '부작용', '자극', '패치테스트', '지성피부', '보관법', '알러지']::text[]),
    ('o3nccMY2NsY', 'kimjongsik', '비싼 옷 사는 것보다 외모 관리에 효과적인 게 뭔가요?', '운동이 비싼 옷이나 화장품보다 외모 관리에 훨씬 효과적입니다. 아무리 명품 백화점에서 비싼 티셔츠를 입어도 몸의 핏이 좋지 않으면 명품처럼 보이지 않아요. 반대로 길거리 5천 원짜리 티셔츠라도 딱 벌어진 체격으로 입으면 훨씬 매력적으로 보입니다. 백화점에서 옷 살 돈으로 헬스장을 다니고 PT를 받아보시는 게 좋아요. 운동의 또 다른 큰 장점은 자신감이 생긴다는 것입니다. 나도 모르게 가슴을 펴게 되고, 고개를 더 들게 되고, 자신감 있게 세상을 바라보게 되거든요. 본인의 장단점을 살려 개성 있게 꾸미는 걸 잘 못하시는 분이라면, 열심히 운동해서 깔끔하고 단정한 외형을 갖추는 것만으로도 상대방에게 호감을 줄 수 있습니다. 돈도 시간도 생각보다 많이 들지 않아요.', '명품보다 운동이 남자 외모에 훨씬 효과적입니다. 체격이 좋으면 5천 원 티셔츠도 멋져 보이는 이유와 자신감 효과를 피부과 전문의 김종식이 설명합니다.', array['운동', '남자외모', '자기관리', '체격', '자신감', '깔끔함']::text[]),
    ('o3nccMY2NsY', 'kimjongsik', '수염 제모하면 피부도 깔끔해진다는 게 진짜예요?', '네, 수염 제모를 하면 피부까지 깔끔해지는 부수적 효과가 있습니다. 면도를 반복하다 보면 피부가 긁혀서 모낭염이 생기고, 모낭염이 사라진 뒤에는 색소침착이 되면서 칙칙해지는 악순환이 반복돼요. 제모를 하면 이 과정 자체가 사라지니까 피부 톤도 깨끗해집니다. 아무리 열심히 면도를 해도 수염 자국이 남아 있는 것과 없는 것은 확실히 차이가 나요. 수염 자국만으로도 지저분해 보이는 인상을 주기 쉽습니다. 어떻게 수염을 관리해야 할지 모르겠거나 자꾸 지저분해 보인다면 과감하게 제모를 해보시는 걸 추천드립니다. 면도하는 시간도 줄어들어 아침이 편해지고, 여행 갈 때 면도기를 안 챙겨도 되는 실질적인 장점도 있어요. 약 20회 정도면 꽤 깔끔한 결과를 얻을 수 있습니다.', '수염 제모를 하면 면도로 인한 모낭염·색소침착 악순환이 끊겨 피부 톤이 깨끗해집니다. 약 20회면 깔끔한 결과를 얻는 제모 효과를 피부과 전문의 김종식이 안내합니다.', array['제모', '수염', '모낭염', '색소침착', '남자피부', '깔끔함', '면도']::text[]),
    ('o3nccMY2NsY', 'kimjongsik', '남자 머리 스타일 어떻게 해야 깔끔해 보이나요?', '어떻게 해야 할지 모르겠다면 그냥 이마를 시원하게 보여주며 머리를 뒤로 넘기시는 게 가장 좋습니다. 남자는 머리 스타일이 주는 인상이 굉장히 크고, 이마를 보여주고 넘기는 스타일이 신뢰감을 준다고 해요. 실제로 깔끔하고 매력적으로 보이는 남자들을 보면 대부분 머리가 넘어가 있습니다. 어떤 스타일로 넘겨야 할지 모르겠다면 유튜브에서 여러 가지 스타일을 찾아보고 본인에게 편안한 걸 시도해 보세요. 물론 본인만의 장점을 살려 멋진 스타일을 이미 하고 계신 분은 그대로 유지하셔도 됩니다. 핵심은 남자 외모에서 깔끔함이 처음부터 끝까지 전부라는 것이에요. 손톱을 단정하게 자르고, 코털을 깎고, 머리를 정돈하는 기본적인 것들만 잘 챙겨도 외모 상위권에 들 수 있습니다.', '이마를 시원하게 넘기는 스타일이 남자 신뢰감을 높입니다. 손톱·코털·머리 정돈 같은 기본 그루밍만으로 외모 상위권에 드는 비결을 피부과 전문의 김종식이 정리합니다.', array['남자헤어', '머리스타일', '깔끔함', '이마', '외모관리', '그루밍']::text[]),
    ('o3nccMY2NsY', 'kimjongsik', '열심히 씻는데 왜 자꾸 냄새가 나는 걸까요?', '귀 뒤, 목 뒤, 겨드랑이 같은 부위를 꼼꼼히 구석구석 씻어주는 것이 핵심입니다. 열심히 씻더라도 이런 부위를 대충 넘기면 쾌쾌한 냄새가 남을 수 있어요. 또 많은 분들이 간과하는 게 옷에서 나는 냄새인데, 옷을 잘 세탁하고 섬유유연제를 사용하며 햇볕에 잘 말려주는 것이 생각보다 매우 중요합니다. 비싼 향수로 냄새를 감추려 하지 마시고 구석구석 잘 씻고 세탁만 잘 해줘도 좋은 향기가 날 수 있어요. 더 좋은 향기를 원하신다면 가볍고 프레쉬한 느낌의 향수를 가볍게 뿌려주시면 됩니다. 괜히 묵직한 향수를 뿌리면 오히려 마이너스예요. 남자는 깔끔한 게 최고라는 원칙을 향기 관리에도 그대로 적용하시면 됩니다.', '귀 뒤·목 뒤·겨드랑이를 구석구석 씻고 옷 세탁만 잘 해도 좋은 향이 납니다. 비싼 향수 없이 깔끔한 체취를 유지하는 핵심 포인트를 피부과 전문의 김종식이 안내합니다.', array['체취', '냄새관리', '세탁', '향수', '남자그루밍', '위생', '깔끔함']::text[]),
    ('-tolahyJbgk', 'kimsoohyung', '비타민C 많이 먹으면 피부가 진짜 밝아지나요?', '네, 비타민C를 꾸준히 먹으면 확실히 피부색이 밝아집니다. 비타민C가 피부에서 색소를 만드는 효소를 억제하는 능력이 있어서 색소침착을 막고 기미도 개선시켜줄 수 있어요. 하루 권장량은 100mg 정도인데, 메가도스(고용량 복용)를 하면 피부결이 좋아지고 톤이 환해지며 탄력이 생기는 변화를 느낄 수 있습니다. 무엇보다 만성 피로 개선이 가장 큰 체감 효과예요. 식후에 1000mg 두 알 정도를 먹으면 2-3시간 후에 갑자기 눈이 번쩍 뜨이면서 피로가 풀리는 느낌이 듭니다. 다만 비타민C는 아스코르빅산이라 공복에 먹으면 속쓰림이 심해질 수 있으니 반드시 밥 먹는 중간이나 식후에 복용하셔야 해요. 역류성 식도염 증상이 나타나면 잠깐 중단했다가 위가 회복된 후 다시 드시면 됩니다.', '비타민C 고용량 복용의 피부 미백 효과와 올바른 복용법을 피부과 전문의 김수형이 설명합니다.', array['비타민C', '메가도스', '피부톤', '색소침착', '기미', '피로회복', '항산화']::text[]),
    ('-tolahyJbgk', 'kimsoohyung', '러닝 많이 하면 피부가 노화된다는데 비타민C로 막을 수 있나요?', '네, 운동 전에 비타민C를 먹으면 활성산소를 낮춰 피부 노화를 예방할 수 있습니다. 러닝이나 고강도 운동을 할 때 피부에서는 활성산소가 만들어지는데, 이것은 배기가스 같은 존재로 피부 노화를 촉진시켜요. 마라톤을 오래 하시는 분들 피부가 처져 있는 것도 활성산소의 영향입니다. 실제 연구에서 사이클링 전에 비타민C 1000mg을 먹은 그룹이 안 먹은 그룹보다 유의하게 활성산소가 낮았다고 해요. 비타민C는 먹고 2-3시간 후에 혈중 농도가 최대치에 도달하기 때문에 밥 먹을 때 같이 드시고 2-3시간 뒤에 러닝하시면 가장 효과적입니다. 소화도 어느 정도 된 후라 뛰기에도 좋고, 활성산소 예방과 건강을 동시에 챙길 수 있는 방법이에요. 주 2-3회 5km씩 뛰시는 분들께 특히 추천드립니다.', '러닝 시 활성산소로 인한 피부 노화를 비타민C로 예방하는 방법을 피부과 전문의 김수형이 안내합니다.', array['비타민C', '활성산소', '러닝', '항산화', '피부노화', '운동', '마라톤']::text[]),
    ('-tolahyJbgk', 'kimsoohyung', '비타민C 많이 먹으면 신장 결석 생긴다는데 어떻게 예방하나요?', '물을 많이 마시는 것이 비타민C 메가도스 시 신장 결석을 예방하는 핵심입니다. 비타민C를 고용량으로 먹으면 몸에서 다 흡수되지 않고 일부가 소변으로 배출되는데, 소변 속 비타민C가 칼슘과 결합하면서 돌을 만들 수 있어요. 신장 결석의 통증은 출산 고통에 비견될 정도로 심하고 남성에게 더 많이 발생합니다. 소변을 계속 빠져나가게 하면 잔여 비타민C가 없으니 결석 위험이 줄어드는 원리예요. 추가로 마그네슘을 함께 복용하는 것도 도움이 됩니다. 마그네슘 제품을 고를 때는 킬레이트형이 흡수율이 가장 높고 위장 장애가 적어 가장 좋은데, 유기염 형태도 적당히 흡수되면서 위장 장애가 없어 괜찮아요. 리포좀 비타민C를 선택하면 인지질로 감싸져 있어 흡수도 잘 되고 역류성 식도염 같은 부작용도 덜합니다.', '비타민C 메가도스 시 신장 결석 예방법과 마그네슘 병용 팁을 피부과 전문의 김수형이 정리합니다.', array['비타민C', '신장결석', '마그네슘', '리포좀', '킬레이트', '메가도스', '예방']::text[]),
    ('-tolahyJbgk', 'kimsoohyung', '유산균이 장 건강 말고 피부에도 효과가 있나요?', '네, 유산균은 장 건강뿐 아니라 피부 염증 개선 효과도 있습니다. 유산균을 먹어 장내 유익균이 많아지면 유해균이 감소해서 염증이 줄어들고, 그 효과가 피부까지 전달되어 피부 염증을 완화시켜요. 유산균을 고를 때는 100억 CFU 이상의 보장균 수가 중요한데, 보장균 수란 유통기한 끝까지 한 포에 살아있는 유산균 수를 말합니다. 프로바이오틱스와 함께 프리바이오틱스(프락토올리고당)가 같이 들어있는지도 확인하세요. 올리고당이 유산균의 장 정착과 증식을 도와줍니다. 다만 장이 원래 활발한 분이 고함량 유산균을 먹으면 화장실을 너무 자주 갈 수 있으니 주의가 필요해요. 다이소에서 영양제를 살 때는 건강기능식품인지, 캔디류나 당류 가공품인지 꼭 확인하시고, 같은 브랜드라도 약국과 다이소 제품은 함량이 다를 수 있습니다.', '유산균의 피부 염증 개선 효과와 올바른 제품 선택법을 피부과 전문의 김수형이 설명합니다.', array['유산균', '피부염증', '장건강', '프로바이오틱스', '프리바이오틱스', '보장균수']::text[]),
    ('pzaQZo4CuWY', 'jeonghanmi', '피부과 의사 120명이 꼽은 인생 스킨케어템이 뭔가요?', '피부과 전문의 120명에게 인생 스킨케어 제품을 물어본 결과, 1위가 아토베리어 보습제였습니다. 2위 제로이드, 3위 보습제, 4위 에스트라 순서로 결국 모두 보습제를 꼽았어요. 보습제에는 세라마이드, 콜레스테롤, 지방산 같은 피부 장벽 구성 성분이 들어있어서 웬만하면 반 이상은 효과를 보장합니다. 피부 장벽이 밑바탕이 안 되면 어떤 기능성 화장품을 발라도 회복이 안 되거든요. 좋은 나이트크림 같은 거 필요 없이 보습제를 듬뿍 바르고 주무시면 됩니다. 아이크림도 아니고, 레티놀도 아니고, 선크림도 아니고 결국 보습제가 가장 기본이 되는 것이죠. 피부에 너무 많은 걸 바르는 건 과유불급이라 기본을 충실히 하는 게 피부가 가장 좋아질 수 있는 지름길이에요.', '피부과 의사 120명이 꼽은 인생 스킨케어 제품과 보습제의 중요성을 피부과 전문의 정한미가 정리합니다.', array['보습제', '아토베리어', '제로이드', '피부장벽', '세라마이드', '스킨케어']::text[]),
    ('pzaQZo4CuWY', 'kwonsuhyun', '피부과 의사들도 백화점 명품 화장품 쓰나요?', '피부과 전문의 120명 중 84%가 백화점 스킨케어 제품을 쓰지 않는다고 답했습니다. 대부분 병원용 제품을 사용하고 있고, 15%만 백화점 제품을 쓴다고 했어요. 쓴다고 한 분들이 사용하는 건 헤라 시그니아 크림, SK-II 피테라 에센스, 키엘 수분크림, 헤라 멀티 디펜스 선크림 정도인데, 사용 이유가 흥미롭습니다. 세라마이드와 지방산이 함유되어 기능이 좋고, 발림성이 좋은데 가격이 합리적이어서 쓴다는 거예요. 50-60만 원대 초고가 라인을 쓰시는 분은 거의 없었습니다. 결국 백화점 제품을 쓰더라도 기능 좋고 발림성 좋고 문제 안 생기는 실용적 기준으로 선택하시지, 브랜드 가치나 가격 때문에 선택하시는 건 아닌 거예요. 피부과 의사들이 화장품 구매 시 가장 중요하게 보는 것도 성분이 압도적 1위였습니다.', '피부과 의사 120명의 명품 화장품 사용 여부와 선택 기준을 피부과 전문의 권수현이 안내합니다.', array['백화점화장품', '명품', '성분', '발림성', '병원용제품', '스킨케어']::text[]),
    ('pzaQZo4CuWY', 'jeonghanmi', '닦토 하면 피부 장벽 무너진다는데 진짜 하면 안 되나요?', '피부과 전문의 120명 중 90%는 닦토를 안 하지만, 10%는 실제로 닦토를 합니다. 피부가 튼튼하거나 지성 피부라면 오히려 닦토를 해야 여드름이 안 생기고 트러블이 안 생기는 분들이 있어요. 이런 분들은 하고 싶어서 하는 게 아니라 안 하면 다음 날 큰 뾰루지가 올라오기 때문에 해야만 하는 겁니다. 결국 닦토가 무조건 나쁜 건 아니고 피부 타입과 상황에 따라 판단해야 합니다. 건성이나 민감 피부라면 피부 장벽이 무너질 수 있으니 피하시는 게 맞고, 지성이면서 피부가 강한 분이라면 필요에 따라 하셔도 괜찮아요. 안 좋으면 안 하면 되는 거니까 본인 피부 반응을 보면서 결정하시면 됩니다. 모든 사람에게 일률적으로 적용되는 정답은 없어요.', '닦토가 필요한 피부 타입과 해도 되는 기준을 피부과 전문의 정한미가 설명합니다.', array['닦토', '피부장벽', '지성피부', '여드름', '트러블', '각질제거']::text[]),
    ('pzaQZo4CuWY', 'kwonsuhyun', '피부과 의사들은 화장품 살 때 뭘 제일 먼저 보나요?', '피부과 전문의들이 화장품 구매 시 가장 우선적으로 보는 것은 성분이며, 압도적인 1위를 차지했습니다. 그 다음으로 발림성과 브랜드가 동점이고, 후기 추천은 거의 고려하지 않는다고 해요. 광고가 많은 환경이니 후기를 크게 신뢰하지 않는 것 같습니다. 성분표를 확인하냐는 질문에도 66%가 확인한다고 답했고, 남녀 비율도 거의 비슷했어요. 환자분들에게 설명해드려야 하는 직업 특성상 성분을 보는 습관이 생긴 것도 있다고 합니다. 결국 피부과 선생님들이 쓰는 보습제도 과학적 성분이 가득 든 게 아니라 심플하고 군더더기 없이 기본 성분만 들어있는 제품이에요. 피부에 너무 많은 걸 바르는 건 과유불급이니 기본에 충실한 제품을 고르시는 게 좋습니다.', '피부과 의사 120명의 화장품 선택 기준과 성분 중심 구매법을 피부과 전문의 권수현이 정리합니다.', array['화장품성분', '성분표', '발림성', '브랜드', '보습제', '피부과의사추천']::text[]),
    ('YzFCnC7KD4Q', 'kwonsuhyun', '피부과 관리 중에 임산부도 안전하게 받을 수 있는 게 있나요?', '네, LDM은 임산부도 안전하게 받을 수 있는 대표적인 피부 관리입니다. LDM은 고밀도 초음파를 사용해 피부에 살짝 열감을 주면서 진정과 재생을 동시에 시켜주는 관리예요. 피부과 시술 중에는 임산부가 받지 못하는 관리들이 꽤 많은데, LDM은 그 제한 없이 받을 수 있어서 안전한 피부 관리를 원하는 임산부분들께 특히 추천드립니다. 건조하고 푸석한 피부에 받으면 뽀송해지는 효과가 있고, 여드름이나 주사 피부염처럼 염증이 심한 경우에도 재생 모드가 따로 있어서 도움이 됩니다. 접촉 피부염이 심할 때 약 복용하면서 LDM을 병행하면 만족도가 굉장히 높고, 피부 장벽을 튼튼하게 해주는 데도 효과적이에요. 홍조 환자분들처럼 피부 장벽이 많이 무너져 뭘 발라도 따갑고 빨개지는 분들도 레이저 치료와 함께 LDM을 받으면 확실히 덜 붉어지는 효과를 볼 수 있습니다.', '임산부도 안전하게 받을 수 있는 LDM 관리의 효과와 적용 대상을 피부과 전문의 권수현이 설명합니다.', array['LDM', '임산부', '피부관리', '피부장벽', '홍조', '진정', '재생']::text[]),
    ('YzFCnC7KD4Q', 'kwonsuhyun', '울쎄라나 써마지는 무서운데 탄력 관리 받을 방법이 있을까요?', '코레지, 조비나 같은 고주파 관리 기계가 울쎄라와 써마지를 무서워하시는 분들에게 좋은 대안입니다. 이 기계들은 찌릿찌릿한 느낌 정도만 나고 크게 불편하지 않아서 편하게 받을 수 있으면서도 피부 탄력과 약간의 리프팅 효과를 볼 수 있어요. 특히 코레지는 울쎄라나 써마지 시술 전 워밍업으로도 활용하는데, 피부 온도를 미리 올려두면 시너지 효과를 낼 수 있기 때문입니다. 예를 들어 써마지 600샷을 쓸 때 초반 몇십 샷은 피부 온도 올리는 데 소비되는데, 코레지로 미리 달궈두면 600샷이 온전히 효과적으로 작용하게 됩니다. 비싼 샷 수를 아끼면서 효율을 극대화하는 방법이라고 보시면 돼요. 시술이 무서워서 리프팅을 시작하지 못하는 분들이 부담 없이 피부 탄력 관리를 시작하기에 적합한 선택입니다.', '울쎄라와 써마지가 무서운 분들을 위한 고주파 탄력 관리 기계를 피부과 전문의 권수현이 안내합니다.', array['코레지', '리프팅', '탄력', '고주파', '울쎄라', '써마지', '조비나']::text[]),
    ('YzFCnC7KD4Q', 'kwonsuhyun', '피부과에서 근육 리프팅 해주는 관리가 있다는데 정말 효과 있나요?', '이브 시너지라는 장비가 저주파 미세전류와 고주파를 함께 흘려 근육 운동을 시켜주는 관리입니다. EMS처럼 근육에 자극을 줘서 엉덩이 운동을 많이 하면 힙업이 되는 것처럼, 얼굴 근육을 운동시켜 처진 부위를 올려주는 원리예요. 꾸준히 받으면 탄력이 살면서 쳐져 있던 게 올라가고, 약간 웃상이 되는 효과를 기대할 수 있습니다. 특히 50대 이상 여성분들은 눈 뜨는 게 힘들다고 많이 호소하시는데, 이브 시너지로 눈가 주변을 자극하면 눈이 훨씬 시원하고 뜨기 편하다는 말씀을 가장 많이 하세요. 통증은 전혀 없고 근육이 움직이는 느낌 때문에 살짝 불편할 수는 있지만 아프지는 않습니다. 진피나 근막층까지 자극하는 다른 시술과 달리 근육층까지 자극을 줄 수 있어서 요즘 대세인 근육 리프팅에 딱 맞는 관리라고 보시면 됩니다.', '근육에 자극을 줘 리프팅 효과를 내는 이브 시너지 관리를 피부과 전문의 권수현이 정리합니다.', array['이브시너지', '근육리프팅', 'EMS', '리프팅', '눈처짐', '탄력', '저주파']::text[]),
    ('YzFCnC7KD4Q', 'kwonsuhyun', '제네오엑스가 연예인 관리로 유명하다던데 뭐가 좋은 건가요?', '제네오엑스는 피부 표면에 이산화탄소 버블을 만들어 피부 깊숙이 있는 산소를 끄집어내 세포에 공급하는 관리입니다. 산소가 풍부한 환경에서 세포가 활발하게 활동하도록 해주는 원리라서, 피부결이 맑아지고 홍조 감소와 혈류 증가 효과를 볼 수 있어요. 추가로 미세 버블들이 약간의 스케일링 작용을 해서 묵은 각질이나 때를 제거하는 효과도 있습니다. 연예인이나 아이돌이 시상식처럼 중요한 행사 직전에 많이 받는다고 해서 유명해졌고, 관리 끝판왕이라 불릴 만큼 프리미엄 관리로 꼽히고 있어요. 건조하고 예민한 피부에도 잘 맞아서 누구나 부담 없이 받을 수 있다는 점도 큰 장점입니다. 산소를 공급하면서 모공에 끼인 묵은 각질도 정리해주는 산소 테라피 같은 개념이라고 보시면 됩니다.', '연예인 관리로 유명한 제네오엑스의 원리와 효과를 피부과 전문의 권수현이 안내합니다.', array['제네오엑스', '산소관리', '피부결', '각질제거', '연예인관리', '홍조', '피부관리']::text[]),
    ('JAciKvJTUS4', 'jeonghanmi', '코팩 하면 모공이 늘어난다는 말, 피부과 의사들은 어떻게 생각해요?', '피부과 의사 120명 설문조사에서 코팩을 해도 모공이 안 늘어난다고 답한 의사가 더 많았습니다. 특히 남자 선생님의 60%가 안 늘어난다를 선택했는데, 코팩이 테이프보다 더 강하게 흡착해서 떼는 방식이다 보니 흔히 늘어난다고 생각하기 쉬워요. 코팩을 하면 당장 다음 날은 코가 깨끗해지는 효과가 있고, 블랙헤드를 물리적으로 제거해주는 역할을 합니다. 다만 이보다 더 중요한 건 평소 클렌징을 잘하는 것이에요. 블랙헤드가 생기기 시작하는 청소년기부터 딥클렌징에 대해 많이 물어보시는데, 꼼꼼한 세안 습관이 기본이 되어야 합니다. 코팩 자체가 모공을 늘리는 주범은 아니지만, 근본적인 피지 관리를 위해서는 올바른 클렌저 선택과 세안법이 더 효과적입니다.', '코팩이 모공을 늘리는지에 대한 피부과 의사 120명의 설문 결과를 피부과 전문의 정한미가 정리합니다.', array['코팩', '모공', '블랙헤드', '클렌징', '피지', '설문조사', '딥클렌징']::text[]),
    ('JAciKvJTUS4', 'jeonghanmi', '피부과 의사 120명이 뽑은 최고의 클렌저가 뭐예요?', '피부과 의사 120명이 뽑은 최고의 클렌저 1위는 제로이드입니다. 제로이드는 원래 병원용 화장품으로 보습제와 클렌저를 만드는 회사였는데, 불필요한 성분을 다 빼고 필요한 성분만 담아 피부가 아프거나 민감한 분들도 안심하고 쓸 수 있는 제품이에요. 아기가 써도 되고 탈이 없어서 피부과 의사 국민템 같은 존재라고 할 수 있습니다. 2위는 라로슈포제로, 에빠끌라 H 아이소-바이옴 클렌저가 약산성이고 순해서 인기가 높아요. 건성 피부에는 이 제품이 잘 맞고, 지성 피부는 에빠끌라 딥클렌징 포밍처럼 좀 더 뽀득뽀득한 제품이 적합합니다. 클렌저는 피부 타입마다 맞는 게 다르기 때문에 본인 피부에 맞는 걸 잘 골라 쓰는 게 가장 중요해요.', '피부과 의사 120명이 선택한 최고의 클렌저 순위를 피부과 전문의 정한미가 안내합니다.', array['클렌저', '제로이드', '라로슈포제', '민감성피부', '건성', '지성', '세안']::text[]),
    ('JAciKvJTUS4', 'kwonsuhyun', '효소 세안제(엔자임 파우더)는 매일 써도 괜찮은 건가요?', '지성 피부라면 매일 사용해도 괜찮지만, 건성이나 민감한 피부는 2주에 한 번 정도가 적당합니다. 효소 세안제는 가루를 물에 거품 내서 올려 쓰는 방식인데, 피부에 묵은 각질이 덮여있는 것 같고 찝찝할 때 깨끗하게 씻어내는 데 효과적이에요. 피부과 의사 120명 중 12명이 최고의 클렌저로 꼽았을 만큼 인기가 있고, ASF, 스킨피디아, 주닥 등 여러 브랜드가 있는데 큰 차이 없이 다 좋습니다. 사용 팁은 거품을 내서 올려놓고 다른 부위를 먼저 씻은 뒤 마무리 세안을 하는 것이에요. 코팩 대신 효소 세안제로 피지 관리를 하는 것도 좋은 방법이고, 여행 갈 때 일회용 포장된 제품을 가져가면 화장도 잘 지워져서 편리합니다. 지성 피부는 데일리로, 건성 피부는 가끔씩 각질이 신경 쓰일 때만 사용하시는 게 좋겠습니다.', '효소 세안제의 올바른 사용 빈도와 피부 타입별 활용법을 피부과 전문의 권수현이 설명합니다.', array['효소세안제', '엔자임파우더', '각질', '클렌저', '지성피부', '건성피부', '스킨피디아']::text[]),
    ('JAciKvJTUS4', 'kwonsuhyun', '피부과 의사들도 각질 제거 스크럽 같은 거 하나요?', '피부과 의사 120명 중 각질 제거를 한다고 답한 비율은 단 9%에 불과합니다. 10명 중 9명은 각질 제거를 하지 않는다고 답했는데, 이는 각질 제거가 피부 장벽을 손상시킬 수 있기 때문이에요. 각질 제거를 한다고 답한 9%는 대부분 지성 피부이거나 피부가 튼튼한 분들이라서, 그런 피부 타입이라면 해도 괜찮습니다. 다만 지성 피부도 여름에 일주일에 1~2회 정도가 적당하고, 이중세안을 열심히 하기 때문에 매일 할 필요는 없어요. 이중세안의 경우 남녀 통틀어 40%만 한다고 답했는데, 여자 선생님은 65%가 하시고 남자 선생님은 12% 정도만 하십니다. 피부 장벽을 위해 웬만하면 각질 제거는 안 하시는 게 좋고, 지성 피부처럼 튼튼한 피부만 소량으로 간헐적으로 하시길 권합니다.', '피부과 의사 120명의 각질 제거 및 이중세안 습관 설문 결과를 피부과 전문의 권수현이 정리합니다.', array['각질제거', '피부장벽', '이중세안', '지성피부', '스크럽', '필링젤', '클렌징']::text[]),
    ('PVJQvsj7FtQ', 'leedoyoung', '피부에서 진짜 광이 나려면 각질 제거를 해야 하나요?', '아닙니다. 각질을 제거하는 것보다 보습을 충분히 해주는 게 피부 광을 내는 데 훨씬 효과적입니다. 피부에서 광이 나려면 피부 장벽이 탄탄해야 하고, 각질같이 도드라져 보이는 게 없어야 하는데 이를 위해 필링젤로 각질을 벗기면 오히려 피부가 예민해지고 장벽이 망가져요. 그러면 반짝반짝 빛나는 게 아니라 빨개지고 푸석푸석해집니다. 운동장에서 먼지가 일어나면 물을 뿌리는 것처럼, 보습크림이나 재생크림을 듬뿍 발라주시는 게 핵심이에요. 그리고 잔주름도 피부를 칙칙하게 만드는 요인인데, 피부 표면이 고르면 빛 반사가 잘 일어나고 울퉁불퉁하면 빛이 여러 방향으로 퍼지는 난반사가 생겨 칙칙해 보입니다. 보습과 잔주름 관리, 이 두 가지만으로도 피부 결 정리의 기본은 완성됩니다.', '피부 광을 위해 각질 제거 대신 보습이 더 중요한 이유를 피부과 전문의 이도영이 설명합니다.', array['피부광', '보습', '각질제거', '피부장벽', '잔주름', '난반사', '피부결']::text[]),
    ('PVJQvsj7FtQ', 'leedoyoung', '피부톤이 어둡고 칙칙한데 IPL 받으면 정말 밝아져요?', '네, IPL은 멜라닌과 헤모글로빈을 동시에 잡아줘서 피부톤을 균일하고 밝게 만드는 데 효과적인 시술입니다. 피부톤을 결정하는 건 단순히 까만 정도만이 아니라 멜라닌(어둡게), 헤모글로빈(붉게), 카로틴(노랗게) 같은 여러 색소가 관여하거든요. IPL은 다양한 파장의 강한 빛을 쏘아 기미, 주근깨, 검버섯 같은 멜라닌 색소를 감소시키고, 여드름 붉은 자국이나 홍조, 늘어난 모세혈관도 개선해줍니다. 거기에 콜라겐과 엘라스틴 같은 섬유 조직 생성도 촉진해서 피부를 탄탄하게 만들어주는 효과까지 있어요. 좀 더 정밀한 치료를 원하면 GV 레이저라는 옵션도 있는데, 이건 레이저로 잡티나 혈관을 하나하나 파괴시키는 방식이라 한 번에 확실한 효과를 원하실 때 적합합니다. 피부톤이 균일하면 인지연령이 최대 28살까지 차이 날 수 있다는 연구도 있을 만큼 피부톤 정리의 효과는 큽니다.', 'IPL과 GV 레이저로 피부톤을 밝고 균일하게 만드는 방법을 피부과 전문의 이도영이 안내합니다.', array['IPL', '피부톤', '멜라닌', '기미', '홍조', 'GV레이저', '미백']::text[]),
    ('PVJQvsj7FtQ', 'leedoyoung', '비타란 스킨부스터 받으면 엠보 없이도 효과가 있는 건가요?', '네, 엠보 없이 오히려 더 좋은 재생과 보습 효과를 낼 수 있습니다. 많은 분들이 비타란이나 리쥬란을 맞으면 올록볼록 엠보가 올라와야만 효과가 있다고 오해하시는데, 엠보는 약물을 1mm보다 깊게 주입했다는 뜻일 뿐이에요. 실제로 재생이 일어나는 핵심 부위는 0.3mm 내외의 아주 얕은 층이기 때문에, 얕게 주사하면 엠보 없이도 재생과 보습 효과를 충분히 볼 수 있습니다. 얕게 놓으면 멍, 붓기, 붉어짐이 거의 없어서 바로 일상생활이 가능하고, 결혼식 직전이나 중요한 촬영 전에 받으시는 분들도 많아요. 통증도 적어서 마취 없이도 시술이 가능할 정도이며, 인젝터와 손기술로 치료하면 환자분들 대부분 안 아프다고 하십니다. 효과는 보통 한 달 정도 지속되고 꾸준히 받으면 점점 오래 가서, 한 번 속광의 맛을 보면 끊기 어렵다는 반응이 많습니다.', '비타란을 엠보 없이 얕게 시술해도 효과가 있는 이유를 피부과 전문의 이도영이 설명합니다.', array['비타란', '스킨부스터', '엠보', '리쥬란', '속광', '재생', '보습']::text[]),
    ('PVJQvsj7FtQ', 'leedoyoung', '피부톤이 균일하고 고르면 진짜 동안으로 보이나요?', '네, 피부톤의 균일함이 인지연령에 큰 영향을 미친다는 논문 결과가 있습니다. 고른 피부톤을 가진 사람은 인지연령이 21살로 평가된 반면, 고르지 않은 사람은 49살로 평가됐어요. 같은 얼굴이라도 피부톤이 고르면 더 건강해 보이고 동안처럼 보이기 때문에, 이성에게도 더 매력적으로 인식된다는 연구도 있습니다. 이는 건강해 보이는 외모가 본능적으로 매력을 느끼게 하는 심리와 연결되어 있어요. 피부톤을 화사하게 만들려면 색소는 IPL이나 GV 레이저로, 속광은 비타란 같은 스킨부스터로 채워주시면 됩니다. 거기에 써마지, 울쎄라, 티타늄 같은 리프팅으로 콜라겐을 챙기면 탱탱하면서도 건강해 보이는 피부를 완성할 수 있어요. 단순히 미백만이 아니라 색소, 혈관, 속광, 콜라겐까지 종합적으로 관리하는 게 진짜 동안 피부의 비결입니다.', '균일한 피부톤이 동안 인상에 미치는 영향과 관리법을 피부과 전문의 이도영이 정리합니다.', array['피부톤', '동안', '인지연령', '콜라겐', '리프팅', '스킨부스터', '미백']::text[]),
    ('gs-z84RKBvg', 'kwonsuhyun', '결혼식 일주일 전에 받아도 티 안 나는 리프팅이 있나요?', '티타늄 리프팅이 결혼식이나 중요한 행사 일주일 전에 받기 가장 좋은 리프팅 시술입니다. 즉각적인 효과가 있으면서 다운타임은 하루 정도 붉어지는 것 외에는 거의 없고 통증도 적어요. 울쎄라도 좋은 시술이지만 붓기가 한 달 가까이 가는 분들도 있어서, 시간적 여유가 없는 상황에서는 티타늄이 훨씬 안전합니다. 특히 티타늄의 장점은 울쎄라가 조심해야 하는 입 옆 라인에도 시술할 수 있다는 점이에요. 불독살처럼 쳐진 부위, 이중턱, 마리오네트 주름, 팔자주름에도 효과가 좋습니다. 실제로 친구에게 결혼식 일주일 전에 시술했는데 다운타임 전혀 없이 이쁘게 결혼식에 나타날 수 있었어요. 한 두 달 여유가 있다면 울쎄라를 추천드리지만, 급하게 예뻐져야 할 때는 리프팅 기계 중 티타늄이 최선입니다.', '결혼식 일주일 전에도 안심하고 받을 수 있는 티타늄 리프팅의 장점을 피부과 전문의 권수현이 설명합니다.', array['티타늄', '리프팅', '결혼식', '다운타임', '울쎄라', '팔자주름', '마리오네트']::text[]),
    ('gs-z84RKBvg', 'kwonsuhyun', '리쥬란 맞으면 너무 아프다던데 안 아프게 받는 방법이 있나요?', '기계를 활용해 얕게 주입하면 멍도 없고 거의 안 아프게 리쥬란이나 비타란을 받을 수 있습니다. 손주사로 하나하나 놓으면 찌를 때 아프고 약물이 들어갈 때 또 아파서 이중 고통이 있는데, 기계로 미세바늘을 이용해 얕게 톡톡 넣으면 깊이가 깊지 않아 통증이 확 줄어요. 음압이 가해지면서 피부를 당기며 들어가는 방식이라 부항처럼 쫙 당기면서 주입되기 때문에 훨씬 편합니다. 마취 10분 정도만 해도 불편하지 않게 받을 수 있고, 마취 안 하고도 시술하는 분들이 많을 정도예요. 다운타임도 거의 없어서 당일 바로 피부결이 좋아지고 화장이 잘 먹는 효과를 볼 수 있습니다. 주사 피부염이 심한 분들도 마취 없이 바로 시술하면 다음 날 좋아지는 경우가 꽤 있어서, 통증과 다운타임이 걱정인 분들에게 정말 좋은 방법입니다.', '리쥬란과 비타란을 안 아프고 다운타임 없이 받는 기계 주입법을 피부과 전문의 권수현이 안내합니다.', array['리쥬란', '비타란', '스킨부스터', '통증', '기계주입', '다운타임', '피부결']::text[]),
    ('gs-z84RKBvg', 'kwonsuhyun', '지성 피부인데 일주일 안에 피부 확 좋아지는 방법 있나요?', '지성 피부라면 스케일링과 압출이 일주일 안에 가장 가성비 있게 피부를 반짝반짝하게 만드는 방법입니다. 지성 피부는 눈에 보이는 여드름이 없더라도 자세히 보면 피지가 박혀 있는데, 이게 화장이 안 먹게 하는 큰 요소예요. 피지를 뽑아주고 기름 덩어리, 미세먼지, 묵은 각질을 제거하면 피부가 굉장히 반짝반짝해집니다. 피부가 튼튼한 분들은 AHA, BHA 성분의 필링을, 민감하지만 각질 정리가 필요한 분들은 좀 더 약한 PHA 필링을 받으시면 됩니다. 가격도 부담 없으면서 효과는 확실해서 일주일 전에 이것만 해도 대만족이에요. 만약 2~3일 전에 염증이 크게 났다면 염증 주사를 강력히 추천드리는데, 막 올라와서 아플랑 말랑 할 때 빨리 오시면 다음 날 확 가라앉습니다.', '지성 피부가 일주일 안에 반짝 피부를 만드는 스케일링과 필링을 피부과 전문의 권수현이 정리합니다.', array['스케일링', '지성피부', '필링', 'AHA', 'BHA', 'PHA', '피지']::text[]),
    ('gs-z84RKBvg', 'kwonsuhyun', '스킨보톡스 맞으면 표정이 어색해지지 않나요?', '부작용 없을 만한 부위에 살짝씩만 놓으면 표정이 어색해지지 않으면서 반짝반짝 팽팽한 피부를 만들 수 있습니다. 스킨보톡스를 맞으면 이마 같은 곳은 바닥을 왁스로 닦은 것처럼 반짝반짝 팽팽해지는데, 주로 이마, 미간, 나비존 위주로 시술하고 눈가는 웃을 때 어색해질 수 있어 굉장히 소량만 얇게 합니다. 입가 주변에 조금이라도 닿으면 입의 움직임이 어색해지거나 입이 돌아간다고 느낄 수 있어서 입가 쪽은 아예 하지 않아요. 이 라인 위주로만 하면 부작용을 겪을 일이 거의 없습니다. 중요한 행사를 앞두고는 욕심을 버리고 과하게 놓지 않는 게 핵심이에요. 한 달 전에 맞으면 혹시 이마가 무겁더라도 충분히 회복될 시간이 있으니, 어떤 시술을 받은 티는 안 나면서 티나게 예뻐질 수 있는 시술입니다.', '스킨보톡스를 표정 어색함 없이 안전하게 맞는 부위와 요령을 피부과 전문의 권수현이 안내합니다.', array['스킨보톡스', '보톡스', '이마', '모공', '부작용', '표정', '리프팅']::text[]),
    ('MRTWtBHBTjA', 'kimsoohyung', '40대인데 써마지 지금 시작해도 효과 있나요?', '40대야말로 써마지를 받으면 가장 만족도가 높은 나이입니다. 써마지는 피부 표면에 열을 줘서 콜라겐 합성을 도와 탄력을 개선시키는 시술인데, 30대에 시작하면 조직학적으로 변화는 있지만 본인이 피부로 느끼는 변화를 잘 못 느껴요. 반면 40대는 써마지를 받으면 확실히 달라붙는 느낌을 체감할 수 있어서 정말 좋아하시는 연령대입니다. 오히려 50대가 지나서 써마지를 시작하면 효과를 느끼기가 쉽지 않기 때문에, 40대가 시작하기 최적기라고 볼 수 있어요. 울쎄라도 마찬가지로 40대에 받기 좋은데, 울쎄라는 깊숙한 근막층에 작용하는 리프팅 시술이라 써마지와 다른 층을 타겟합니다. 써마지와 울쎄라는 피부과의 국영수 같은 기본 리프팅 시술이니, 40대라면 피부에 장기적인 적금을 들인다는 마음으로 꼭 시작하시길 추천드립니다.', '40대가 써마지를 시작하기 최적인 이유와 효과를 피부과 전문의 김수형이 설명합니다.', array['써마지', '40대', '리프팅', '울쎄라', '콜라겐', '탄력', '피부노화']::text[]),
    ('MRTWtBHBTjA', 'parkhyojin', '30대인데 피부에 뭘 발라도 안 먹는 느낌인데 어떡하죠?', '30대에 뭘 발라도 흡수가 안 되는 느낌이 시작된다면 스킨부스터가 가장 효과적인 해결책입니다. 스킨부스터는 말 그대로 피부를 확 끌어올리는 부스터 역할을 하는데, 30대는 큰 피부 문제가 없더라도 미리 적금을 들어놓는 개념으로 받으면 좋아요. 종류도 다양해서 쥬베룩처럼 콜라겐을 생성해주는 콜라겐 부스터, 리쥬란처럼 피부 장벽을 만드는 PN 성분을 직접 넣어주는 부스터, 콜라겐을 직접 넣어주는 리투오 같은 것도 있습니다. 속건조, 모공 늘어남 같은 고민을 해소시켜줄 수 있고, 피부로 제일 잘 느끼는 시술이 바로 스킨부스터예요. 30대에 스킨부스터를 하면 비용 대비 효과가 가장 좋은 시기이기 때문에 놓치고 지나가지 않는 게 중요합니다. 건성 피부분들이 특히 체감 효과가 크니 꼭 시도해보시길 권합니다.', '30대에 스킨부스터가 최적의 선택인 이유와 종류를 피부과 전문의 박효진이 안내합니다.', array['스킨부스터', '30대', '리쥬란', '쥬베룩', '콜라겐', '속건조', '모공']::text[]),
    ('MRTWtBHBTjA', 'kimsoohyung', '20대 남자인데 이마 주름이 벌써 생겼는데 보톡스 맞아야 하나요?', '네, 이마 주름이 이미 보인다면 20대라도 빨리 보톡스를 맞으셔야 합니다. 남자분들은 여자분들보다 눈썹 아치가 훨씬 높고 튀어나와 있는 경우가 많아서, 이마 근육을 습관적으로 쓰면서 가로주름이 일찍 생기기 쉬워요. 지금부터 이마 보톡스로 근육 사용을 줄여놓지 않으면 40대만 돼도 흉터 같은 깊은 이마 가로주름이 자리잡게 됩니다. 심한 경우 10대도 이미 굵은 이마 주름이 있는 분들이 있을 정도예요. 남자는 피부가 여자보다 두껍고 근육량이 많아 움직임이 커서 잔주름이 깊게 지기 쉽습니다. 보톡스만으로 할 수 있던 걸 시기를 놓치면 보톡스에 필러까지 추가해야 할 수 있으니, 주름이 져 있다면 미루지 마세요. 20대는 여드름 흉터 치료도 재생이 잘 일어나는 시기라 가장 좋은 효과를 얻을 수 있습니다.', '20대 남자가 이마 보톡스를 일찍 시작해야 하는 이유를 피부과 전문의 김수형이 설명합니다.', array['보톡스', '이마주름', '20대', '남자피부', '주름예방', '여드름흉터', '미간']::text[]),
    ('MRTWtBHBTjA', 'kimsoohyung', '60대인데 팔자주름이 흉터처럼 깊은데 이거 시술로 좋아질 수 있나요?', '60대에 흉터처럼 깊어진 팔자주름과 마리오네트 주름에는 쥬브젠이 가장 효과적입니다. 쥬브젠은 기계를 통해 필러와 이산화탄소를 번갈아 주입하는 시술인데, 이산화탄소가 피부 재생을 촉진해줘서 단순히 필러만 넣는 것보다 효과가 훨씬 빠르게 나타나요. 채워주면서 동시에 재생을 유도해 주름을 위로 올리는 원리입니다. 비슷한 효과를 내는 하이드로 리프팅도 있는데, 이건 묽은 필러를 손으로 피부층에 깔아주는 방식이에요. 쥬브젠이 기계로 주입해 좀 더 정밀하고 이산화탄소 효과까지 더해져 재생이 빠른 편입니다. 60대 중에서도 많이 처진 경우 안면거상 수술이 필요할 수 있지만, 수술 없이 관리하고 싶다면 울쎄라 같은 리프팅도 충분히 해볼 만하고 거상 시기를 늦춰주는 효과도 있습니다.', '60대 깊은 팔자주름에 효과적인 쥬브젠 시술의 원리와 장점을 피부과 전문의 김수형이 정리합니다.', array['쥬브젠', '팔자주름', '60대', '마리오네트', '필러', '리프팅', '재생']::text[]),
    ('KI40pGEqEtw', 'kwonsuhyun', '피부과 의사 120명이 평생 하나만 받겠다고 고른 시술이 뭐예요?', '피부과 의사 120명 중 56표로 압도적 1위를 차지한 시술은 써마지입니다. 써마지가 선택된 이유는 부작용이 거의 없으면서 피부를 튼튼하게 하고, 잔주름을 개선하며, 늘어진 모공을 쫀쫀하게 만들어주기 때문이에요. 슬로우 에이징의 대명사로, 꾸준히 받으면 남들보다 5년에서 10년 덜 늙을 수 있다고 합니다. 당장은 드라마틱한 변화가 눈에 안 보일 수 있지만, 써마지를 꾸준히 받은 사람과 안 받은 사람이 10년 뒤에 만나면 그 격차는 정말 크고 다시 메꾸기도 쉽지 않아요. 1년에 한 번만 해줘도 장기적 효과가 확실하기 때문에 피부과 의사들이 직접 환자를 보면서 그 차이를 확인한 결과 이 시술을 고르신 거죠. 젊었을 때 야금야금 해놓는 것과 노화가 많이 진행된 뒤 복구하는 것은 완전히 다른 문제라는 점을 기억하세요.', '피부과 의사 120명이 평생 하나의 시술로 써마지를 선택한 이유를 피부과 전문의 권수현이 설명합니다.', array['써마지', '안티에이징', '슬로우에이징', '모공', '잔주름', '리프팅', '피부과시술']::text[]),
    ('KI40pGEqEtw', 'jeonghanmi', '보톡스 효과 풀리면 오히려 더 늙어 보이는 거 아닌가요?', '아닙니다, 보톡스가 풀려도 더 처지거나 주름이 더 지는 일은 없습니다. 보톡스는 효과가 있는 4~6개월 동안 표정 근육 사용을 줄여 고정 주름이 생기는 시간을 늦춰주는 원리예요. 효과가 빠지면 원래 상태로 돌아올 뿐, 더 나빠지지는 않습니다. 유명한 쌍둥이 비교 논문을 보면 한 명은 계속 보톡스를 맞고 한 명은 안 했는데, 나중에 비교하면 완전히 다른 사람처럼 보일 정도로 차이가 나요. 25살 때부터 꾸준히 맞으면 그때의 근육 상태가 계속 유지되는 것과 같은 효과를 기대할 수 있죠. 피부과 의사 투표에서도 보톡스가 2위를 차지했는데, 저렴하면서도 맞으면 바로 이마 주름이 펴지고 사각턱이 줄어드는 효과가 눈에 보이기 때문입니다. 처음 맞을 때 거부감이 있을 수 있지만 안티에이징 효과는 확실하니 안심하셔도 됩니다.', '보톡스 효과가 풀려도 더 늙지 않는 원리와 안티에이징 효과를 피부과 전문의 정한미가 안내합니다.', array['보톡스', '안티에이징', '이마주름', '사각턱', '주름예방', '슬로우에이징']::text[]),
    ('KI40pGEqEtw', 'jeonghanmi', '울쎄라는 써마지랑 뭐가 달라서 3위를 했어요?', '울쎄라는 써마지로는 할 수 없는 얼굴 윤곽 변화까지 가능한 시술이라 3위에 올랐습니다. 써마지가 피부 표면을 탄탄하게 만드는 데 집중한다면, 울쎄라는 깊은 층부터 끌어올려 처짐을 개선하고 지방층을 정리하는 역할을 해요. 특히 1.5 팁이라는 피부층 전용 팁이 있어서 리프팅과 써마지 효과를 동시에 누릴 수 있다는 게 가장 큰 장점입니다. 나이 들면서 아래쪽이 커지고 불독처럼 처지는 느낌이 드는 분들은 울쎄라를 하면 갸름해지면서 젊은 느낌이 돌아와요. 앞볼이 내려와서 팔자가 깊어지거나 이중턱이 생긴 분들에게 특히 효과적이죠. 다만 써마지 56표에 비해 울쎄라는 12표로, 피부가 두껍고 살이 있는 얼굴에 더 적합한 시술이라 선택한 분이 적었을 수 있습니다. 살이 많아 처짐이 고민인 분이라면 울쎄라를 우선 고려해보세요.', '울쎄라가 써마지와 다른 점과 적합한 얼굴 타입을 피부과 전문의 정한미가 정리합니다.', array['울쎄라', '써마지', '리프팅', '팔자주름', '이중턱', '처짐', '윤곽']::text[]),
    ('KI40pGEqEtw', 'kwonsuhyun', '스킨보톡스 맞으면 진짜 모공이 줄어들어요?', '네, 스킨보톡스를 맞으면 100% 기름기가 줄고 모공이 닫히는 효과가 있습니다. 피부과 의사 투표 4위에 오른 시술인데, 피부층에 보톡스를 얇게 깔아주는 방식이라 쪼글쪼글한 부분이 펴지고 피부가 반짝반짝해져요. 특히 기름기가 많거나 화장이 잘 안 먹는 분들에게 효과가 확실합니다. 또한 일반 근육 보톡스를 맞았을 때 눈이 무겁다고 느끼시는 분들도 스킨보톡스로 전환하면 자연스러우면서도 만족도가 높아요. 피부가 너무 두껍고 강한 분이나 반대로 너무 얇아서 세게 받으면 안 되는 분 모두에게 잘 맞는 시술이기도 합니다. 화장이 잘 먹는 매끈한 피부를 원하신다면 스킨보톡스를 한번 시도해보시는 걸 추천드립니다.', '스킨보톡스로 모공과 피지를 줄이는 효과와 적합한 피부 타입을 피부과 전문의 권수현이 안내합니다.', array['스킨보톡스', '모공', '피지조절', '보톡스', '피부결', '화장먹힘']::text[]),
    ('RV6Fo-pHN2c', 'jeonghanmi', '먹는 선크림이 있다는데 진짜 효과 있나요?', '네, Polypodium leucotomos라는 고사리 계열 식물 추출물이 들어간 캡슐로 광 보호 효과가 있습니다. 이 성분은 고대 마야 문명에서 피부병 치료에 쓰던 고사리에서 유래했는데, 70년대 의사들이 연구한 결과 햇볕으로부터 피부를 보호하는 역할이 있다는 걸 밝혀냈어요. 비타민C, 비타민E, 라이코펜, 루테인 같은 강력한 항산화 성분도 함께 들어있어서 야외 나가기 30분 전에 캡슐을 먹으면 4시간 정도 광 보호를 해준다고 합니다. 다만 이걸 먹는다고 피부에 물리적 방어막이 생기는 건 아니기 때문에 선크림은 따로 바르셔야 해요. 나갈 때 선크림 챙겨 바르고 덧바르는 게 귀찮을 때 보조 수단으로 활용하면 편리합니다. 현재 한국에서는 구하기 어렵고 해외에서 구매해야 하는 제품이에요.', '고사리 추출물 캡슐을 먹으면 4시간 광 보호 효과가 있습니다. 먹는 선크림의 항산화 원리와 바르는 선크림과 병행해야 하는 이유를 피부과 전문의 정한미가 안내합니다.', array['먹는선크림', '자외선차단', '항산화', '비타민C', '광보호', '선크림']::text[]),
    ('RV6Fo-pHN2c', 'jeonghanmi', '클렌징 오일 쓰면 피부가 무겁고 뻑뻑한데 괜찮은 제품 있나요?', '바비브라운 수딩 클렌징 오일은 오일 특유의 무거운 느낌이 거의 없고 가볍고 촉촉한 사용감이 특징입니다. 보통 클렌징 오일을 쓰면 약간 뻑뻑하고 무거운 느낌이 있는데, 이 제품은 비사보롤과 생강추출물 같은 진정 성분이 들어있어서 클렌징 과정에서 피부 자극을 낮춰주는 역할을 해요. 토코페롤, 블루베리 추출물, 구기자 추출물 같은 항산화 성분도 포함되어 피부를 보호하는 데 도움이 됩니다. 겨울에는 촉촉한 느낌이 오히려 좋아서 거부감 없이 쓸 수 있고, 사용 후에도 산뜻한 편이에요. 성분보다는 사용감 자체가 좋아서 계속 쓰게 되는 제품이라고 합니다. 클렌징 오일의 무거움 때문에 꺼리셨던 분들이라면 한번 시도해볼 만합니다.', '비사보롤·생강추출물 등 진정 성분이 들어간 클렌징 오일은 무겁지 않고 산뜻합니다. 겨울에도 부담 없이 쓸 수 있는 가벼운 오일 클렌저 선택법을 피부과 전문의 정한미가 정리합니다.', array['클렌징오일', '세안', '바비브라운', '진정성분', '항산화', '겨울스킨케어']::text[]),
    ('RV6Fo-pHN2c', 'jeonghanmi', '물놀이할 때 선크림 덧바르기 너무 번거로운데 방법 없나요?', '젖은 피부에 바로 발라도 광 보호 효과가 유지되는 선크림 제품이 있습니다. 보통 피부에 물이 묻어 있을 때 선크림을 바르면 하얗게 뜨면서 그냥 닦여버리잖아요. 그래서 물놀이 중 선크림을 덧발라야 할 때 수건으로 닦고 다시 바르는 과정이 번거로운데, 라로슈포제에서 나온 이 제품은 젖은 상태 그대로 발라도 자외선 차단 효과가 있어요. 또한 스프레이 형태 선크림 중 플라스틱 용기 제품은 기체 반입이 안 되는 캔과 달리 해외여행 시 비행기에 가져갈 수 있어 편리합니다. 아벤느에서 나온 앰플형 선스크린은 SPF50+에 UVA까지 차단되면서도 세럼 제형이라 가볍게 바를 수 있어요. 야외 활동이 많은 분이라면 상황에 맞는 선크림 형태를 여러 개 갖추는 것도 좋은 방법입니다.', '젖은 피부에 바로 발라도 효과가 유지되는 선크림이 있습니다. 물놀이 중 간편하게 덧바를 수 있는 스프레이·앰플형 선크림을 피부과 전문의 정한미가 소개합니다.', array['선크림', '자외선차단', '물놀이', '덧바르기', '라로슈포제', 'SPF50']::text[]),
    ('RV6Fo-pHN2c', 'jeonghanmi', '호주 포포크림이 피부 재생에 좋다는데 바세린이랑 뭐가 달라요?', '루카스 포포 크림은 바세린 같은 꾸덕한 제형이지만 비타민E 같은 성분이 추가로 들어있어 재생과 진정, 회복에 더 좋습니다. 호주 사람들은 우리가 피부 안 좋을 때 바세린을 바르듯이 포포크림을 일상적으로 사용한다고 해요. 피부가 안 좋을 때, 입술이 갈라졌을 때, 발뒤꿈치가 텄을 때 등 다양한 상황에서 만능 연고처럼 활용합니다. 단순한 바세린과 달리 재생을 돕는 성분이 들어있어서 조금 더 회복 효과를 기대할 수 있는 점이 차이예요. 호주 여행 시 마트에서 쉽게 구할 수 있고, 호주에서 오면 많이들 사오는 대표 제품 중 하나이기도 합니다. 만능 보습 연고가 필요하신 분이라면 하나 구비해두시면 활용도가 높을 거예요.', '루카스 포포크림은 바세린 제형에 비타민E가 추가되어 재생·진정 효과가 더 좋습니다. 입술·발뒤꿈치 등 만능 연고 활용법을 피부과 전문의 정한미가 설명합니다.', array['포포크림', '피부재생', '보습', '바세린', '비타민E', '진정']::text[]),
    ('0WsdmFY9ZO4', 'kimsoohyung', '콜라겐 앰플이나 팩 열심히 바르면 진짜 탄력이 좋아지나요?', '아닙니다, 바르는 콜라겐 제품으로 실질적인 탄력 개선을 기대하기는 어렵습니다. 바르는 것은 피부 자체의 지지층을 통과해서 흡수되는 것 자체가 정말 쉽지 않은 문제이기 때문이에요. 팩을 했을 때 수분감이 채워지고 쿨다운 효과로 피부가 좋아 보이고 화장이 잘 먹는 정도의 효과는 분명히 있습니다. 하지만 궁극적으로 탄력이 좋아지고 시술을 많이 해서 개선되는 수준과는 완전히 다른 차원이에요. 써마지로 콜라겐이 있는 층만 정확히 타겟해서 시술을 해도 고객분들이 느끼기 어려운 경우가 있는데, 바르는 것만으로 그 효과가 난다면 노벨상감이라고 할 수 있죠. 일시적으로 촉촉해 보이는 효과는 즐기되, 근본적인 탄력 개선은 시술의 영역이라고 생각하시면 됩니다.', '바르는 콜라겐 제품의 한계와 실제 탄력 개선 방법을 피부과 전문의 김수형이 설명합니다.', array['콜라겐', '앰플', '팩', '탄력', '홈케어', '써마지', '바르는화장품']::text[]),
    ('0WsdmFY9ZO4', 'parkhyojin', '모공 줄여준다는 화장품 정말 효과가 있는 건가요?', '모공을 실제로 줄이기는 어렵지만, 나이아신아마이드 성분은 피지 분비 감소에 유의미한 효과가 있어 피부 결을 좋아 보이게 할 수 있습니다. 모공이 늘어난 원인에 따라 다른데, 피지 과다로 늘어나 보이는 경우에는 나이아신아마이드의 피지 조절 효과가 도움이 됩니다. 반면 세로로 늘어난 모공, 즉 콜라겐 감소로 인한 노화성 모공을 앰플만으로 줄이는 것은 거의 불가능해요. 각질이 많아지면서 모공이 부각되어 보이는 건성 피부의 경우, 레티놀로 각질 턴오버를 촉진하면 결이 좋아지고 모공이 작아 보이는 효과는 있습니다. 다만 모공이 정말 많고 넓은 지성 피부의 모공 자체를 개선하기는 시술로도 힘든데 바르기만으로 효과가 난다는 건 과대 광고에 가깝습니다. 피지형 모공이라면 나이아신아마이드를, 각질형이라면 레티놀을 시도해보세요.', '모공 줄이는 화장품의 실제 효과와 성분별 차이를 피부과 전문의 박효진이 정리합니다.', array['모공', '나이아신아마이드', '피지', '레티놀', '각질', '지성피부', '피부결']::text[]),
    ('0WsdmFY9ZO4', 'kimsoohyung', '비싼 아이크림 20대부터 꾸준히 바르면 효과 있나요?', '20대부터 아이크림을 바른다고 해서 눈가 주름을 예방하는 큰 효과를 기대하기는 어렵습니다. 눈가 잔주름의 핵심은 타고난 피부 두께인데, 원래 피부가 얇고 눈 밑에 잔주름이 잘 생기는 사람이 아이크림을 발랐다고 그게 안 생기지는 않거든요. 20대에는 노화가 빨리 진행되지 않기 때문에 아이크림의 필요성이 더 낮아요. 아이크림을 꾸준히 바르는 분이라면 전반적으로 피부에 신경을 많이 쓰는 분이니 아이크림 단독의 효과라고 보기 힘든 측면도 있습니다. 아이크림이 생각보다 비싸서 대충 검색해도 6만 원대인데, 같은 비용이면 보톡스를 한 번 맞는 게 눈가 주름 예방에 훨씬 효과적이에요. 근육 사용을 제한해서 주름이 커지는 걸 막는 보톡스가 더 확실한 투자입니다.', '아이크림의 실제 효과와 보톡스 대안을 피부과 전문의 김수형이 안내합니다.', array['아이크림', '눈가주름', '잔주름', '보톡스', '20대', '눈밑', '주름예방']::text[]),
    ('0WsdmFY9ZO4', 'parkhyojin', '아침에 물 세안만 하면 정말 괜찮은 건가요?', '아침에도 순한 세안제로 세안을 해주는 게 맞고, 물 세안만으로는 부족합니다. 밤 사이에 쌓이는 먼지나 기름, 베개에서 묻는 노폐물 등을 아침에 제거해줘야 하루를 깨끗하게 지낼 수 있어요. 다만 저녁보다는 훨씬 순한 세정제를 쓰는 게 좋고, 피부 타입에 따라 차이는 있습니다. 피부가 얇은 건성 타입이라면 일주일 중 3~4일은 물 세안, 3~4일은 순한 클렌징을 번갈아 하는 방법도 괜찮아요. 반면 지성 피부이신 분들은 아침에도 꼭 폼클렌저를 사용해서 세안을 해주셔야 여드름도 덜 나고 관리가 쉬워집니다. 자고 일어났을 때 피부의 pH와 비슷한 폼클렌저를 사용해서 산성도를 맞춰주는 역할도 중요하니, 본인 피부 타입에 맞게 세안 강도를 조절하세요.', '아침 물 세안의 한계와 피부 타입별 올바른 세안법을 피부과 전문의 박효진이 안내합니다.', array['물세안', '아침세안', '폼클렌저', '지성피부', '건성피부', '노폐물', 'pH']::text[]),
    ('21ZaQr_YlWg', 'kimjongsik', '세르프가 써마지보다 덜 아프다는데 진짜예요?', '써마지보다는 확실히 덜 아프지만 완전히 안 아픈 시술은 아닙니다. 세르프는 쿨링 시스템이 매우 강력하고 조절이 가능해서 표면을 차갑게 해주면 통증도 줄고 화상 위험도 줄어들어요. 마취크림을 바르고 레벨 5 정도로 시술하면 편안하게 받으실 수 있고, 에너지를 높여도 부위에 따라 통증이 거의 없는 곳도 있습니다. 매년 써마지를 받으면서 통증 때문에 괴로워하시던 분들이 세르프로 바꾸면 만족도가 크게 올라가는 경우가 많아요. 써마지가 두려워서 예약을 몇 번이나 변경하고 가슴이 콩닥콩닥하셨던 분들도 세르프로 전환한 뒤에는 편하게 받으신다고 합니다. 에너지 레벨을 높여서 효과를 극대화하면서도 덜 아프게 시술할 수 있는 방법들이 있어서, 통증 때문에 리프팅을 포기했던 분에게 추천드립니다.', '세르프가 써마지보다 덜 아픈 이유와 통증 조절 방법을 피부과 전문의 김종식이 설명합니다.', array['세르프', '써마지', '리프팅', '통증', '고주파', '쿨링', '마취']::text[]),
    ('21ZaQr_YlWg', 'kimjongsik', '세르프는 화상 위험이 없다는 게 사실인가요?', '네, 세르프는 스파이더 패턴이라는 거미줄 모양 팁 구조 덕분에 화상 케이스가 없는 시술입니다. 써마지는 팁이 피부에 완전히 밀착되어야 하는데, 세르프는 팁이 1.5배 정도 더 크기 때문에 컨택이 덜 될 때도 있을 수 있어요. 그럼에도 화상이 안 생기는 이유가 바로 스파이더 패턴 설계 때문입니다. 레벨 9의 높은 에너지를 기본으로 깔고 900샷을 쏴도 화상 케이스가 단 한 건도 없었다고 해요. 또한 강한 쿨링 시스템이 표면을 차갑게 만들어 전기가 깊은 층으로 더 잘 흘러가도록 하면서 동시에 피부 표면의 화상을 막아줍니다. 세르프 600샷이면 써마지 900샷 효과를 낼 수 있고, 실제 들어가는 에너지도 1.5배 이상 높은데도 안전하다는 점이 큰 장점이에요.', '세르프가 높은 에너지에도 화상을 입히지 않는 원리를 피부과 전문의 김종식이 설명합니다.', array['세르프', '화상', '스파이더패턴', '고주파', '리프팅', '써마지', '안전성']::text[]),
    ('21ZaQr_YlWg', 'leedoyoung', '세르프로 볼륨을 채우거나 윤곽을 바꿀 수 있나요?', '네, 세르프는 딥 모드를 활용하면 볼륨을 이동시키고 윤곽을 다듬는 것이 어느 정도 가능합니다. 볼륨 리플레이스먼트라고 하는데, 중안면 쪽이 꺼져 있거나 옆 볼이 빠져 있는 분들에게 열심히 디자인해서 시술하면 볼륨이 살짝 올라가고 채워지는 느낌을 줄 수 있어요. 딥, 미들, 쉘로우 세 가지 깊이 모드가 있어서 딥 모드로는 라인 잡기, 미들은 써마지와 유사한 효과, 쉘로우는 모공과 피부결 개선에 각각 활용됩니다. 튀어나온 부분은 딥모드로 안쪽으로 밀어넣고, 파인 부분은 쉘로우 모드로 펴주는 식의 맞춤 디자인이 가능하죠. 다만 실 리프팅처럼 극적인 변화를 기대하면 안 되고, 써마지와 달리 고주파 중에서 유일하게 컨셉을 가지고 시술할 수 있는 장비라는 게 핵심입니다.', '세르프의 깊이별 모드로 볼륨 이동과 윤곽 개선이 가능한 원리를 피부과 전문의 이도영이 안내합니다.', array['세르프', '볼륨', '리프팅', '윤곽', '중안면', '딥모드', '고주파']::text[]),
    ('21ZaQr_YlWg', 'leedoyoung', '세르프랑 같이 하면 좋은 시술 조합이 뭐예요?', '세르프와 궁합이 좋은 대표 조합은 레디어스와 힐로웨이브입니다. 레디어스는 볼륨감이 많이 생기지 않으면서 피부 퀄리티를 개선해주는 시술인데, 밑에서 깔아주고 세르프가 위에서 에너지를 주면 대만 샌드위치처럼 꽉 눌린 느낌으로 피부가 조여져요. 2주 뒤에 다시 오시면 피부가 샌드위치 딱딱 눌러놓은 것처럼 탄탄해졌다고 말씀하시는 분들이 많습니다. 또한 힐로웨이브는 히알루론산 베이스 스킨부스터로, 볼이 꺼지는 게 걱정되는 분들에게 즉각적인 볼륨감과 투명한 광을 줘요. 리투오도 좋은 조합인데 만들어진 좋은 성분을 넣어주고 그 위에 열 자극을 주면 시너지 효과가 크다고 합니다. 고주파 단독보다 부스팅 시술을 병행하면 훨씬 좋은 결과를 기대할 수 있습니다.', '세르프와 병행하면 효과적인 시술 조합을 피부과 전문의 이도영이 정리합니다.', array['세르프', '레디어스', '힐로웨이브', '리프팅', '고주파', '스킨부스터', '콤비시술']::text[]),
    ('3bbyb8LGn-c', 'kimsoohyung', '울쎄라 써마지 받고 싶은데 왜 의사는 스컬트라를 권하나요?', '볼륨이 빠져있는 얼굴에 울쎄라나 써마지를 아무리 받아도 채워질 수가 없기 때문입니다. 이것을 정보의 비대칭성이라고 하는데, 환자분들은 유명한 시술을 받으면 좋아질 거라고 생각하지만 실제로는 본인에게 뭐가 필요한지 모르는 경우가 많아요. 특히 북방계 얼굴형은 나이가 들수록 살이 빠지면서 중안부가 길어지고 노안으로 보이는데, 이런 경우 볼륨을 채워주는 시술이 훨씬 효과적이에요. 필러보다는 자연스럽게 볼류밍을 해주는 스컬트라 같은 시술을 선호하는 이유가 여기에 있습니다. 얼굴에 볼륨감이 없는 상태에서 피부 겉을 아무리 좋게 만들어도 근본적인 개선은 어렵거든요. 피부과 의사 100명에게 물었을 때도 써마지가 1위인 이유가 건성 피부가 많기 때문이지, 모든 사람에게 맞는 건 아닙니다.', '울쎄라 써마지 대신 스컬트라를 권하는 이유와 얼굴형 차이를 피부과 전문의 김수형이 설명합니다.', array['스컬트라', '울쎄라', '써마지', '볼륨', '북방계', '리프팅', '안티에이징']::text[]),
    ('3bbyb8LGn-c', 'parkhyojin', '남방계 동글동글한 얼굴형인데 어떤 시술이 잘 맞나요?', '남방계 얼굴은 울쎄라와 스킨보톡스를 같이 받으면 효과가 가장 좋습니다. 남방계는 이목구비가 또렷하고 얼굴이 동글동글한 편인데, 나이가 들면 옆 라인이 넓어지고 스키니하지 않아져서 얼굴 라인에 자신이 없어지는 게 특징이에요. 울쎄라가 근막에 에너지를 줘서 갖다 붙이면 날렵하고 갸름해지는 효과가 있어 남방계에 특히 잘 맞습니다. 스킨보톡스도 피부 결을 좋아지게 하면서 동시에 근육의 볼륨 자체를 조절해 깎아주는 역할을 하기 때문에 남방계 분들에게 필수적이에요. 특히 턱 밑이 두둑하신 분들은 스킨보톡스를 같이 맞아주면 라인이 정리됩니다. 남방계는 기본적으로 피부가 건강하고 노화가 덜 오는 편이니, 채우기보다는 깎는 시술에 집중하시면 됩니다.', '남방계 얼굴에 울쎄라와 스킨보톡스가 잘 맞는 이유를 피부과 전문의 박효진이 안내합니다.', array['남방계', '울쎄라', '스킨보톡스', '얼굴형', '리프팅', '얼굴라인', '보톡스']::text[]),
    ('3bbyb8LGn-c', 'kimsoohyung', '건성 피부인데 써마지가 속건조·잔주름에 왜 좋은 건가요?', '써마지는 피부에 열을 가해 새로운 콜라겐을 생성하도록 자극해서, 건성 피부의 핵심 문제인 속건조와 잔주름을 동시에 개선합니다. 건성 피부는 피부가 얇은 게 핵심인데, 써마지로 열을 계속 줘서 콜라겐 층을 두껍게 만들어주면 장벽이 튼튼해지면서 수분 증발이 줄어들어요. 피부가 두꺼워지면 건조함으로 인한 잔주름도 개선되고 탄력도 좋아집니다. 피부과 의사 100명 투표에서 써마지가 압도적 1위를 차지한 것도 결국 건성 피부가 많기 때문이고, 이 시술 하나로도 많은 것이 개선되기 때문이에요. 북방계 건성 피부 분들은 볼륨 채움과 함께 써마지를 꾸준히 받으면 노화 방지에 가장 효과적입니다. 반복해서 맞을수록 콜라겐이 쌓여 피부 전체가 탄탄해지는 걸 느끼실 수 있어요.', '건성 피부에 써마지가 속건조와 잔주름을 개선하는 원리를 피부과 전문의 김수형이 설명합니다.', array['써마지', '건성피부', '콜라겐', '속건조', '잔주름', '피부장벽', '안티에이징']::text[]),
    ('3bbyb8LGn-c', 'parkhyojin', '지성 피부는 써마지 말고 어떤 시술이 더 맞나요?', '지성 피부에는 스킨보톡스와 미세바늘 고주파(포텐자)가 환자 만족도가 가장 높은 시술입니다. 지성 피부는 원래 피부 자체가 건강하고 탄력도 좋은 편이라 써마지를 받아도 효과를 크게 느끼기 어려워요. 써마지가 전체적으로 데워주는 방식이다 보니 지성 피부에는 너무 약하게 느껴지는 반면, 미세바늘 고주파는 바늘이 들어간 길을 따라 열을 줘서 모공 주변 콜라겐 생성이 잘 되어 모공 축소 효과가 더 확실합니다. 스킨보톡스는 피지선 조절과 모공을 매끈하게 하면서 근육 볼륨까지 줄여주니 지성 피부에는 이만한 시술이 없어요. 모공이 넓은 분들의 궁극적 목표는 모공 자체를 없애는 것보다 피부 결을 좋아지게 하는 것으로 바뀌게 되는데, 그런 면에서도 이 두 시술이 가장 적합합니다. 스킨부스터를 하나 추가한다면 콜라겐 생성을 유도하는 쥬베룩 정도를 고려해보세요.', '지성 피부에 써마지보다 효과적인 시술 조합을 피부과 전문의 박효진이 정리합니다.', array['지성피부', '스킨보톡스', '미세바늘고주파', '모공', '포텐자', '쥬베룩', '피지']::text[]),
    ('yXq8W7FE_K0', 'jeonghanmi', '여행 갈 때 클렌징은 뭘로 간단하게 해결하나요?', '여행에는 클렌징 패드가 가장 편리합니다. 클렌징 밀크나 오일은 새기도 하고 휴대하기 불편한데, 개별 포장된 클렌징 패드라면 부피도 작고 가볍게 화장을 지울 수 있어요. 아이 메이크업을 했다면 패드를 바로 닦아내지 말고 잠시 눈 위에 올려두어 불려서 닦아내는 게 포인트입니다. 면봉에 패드 액을 적셔서 눈가 라인을 꼼꼼하게 닦아주면 잔여물이 깔끔하게 제거돼요. 이후 약산성 거품 클렌저로 2차 세안을 하면 이중 세안이 완성됩니다. 수정 화장용으로 나온 제품도 여행용 클렌징 패드로 활용할 수 있으니 용도를 고정해서 생각하지 마세요. 선크림과 메이크업을 함께 한 날은 이렇게 이중 세안을 해줘야 모공에 잔여물이 남지 않습니다.', '개별 포장 클렌징 패드는 가볍고 새지 않아 여행에 최적입니다. 아이 메이크업 불림 기법과 약산성 클렌저 이중 세안 팁을 피부과 전문의 정한미가 안내합니다.', array['클렌징패드', '여행스킨케어', '이중세안', '클렌징', '약산성', '아이메이크업']::text[]),
    ('yXq8W7FE_K0', 'jeonghanmi', '자외선 많은 곳 여행할 때 항산화 제품이 꼭 필요한가요?', '네, 해를 많이 보는 여행지에서는 항산화 제품이 필수입니다. 자외선에 노출되면 활성산소가 생기면서 피부 노화가 빨라지는데, 항산화제가 이를 잡아주는 역할을 해요. 스킨수티컬즈의 CE 페룰릭은 비타민C와 비타민E, 페룰산이 조합된 대표적인 항산화 세럼이고, 레스베라트롤 BE는 알파-토코페롤(비타민E)과 바이칼린까지 들어간 강력한 항산화제입니다. 호주처럼 자외선이 강한 곳에 갈 때는 집에 있는 항산화 제품 중 하나라도 챙겨가는 게 좋아요. 레스베라트롤 BE는 제형 자체가 꽤 촉촉해서 로션 정도의 느낌으로 바를 수 있습니다. 선크림 아래에 항산화 세럼을 레이어링하면 자외선 방어와 피부 보호를 동시에 할 수 있어요. 건조한 여행지라면 그 위에 크림을 하나 더 얹어주면 보습까지 완성됩니다.', '자외선이 활성산소를 만들어 피부 노화를 앞당기기 때문에 항산화 세럼이 필수입니다. CE 페룰릭·레스베라트롤 BE 등 여행용 항산화제 선택법을 피부과 전문의 정한미가 설명합니다.', array['항산화', '비타민C', 'CE페룰릭', '레스베라트롤', '자외선', '스킨수티컬즈', '여행스킨케어']::text[]),
    ('yXq8W7FE_K0', 'jeonghanmi', '야외활동 많은 여행에서 선크림은 어떻게 선택해야 하나요?', '얼굴용과 바디용을 나눠서 준비하는 게 핵심입니다. 얼굴에는 블루라이트까지 차단해주는 톤업 선크림처럼 발림성 좋은 제품을 쓰고, 아이들이나 가족에게는 제로이드 모이스처 리페어 선크림같이 저자극 제품을 쓰면 좋아요. 목이나 팔 같은 넓은 부위에는 양이 많이 필요하므로 현지에서 대용량 선크림을 사서 쓰는 것도 방법입니다. 호주 약국(케미스트 웨어하우스)에서는 1리터짜리 4시간 방수 브로드 스펙트럼 선스크린도 판매하고 있어요. 피부과 의사 100인 설문에서 발림성 좋다고 추천된 제품처럼 텍스처를 직접 확인하고 고르는 게 중요합니다. 야외에서 대여섯 시간 이상 활동한다면 선크림은 2~3시간 간격으로 덧발라야 효과가 유지돼요. 아이용은 별도의 저자극 제품을 준비해서 온 가족이 부담 없이 자외선 차단을 하시길 권합니다.', '얼굴엔 톤업 선크림, 바디엔 대용량 브로드 스펙트럼 제품으로 나눠 준비하는 것이 좋습니다. 2~3시간 덧바르기 원칙과 아이용 저자극 선택법을 피부과 전문의 정한미가 정리합니다.', array['선크림', '자외선차단', '브로드스펙트럼', '제로이드', '톤업선크림', '야외활동']::text[]),
    ('yXq8W7FE_K0', 'jeonghanmi', '하루 종일 햇빛 본 날 저녁에 마스크팩 하면 효과 있나요?', '네, 자외선에 오래 노출된 날 저녁에는 마스크팩으로 피부를 진정·보습해주는 게 도움이 됩니다. 특히 바이오 셀룰로스 재질 마스크는 앰플 같은 에센스를 잘 머금고 있어서 일반 시트 마스크보다 보습 효과가 뛰어나요. 바이오 셀룰로스는 마스크 재질 중에서 가장 비싼 축에 속하는 프리미엄 시트 제형입니다. 여기에 PDRN(연어 DNA 성분) 같은 재생 성분이 들어있으면 자외선으로 지친 피부 회복에 더 좋아요. 약 20분 정도 붙여두었다가 떼어내고 잔여 에센스를 흡수시키면 됩니다. 야외에서 대여섯 시간 햇빛을 보고 나서 피부가 건조하게 느껴질 때 이렇게 해주면 다음날 피부 컨디션이 확연히 달라져요. 여행 가실 때 샘플이나 개별 포장된 마스크팩을 한두 장 챙겨가시면 자외선 많이 본 날 구급 케어로 활용할 수 있습니다.', '바이오셀룰로스 마스크팩은 일반 시트보다 보습력이 뛰어나 자외선 지친 피부 회복에 효과적입니다. PDRN 재생 성분과 20분 사용법을 피부과 전문의 정한미가 안내합니다.', array['마스크팩', '바이오셀룰로스', 'PDRN', '보습', '자외선', '피부진정', '재생']::text[]),
    ('UiiAyU7D2Fo', 'jeonghanmi', '선크림이 노화 방지에 진짜 그렇게 중요한 건가요?', '네, 선크림은 피부 노화를 막는 가장 강력한 첫 번째 수단입니다. 햇빛에 노출되면 피부 노화가 촉진되어 주름이 깊어지고 피부가 얇아지는데, 선크림이 이를 차단해주는 역할을 하죠. 70-80년대만 해도 선크림은 해수욕장이나 등산할 때만 바르는 것이었고, 제형도 뻑뻑하고 하얗게 떠서 일상용으로는 쓸 수가 없었어요. 그 시절 사람들이 동일한 야외활동을 했지만 자외선 차단을 못해서 피부 노화가 급속도로 왔던 겁니다. 지금은 발림성 좋은 제품들이 나와서 매일 바르는 게 자연스러워졌고, 이 차이가 70-80년대 남성들과 요즘 남성들의 외모 격차를 만들어낸 핵심 이유예요. 옛날 배우 사진을 보면 25살인데도 30대 중반처럼 보이는 경우가 많은데 자외선 누적 노출이 가장 큰 원인이었습니다. 늙지 않으려면 선크림은 일상에서 매일 바르는 습관이 되어야 합니다.', '선크림이 피부 노화 방지에 가장 중요한 이유를 피부과 전문의 정한미가 설명합니다.', array['선크림', '자외선', '피부노화', '안티에이징', '동안', '주름예방', '광노화']::text[]),
    ('UiiAyU7D2Fo', 'jeonghanmi', '남자도 스킨케어 루틴을 꼭 해야 동안이 되나요?', '네, 매일 꾸준히 기초 스킨케어를 하는 것만으로도 노화 속도가 확연히 달라집니다. 70-80년대 남성들은 비누로 세수하고 스킨이나 로션 정도만 가볍게 바르는 게 전부였어요. 면도할 때도 비누 거품으로 하거나 아예 거품 없이 깎는 경우가 많았죠. 반면 요즘 남성들은 폼클렌징, 기초 단계 바르기, 선크림, 이중 세안, 심지어 마스크팩까지 하시는 분들이 꽤 있습니다. 이런 루틴이 별것 아닌 것 같아도 매일 해주면 피부에 수분을 공급하고 지친 피부를 재생시켜서 노화를 확실히 늦춰줘요. 요즘 40대 배우들이 20대처럼 보이는 건 타고난 것도 있지만 매일의 스킨케어 루틴이 결정적인 역할을 하고 있습니다. 남성분들도 최소한 클렌징, 보습, 선크림 세 단계는 꼭 챙기시길 권합니다.', '남성 스킨케어 루틴이 동안에 미치는 영향을 피부과 전문의 정한미가 정리합니다.', array['남성스킨케어', '동안', '보습', '안티에이징', '기초케어', '클렌징']::text[]),
    ('UiiAyU7D2Fo', 'jeonghanmi', '담배 피우면 얼굴 피부가 진짜 빨리 늙나요?', '네, 흡연은 피부 조기 노화의 대표적인 원인 중 하나입니다. 담배를 피우면 유해 물질이 체내로 들어가서 콜라겐을 파괴하고, 비타민C의 기능을 떨어뜨리면서 피부가 칙칙해지고 주름이 깊어지는 현상이 나타나요. 70-80년대에는 흡연이 남성성의 상징으로 여겨져서 성인 남성이면 당연히 담배를 피우는 문화가 있었습니다. 대중매체에서도 배우가 고뇌하거나 카리스마를 보일 때 담배가 필수 소품이었고, 그 모습 자체가 멋으로 인식됐죠. 그래서 당시 남성 흡연율이 지금보다 훨씬 높았고, 이것이 피부 노화를 가속시켜 같은 나이라도 더 늙어 보이게 만들었습니다. 흡연은 콜라겐 파괴와 혈류 감소를 동시에 일으키기 때문에 피부가 빠르게 탄력을 잃어요. 피부 노화가 신경 쓰인다면 금연이 어떤 고가 크림보다 효과적인 안티에이징입니다.', '흡연이 피부 조기 노화를 일으키는 원리를 피부과 전문의 정한미가 설명합니다.', array['흡연', '피부노화', '콜라겐', '주름', '금연', '안티에이징', '비타민C']::text[]),
    ('UiiAyU7D2Fo', 'jeonghanmi', '옷 스타일도 나이 들어 보이는 데 영향을 주나요?', '네, 패션은 실제 나이와 상관없이 외모 인상을 크게 좌우합니다. 70-80년대 사진을 보면 20대인데도 정장에 넥타이를 하고 있어서 30대 이상으로 보이는 경우가 많았어요. 당시에는 격식과 성숙함, 권위를 내세우는 패션이 주류였기 때문에 남성들이 실제 나이보다 훨씬 어른스럽게 보였죠. 반면 요즘은 50대도 후드티에 짧은 자켓을 걸치거나 찢어진 청바지를 입는 등 나이 구분 없이 편안한 옷을 입는 시대가 됐습니다. 또 예전에는 매체가 적어서 TV 연예인 패션을 그대로 따라해 획일적이었지만, 지금은 자기 개성 중심으로 옷을 입으니 더 젊어 보이는 효과가 있어요. 나훈아, 남진이 20-21살인데 정장 차림 때문에 30대 초중반으로 보였던 사례가 이를 증명합니다. 젊어 보이고 싶다면 포멀한 스타일보다 본인에게 어울리는 캐주얼 룩을 찾아보시는 게 도움이 됩니다.', '옷 스타일이 나이 인상에 미치는 영향을 피부과 전문의 정한미가 안내합니다.', array['패션', '동안', '안티에이징', '옷스타일', '캐주얼', '젊어보이는법']::text[]),
    ('cjid131LV_g', 'leedoyoung', '스킨부스터 리투오가 리쥬란이랑 뭐가 다른 건가요?', '리쥬란은 피부세포에 재생 신호를 보내는 것이고, 리투오는 완성된 피부 구조물을 직접 넣어주는 것으로 원리가 완전히 다릅니다. 리쥬란은 세포한테 콜라겐을 만들라는 설계도를 넣어주는 역할이라 효과가 나타나기까지 시간이 걸려요. 반면 리투오는 사람의 진피를 가공해서 세포 외 기질(집) 자체를 통째로 넣어주기 때문에 효과가 즉각적으로 나타납니다. 넣어준 세포 외 기질에 줄기세포, 섬유모세포 같은 세포들이 몰려들면서 콜라겐과 엘라스틴, 히알루론산을 만들어내고, 혈관까지 새로 형성되어 인프라가 구축돼요. 쉽게 비유하면 리쥬란은 세포에게 집 짓는 설계도를 주는 것, 리투오는 이미 지어진 집을 통째로 넣어주는 것입니다. 그래서 리투오는 맞자마자 피부가 바로 좋아지는 즉각적인 변화를 느낄 수 있어요. 효과는 한 달에 최대로 나오고 두 달에서 길게는 세 달까지 지속됩니다.', '리쥬란은 설계도, 리투오는 완성된 집을 통째로 넣는 원리로 즉각적 효과가 나는 차이를 피부과 전문의 이도영이 설명합니다.', array['리투오', '리쥬란', '스킨부스터', '세포외기질', '콜라겐', '탄력', '재생']::text[]),
    ('cjid131LV_g', 'leedoyoung', '리프팅 시술 전에 리투오를 먼저 받으면 효과가 더 좋나요?', '네, 리투오로 세포 외 기질을 채워놓고 리프팅을 받으면 효과가 훨씬 좋고 오래 갑니다. 나이가 들면 세포 외 기질이 매년 줄어들기 때문에 리프팅을 받아도 젊었을 때만큼 효과가 안 나오는 경우가 많아요. 리투오로 세포 외 기질을 보충하고 인프라를 만들어 놓으면 그 위에 써마지, 울쎄라, 세르프, 올타이트, 리니어지, 텐트리플 같은 리프팅 시술의 효과가 극대화됩니다. 타이밍은 바쁜 분은 같은 날 바로 할 수도 있지만, 세포 외 기질이 자리 잡고 인프라가 구성된 후인 한 달 뒤에 리프팅을 하는 게 더 좋은 전략이에요. 고주파(써마지, 세르프, 올타이트), 초음파(울쎄라, 리니어지, 텐트리플), 레이저(티타늄) 시술 모두 궁합이 좋습니다. 피부 컨디션이 떨어진 채로 리프팅만 반복하시는 분이라면 리투오를 먼저 받아서 토대를 만들어주는 것을 고려해보세요. 탄탄한 기반 위에 리프팅을 하면 결과의 질이 달라집니다.', '리투오로 세포 외 기질을 먼저 채운 뒤 리프팅하면 효과가 극대화되는 이유와 최적 타이밍을 피부과 전문의 이도영이 안내합니다.', array['리투오', '리프팅', '써마지', '울쎄라', '스킨부스터', '탄력', '세포외기질']::text[]),
    ('cjid131LV_g', 'leedoyoung', '입가 잔주름에 리투오가 필러보다 나은 이유가 뭔가요?', '입가는 움직임이 많아서 필러를 넣으면 이동하거나 무거워져 처지기 쉬운데, 리투오는 그런 부담 없이 매끈하게 개선시켜줍니다. 필러는 입 주변에 넣으면 볼륨감이 무겁게 느껴질 수 있고, 보톡스는 잘못 넣으면 입이 돌아갈 수 있어 위험한 부위예요. 리투오는 볼륨을 채우는 게 아니라 피부 자체를 탄탄하고 매끈하게 만들어주는 원리라서 자연스러운 결과를 줍니다. 시술 시 깊은 층에는 캐뉼라(뭉툭한 관)로 약간 긁듯이 자극을 주면서 넣는데, 이렇게 하면 상처 재생 신호와 함께 리투오 성분이 더 잘 안착돼요. 입 주변 시술 후 멍이 조금 들 수 있지만, 멍이 절대 안 되는 상황이면 덜 긁으면 되니 조절이 가능합니다. 예전에는 입 주변 개선에 레디어스를 많이 썼지만 최근에는 리투오가 더 매끈해지는 느낌이 좋아서 선호하고 있어요. 입가 잔주름이 고민이라면 필러 대신 리투오를 먼저 고려해보시길 권합니다.', '움직임 많은 입가에 필러 대신 리투오로 매끈하게 개선하는 원리와 캐뉼라 시술법을 피부과 전문의 이도영이 설명합니다.', array['리투오', '입가주름', '필러', '잔주름', '스킨부스터', '캐뉼라', '입주변']::text[]),
    ('cjid131LV_g', 'leedoyoung', '리투오 맞으면 결절이 생길 수도 있다는데 괜찮은 건가요?', '결절이 드물게 생길 수 있지만, 쥬베룩이나 스컬트라의 결절과는 달리 간단하게 해결할 수 있어서 크게 걱정하지 않으셔도 됩니다. 리투오는 파우더를 수화(액체로 녹여) 해서 주입하는데, 이 과정에서 가루가 완전히 녹지 않으면 뭉친 채로 피부에 들어갈 수 있어요. 분유를 탈 때 가루가 뭉치는 것과 같은 원리인데, 뭉친 부위에 생리식염수를 넣으면 터지면서 고르게 녹아 간단히 해결됩니다. 리투오는 무세포 동종 진피, 즉 사람 피부의 진피층에서 면역 세포를 제거하고 곱게 갈아놓은 파우더이기 때문에 인체 적합성이 높아요. 결국 사람 피부를 3D 프린터로 복사해서 넣어주는 것과 같아 이물 반응이 적습니다. 부작용으로는 멍이 가장 흔하고 특히 입 주변은 멍이 잘 드는 부위라 시술 전에 미리 일정을 고려하시는 게 좋아요. 볼륨이 채워지는 시술이 아니라 피부를 탄탄하게 만드는 시술이니 필러 같은 풍선 효과를 기대하시면 안 됩니다.', '리투오 결절은 파우더 뭉침으로 생리식염수로 간단히 해결되는 원리와 주의사항을 피부과 전문의 이도영이 안내합니다.', array['리투오', '결절', '부작용', '스킨부스터', '무세포동종진피', '멍', '주의사항']::text[]),
    ('V2gzIokZF7o', 'kimsoohyung', '리프팅 레이저 받으면 피부가 너덜너덜해져서 나중에 더 처진다는 게 사실인가요?', '아닙니다, 이건 정말 엄청난 미신이에요. 울쎄라의 원리는 깊은 층의 근막에 자극을 줘서 조직을 더 튼튼하게 만들어 끌어올리는 것이라 오히려 강화되면 강화됐지 너덜너덜해질 수가 없습니다. 이 오해가 나온 배경은 성형외과 거상수술 시 근막을 벗겨서 당겨야 하는데, 울쎄라를 많이 받으면 유착이 생겨 수술이 어려워질 수 있다는 점에서 비롯된 것 같아요. 다만 중요한 건 조직이 재생될 충분한 시간을 줘야 한다는 것인데, 한 달 간격으로 세 번씩 하는 건 너무 과한 겁니다. 울쎄라나 써마지 같은 시술의 권장 주기가 6개월에서 1년인 이유가 바로 피부가 재생되고 리모델링할 시간이 필요하기 때문이에요. 최소 3~6개월은 기다려줘야 조직이 충분히 회복됩니다. 적절한 간격을 지키면서 받으면 피부에 해를 가하는 게 아니라 오히려 피부 장벽을 튼튼하게 만들어주니 걱정하지 않으셔도 됩니다.', '리프팅 레이저가 피부를 망가뜨린다는 오해의 진실을 피부과 전문의 김수형이 설명합니다.', array['울쎄라', '리프팅', '레이저', '피부노화', '근막', '써마지', '부작용']::text[]),
    ('V2gzIokZF7o', 'parkhyojin', '레이저 시술은 겨울에 받아야 효과가 더 좋은 건가요?', '색소 레이저에 한해서는 여름철 주의가 필요하지만, 리프팅이나 항노화 시술은 계절과 무관합니다. 색소, 기미, 잡티 치료는 햇빛 영향을 많이 받다 보니 여름에 과하게 하면 자극이 심해지거나 효과가 떨어질 수 있어요. 특히 농사를 짓거나 야외에서 하루 종일 일하시는 분이라면 색소 치료는 여름에 안 하는 게 좋습니다. 그런데 하루 종일 사무실에 계시고 휴양지에서 열심히 놀지 않는 분이라면 사실 여름과 겨울에 큰 차이가 없어요. 점 빼기나 검버섯 제거 같은 시술은 테이프 붙이고 재생하는 동안 땀이 차서 불편할 수 있어서 여름에 하지 말라는 말이 나온 것입니다. 써마지나 울쎄라 같은 항노화 리프팅 시술은 여름이든 겨울이든 차이가 없고, 오히려 여름엔 환자가 적어 의사가 더 정성스럽게 케어해줄 수 있어요. 색소 치료만 여름철에 강도를 조절하면 되고 나머지 시술은 계절을 가릴 필요가 없습니다.', '레이저 시술의 여름·겨울 차이와 계절별 주의점을 피부과 전문의 박효진이 안내합니다.', array['레이저', '색소', '여름시술', '기미', '써마지', '울쎄라', '계절']::text[]),
    ('V2gzIokZF7o', 'kimsoohyung', '국산 보톡스랑 수입 보톡스 내성이나 유지기간 차이가 진짜 있나요?', '국산이라고 효과가 떨어지는 건 아니며, 내성이 걱정된다면 코어톡스를 추천합니다. 보톡스 내성 이야기가 나온 건 톡신에 단백질이 붙어있느냐 아닌지가 핵심인데, 단백질이 없는 제품이 내성 가능성이 낮아요. 외산 제오민이 분자량이 국산 보톡스의 4~5분의 1로 작아서 내성 걱정이 적은 걸로 유명한데, 이걸 국산 버전으로 만든 게 코어톡스입니다. 여러 환자에게 시술하면서 느낀 바로는 코어톡스가 제오민보다 효과가 조금 더 세고 유지기간도 길다고 합니다. 가격은 일반 국산이 가장 저렴하고 코어톡스, 제오민 순으로 약 2배씩 차이가 나요. 처음 보톡스를 맞아보는 분이라면 한 번으로 내성이 생길 일은 없으니 저렴한 국산부터 시작해도 무방합니다. 다만 꾸준히 맞을 계획이라면 내성과 유지기간을 고려해 코어톡스를 선택하는 게 현명한 전략이에요.', '국산·수입 보톡스의 내성과 유지기간 차이를 피부과 전문의 김수형이 정리합니다.', array['보톡스', '내성', '코어톡스', '제오민', '국산보톡스', '유지기간', '주름']::text[]),
    ('V2gzIokZF7o', 'parkhyojin', '피부과 시술 한 번 받다가 그만두면 효과가 다 사라지나요?', '아닙니다, 한 번이라도 받은 효과는 피부에 남아있고 절대 원점으로 돌아가지 않습니다. 피부과 시술은 PT와 비슷해서 한 번 한다고 드라마틱한 변화가 보이진 않지만 꾸준히 하면 건강한 피부가 완성되는 구조예요. 시술을 중단하면 효과가 사라진 것처럼 느끼지만, 사실은 노화가 계속 진행되면서 올려놓은 것에서 깎여나간 것이지 원래 상태로 돌아간 게 아닙니다. 비유하자면 밑에 구멍 뚫린 항아리에 물을 채우는 것과 같아서, 햇빛과 노화라는 주적이 있는 한 계속 채워줘야 유지되는 거예요. 0이었던 피부를 7까지 올렸다면 중단해도 5 정도로 돌아올 수는 있지만 다시 0이 되진 않습니다. 그리고 이런 시술이 중첩되고 쌓이는 게 정말 중요해서 꾸준히 관리한 분과 안 한 분의 50대 피부는 극적으로 달라요. 운동과 마찬가지로 꾸준히 해야 유지되는 것이지 말짱 도루묵은 절대 아닙니다.', '피부과 시술 중단 시 효과가 사라지는지 여부를 피부과 전문의 박효진이 설명합니다.', array['피부과시술', '유지기간', '안티에이징', '노화', '꾸준한관리', '피부관리']::text[]),
    ('6LS_rrVi2gk', 'jeonghanmi', '비타민C·레티놀이 자극되는 민감 피부는 어떻게 안티에이징하나요?', '민감 피부는 순수 비타민C나 레티노익애씨드처럼 강한 성분을 무리하게 쓰기보다 자극이 덜한 대체 성분으로 가는 게 안전한 안티에이징 방법이에요. 비타민C 자극이 부담스럽다면 마그네슘 아스코빌 포스페이트, 아스코빌 글루코사이드 같은 비타민C 유도체가 좋고, 미백이 목적이면 5% 미만의 나이아신아마이드도 좋은 대안입니다. 레티노이드는 4세대 아크리프 같은 비교적 순한 처방 성분도 있지만 그래도 자극이 있으면 레티놀이나 레티날 화장품 라인으로 단계적으로 내려가야 해요. 그래도 따갑거나 뒤집어진다면 양을 쌀알만큼 줄여 크림에 섞어 쓰는 식의 빈도·농도 조절이 필요합니다. 자극을 피하면서 탄력·항노화를 노리려면 EGF·FGF 같은 성장인자, 리쥬란으로 대표되는 PDRN 성분, 엑소좀 함유 화장품도 좋은 선택이에요. 처음 사용 시에는 패치 테스트 후 주 2~3회로 시작해 점차 늘려보시면 됩니다. 강한 성분을 무리해서 쓰는 것보다 견딜 수 있는 성분을 꾸준히 쓰는 게 결과가 더 좋아요.', '민감 피부도 쓸 수 있는 자극 적은 안티에이징 성분을 피부과 전문의 정한미가 정리합니다.', array['안티에이징', '비타민C유도체', '나이아신아마이드', '레티놀', '리쥬란', '엑소좀', '민감피부']::text[]),
    ('6LS_rrVi2gk', 'jeonghanmi', '안티에이징에서 가장 중요한 단 하나의 성분은 무엇인가요?', '결론부터 말씀드리면 안티에이징의 기본은 보습이고, 그중에서도 세라마이드·콜레스테롤·지방산이 함께 들어간 보습제가 원탑입니다. 피부 장벽이 무너진 상태에서 비타민C·레티놀 같은 자극 성분만 열심히 바르면 오히려 피부가 더 안 좋아지는 경우가 정말 많아요. 보습은 단순히 수분을 채우는 게 아니라 외부 자극을 막아주는 장벽 그 자체를 튼튼하게 만들어 주는 역할을 합니다. 장벽이 회복되면 피부는 자연스레 색소·주름·탄력 면에서도 좋아지는 흐름을 보여요. 그래서 본인이 지성이든 건성이든 보습을 빼면 안 되고, 안티에이징 크림에 들어 있는 보습 성분만으로는 부족할 수 있습니다. 보습제 따로, 안티에이징 크림 따로 단계로 쓰면 두 효과를 모두 챙길 수 있어요. 제품 종류는 다양하지만 본인 피부에 맞아 자극 없이 꾸준히 쓸 수 있는 것을 고르시는 게 가장 중요합니다. 환절기·겨울에는 보습 단계를 한 번 더 추가해 주는 것도 권해드려요.', '안티에이징의 기본인 보습과 핵심 성분을 피부과 전문의 정한미가 안내합니다.', array['보습', '세라마이드', '콜레스테롤', '지방산', '피부장벽', '안티에이징', '환절기']::text[]),
    ('6LS_rrVi2gk', 'jeonghanmi', '보습제와 안티에이징 크림은 어떻게 다르고 같이 써야 하나요?', '보습제와 안티에이징 크림은 모두 크림 형태지만 메인 목적이 달라서 서로 대체하기보다 함께 쓰는 게 좋아요. 보습제는 세라마이드·콜레스테롤·지방산처럼 장벽을 채우는 성분이 메인이라 피부 장벽 회복과 수분 유지에 충실합니다. 반면 안티에이징 크림은 EGF·FGF 같은 성장인자, PDRN, 엑소좀 같은 기능성 성분이 메인이라 주름·탄력·재생에 초점이 맞춰져 있어요. 안티에이징 크림에도 기본 보습제는 들어 있지만 보습 전용 제품만큼 충분하지 않을 수 있습니다. 그래서 장벽이 약한 분은 보습제를 먼저 발라 장벽을 안정시키고 그 위에 안티에이징 크림을 얹는 순서가 효과적이에요. 시술을 받고 있는 분이라면 더더욱 홈케어 보습이 뒷받침돼야 시술 효과를 온전히 볼 수 있습니다. 단계가 부담스러우면 보습이 충분한 안티에이징 크림 한 종류로 시작해도 괜찮아요. 장기적으로 결과를 내려면 자극 없이 꾸준히 바르는 게 가장 중요합니다.', '보습제와 안티에이징 크림의 차이와 병용법을 피부과 전문의 정한미가 설명합니다.', array['보습제', '안티에이징크림', '성장인자', '리쥬란', '엑소좀', '피부장벽', '홈케어']::text[]),
    ('6LS_rrVi2gk', 'jeonghanmi', '시술과 홈케어 중 어느 쪽이 안티에이징에 더 중요한가요?', '시술이 빠른 변화를 주는 건 맞지만, 안티에이징의 토대는 결국 매일 반복하는 홈케어이고 둘은 보완 관계예요. 아무리 좋은 시술을 받아도 클렌징·보습·자외선 차단·기능성 성분 사용 같은 기본 홈케어가 빠지면 시술 효과의 지속력이 크게 떨어집니다. 반대로 홈케어만으로 깊은 주름이나 처진 라인을 단번에 되돌리긴 어렵기 때문에 필요한 시점에는 시술이 효율적이에요. 50대 남성 피부과 의사처럼 보습 위주의 홈케어만으로도 트러블 없이 좋은 컨디션을 유지하는 사례도 많습니다. 핵심은 본인 피부 상태에 맞춰 자극 없는 성분을 꾸준히 사용하는 거고, 부족한 부분만 시술로 보완하는 거예요. 처음부터 강한 성분과 시술을 동시에 시작하기보다 보습→자외선 차단→기능성 성분 순으로 단계를 올리는 걸 권합니다. 한 가지 좋은 제품에만 의존하지 말고, 본인이 매일 바를 수 있는지 여부로 제품을 골라야 효과가 누적돼요. 결국 안티에이징은 어렵게 하기보다 기본을 오래 잘하는 게 가장 큰 차이를 만듭니다.', '시술과 홈케어의 균형 잡힌 안티에이징 전략을 피부과 전문의 정한미가 정리합니다.', array['안티에이징', '홈케어', '보습', '자외선차단', '시술', '기능성성분', '피부관리']::text[]),
    ('uKuOvFfJM-A', 'kwonsuhyun', '피부과 의사들은 진짜로 어떤 영양제를 챙겨 먹나요?', '피부과 전문의 120명에게 물어본 결과, 1위는 비타민C였습니다. 비타민C는 항산화 작용으로 산화물질이 피부에 쌓여 푸석해지거나 주름이 깊어지는 것을 억제하고, 면역 강화와 피로회복에도 도움을 줍니다. 2위는 종합비타민, 3위는 비타민D, 4위 유산균, 5위 비타민B 순이었어요. 비타민D는 건선 등 염증성 질환에 도움이 되어 대학병원에서도 환자에게 복용을 권하기도 합니다. 흥미로운 건 전체의 약 3분의 1은 영양제를 아예 안 드신다는 점이에요. 챙겨 드시는 67%의 이유도 안 먹으면 안 될 것 같아서, 혹은 배우자가 챙겨줘서라는 답이 많았습니다. 피부를 위해서는 비타민C를 먹는 것보다 바르는 게 즉각적인 효과가 더 크니, 먹는 건 전체 컨디션 관리 차원에서 챙기시는 게 좋습니다.', '피부과 전문의 120명이 실제로 챙겨 먹는 영양제 순위를 피부과 전문의 권수현이 정리합니다.', array['비타민C', '영양제', '비타민D', '항산화', '피로회복', '유산균', '피부관리']::text[]),
    ('uKuOvFfJM-A', 'kwonsuhyun', '먹는 콜라겐이 피부 탄력에 진짜 도움 되나요?', '피부과 의사 120명 중 81.7%가 도움이 되지 않는다고 답했지만, 최근 논문에 따르면 완전히 무의미하지는 않습니다. 예전 콜라겐은 체내에서 분해되어 70~80%가 배설됐지만, 요즘 초저분자 콜라겐은 이미 잘게 쪼개져 있어 70~80%가 흡수되는 제품도 나오고 있어요. 실제로 초저분자 콜라겐 복용 후 혈액에서 프로콜라겐이 돌아다니는 것을 발견한 연구도 있습니다. 3개월 이상 꾸준히 복용하면 유의미한 효과가 있을 수 있다는 논문 결과가 몇 건 존재해요. 다만 100을 먹어서 얼마나 피부까지 가서 콜라겐으로 합성되느냐의 문제이므로, 과도한 기대보다는 보조 수단으로 생각하시는 게 현실적입니다. 먹는 콜라겐을 선택하실 거라면 저분자·초저분자 제품을 3개월 이상 꾸준히 드시는 방향을 추천드립니다.', '먹는 콜라겐이 피부 탄력에 실제로 도움 되는지 논문 근거와 함께 피부과 전문의 권수현이 설명합니다.', array['콜라겐', '초저분자콜라겐', '피부탄력', '항노화', '프로콜라겐', '영양제', '보충제']::text[]),
    ('uKuOvFfJM-A', 'jeonghanmi', '피부를 가장 망가뜨리는 생활습관이 뭔가요?', '피부과 전문의 120명이 꼽은 1위는 잘못된 세안으로, 30%가 선택했습니다. 과도하게 씻거나 너무 세게 씻는 것, 반대로 대충 씻거나 안 씻고 자는 것 모두 해당돼요. 실제 진료실에서도 피부 문제로 오시는 분 중 클렌징을 잘못하는 경우가 매우 많습니다. 2위는 자외선으로, 햇빛에 많이 노출된 피부는 10년 뒤 눈에 띄게 노화가 심해집니다. 3위는 과도한 각질 제거인데, 지성 피부라도 주 1~2회를 넘기면 피부 장벽이 무너질 수 있어요. 4위 수면 부족, 5위 얼굴 만지기, 6위 보습 미실시, 7위 무분별한 홈케어 디바이스 순이었습니다. 보습은 지성 피부라도 반드시 해줘야 하며, 기름이 있다고 수분을 안 줘도 되는 건 아닙니다.', '피부과 의사 120명이 꼽은 피부를 망치는 최악의 습관 순위를 피부과 전문의 정한미가 안내합니다.', array['세안', '피부장벽', '자외선', '각질제거', '수면부족', '보습', '생활습관']::text[]),
    ('uKuOvFfJM-A', 'jeonghanmi', '타고난 피부가 안 좋아도 관리하면 진짜 좋아질 수 있나요?', '네, 타고난 꿀피부 수준까지는 어렵지만 평균 이상으로 충분히 좋아질 수 있습니다. 실제 설문에서도 극복할 수 있다 56%, 없다 44%로 거의 반반이었어요. 모공이 크고 트러블이 잘 나는 피부여도 꾸준히 홈케어하고 필요한 시술을 병행하면 주변에서 피부 좋다는 말을 들을 수 있는 수준까지 도달합니다. 다만 지성 피부가 갑자기 건성으로 바뀌거나, 타고난 두꺼운 피부가 얇아지는 식의 근본적 피부 타입 변화는 불가능해요. 상위 1%의 모공 하나 없는 피부까지 가기는 현실적으로 어렵지만, 그렇다고 방치하면 절대 좋아지지 않습니다. 내가 가진 피부 조건 안에서 최선의 관리를 꾸준히 해나가시는 게 핵심이에요.', '타고난 피부가 안 좋아도 관리로 좋아질 수 있는 현실적 범위를 피부과 전문의 정한미가 설명합니다.', array['피부관리', '타고난피부', '모공', '피부타입', '홈케어', '안티에이징', '꾸준한관리']::text[]),
    ('GzfaD3bEuQc', 'kwonsuhyun', '울쎄라 효과 잘 보는 얼굴형이 따로 있나요?', '네, 피부가 얇지 않고 기본적으로 살이 있으며 얼굴형이 둥근 분들이 울쎄라에 가장 잘 맞습니다. 이런 타입은 뼈에서 떨어진 살들이 시술 후 다시 뼈에 붙는 느낌을 확실히 받을 수 있어요. 반대로 뼈와 근육이 큰 얼굴은 울쎄라로 해결이 안 되고, 살이 없고 볼이 꺼진 타입은 볼패임이 생길까 걱정하실 수 있지만 적은 샷수로도 효과를 볼 수 있습니다. 얼굴에 살이 너무 많은 분은 1,000샷 이상 해야 어느 정도 효과가 나기 때문에, 먼저 안쪽 지방이나 근육을 해결하고 나서 처진 살을 울쎄라로 올리는 순서가 비용 대비 효율적이에요. 거상 수술만큼 드라마틱한 리프팅을 기대하면 실망할 수 있으니, 30~40대 초반에서 미묘하게 처지기 시작한 시점에 받으시는 게 가장 만족도가 높습니다.', '살이 있고 둥근 얼굴형이 울쎄라 효과를 가장 잘 봅니다. 볼패임 위험 타입과 30~40대 초반이 최적 시기인 이유를 피부과 전문의 권수현이 정리합니다.', array['울쎄라', '리프팅', '얼굴형', '볼패임', '처진살', '울쎄라피프라임', '지방흡입']::text[]),
    ('GzfaD3bEuQc', 'jeonghanmi', '울쎄라 팁 종류랑 에너지 레벨 차이가 뭔가요?', '울쎄라 팁은 4.5mm, 3.0mm, 1.5mm 세 종류로, 숫자가 피부 속 침투 깊이를 의미합니다. 4.5mm는 근막층(SMAS)을 수축시켜 피부를 붙여주는 핵심 팁이고, 3.0mm는 지방층을 타겟해서 불필요한 지방을 줄여줍니다. 1.5mm는 진피층에 들어가 피부 탄력과 모공 개선에 효과적이에요. 살이 별로 없는 얼굴에 3.0mm 팁을 광대 아래에 많이 쓰면 볼꺼짐이 생길 수 있으니 주의가 필요합니다. 에너지 레벨은 1~4까지 있는데, 레벨 4는 수면마취가 필요할 만큼 아프고 보통 레벨 3으로 시술하면 충분한 효과를 기대할 수 있어요. 이처럼 피부층·지방층·근육층을 하나의 기계로 모두 타겟할 수 있다는 점이 울쎄라의 가장 큰 장점입니다.', '울쎄라 4.5mm는 근막층, 3.0mm는 지방층, 1.5mm는 진피층을 타겟합니다. 팁별 효과 차이와 에너지 레벨 1~4 선택 기준을 피부과 전문의 정한미가 안내합니다.', array['울쎄라', '리프팅', '근막층', '진피층', '모공', '에너지레벨', '팁']::text[]),
    ('GzfaD3bEuQc', 'jeonghanmi', '울쎄라 300샷 두 번이랑 600샷 한 번 중 뭐가 나아요?', '같은 샷수라면 한 번에 몰아서 받는 게 효과가 더 좋습니다. 울쎄라는 열이 축적되면서 효과를 내는 원리인데, 300샷 나눠 받으면 처음 300샷에 열 올리는 시간이 필요하고 다음 방문 때 또 처음부터 열을 올려야 해요. 반면 한 번에 600샷을 받으면 열이 쌓인 상태로 연속 시술되어 온전한 효과를 기대할 수 있습니다. 얼굴에 필요한 샷수는 피부 두께로 판단하면 쉬운데, 살이 별로 없고 얇은 피부는 400샷 정도, 피부가 두껍고 살이 있는 타입은 600샷 정도가 적정선이에요. 울쎄라와 써마지를 같이 받는 경우라면 울쎄라는 3.0mm, 4.5mm 팁 위주로 400샷, 나머지 1.5mm 역할은 써마지로 대체하는 방법도 효율적입니다. 본인의 피부 상태에 맞는 샷수를 의사와 상담해서 결정하시는 게 가장 중요합니다.', '같은 샷수라면 나눠 받는 것보다 한 번에 받는 게 열 축적 효과로 더 좋습니다. 피부 두께별 적정 샷수(400~600샷)와 써마지 병행 전략을 피부과 전문의 정한미가 설명합니다.', array['울쎄라', '샷수', '써마지', '리프팅', '열축적', '피부두께', '시술효과']::text[]),
    ('GzfaD3bEuQc', 'kwonsuhyun', '울쎄라 받으면 광고처럼 확 리프팅 되나요?', '아니요, 거상 수술처럼 드라마틱하게 끌어올려지는 효과를 기대하시면 실망하실 수 있습니다. 광고나 인플루언서 사진에서 보이는 것처럼 쫙 리프팅된 모습은 과장된 경우가 많아요. 기계 하나로 처진 얼굴을 확 끌어올리기는 현실적으로 쉽지 않습니다. 30~40대 초반 정도에서 약간 처지기 시작한 단계라면 울쎄라 하나만으로도 정말 좋은 결과를 얻을 수 있어요. 하지만 60대 이상으로 많이 처진 경우에는 울쎄라가 적합하지 않고 성형외과 수술이 필요한 영역입니다. 팔자주름 부위는 신경이 지나가는 자리라 울쎄라가 들어갈 수 없어 해당 부분이 펴지진 않는다는 점도 알고 계시면 좋습니다.', '울쎄라는 거상 수술처럼 드라마틱하게 당기는 시술은 아닙니다. 30~40대 초반 미묘한 처짐에 가장 효과적인 현실적 기대치와 한계를 피부과 전문의 권수현이 안내합니다.', array['울쎄라', '리프팅', '거상수술', '팔자주름', '30대', '40대', '기대효과']::text[]),
    ('e03LNdc1mFo', 'jeonghanmi', '피부 안 좋던 사람이 피부과 의사처럼 좋아질 수 있는 비결은 뭔가요?', '정답은 화려한 시술이 아니라 ''본인에게 맞는 보습제''를 꾸준히 쓰는 것입니다. 영상에 출연하신 20년 차 동안 피부과 의사 분도 과거에는 지루성 피부염, 주사 피부염까지 있었지만 보습제를 잘 쓰기 시작하면서 피부가 회복됐다고 하셨어요. 피부 장벽이 무너져 있으면 어떤 시술이나 화장품도 효과를 제대로 내기 어렵기 때문에 가장 먼저 장벽을 회복시키는 게 핵심이에요. 보습제 종류가 너무 많지만 따갑거나 간지러운 제품은 무조건 배제하시고, 피부 타입에 맞춰 고르시면 됩니다. 건성은 밀폐력이 있는 크림, 지성·여드름은 가벼운 수분 위주의 제품, 민감성은 자극 없는 제품이 기본이에요. 세라마이드·콜레스테롤·지방산이 함께 든 보습제는 어느 피부에나 비교적 무난하게 잘 맞습니다. 이분도 아토베리어 365 크림을 10년 이상 꾸준히 사용해 오셨어요. 비싼 시술보다 매일 쓰는 보습제 한 통이 결국 피부를 바꿔줍니다.', '동안 피부과 의사의 핵심 비결인 보습제 활용법을 피부과 전문의 정한미가 정리합니다.', array['보습제', '피부장벽', '세라마이드', '아토베리어', '안티에이징', '민감성', '피부염']::text[]),
    ('e03LNdc1mFo', 'jeonghanmi', '집에서 누구나 따라할 수 있는 동안 얼굴 운동이 있을까요?', '네, 두 가지 운동이 있는데 입꼬리 내리는 근육의 힘은 빼고, 입꼬리 올리는 근육은 강화하는 게 핵심입니다. 첫째는 힘 빼기예요. 평소 입을 다물고 있으면 입꼬리 내리는 근육에 힘이 들어가 처짐이 가속되니까 입술은 다물되 치아는 살짝 벌리고 혀를 입천장이나 앞니 뒤에 살짝 붙이세요. "은-" 하는 발음과 비슷한 자세가 유지됩니다. 둘째는 힘 주기로, 입꼬리를 올리는 앞쪽 근육에 의도적으로 힘을 주는 거예요. "어흥" 하는 표정처럼 살짝 힘을 주면 되고 일부러 가짜 웃음을 지으면 입가 주름이 더 생길 수 있으니 살짝만 줘도 충분합니다. 운전이나 타이핑할 때 무표정으로 있으면 입꼬리가 떨어지기 쉬우니 의식적으로 신경 쓰는 게 좋아요. 입꼬리 내리는 근육에 보톡스를 맞으면 강제로 힘이 빠져 운동 효과를 보조해 줍니다. 매일 의식하기 어려우신 분들에겐 보톡스가 도움이 됩니다.', '집에서 따라하는 동안 얼굴 운동과 보톡스 활용법을 피부과 전문의 정한미가 안내합니다.', array['얼굴운동', '입꼬리', '보톡스', '안티에이징', '표정근육', '동안', '처짐']::text[]),
    ('e03LNdc1mFo', 'jeonghanmi', '안티에이징을 위한 영양제는 어떤 걸 챙겨 먹어야 하나요?', '영상에 출연하신 동안 피부과 의사 분 기준으로는 비타민C 고용량을 기본으로 하되 한 가지에 매달리지 않고 로테이션으로 챙겨 드시는 게 핵심이었어요. 매일 챙겨 드시는 건 비타민C 3000mg 메가도즈, 비타민B 컴플렉스, 종합 비타민이 기본이고요. 추가로 오메가3, 글루타치온, 마그네슘, 셀레늄, 루테인 등을 식탁 위에 모아두고 생각날 때마다 드신다고 했어요. 중요한 건 아무리 좋은 성분이라도 너무 과하거나 너무 오래 같은 걸 먹으면 좋지 않을 수 있어 두세 달 단위로 바꾸는 로테이션 방식을 쓴다는 거예요. 영양제는 시술처럼 즉각 변화를 보여주진 않지만 체력·면역력과 피부 상태가 오래 유지되도록 받쳐주는 역할을 합니다. 본인 식습관과 부족한 영양소를 점검하고 가장 기본인 비타민군부터 시작하시면 좋아요. 무엇보다 한 가지 영양제만 의존하지 마시고 다양하게 균형 있게 챙기시는 게 안전합니다.', '동안 피부과 의사의 안티에이징 영양제 챙김법을 피부과 전문의 정한미가 정리합니다.', array['영양제', '비타민C', '안티에이징', '종합비타민', '오메가3', '글루타치온', '면역력']::text[]),
    ('e03LNdc1mFo', 'jeonghanmi', '피부과 의사는 안티에이징을 위해 어떤 시술을 받고 어떻게 생활하나요?', '피부과 의사들은 보톡스를 1순위로 챙기고 울쎄라·써마지 같은 리프팅과 스킨부스터를 주기적으로 받습니다. 영상의 동안 피부과 의사 분도 첫 번째로 보톡스를 꼽으셨는데, 주름을 만드는 내리는 근육의 힘을 막아 처짐 자체를 예방하는 게 안티에이징의 출발이라는 이유에서예요. 그 외에는 울쎄라·써마지처럼 진피·근막을 자극하는 리프팅을 주기적으로 받고, 스킨부스터로 피부에 영양을 주사로 채워주는 방식을 병행합니다. 시술만큼 중요한 건 충분한 수면이에요. 잠이 부족하면 피부 수분·탄력·광택이 모두 떨어진다는 연구도 있고, 요즘 가장 큰 적은 잠들기 전 쇼츠 시청이라고 하셨어요. 평균 6~7시간 수면을 목표로 하시고 자기 전 휴대폰 디톡스를 권해드립니다. 그리고 피부 문제가 생겼을 때 방치하지 말고 즉시 회복시키는 습관이 노화를 늦추는 데 결정적입니다. 시술·생활습관·수면 세 박자가 함께 가야 동안이 만들어져요.', '피부과 의사가 직접 챙기는 안티에이징 시술과 생활습관을 피부과 전문의 정한미가 정리합니다.', array['보톡스', '울쎄라', '써마지', '스킨부스터', '수면', '안티에이징', '리프팅']::text[]),
    ('bRMNnO-tC0I', 'kimjongsik', '깊은 팔자주름에 필러 직접 넣으면 진짜 좋아지나요?', '팔자주름 자체에 필러를 넣는 것보다 앞볼을 채우는 게 훨씬 자연스럽고 효과적입니다. 팔자주름이 고민이라고 오시는 분 중 진짜 팔자가 문제인 경우는 10%도 안 되거든요. 대부분은 앞볼이 꺼지면서 팔자주름처럼 보이는 것이에요. 앞볼을 채우면 한정된 공간에서 볼이 올라가면서 팔자주름처럼 느껴졌던 부분을 자연스럽게 끌고 올라가줍니다. 반대로 팔자주름 라인에 직접 필러나 쥬베룩 볼륨을 넣으면 볼록하게 튀어나와 부자연스러운 결과가 나올 수 있어요. 앞볼과 옆볼을 함께 잡아주면 90% 이상은 팔자주름 별도 시술 없이도 만족하십니다. 거울을 보실 때 팔자주름 자체보다 볼이 꺼져 있진 않은지 확인해보시는 게 좋습니다.', '팔자주름의 진짜 원인이 앞볼 꺼짐인 이유와 올바른 시술 방향을 피부과 전문의 김종식이 설명합니다.', array['팔자주름', '필러', '앞볼', '볼륨', '쥬베룩', '리프팅', '볼꺼짐']::text[]),
    ('bRMNnO-tC0I', 'kimjongsik', '볼륨 채우고 싶은데 필러 무섭다면 대안이 뭐가 있나요?', '필러에 대한 공포가 있다면 힐로웨이브라는 스킨부스터를 테스트 삼아 먼저 받아보시는 걸 추천드립니다. 힐로웨이브는 볼륨을 즉각적으로 채워주면서도 필러처럼 단단하지 않아요. 필러가 츄파춥스라면 힐로웨이브는 솜사탕에 비유할 수 있는데, 3개월이면 자연스럽게 녹아 없어집니다. 그래서 이물감도 적고 과교정 걱정도 없으며, 마음에 안 들어도 시간이 지나면 원래대로 돌아가요. 볼륨이 찼을 때 모습이 마음에 드신다면 3개월 뒤 힐로웨이브를 반복할지, 더 오래 가는 필러로 전환할지 선택하면 됩니다. 결혼식 같은 큰 일정 앞두고 일시적으로 좋아 보이고 싶은 분들에게도 딱 맞는 선택이에요.', '필러가 두려울 때 대안으로 힐로웨이브를 활용하는 방법을 피부과 전문의 김종식이 안내합니다.', array['힐로웨이브', '필러', '스킨부스터', '볼륨', '이물감', '과교정', '앞볼']::text[]),
    ('bRMNnO-tC0I', 'leedoyoung', '사각턱 보톡스 습관적으로 맞아도 괜찮나요?', '아니요, 무턱대고 맞으면 오히려 얼굴이 처질 수 있어 신중해야 합니다. 사각턱 근육은 피부를 지탱해주는 기둥 역할을 하기 때문에, 계속 위축시키면 피부를 잡아줄 게 없어져 흘러내리게 됩니다. 특히 40~50대 이상에서는 사각턱이 없으면 피부가 처지므로 함부로 줄이시면 안 돼요. 20~30대부터 습관적으로 맞아 온 분들 중 옆라인이 완전히 꺼지고 피부가 늘어진 경우를 실제로 봅니다. 심술보(턱 앞쪽 처짐)가 시작된 분은 사각턱 보톡스를 중단해야 하며, 대신 귀밑샘 보톡스나 자갈턱 보톡스, 라인 보톡스로 전환하면 갸름한 효과를 더 안전하게 낼 수 있어요. 사각턱을 줄이지 않아도 스킨보톡스로 1~2mm만 줄여도 윤곽이 많이 달라집니다.', '사각턱 보톡스의 위험성과 더 안전한 대안 시술을 피부과 전문의 이도영이 정리합니다.', array['사각턱', '보톡스', '스킨보톡스', '귀밑샘보톡스', '자갈턱', '라인보톡스', '처짐']::text[]),
    ('bRMNnO-tC0I', 'kimjongsik', '눈 밑 꺼짐 고민인데 필러 말고 방법이 있나요?', '눈 밑이 꺼졌다고 오시는 분의 절반 이상은 실제로 앞볼이 꺼진 경우라, 앞볼을 채우면 눈 밑 꺼짐도 함께 개선됩니다. 눈 밑 필러는 얕게 놓으면 비쳐 보이거나 불룩해질 수 있어 시술 난이도가 높아요. 그래서 울트라콜이나 스컬트라 같은 콜라겐 부스터로 간접적으로 채우거나, 리투오 같은 제품으로 환경과 탄력을 개선하는 방법을 활용하기도 합니다. 시술 없이도 엠페이스, 조비나 같은 근육 강화 기기나 입꼬리 올리는 운동으로 중안면 근육을 키우면 앞볼 볼륨이 자연스럽게 좋아지면서 눈 밑도 개선돼요. 요즘은 너무 과하지 않게, 아무도 모르지만 예뻐 보이게 해달라는 니즈가 커서 이런 자연스러운 접근이 더 인기를 끌고 있습니다.', '눈 밑 꺼짐을 필러 없이 자연스럽게 개선하는 방법을 피부과 전문의 김종식이 설명합니다.', array['눈밑꺼짐', '스컬트라', '앞볼', '필러', '엠페이스', '중안면', '콜라겐']::text[]),
    ('uT8n3Zt3pCQ', 'jeonghanmi', '마스크팩 떼면 촉촉한데 진짜 효과 있는 건가요?', '마스크팩을 떼자마자 느끼는 촉촉함과 밝아 보이는 효과는 대부분 일시적입니다. 팩을 덮어놓으면 수분이 증발하지 못해 각질층이 물에 불은 상태가 되고, 빛 반사가 고르게 되면서 피부가 좋아 보이는 건데 이 효과가 며칠씩 유지되지는 않아요. 또한 마스크팩의 쿨링감이 모세혈관을 수축시켜 붉은기가 가라앉으면서 하얗게 보이는 것이지, 혈관을 없애거나 염증을 치료하는 건 아닙니다. 마스크팩의 진짜 가치는 유효성분을 피부 속에 강제로 밀어넣는 밀폐 효과에 있어요. 피부과에서 아토피 환자에게 하는 밀폐요법과 같은 원리로, 팩으로 덮으면 성분 흡수량이 10배에서 100배까지 증가할 수 있다고 교과서에 나와 있습니다. 즉 마스크팩 자체보다 어떤 성분이 들어있느냐가 핵심입니다.', '마스크팩의 일시적 효과와 실제 작동 원리인 밀폐 효과를 피부과 전문의 정한미가 설명합니다.', array['마스크팩', '밀폐요법', '수분', '각질층', '피부장벽', '성분흡수', '시트마스크']::text[]),
    ('uT8n3Zt3pCQ', 'jeonghanmi', '시트 마스크랑 겔 마스크 중 뭐가 더 좋아요?', '피부 상태와 목적에 따라 다르며, 시트 마스크는 진정·회복용, 겔 마스크는 성분 극대화용으로 구분해 쓰시면 됩니다. 시트 마스크는 에센스를 적셔서 올리는 방식으로, 피부 컨디션이 엉망일 때 빠르게 진정시키기 좋아요. 겔 마스크는 히알루론산이나 콜라겐 같은 유효성분을 젤리처럼 굳혀놓은 것이라 피부 온도에 녹으면서 흡수되는 원리입니다. 겔 마스크는 3시간 이상 붙이고 있으면 성분이 피부로 흡수되면서 투명하게 변하고, 떼었을 때 촘촘하게 결이 정리되는 느낌을 받을 수 있어요. 다만 겔 마스크가 시트보다 비싸고, 시트 마스크도 바이오셀룰로스 소재를 선택하면 밀착력이 뛰어나 성분 전달력이 좋아집니다. 피부가 건조하지 않은 20~30대 지성 피부는 가벼운 시트 마스크, 보습과 영양이 부족한 분은 겔 마스크를 추천드립니다.', '시트 마스크와 겔 마스크의 원리와 피부 타입별 선택법을 피부과 전문의 정한미가 정리합니다.', array['마스크팩', '겔마스크', '시트마스크', '바이오셀룰로스', '히알루론산', '콜라겐', '보습']::text[]),
    ('uT8n3Zt3pCQ', 'jeonghanmi', '겔 마스크 중에 피부과 의사가 실제로 쓰는 제품이 뭔가요?', '바이오던스 하이드로 세라놀 리얼 딥 마스크를 꾸준히 잘 쓰고 있습니다. 이 제품은 3시간 이상 붙이고 있으면 겔이 녹으면서 투명하게 변하는데, 떼었을 때 끈적이기보다 피부 속이 채워진 느낌과 결이 정리된 느낌이 들어요. 겔 자체가 실온에서도 차가워서 쿨링감이 좋은 것도 장점입니다. 또한 아이오페 레티놀 세럼 인 겔 마스크는 레티놀 1%가 들어있어 밝아지고 각질 정리와 항노화를 기대할 수 있고, 일주일에 한 번 정도 쓰면 피부 뒤집힘 없이 효과를 누릴 수 있어요. 아로셀 보툴 케어 프라임톡스 마스크는 바르는 보톡스 펩타이드 성분이 들어있어 잔주름이 펴지는 느낌을 주며, 아비브 콜라겐 부활초 겔 마스크는 세라마이드가 들어있어 급건조할 때 영양을 빠르게 채워줍니다.', '피부과 전문의 정한미가 실제로 사용하는 겔 마스크 제품과 특징을 피부과 전문의 정한미가 안내합니다.', array['겔마스크', '바이오던스', '레티놀', '아이오페', '아로셀', '콜라겐', '아비브']::text[]),
    ('uT8n3Zt3pCQ', 'jeonghanmi', '마스크팩 효과를 확 높이는 꿀팁이 있나요?', '마스크팩 전에 효과를 보고 싶은 세럼을 미리 바르면 흡수도를 크게 높일 수 있습니다. 예를 들어 건조함이 심할 때 히알루론산 세럼을 바른 뒤 마스크팩을 올리면 팩의 밀폐 효과로 세럼 성분까지 훨씬 깊이 침투되어 보습감이 배가돼요. 두 번째는 샌드위치 법인데, 가벼운 시트 마스크를 떼어낸 후 꾸덕한 크림으로 밀폐시켜주고 자면 다음 날 보습감이 훨씬 오래 유지됩니다. 마스크팩을 떼고 나면 그때부터 수분 증발이 시작되기 때문에 20~30분이면 다시 마르는 느낌이 나거든요. 세 번째는 팩을 뗀 후 남은 앰플을 가만히 두지 말고 톡톡 두드려서 흡수시키는 건데, 물리적 자극으로 흡수를 증가시키는 단순하지만 꽤 차이 나는 방법입니다.', '마스크팩 전후 세럼 활용과 샌드위치 법으로 효과 극대화하는 팁을 피부과 전문의 정한미가 안내합니다.', array['마스크팩', '세럼', '밀폐요법', '보습', '히알루론산', '샌드위치법', '흡수']::text[]),
    ('YUchtk3qv6s', 'jeonghanmi', '외국인들이 한국까지 와서 피부과 시술 받는 이유가 뭔가요?', '한국 피부과 시술은 해외보다 가격이 훨씬 저렴하면서도 기술력이 앞서 있어서 외국인들이 몰려옵니다. 일본 피부과 전문의에 따르면 같은 시술을 일본에서 받으면 한국보다 전반적으로 비싸고, 브라질의 경우 슈링크가 220~368만 원인데 한국에선 50~100만 원 수준이에요. 단순히 가격만 싼 게 아니라 한국 선생님들의 주사 기술이 워낙 좋고, 일본에서 아직 도입되지 않은 새로운 시술을 6개월~1년 먼저 경험할 수 있다는 점도 큽니다. 거기에 K-뷰티 문화 자체를 체험하고 싶어하는 수요까지 겹치면서 시술뿐 아니라 문화적 경험을 함께 즐기러 오는 셈이죠. 코리아더마 학회에 전 세계 피부과 의사 3천 명 이상이 참석할 정도로 한국의 명성은 확고합니다. 가격, 기술력, 최신 트렌드 세 박자가 맞아떨어지니 굳이 자국에서 받을 수 있는 시술도 한국까지 찾아오는 겁니다.', '외국인이 한국 피부과를 찾는 이유(가격·기술력·최신시술)를 피부과 전문의 정한미가 정리합니다.', array['K뷰티', '피부과시술', '한국시술가격', '리쥬란', '슈링크', '외국인시술', '코리아더마']::text[]),
    ('YUchtk3qv6s', 'jeonghanmi', '외국 피부과 의사들이 가족한테 딱 하나만 해준다면 어떤 시술을 고르나요?', '인도, 일본, 이스라엘 피부과 전문의 모두 스킨부스터와 보톡스를 압도적으로 꼽았습니다. 인도 의사는 40대 후반임에도 스킨부스터(리쥬란, 비타란 등 히알루론산+폴리뉴클레오타이드)를 선택했는데, 타이트닝을 해도 피부에 수분감과 재생 능력이 없으면 나아지지 않기 때문이라고 설명했어요. 일본 의사는 덴서티를 골랐는데 처진 피부에 효과가 좋으면서 다른 장비보다 위험 부담이 적다는 이유였습니다. 이스라엘 의사는 보톡스(제오민)를 선택하며 얼굴 전체와 목까지 사용한다고 했고, 두 번째로는 리쥬란을 꼽았어요. 흥미로운 점은 세 나라 의사 모두 재생과 피부 결에 집중하는 시술을 우선시했다는 겁니다. 강력한 리프팅보다 피부 자체의 질을 높이는 방향이 글로벌 트렌드임을 보여줍니다.', '외국 피부과 의사가 가족에게 해주고 싶은 시술 1순위를 피부과 전문의 정한미가 정리합니다.', array['스킨부스터', '리쥬란', '보톡스', '덴서티', '피부재생', '폴리뉴클레오타이드', '제오민']::text[]),
    ('YUchtk3qv6s', 'jeonghanmi', '외국 피부과 의사도 선크림을 매일 꼭 바르나요?', '대부분의 피부과 의사는 선크림을 필수로 바르지만, 놀랍게도 안 바르는 의사도 있습니다. 브라질 의사는 절대 선크림 바르는 걸 잊지 않는다고 했고, 인도 의사는 비타민C가 내장된 선크림을 낮에 반드시 사용해요. 반면 이스라엘 의사는 45세인데도 선크림을 한 번도 쓴 적이 없다고 솔직히 밝혔습니다. 환자에게는 바르라고 말하지만 자기 얼굴에서는 차이를 못 느끼겠다는 이유였어요. 대신 그 의사가 가장 중요하게 여기는 건 클렌징과 보습, 그리고 지저분한 얼굴로 절대 자러 가지 않는 것이었습니다. 물론 자외선 차단은 광노화 예방의 기본이므로 바르는 쪽이 권장되지만, 보습과 클렌징이 기본 중의 기본이라는 점은 모든 의사가 동의하는 부분이에요.', '외국 피부과 의사들의 선크림 사용 여부와 스킨케어 핵심을 피부과 전문의 정한미가 안내합니다.', array['선크림', '자외선차단', '보습', '클렌징', '스킨케어루틴', '광노화예방']::text[]),
    ('YUchtk3qv6s', 'jeonghanmi', '리쥬란이 외국에서도 인기 많은 시술인가요?', '네, 리쥬란은 현재 해외에서 폭발적으로 뜨고 있는 K-시술의 대표 주자입니다. 이스라엘 피부과 의사는 리쥬란을 배우러 한국에 왔다고 밝혔고, 리쥬란을 해야 환자들이 좋아한다고 했어요. 인도 의사는 평생 한 가지 시술만 고른다면 스킨부스터(리쥬란/비타란)를 선택하겠다고 답했는데, 재생 능력이 피부 개선의 핵심이라고 봤기 때문입니다. 리쥬란 성분인 폴리뉴클레오타이드(PN)가 아직 도입되지 않은 나라들이 꽤 있어서, 그런 나라 사람들은 자국에서 받을 수 없으니 한국에 와서 꼭 받고 가는 거죠. 한국이 리쥬란을 만든 나라이기도 하고 선생님들의 주사 기술이 좋으니 가격도 저렴하면서 결과도 좋습니다. 이스라엘에서도 최근 굉장히 핫해져서 의사들이 직접 배우러 올 정도예요.', '리쥬란이 해외에서 인기 폭발 중인 이유를 피부과 전문의 정한미가 설명합니다.', array['리쥬란', '폴리뉴클레오타이드', '스킨부스터', 'K시술', '피부재생', '이스라엘', '인도']::text[]),
    ('HfFLhnlAY0g', 'jeonghanmi', '요즘 스킨부스터 중에 리투오가 핫하다는데 리쥬란이랑 뭐가 달라요?', '리투오는 가장 최근에 나온 스킨부스터로, 기존 제품들과 달리 완제품을 피부에 바로 넣어주는 원리라 효과가 즉각적입니다. 리쥬란이나 쥬베룩 같은 스킨부스터는 피부 재생을 도와주는 재료를 넣고 그 재료가 일을 해서 효과가 나타나기까지 일주일에서 한 달 정도 걸리거든요. 반면 리투오는 사람의 피부 성분에서 문제될 수 있는 것만 제거하고 건조시켜 만든 파우더 제형이라 이미 완성된 피부 성분을 직접 넣어주는 셈이에요. 그래서 하루 이틀 주사 자국만 가라앉으면 바로 쫀쫀하고 탄탄한 느낌이 금방 납니다. 파우더에 PDRN이나 히알루론산 같은 액체 성분을 섞어서 주사하기 때문에 원장님마다 레시피가 다를 수 있어요. 주사 자국도 견딜 수 없다면 인젝터를 이용해 살짝 놔주면 그날 저녁이나 다음 날부터 티가 안 나서 다운타임 없이 받을 수 있습니다.', '스킨부스터 리투오와 리쥬란의 차이점 및 즉각 효과의 원리를 피부과 전문의 정한미가 설명합니다.', array['리투오', '스킨부스터', '리쥬란', '쥬베룩', 'PDRN', '피부재생', '다운타임']::text[]),
    ('HfFLhnlAY0g', 'jeonghanmi', '필러가 요즘 인기 없다던데 정말 지는 시술인가요?', '네, 히알루론산 필러는 확실히 예전보다 찾는 분이 크게 줄어 지는 시술에 가깝습니다. 필요해서 권해드려도 필러는 싫다고 거부하시는 분이 정말 많아졌어요. 가장 큰 이유는 요즘 트렌드가 티 나지 않고 자연스러운 것을 추구하는 쪽으로 바뀌었기 때문입니다. 필러는 히알루론산이 물을 머금는 성질이 있어서 양이 과하면 얼굴이 부어 보이거나 어벙벙한 인상을 줄 수 있거든요. 또 다른 단점은 시간이 1년~1년 반 지나면서 녹을 때 부위마다 속도가 달라 단차가 생겨 울퉁불퉁하게 느껴질 수 있다는 점이에요. 예전에는 볼륨이 빵빵한 걸 좋아하는 트렌드였지만, 지금은 내 것 같은 자연스러움이 핵심이라 티가 날 수 있는 필러를 피하는 겁니다. 다만 효과가 없는 게 아니라 트렌드가 바뀐 것이니 필요한 경우에는 여전히 쓸 수 있는 시술입니다.', '히알루론산 필러가 인기 없어진 이유와 단점을 피부과 전문의 정한미가 안내합니다.', array['필러', '히알루론산', '볼륨시술', '자연스러움', '스컬트라', '콜라겐', '트렌드']::text[]),
    ('HfFLhnlAY0g', 'jeonghanmi', '스컬트라가 필러 대신 뜬다던데 효과가 어떻게 다른 건가요?', '스컬트라는 필러와 달리 내 콜라겐과 지방을 천천히 차오르게 해서 시술 받은 티가 전혀 나지 않는 게 핵심 차이입니다. 필러는 만들어진 젤리를 넣어 즉시 볼륨을 올리지만, 스컬트라는 가루에 물을 타서 피부 속에 넣는 방식이에요. 첫날은 물 때문에 빵빵해 보이지만 2~3일이면 물이 흡수되고 가루만 남습니다. 이 가루가 점점 녹으면서 주변 세포를 자극해 콜라겐을 만들게 하고, 지방도 증식시키거든요. 그래서 몇 달 만에 만난 지인들이 얼굴이 예뻐졌다거나 왜 안 늙고 그대로냐는 말을 듣게 하는 시술이에요. 예전에는 천천히 효과가 나온다는 게 단점이었지만, 티 안 나는 게 최고인 요즘 트렌드에서는 오히려 최대 장점으로 부각되고 있습니다. 병원 직원들도 줄을 서서 받을 정도로 만족도가 높은 시술이에요.', '스컬트라가 필러 대신 뜨는 이유와 효과 원리를 피부과 전문의 정한미가 설명합니다.', array['스컬트라', '콜라겐', '필러', '자연스러움', '볼륨', '리프팅', '지방증식']::text[]),
    ('HfFLhnlAY0g', 'jeonghanmi', '리쥬란이 너무 아프다던데 덜 아프게 받을 방법 없나요?', '리쥬란의 가장 큰 허들은 통증이 맞지만, 요즘은 덜 아프게 받을 수 있는 옵션이 여러 가지 있습니다. 먼저 마취 성분이 들어가 있는 리쥬란 HB를 선택하면 통증이 상당히 줄어들어요. 또 비타란이라는 제품은 리쥬란과 똑같은 폴리뉴클레오타이드 성분인데 pH를 조절해놔서 맞을 때 통증이 리쥬란보다 훨씬 덜합니다. 리쥬란은 필러처럼 괴사나 심각한 부작용이 전혀 없고, 가장 큰 부작용이 아픈 것일 정도로 안전한 시술이에요. 한국에서는 새로운 옵션이 많아져서 예전만큼 독보적이진 않지만, 외국인들에게는 여전히 한국 와서 반드시 받고 가는 필수 시술처럼 번져 있습니다. 리쥬란을 만든 회사가 한국 회사이고 한국이 해외보다 가격도 훨씬 저렴하기 때문이죠. 통증만 해결되면 가볍게 받기 좋은 시술이니 HB나 비타란을 고려해 보시는 걸 추천드립니다.', '리쥬란 통증을 줄이는 방법(HB·비타란)과 안전성을 피부과 전문의 정한미가 안내합니다.', array['리쥬란', '통증', '비타란', '폴리뉴클레오타이드', '스킨부스터', '리쥬란HB', '다운타임']::text[]),
    ('AEWZDMcjoMs', 'gohyerim', '스티바A 크림 단종됐는데 대체할 제품이 뭐가 있나요?', '스티바A와 같은 트레티노인 성분의 투앤티크림이 가장 직접적인 대체 제품입니다. 성분은 똑같고 회사만 다르다고 생각하시면 쉬워요. 트레티노인은 광노화로 인한 주름, 잡티, 피부 얇아짐을 억제하고 되돌려주는 효과가 검증된 골드 스탠다드 성분입니다. 실제로 70대 후반 분이 스티바A 크림을 15년간 꾸준히 발라 한 달 15,000원 정도로 놀라운 피부를 유지한 사례도 있어요. 다만 투앤티크림은 0.025% 농도 하나만 나와서 스티바A처럼 0.01%부터 단계적으로 적응시키기 어렵다는 단점이 있습니다. 처음 쓸 때는 쌀 한 톨만큼 짜서 로션이나 크림에 섞어 일주일에 1~2회부터 시작하고, 피부가 뒤집어지지 않는지 확인하면서 양과 횟수를 점점 늘려가는 게 안전합니다. 임산부는 사용 금기이니 반드시 주의하세요.', '단종된 스티바A 크림의 대체 제품과 안전한 사용법을 피부과 전문의 고혜림이 안내합니다.', array['스티바A', '투앤티크림', '트레티노인', '레티노이드', '광노화', '주름', '항노화']::text[]),
    ('AEWZDMcjoMs', 'gohyerim', '디페린겔이 여드름에 좋다던데 노화 방지에도 효과 있나요?', '디페린겔은 여드름 완화가 주 기능이고, 광노화 효과는 있지만 트레티노인보다는 약합니다. 아다팔렌이라는 3세대 레티노이드 성분으로 스티바A(1세대)보다 자극이 확실히 적어서 예민한 피부도 사용할 수 있어요. 실제로 발라봤을 때 피부 뒤집어지는 게 적었고, 턱에 여드름 날 때 넓게 펴바르기도 좋습니다. 젊고 광노화가 덜 걱정되면서 피부는 예민하고 피지가 많고 블랙헤드가 있는 분들이 처음 쓰기에 적합해요. 아다팔렌 0.1%도 광노화에 효과가 있다는 논문들이 있긴 하지만, 이 약 자체가 여드름 약이라 노화 방지를 주목적으로 쓰기엔 한계가 있습니다. 고등학생이나 20대 초반처럼 노화보다 여드름이 더 문제인 분들에게 많이 처방하는 제품이에요.', '디페린겔의 여드름·광노화 효과와 적합한 피부 타입을 피부과 전문의 고혜림이 설명합니다.', array['디페린겔', '아다팔렌', '레티노이드', '여드름', '광노화', '민감성피부', '블랙헤드']::text[]),
    ('AEWZDMcjoMs', 'gohyerim', '아크리프가 기미에도 효과 있다던데 함부로 발라도 되나요?', '아크리프는 기미 개선에 도움이 될 수 있지만, 잘못 쓰면 오히려 기미가 악화될 수 있으니 주의가 필요합니다. 4세대 레티노이드인 아크리프는 여드름, 색소침착, 광노화를 동시에 잡아주는 멀티 기능 제품이에요. 다만 디페린겔보다 훨씬 자극이 세서 피부 껍질이 벗겨지거나 빨개지면 기미가 더 심해질 가능성이 있습니다. 그래서 기미가 있으면서 민감하거나 아토피가 있는 분에게는 처방하지 않고, 견딜 수 있을 것 같은 분에게만 처방해요. 기미 부위는 처음부터 바르지 말고 다른 부위부터 시험해보고, 괜찮다 싶으면 기미 부위까지 아주 얇게 쓰는 게 안전합니다. 전신 부작용이 적어 가슴과 등에도 바를 수 있고 75g 대용량으로 나온다는 것도 장점이에요. 반드시 전문의 처방 하에 본인 피부 상태를 확인하고 사용하세요.', '아크리프의 기미 개선 효과와 주의사항을 피부과 전문의 고혜림이 안내합니다.', array['아크리프', '기미', '레티노이드', '색소침착', '여드름', '광노화', '전문의약품']::text[]),
    ('AEWZDMcjoMs', 'jeonghanmi', '레티노이드 크림 처음 쓸 때 어떻게 발라야 피부가 안 뒤집어지나요?', '처음에는 원액을 바르지 말고 쌀 한 톨만큼 짜서 사용하던 로션이나 크림에 섞어 희석한 뒤 일주일에 1~2회만 바르세요. 피부가 뒤집어지는지 확인하면서 괜찮으면 양과 횟수를 점점 늘려가는 방식이 안전합니다. 예민한 피부의 고혜림 원장도 아크리프를 일주일에 1~2회 소량만 쓰면서 보습제를 다 바른 위에 쌀알만큼 짜서 보습제 3배 정도로 희석해 살짝 바르는 정도로 사용해요. 그 정도로 조심스럽게 써도 꾸준히 쓰고 싶어할 만큼 효과가 좋은 성분이라는 뜻이죠. 따갑거나 피부 컨디션이 안 좋은 날에는 과감히 안 바르는 것도 중요합니다. 레티노이드는 저녁에 바르면 되고 아침에 선크림을 잘 바르시면 돼요. 지금 당장 효과가 느껴지지 않더라도 꾸준함이 핵심이니 까먹지 않고 루틴에 넣어두시는 게 좋습니다.', '레티노이드 크림의 안전한 첫 사용법과 희석 요령을 피부과 전문의 정한미가 정리합니다.', array['레티노이드', '트레티노인', '피부자극', '보습', '사용법', '선크림', '항노화']::text[]),
    ('Kg3a2bvg2xs', 'gohyerim', '재생 크림이랑 장벽 크림이 뭐가 다른 건지 모르겠어요', '재생 크림은 피부 세포 재생을 촉진하는 성분(병풀 추출물, 판테놀, EGF 등)이 핵심이고, 장벽 크림은 피부 장벽을 보강하는 세라마이드·콜레스테롤·지방산 세 가지가 핵심입니다. 재생 크림은 레이저 시술 후 빠른 회복이 필요할 때, 여드름 자국 색소침착을 진정시킬 때, 흉터를 빨리 낫게 하고 싶을 때 주로 쓰면 좋아요. 장벽 크림은 피부염이 생겼거나 너무 건조하고 각질이 일어나서 뭘 써도 따가운 상황에서 선택하시면 됩니다. 다만 요즘 제품들은 이 성분들이 섞여 있는 경우가 정말 많기 때문에 이름보다는 성분표를 보는 게 더 중요해요. 세라마이드, 콜레스테롤, 지방산 세 가지가 골고루 들어있는지 확인하시고, 재생 성분인 센텔라 아시아티카나 EGF가 앞단에 보이면 재생 기능이 강한 크림이라고 판단하시면 됩니다. 둘 다 데일리로 써도 문제없으니 본인 피부 상태에 맞춰 선택하세요.', '재생 크림과 장벽 크림의 성분 차이와 선택 기준을 피부과 전문의 고혜림이 설명합니다.', array['재생크림', '장벽크림', '세라마이드', '병풀추출물', 'EGF', '보습', '민감성피부']::text[]),
    ('Kg3a2bvg2xs', 'jeonghanmi', '피부과 의사가 겨울에 실제로 쓰는 크림은 뭔가요?', '정한미 원장은 라로슈포제 시카플라스트 B5 멀티 리페어 크림, 고혜림 원장은 제로이드 인텐시브 크림MD와 아토베리어 잇칭 크림을 씁니다. 정한미 원장의 피부는 장벽이 튼튼해서 보습만 잘해주면 특별한 문제가 없는 타입이라 겨울이 되면 재생 크림인 시카플라스트를 데일리로 바르고 겨울에 1~2통 정도 사용해요. 고혜림 원장은 어릴 때부터 아토피가 있는 극민감 피부라 성분이 적은 제품을 선호합니다. 제로이드는 성분이 20가지밖에 안 돼서 알러지 확률이 낮고, 아토베리어 잇칭 크림은 아시바트랩 성분이 가려움과 민감함을 줄여줘서 아토피나 홍조 있는 분에게도 잘 맞아요. 피부가 뒤집어지거나 따가울 때는 장벽 크림만 단독으로 쓰고, 괜찮은 날에는 기능성 앰플을 추가하는 식으로 상태에 맞춰 조절하는 게 포인트입니다.', '피부과 의사 두 명이 겨울에 실제로 쓰는 크림과 선택 이유를 피부과 전문의 정한미가 정리합니다.', array['겨울크림', '시카플라스트', '제로이드', '아토베리어', '보습', '민감성피부', '아토피']::text[]),
    ('Kg3a2bvg2xs', 'gohyerim', '피부과 의사가 매일 쓰는 비타민C 앰플은 뭐예요?', '비타민C 앰플은 두 원장 모두 반드시 쓰는 필수 아이템이고, 그중에서도 스킨수티컬즈 CE 페룰릭을 최애로 꼽았습니다. 비타민C는 미백과 항산화 기능 때문에 피부과 의사라면 거의 대부분 쓸 수밖에 없는 성분이에요. 고혜림 원장은 CE 페룰릭이 비쌀 때 닥터디퍼런트 CEQ PH.D를 번갈아 쓰면서 1년 내내 비타민C를 유지합니다. 추가로 스킨수티컬즈 P-TIOX도 사용하는데, PHA와 BHA 성분이 각질을 정리하고 수분을 끌어당겨 유리알처럼 반짝이는 피부결을 만들어줘요. 정한미 원장은 피부가 튼튼해서 CE 페룰릭 바르고 겨울엔 리페어 크림이면 끝날 정도로 단순하게 씁니다. 앰플 딱 하나만 고르라면 두 분 모두 CE 페룰릭을 선택할 만큼, 비타민C는 나이 들어갈수록 포기할 수 없는 성분이에요.', '피부과 의사가 매일 쓰는 앰플과 비타민C 필수 이유를 피부과 전문의 고혜림이 안내합니다.', array['비타민C', 'CE페룰릭', '앰플', '항산화', '미백', '스킨수티컬즈', 'P-TIOX']::text[]),
    ('Kg3a2bvg2xs', 'gohyerim', '예민한 피부인데 레티노이드를 꼭 써야 하나요?', '예민한 피부라도 레티노이드는 항노화를 위해 포기하기 어려운 성분이지만, 약 대신 화장품 형태의 레티날을 쓰는 게 현실적입니다. 고혜림 원장은 극민감 피부임에도 레티노이드를 안 쓸 수 없어서 닥터디퍼런트의 레티날 제품을 일주일에 2~3회 크림 위에 덧바르는 방식으로 사용해요. 레티노이드는 트레티노인(약) > 레티날 > 레티놀 순으로 효과와 자극이 모두 약해지는데, 레티날 정도면 농도만 잘 맞추면 예민한 피부도 견딜 수 있습니다. 매일 바르지 않고 간격을 두니까 뒤집어지지 않고, 레티날 제품에 히알루론산이 들어있어 촉촉해서 단독으로 발라도 괜찮아요. 지금 당장 느껴지지 않더라도 꾸준히 써야 장기적인 잔주름 예방과 항노화 효과를 볼 수 있습니다. 피부 컨디션이 안 좋은 날에는 과감히 쉬고, 상태가 좋은 날에만 쓰는 유연한 접근이 핵심이에요.', '예민한 피부의 레티노이드 사용법과 레티날 추천을 피부과 전문의 고혜림이 설명합니다.', array['레티날', '레티노이드', '민감성피부', '항노화', '잔주름', '레티놀', '닥터디퍼런트']::text[]),
    ('ot_n3YB4Za0', 'leedoyoung', '피부과 한 번도 안 가본 친구한테 뭘 해주면 좋을까요?', '통증과 다운타임이 거의 없으면서 즉각 효과가 나는 티타늄과 스킨보톡스 조합을 추천합니다. 피부과를 안 가본 사람이 가장 걱정하는 게 통증과 다운타임인데, 티타늄은 BTS 효과라고 불리는 화사해지고, 쫀쫀해지고, 슬림해지는 변화가 다운타임 없이 즉각적으로 나타나요. 스킨보톡스는 근육을 마비시키는 게 아니라 이완시켜주는 방식이라 전체적으로 주름이 펴지면서 반짝반짝한 효과가 나타납니다. 주사 후 생기는 Wheal(두드러기 같은 자국)도 2~3시간이면 사라지고, 약 배합을 잘 하면 통증도 획기적으로 줄일 수 있어요. 예전에는 울면서 받는 스킨보톡스로 유명했지만 지금은 웃으면서 받을 정도로 편해졌습니다. 주름 보톡스를 바로 맞으면 불편함을 느낄 수 있으니, 처음엔 스킨보톡스 형태가 부담이 적어 좋습니다.', '피부과 처음 가는 사람에게 추천하는 무통·무다운타임 시술을 피부과 전문의 이도영이 안내합니다.', array['티타늄', '스킨보톡스', '다운타임', '연말시술', '리프팅', '보톡스', '첫시술']::text[]),
    ('ot_n3YB4Za0', 'leedoyoung', '티타늄 효과가 금방 사라진다던데 오래 가게 할 방법 있나요?', '티타늄에 고주파를 함께 받으면 효과가 더 오래 가고 결과도 좋아집니다. 티타늄 단독으로 받으면 지속 기간이 짧다는 이야기가 있는데, 오래 사용하면서 고주파를 같이 조합하는 방법으로 극복할 수 있어요. 실제 사례로 3월 결혼식을 앞두고 11월에 온 환자분이 있었는데, 티타늄+리쥬란+스킨보톡스 조합을 해드렸더니 결혼식 전날에야 다시 오셨을 정도로 효과가 오래갔습니다. 원래 1월과 3월 초에 추가 시술을 계획했지만 효과가 유지되어 전날 티타늄과 리쥬란만 해드리고, 신혼여행 갔다 와서 4개월 뒤에 다시 오셨어요. 결혼식이나 중요한 모임 전에는 티타늄을 기본으로 깔고 스킨부스터나 스킨보톡스를 조합하면 즉각적이면서도 지속력 있는 결과를 얻을 수 있습니다. 멀리서 보는 자리에서 전체적으로 슬림하고 화사해 보이는 효과가 핵심이에요.', '티타늄 효과를 오래 유지하는 조합 시술법을 피부과 전문의 이도영이 설명합니다.', array['티타늄', '고주파', '결혼식시술', '리쥬란', '스킨보톡스', '지속기간', '리프팅']::text[]),
    ('ot_n3YB4Za0', 'kimjongsik', '레비나스가 뭔지 모르겠는데 경락 마사지 같은 건가요?', '네, 레비나스는 체외 충격파를 이용해 경락 마사지하듯 피부를 눌러주는 시술이라 아프지 않고 마취 크림도 필요 없습니다. 마사지하듯 피부를 전체적으로 눌러줘서 림프 순환을 시켜주고 근육을 풀어주는 원리예요. 열을 가하지 않기 때문에 느낌이 편하고 거부감이 적습니다. 처음에는 정형외과에서 쓰는 충격파와 같다고 생각했지만 실제로 받아보면 확실히 다르고, 여러 번 받으면 써마지 받았을 때의 쫀쫀함과 비슷한 느낌이 들어 놀랐다고 해요. 근육을 풀어준 뒤 엠페이스나 조비나 같은 근육 운동 장비를 조합하면 효과가 더 커집니다. 연말 모임처럼 사람을 멀리서 보는 자리에서 전체적으로 라인이 슬림해 보이고 얼굴이 뽀송하게 보이는 시술을 원할 때 적합해요. 다운타임이 제로라 중요한 일 전날 받아도 문제없습니다.', '레비나스(체외충격파)의 원리와 장점을 피부과 전문의 김종식이 안내합니다.', array['레비나스', '체외충격파', '경락', '림프순환', '리프팅', '다운타임', '근육이완']::text[]),
    ('ot_n3YB4Za0', 'kimjongsik', '리쥬란 맞으면 엠보 생기고 멍든다던데 요즘도 그런가요?', '요즘은 시술 방법이 발전해서 엠보도 거의 안 생기고 멍도 없는 방식으로 리쥬란을 맞을 수 있습니다. 예전에는 리쥬란이 엠보 생기고 멍들고 아프기로 유명해서 중요한 일 1~2주 전에 맞아야 했는데, 효과가 한 달 전에 맞으면 이미 사라져서 쓸모없는 시술 취급을 받기도 했어요. 핵심은 인젝터를 이용해 유두진피층에 아주 미세하게 깔아주는 기술인데, 이렇게 하면 중요한 일 직전에 맞아도 다운타임이 거의 없습니다. 실제로 결혼식 전날 이 방법으로 리쥬란을 해드린 분도 전혀 문제없이 다음 날 결혼식을 치르셨어요. 마취크림만 바르면 충분히 할 만하고, 만족도도 기존 방식과 차이가 없습니다. 예전에 리쥬란 맞고 다운타임 때문에 고생했던 분들도 이 방법이라면 다시 시도해볼 만합니다.', '리쥬란 다운타임 없이 받는 최신 시술법을 피부과 전문의 김종식이 설명합니다.', array['리쥬란', '엠보', '다운타임', '인젝터', '유두진피층', '멍', '스킨부스터']::text[]),
    ('q2oPdblGsC4', 'gohyerim', '비타민C 말고도 피부에 좋은 항산화 성분이 있나요?', '네, 비타민E와 페룰릭애씨드가 비타민C와 함께 쓰면 황금조합을 이룹니다. 비타민C는 그 자체로 항산화 성분이지만 빛이나 열에 취약해서 스스로 산화되어 기능을 잃을 수 있어요. 이때 비타민E가 산화된 비타민C를 다시 살아나게 도와주는 역할을 합니다. 페룰릭애씨드는 방패처럼 비타민C의 안정도를 8배까지 높여준다는 논문이 있을 정도로 강력한 보조 역할을 하죠. 세 성분이 각각 항산화 효과를 가지면서도 합쳐지면 시너지 효과를 내기 때문에 CE 페룰릭 조합 제품을 찾으시는 게 좋습니다. 스킨수티컬즈 CE 페룰릭이 오리지널이지만 고가이므로 닥터디퍼런트 CEQ Ph.D 같은 동일 조합 제품을 쓰셔도 무방해요. 핵심은 비타민C, 비타민E, 페룰릭애씨드 세 가지가 함께 들어간 제품을 선택하시는 겁니다.', '비타민C 외 비타민E와 페룰릭애씨드의 시너지 항산화 효과를 피부과 전문의 고혜림이 설명합니다.', array['항산화', '비타민C', '비타민E', '페룰릭애씨드', '스킨케어', 'CE페룰릭', '노화예방']::text[]),
    ('q2oPdblGsC4', 'gohyerim', '레스베라트롤이 피부 노화 방지에 정말 효과 있나요?', '레스베라트롤은 장수 유전자인 써투인을 활성화시켜 세포 손상을 막아주는 강력한 항산화 성분입니다. 프랑스 사람들이 기름진 음식을 많이 먹으면서도 성인병이 적었던 비밀이 바로 레드 와인 속 레스베라트롤이었다는 연구에서 주목받기 시작했어요. 포도 껍질과 포도씨에서 추출되는 이 성분은 식물이 자외선이나 해충으로부터 스스로를 보호하기 위해 만든 물질이기도 합니다. 스킨수티컬즈 레스베라트롤 BE 제품이 대표적인데, 레스베라트롤과 바이칼린, 비타민E 세 가지가 시너지 효과를 내도록 구성되어 있죠. 가격이 부담된다면 디오디너리 레스베라트롤 제품처럼 레스베라트롤 3%와 페룰릭애씨드 3%만 들어간 간결한 제품도 괜찮습니다. 다만 물이 전혀 없는 제형이라 처음 바를 때 오일 느낌이 나고 피부가 따뜻해지는 느낌이 있을 수 있어요. 지성 피부는 조금 오일리하게 느낄 수 있지만 금방 흡수되니 참고하세요.', '레스베라트롤의 장수 유전자 활성화 원리와 추천 제품을 피부과 전문의 고혜림이 안내합니다.', array['레스베라트롤', '항산화', '장수유전자', '써투인', '스킨수티컬즈', '디오디너리', '노화방지']::text[]),
    ('q2oPdblGsC4', 'jeonghanmi', '항산화 제품은 도대체 몇 살부터 발라야 효과가 있나요?', '지금 이 글을 보고 계시다면 오늘부터 바르시면 됩니다. 피부는 20대 중반부터 노화가 시작되기 때문에 빠르면 20대 초반부터 항산화 제품을 꾸준히 써주는 것이 예방 차원에서 가장 효과적이에요. 이미 노화가 다 진행된 후에 쓴다기보다 미리 활성산소로 인한 세포 손상을 막아주는 것이 핵심입니다. 자외선이나 미세먼지에 많이 노출되는 환경이라면 10대부터도 사용할 수 있어요. 피부과 시술도 마찬가지로 이미 다 노화된 후에는 완전히 돌릴 수 없기 때문에 예방이 가장 중요합니다. 과거를 거슬러 갈 수는 없으니 50대든 60대든 20대든 나이에 상관없이 지금부터 시작하시는 게 맞아요. 보통 추천드리는 나이는 성인이 되는 20대 정도부터입니다.', '항산화 제품의 적정 시작 나이와 예방적 사용 원리를 피부과 전문의 정한미가 정리합니다.', array['항산화', '노화예방', '20대스킨케어', '활성산소', '자외선', '안티에이징', '스킨케어시작']::text[]),
    ('q2oPdblGsC4', 'jeonghanmi', '항산화 제품 바를 때 선크림 꼭 같이 발라야 하나요?', '네, 항산화 제품을 아침에 바르신다면 선크림은 반드시 함께 발라야 합니다. 항산화 제품 대부분이 빛이나 열에 취약하기 때문에 낮에 자외선 차단 없이 사용하면 제 기능을 못 할 수 있어요. 아침에 바르는 항산화 제품은 자외선으로부터 피부를 보호하는 작용을 하고, 저녁에 바르는 제품은 자는 동안 세포를 복구하는 기능을 합니다. 스킨수티컬즈 레스베라트롤처럼 저녁 전용으로 나온 제품도 있으니 사용 시간을 확인하세요. 자주 오는 질문 중 하나가 저녁에 비타민C를 바르면 선크림도 발라야 하냐는 건데, 저녁에는 자외선이 없으니 항산화 제품만 바르고 주무시면 됩니다. 어떤 제품이든 낮 시간에는 자외선 차단제를 꼭 함께 쓰는 것이 항산화 효과를 제대로 보는 핵심이에요. 아침용과 저녁용을 구분해서 사용하시는 것을 권해드립니다.', '항산화 제품과 선크림 병행 사용법 및 아침저녁 루틴을 피부과 전문의 정한미가 안내합니다.', array['항산화', '선크림', '자외선차단', '비타민C', '아침저녁루틴', '스킨케어', '자외선']::text[]),
    ('kBYI-YZWhLE', 'kimjongsik', '피부과 의사 아내도 울쎄라 써마지 안 받는다는 게 사실인가요?', '네, 사실입니다. 두 원장 모두 아내에게 울쎄라와 써마지를 한 번도 해준 적이 없다고 밝혔습니다. 이유는 통증 때문이에요. 아내분들이 통증에 굉장히 예민한 편이라 울쎄라나 써마지처럼 아픈 시술은 시도조차 못 한 거죠. 대신 김종식 원장은 써마지와 같은 고주파 계열이면서 통증이 훨씬 적은 올리지오를 해주고 있고, 이도영 원장은 안 아프고 다운타임 없는 티타늄 리프팅을 선택했습니다. 피부과 의사 아내라고 비싸고 아픈 시술을 다 받는 게 아니라 오히려 자주 받을 수 있으니까 덜 아프게 관리하는 수준으로도 충분히 만족한다는 거예요. 요즘 트렌드인 저속 노화 개념처럼 큰 시술 한 번보다 꾸준한 자극으로 피부를 건강하게 유지하는 방식을 택한 셈입니다.', '피부과 의사가 아내에게 울쎄라 대신 올리지오와 티타늄을 선택한 이유를 피부과 전문의 김종식이 설명합니다.', array['울쎄라', '써마지', '올리지오', '티타늄', '리프팅', '통증', '저속노화']::text[]),
    ('kBYI-YZWhLE', 'kimjongsik', '올리지오가 써마지보다 효과가 떨어지는 거 아닌가요?', '효과 차이는 있지만, 통증 대비 만족도로 보면 올리지오도 충분히 훌륭한 선택입니다. 올리지오는 써마지와 같은 고주파 계열로 전체적인 콜라겐 재생 효과가 있으며, 가장 큰 장점은 확실히 덜 아프다는 점이에요. 맥시멈 통증으로 비교하면 써마지가 10일 때 올리지오는 4 정도로, 써마지를 세게 했을 때 아예 못 참는 분도 올리지오는 마취크림만 바르면 충분히 견딜 수 있습니다. 다만 가격으로 따지면 올리지오 두 번이 써마지 한 번 정도이고, 효과 면에서는 올리지오 네 번보다 써마지 두 번이 더 좋다는 의견도 있어요. 피부가 얇고 나이가 젊으신 분, 통증에 예민하신 분은 올리지오가 오히려 더 적합합니다. 600샷씩 3개월 간격으로 3-4회 정도 받으면 꾸준한 리프팅 관리가 가능해요.', '올리지오와 써마지의 통증 및 효과 차이를 피부과 전문의 김종식이 비교 설명합니다.', array['올리지오', '써마지', '고주파', '리프팅', '통증', '콜라겐', '피부탄력']::text[]),
    ('kBYI-YZWhLE', 'leedoyoung', '티타늄 리프팅이 안 아프면서도 효과가 좋다는 게 진짜예요?', '네, 티타늄은 안 아프고 다운타임 없으면서 즉각적인 효과가 나타나는 게 큰 장점입니다. 이도영 원장이 직접 아내에게 해주고 있으며, 시술 다음날 아침에 피부를 만져보고 좋아했을 정도로 체감 효과가 빠릅니다. 티타늄의 핵심 효과는 BTS 효과라 불리는 브라이트닝(화사해짐), 타이트닝(쫀쫀해짐), 슬리밍(슬림해짐) 세 가지예요. 울쎄라나 써마지가 통증 때문에 고민이라면 티타늄을 먼저 시도해보시는 것을 추천드립니다. 아내분은 시술 후 피부가 쫙 달라붙는 느낌이 바로 나서 가장 좋았다고 답했어요. 통증을 극도로 싫어하는 분도 편안하게 받을 수 있어서 리프팅 입문용으로도 적합합니다.', '티타늄 리프팅의 BTS 효과와 무통증 장점을 피부과 전문의 이도영이 안내합니다.', array['티타늄', '리프팅', '다운타임', '브라이트닝', '타이트닝', '슬리밍', '무통증']::text[]),
    ('kBYI-YZWhLE', 'kimjongsik', '세르프가 써마지 대신할 만큼 효과가 좋나요?', '세르프는 써마지와 유사한 고주파 장비이면서 통증이 확실히 적어서, 통증에 민감한 분에게 좋은 대안입니다. 김종식 원장은 병원에 세르프를 들이기 전에 본인이 먼저 맞아보고 아내에게 테스트한 뒤 도입을 결정했어요. 아내분이 올리지오보다는 약간 아파했지만 에너지 강도를 조절하니 600샷까지 잘 받았다고 합니다. 이도영 원장은 눈가 처짐이 스트레스인 아내에게 세르프 아이팁을 사용해서 써마지 아이 대신 시술했는데 반응이 꽤 좋았어요. 세르프의 장점은 깊이 조절이 가능해서 환자 맞춤형 치료가 된다는 점입니다. 써마지를 최고 강도로 받기 어려운 분이라면 세르프로 적절한 강도를 찾아 시술받는 것이 현실적인 선택이 될 수 있습니다.', '세르프의 통증 및 효과를 써마지와 비교하며 피부과 전문의 김종식이 정리합니다.', array['세르프', '써마지', '고주파', '리프팅', '통증', '아이팁', '눈가']::text[]),
    ('hUFuJI4m-rM', 'leedoyoung', '이마 보톡스 맞으면 눈이 부어 보이는 이유가 뭔가요?', '이마 보톡스를 맞으면 근육뿐 아니라 림프관과 혈관도 마비되면서 물이 잘 빠지지 않아 부을 수 있습니다. 림프관은 고여있는 물을 배수하는 역할인데 여기가 마비되면 물이 저류되어 눈꺼풀이 라면 먹고 잔 것처럼 붓는 거예요. 적당히 저류되면 광낸 사과처럼 빤딱해지는 좋은 효과가 나지만, 과하면 눈꺼풀이 붓는 부작용이 됩니다. 해결법은 의외로 간단해요. 눈꺼풀과 눈썹 위의 림프 경로를 마사지해주면 물이 빠져나가면서 호전됩니다. 아침에 일어났을 때 가장 심하니 그때 마사지를 해주시면 도움이 돼요. 마사지한다고 보톡스 효과가 풀리는 건 아니니 걱정하지 마세요. 머물러 있는 물을 빼주는 것이지 보톡스가 빠져나가는 개념이 아닙니다.', '이마 보톡스 후 눈 부기의 원인과 림프 마사지 해결법을 피부과 전문의 이도영이 설명합니다.', array['보톡스', '이마보톡스', '눈부음', '림프마사지', '부작용', '저류', '눈꺼풀']::text[]),
    ('hUFuJI4m-rM', 'leedoyoung', '이마로 눈을 뜨는 사람은 보톡스 맞으면 안 되나요?', '맞으면 안 되는 건 아니지만, 용량과 깊이를 반드시 조절해야 합니다. 눈꺼풀 올림근이 선천적으로 약한 분들은 이마 힘으로 눈을 같이 들어 올리고 있기 때문에 이마를 마비시키면 눈 뜨기가 힘들어질 수 있어요. 시술 전 간단한 테스트로 이마에 힘을 빼고 눈을 뜨게 해보면 위험도를 미리 파악할 수 있습니다. 보톡스를 진피층에 얕게 놓으면 깊이 놓을 때보다 퍼짐이 적어서 부작용 리스크를 줄일 수 있어요. 만약 눈 뜨기가 힘들어졌다면 조비나나 엠페이스 같은 근육 자극 장비로 눈썹 위쪽 근육을 자극해주면 회복을 도울 수 있습니다. 보톡스를 놓지 않은 눈썹 바로 위쪽 근육은 마비가 덜 되어 있어서 그쪽을 자극하면 눈 뜨기가 편해지죠. 처음 맞으시는 분은 보수적으로 소량부터 시작해서 2주 뒤에 추가하는 방식이 안전합니다.', '이마로 눈 뜨는 분의 보톡스 주의사항과 부작용 해결법을 피부과 전문의 이도영이 안내합니다.', array['보톡스', '이마보톡스', '눈꺼풀올림근', '부작용', '용량조절', '엠페이스', '조비나']::text[]),
    ('hUFuJI4m-rM', 'jeonghanmi', '눈가 보톡스 너무 많이 맞으면 표정이 이상해지나요?', '네, 과하게 맞으면 입만 웃고 눈은 안 웃는 팬암 미소가 되어 가짜 웃음처럼 보일 수 있습니다. 정한미 원장 본인도 눈가 주름이 신경 쓰여서 셀프로 보톡스를 놨다가 눈가가 아예 안 움직여져서 영상을 2-3주 못 찍었다고 해요. 처음이라 본인 적정 용량을 몰랐던 게 원인이었습니다. 눈가주름은 진정성이 담긴 주름이라서 완전히 펴는 것보다 힘만 빼주는 정도가 자연스러워요. 그래서 처음 맞으시는 분에게는 보수적으로 소량만 놓고 만족스러우면 유지, 부족하면 추가 터치업하는 방식을 권합니다. 눈가 보톡스를 맞는 이유는 웃을 때 주름이 너무 진하면 나이 들어 보이고, 오래되면 깊은 주름으로 패여서 나중에 보톡스로도 안 없어지기 때문이에요. 미리미리 관리하되 과하지 않게 하시는 게 핵심입니다.', '눈가 보톡스 과다 시 팬암 미소 부작용과 적정 용량 접근법을 피부과 전문의 정한미가 정리합니다.', array['보톡스', '눈가주름', '팬암미소', '부작용', '용량조절', '주름예방', '터치업']::text[]),
    ('hUFuJI4m-rM', 'leedoyoung', '40대 넘으면 사각턱 보톡스 맞지 말라는 말이 사실인가요?', '40대 중후반 이후 심술보가 생기기 시작하면 사각턱 보톡스를 권하지 않는 경우가 많습니다. 교근을 줄이면 그 살이 아래로 흘러내리면서 턱 라인이 오히려 처질 수 있기 때문이에요. 젊은 20-30대에는 효과적이지만, 피부 처짐이 시작된 분은 교근을 확 줄이는 대신 라인보톡스나 윤곽보톡스로 다듬는 수준이 더 적합합니다. 라인보톡스는 얼굴 가장자리 윤곽을 따라 부위별로 용량과 깊이를 다르게 놓아서 푹 꺼짐 없이 매끈한 라인을 만들어주는 방식이에요. 볼패임 걱정 없이 얼굴이 줄어드는 효과를 줄 수 있죠. 사각턱 보톡스를 아무 생각 없이 반복하면 볼이 꺼지고 처지는 부작용이 올 수 있으니, 특히 처짐이 시작된 분들은 반드시 의사와 상담 후 적절한 방식을 선택하세요.', '40대 이후 사각턱 보톡스의 위험성과 라인보톡스 대안을 피부과 전문의 이도영이 설명합니다.', array['사각턱', '보톡스', '라인보톡스', '윤곽보톡스', '볼패임', '심술보', '턱라인']::text[]),
    ('RrblzmcJ86s', 'leedoyoung', '리투오 맞았는데 팔자주름이 안 펴지는 이유가 뭔가요?', '리투오는 피부를 탄탄하게 만들어주는 시술이지 볼륨을 채우는 용도가 아니기 때문입니다. 팔자주름을 펴려면 필러가 더 나은 선택이에요. 리투오의 목적은 피부를 전체적으로 매끈하게 만들어주는 것으로, 스팀 다리미로 옷을 다리면 살짝씩 펴지지만 굵은 주름까지 펴지지는 않는 것과 같은 원리입니다. 다만 입 옆까지 내려온 팔자주름이 펴지는 데는 도움이 될 수 있어요. 리투오를 주사형 써마지라고 설명하기도 하는데, 써마지를 받아서 탄력을 올리려는 효과와 리투오로 세포외기질 성분을 직접 주입하는 효과가 본질적으로 같다고 볼 수 있습니다. 유명하다고 다 본인에게 맞는 게 아니니, 볼륨이 필요한지 탄력이 필요한지를 먼저 파악하시는 게 중요해요.', '리투오로 팔자주름이 안 펴지는 이유와 적합한 대안을 피부과 전문의 이도영이 설명합니다.', array['리투오', '팔자주름', '스킨부스터', '필러', '탄력', '세포외기질', '볼륨']::text[]),
    ('RrblzmcJ86s', 'leedoyoung', '스컬트라나 쥬베룩 맞으면 결절 생긴다는데 위험하지 않나요?', '결절이 생길 수 있지만 예방과 해결 방법이 모두 있으니 크게 걱정하지 않으셔도 됩니다. 결절은 스컬트라든 쥬베룩이든 입자가 고르게 퍼지지 않은 상태에서 과한 염증이 일어나면 피부 아래에서 단단하게 만져지는 것을 말해요. 예방하려면 수화를 고르게 하고 피부 속에서 성분이 잘 퍼지도록 시술하는 것이 가장 중요합니다. 결절이 생겼더라도 열을 주거나 물리적으로 깨버리는 시술을 하면 시간이 지나면서 사라져요. 리투오 역시 결절이 아예 안 생기는 건 아니지만, 리투오의 결절은 단순히 분말이 뭉쳐진 형태라 염증이 동반되지 않습니다. 생리식염수를 주입하고 물리적 힘을 가해주면 대부분 자연적으로 없어지니까 콜라겐 자극제의 결절보다 해결이 쉬운 편이에요.', '스컬트라와 쥬베룩 결절의 원인과 예방 및 해결법을 피부과 전문의 이도영이 안내합니다.', array['결절', '스컬트라', '쥬베룩', '리투오', '스킨부스터', '콜라겐', '부작용']::text[]),
    ('RrblzmcJ86s', 'leedoyoung', '힐로웨이브가 3개월이면 사라지는데 왜 맞는 건가요?', '힐로웨이브는 넣자마자 즉각적으로 볼륨이 차오르면서도 자연스럽고, 마음에 안 들면 녹일 수 있다는 게 큰 장점입니다. 필러가 츄파춥스 같은 단단한 느낌이라면 힐로웨이브는 솜사탕처럼 무른 물성이라 훨씬 자연스럽게 볼륨이 채워져요. 스컬트라나 쥬베룩은 넣고 콜라겐이 만들어질 때까지 최소 6개월을 기다려야 하지만, 힐로웨이브는 히알루론산 베이스라 바로 결과를 볼 수 있습니다. 그래서 볼륨이 꺼진 분에게 일종의 테스터로 추천하기도 해요. 먼저 힐로웨이브로 볼륨이 찼을 때 어떤 느낌인지 확인하고 만족하면 계속 유지할지, 지속기간이 긴 필러로 갈지, 콜라겐 자극제로 갈지 선택지를 넓힐 수 있습니다. 최소 3개월 이상 간격을 두고 시술하며, 만족도는 꽤 높은 편이에요.', '3개월 지속인 힐로웨이브의 즉각적 볼륨 효과와 활용법을 피부과 전문의 이도영이 정리합니다.', array['힐로웨이브', '스킨부스터', '볼륨', '히알루론산', '필러', '자연스러움', '즉각효과']::text[]),
    ('RrblzmcJ86s', 'leedoyoung', '목에 생긴 가로주름·잔주름도 스킨부스터로 없앨 수 있나요?', '목주름 종류에 따라 다르지만, 스킨부스터와 장비를 적절히 조합하면 개선이 가능합니다. 목주름은 잔주름, 가로주름, 세로주름 세 가지로 나뉘며 각각 치료법이 달라요. 잔주름은 탄력 저하 때문에 생기므로 더블타이트라는 바늘 고주파에 스킨부스터를 동시 주입하면 효과적입니다. 더블타이트는 고주파 자극과 스킨부스터 주입이 동시에 가능한 장비라서 목 잔주름이 펴지는 효과를 볼 수 있어요. 가로주름은 굉장히 소프트한 필러로 치료하고, 세로주름은 넓은목근이라는 근육 때문에 생기므로 보톡스로 해결합니다. 스킨보톡스도 피부결 개선과 잔주름 완화에 도움이 되지만, 뭔가를 만들어내는 게 아니라 과한 것을 줄여주는 역할이라 목적에 따라 선택하셔야 해요.', '목주름 유형별 스킨부스터 치료법과 장비 조합을 피부과 전문의 이도영이 안내합니다.', array['목주름', '스킨부스터', '더블타이트', '보톡스', '잔주름', '가로주름', '세로주름']::text[]),
    ('Nx-2HHTrnZU', 'jeonghanmi', '30살인데 울쎄라 써마지 꼭 받아야 하나요?', '아닙니다. 30살이라면 굳이 비싸고 아픈 울쎄라나 써마지에 돈을 모을 필요 없이 다른 좋은 선택지가 많습니다. 요즘 미용 시술 트렌드는 비싸고 아파도 효과 확실한 쪽에서 안 아프고 편하게 받으면서 서서히 개선되는 방향으로 바뀌고 있어요. 세르프는 써마지와 비슷한 고주파 장비인데 통증이 적고 깊이 조절이 가능해서 환자 맞춤형 치료를 할 수 있습니다. 울쎄라도 최근에는 1.5mm 팁으로 얕은 층에 부드럽게 쏘면서 모공 축소와 피부 탄탄함을 만드는 방식이 트렌드예요. 젊은 분이라면 이런 가벼운 시술로 시작해서 꾸준히 관리하는 게 한 번 크게 받는 것보다 효율적입니다. 장비들도 덜 아프고 편안한 쪽으로 계속 발전하고 있으니 본인 상황에 맞는 걸 찾아보세요.', '30대가 울쎄라 대신 선택할 수 있는 리프팅 트렌드를 피부과 전문의 정한미가 안내합니다.', array['울쎄라', '써마지', '세르프', '리프팅', '30대관리', '1.5mm팁', '고주파']::text[]),
    ('Nx-2HHTrnZU', 'leedoyoung', '2026년에 주목해야 할 스킨부스터가 뭔가요?', '2025년이 리투오의 해였다면, 2026년에는 히알루론산 베이스 스킨부스터가 다시 각광받을 것으로 예상됩니다. 히알루론산의 최대 장점은 넣으면 즉각적으로 볼륨이 나오고, 부작용이 생기면 녹일 수 있다는 거예요. 힐로웨이브는 자연스럽게 볼륨을 채우면서 수분 공급 효과도 있고, 벨로테로 리바이브나 스킨바이브 같은 제품은 속광이 나고 촉촉하게 만들어줍니다. 스컬트라도 20년이 넘은 제품인데 자연스러운 티 안 나는 시술 트렌드에 맞아 오히려 요즘 더 인기가 올라가고 있어요. 레디어스 역시 예전에는 코나 턱 높이는 데 쓰였지만 지금은 부드럽게 희석해서 피부 탄탄함 목적으로 사용법이 바뀌었습니다. 제품은 같아도 트렌드에 맞게 활용법이 달라지니 최신 시술법을 아는 의사에게 받으시는 게 중요해요.', '2026년 주목할 히알루론산 스킨부스터 트렌드를 피부과 전문의 이도영이 정리합니다.', array['스킨부스터', '리투오', '힐로웨이브', '히알루론산', '스컬트라', '레디어스', '2026트렌드']::text[]),
    ('Nx-2HHTrnZU', 'leedoyoung', '시술 후 회복을 빠르게 하는 애프터 케어가 있나요?', '엑소좀이나 PDRN을 시술 직후 침투시키면 회복이 눈에 띄게 빨라집니다. 바늘 고주파 같은 시술로 이미 피부에 상처가 나있는 상태에 엑소좀을 뿌려서 침투시켜주면 바로 진정이 되는 것을 많이 경험했어요. 플라즈마 장비나 크라이오셀을 이용해서 침투를 시키는 방법이 있습니다. 엑소좀은 화장품으로 허가된 제품이라 주사는 안 되지만 침투 방식으로 사용하면 재생에 도움이 되죠. 리쥬란 같은 스킨부스터를 리프팅 시술과 같이 하는 것도 회복과 효과를 동시에 높이는 방법이에요. 요즘은 시술 받은 티가 안 나야 하는 트렌드라서 이런 애프터 케어의 중요성이 점점 더 커지고 있습니다. 집에서는 마스크팩을 잘 골라 10-20분 적정 시간만 붙이는 것도 가성비 좋은 홈케어 방법이에요.', '시술 후 빠른 회복을 위한 엑소좀과 PDRN 활용법을 피부과 전문의 이도영이 설명합니다.', array['애프터케어', '엑소좀', 'PDRN', '플라즈마', '회복', '마스크팩', '재생']::text[]),
    ('Nx-2HHTrnZU', 'jeonghanmi', '가정용 홈 디바이스가 피부과 시술을 대체할 수 있나요?', '대체는 어렵지만, 피부과에 자주 가기 힘든 상황이라면 적당히 쓰는 건 분명 도움이 됩니다. 피부과 의사들이 홈 디바이스에 관심이 적은 이유는 병원 장비가 몇십 배 출력이 센 걸 그냥 쓸 수 있기 때문이에요. 하지만 해외 거주 등으로 피부과 시술이 어려운 분이라면 홈 디바이스로 앰플을 흡수시키고 관리하는 것만으로도 도움이 됩니다. 다만 효과를 보겠다고 하루에 1시간씩 과하게 하면 오히려 골병들 수 있어요. 근력운동처럼 어느 정도 센 자극이 있어야 효과가 나는 것이므로 홈 디바이스의 한계를 인지하면서 주기적인 병원 치료도 병행하는 것이 바람직합니다. 피부가 특별히 예민하거나 기미가 심한 분이 아니라면 적당한 빈도로 사용하시는 걸 권해드려요.', '가정용 홈 디바이스의 효과 한계와 적절한 활용법을 피부과 전문의 정한미가 안내합니다.', array['홈디바이스', '피부관리', '메디큐브', '고주파', '초음파', '홈케어', '피부과시술']::text[]),
    ('HMAznuRwyKs', 'kimsoohyung', '입을 꽉 다물고 있는 습관이 진짜 얼굴 처짐을 만드나요?', '네, 입을 꾹 다물고 있는 습관은 마리오네트 라인(입꼬리 주름)을 심화시키는 대표적인 노화 촉진 습관입니다. 아래턱 근육에 지속적으로 힘이 들어가면 그 근육이 강화되면서 팔자주름과 불독살이 더 도드라지게 됩니다. 특히 한국인들은 지하철에서도 무표정하게 입을 다문 채로 있는 경우가 많아 서양인보다 마리오네트 주름이 생기기 쉬운 구조예요. 아시안은 입꼬리 내림근이 더 발달되어 있어 처짐이 잘 오는 반면, 서양인은 입꼬리 올림근이 발달해 동안으로 보이는 경향이 있습니다. 이너피스가 강한 분들, 즉 생각이 많고 고민이 많은 분들은 잘 때도 이를 꽉 다물고 계시는 경우가 많거든요. 혼자 있을 때 의식적으로 턱에 힘을 빼고 어금니 사이를 벌려두는 연습을 해보세요. 거울 앞에서 "우-" 해봤을 때 자갈턱이 보이는 분이라면 평소 근육을 과하게 쓰고 있을 가능성이 높습니다.', '입 다무는 습관이 마리오네트 라인을 심화시키는 원리와 예방법을 피부과 전문의 김수형이 설명합니다.', array['마리오네트', '팔자주름', '입꼬리주름', '자갈턱', '노화습관', '표정근육', '동안']::text[]),
    ('HMAznuRwyKs', 'parkhyojin', '뽀득뽀득 세안하는 게 오히려 피부를 늙게 한다고요?', '너무 꼼꼼하게 세게 씻으려는 습관이 오히려 피부를 늙게 만듭니다. 뽀득뽀득 씻겨야 잘 씻었다고 생각하시는 분들이 많은데, 강한 세안제뿐 아니라 패드로 닦는 습관, 클렌징 티슈, 필링젤 등 피부에 마찰을 주는 행위들이 미세한 자극으로 쌓여 피부 장벽을 무너뜨려요. 피부 장벽이 한번 무너지면 재생이 어렵고 노화가 빠르게 진행됩니다. 세수할 때 뜨거운 물도 금물인데, 얼굴만큼은 무조건 미온수로 해야 합니다. 사우나를 오래 하시는 분들 피부가 얇아지는 것도 같은 원리로, 적정 온도 이상의 열이 활성산소를 증가시켜 피부를 손상시킵니다. 씻고 나서 수건으로 박박 닦지 말고 톡톡 두드리듯 물기를 남겨둔 상태에서 보습제를 바르는 게 핵심이에요. 좀 덜 씻기더라도 갖고 있는 피부 장벽을 무너뜨리지 않는 게 훨씬 더 중요합니다.', '과도한 세안과 마찰이 피부 장벽을 무너뜨려 노화를 촉진하는 이유를 피부과 전문의 박효진이 정리합니다.', array['세안', '피부장벽', '클렌징', '미온수', '보습', '노화습관', '사우나']::text[]),
    ('HMAznuRwyKs', 'kimsoohyung', '돈 안 쓰고 집에서 할 수 있는 최고의 동안 운동이 뭔가요?', '중안부 스쿼트, 쉽게 말해 ''어흥 운동''이 가장 효과적인 동안 유지 운동입니다. 윗입술을 위로 올리는 근육 3개를 수직으로 자극하면 중안부가 볼록해지면서 팔자주름을 들어 올리는 효과가 있어요. 호텔리어, 강사, CS업종 분들이 유독 동안인 이유도 항상 중안부 근육을 쓰며 환하게 웃기 때문입니다. 핵심은 어흥 동작을 할 때 눈을 웃으면 안 된다는 점인데, 눈을 웃으면 눈주름이 생기기 때문에 위쪽 근육만 고립시켜서 힘을 줘야 합니다. 처음에는 반드시 거울을 보면서 다른 곳에 주름이 잡히지 않는지 확인하며 연습하세요. 익숙해지면 거울 없이도 수시로 할 수 있게 됩니다. 이 운동과 함께 선크림, 레티놀, 비타민C 앰플까지 꾸준히 병행하면 돈 들이지 않고도 상당한 노화 예방 효과를 볼 수 있어요.', '비용 없이 동안을 유지하는 중안부 운동법과 홈케어 핵심을 피부과 전문의 김수형이 안내합니다.', array['중안부운동', '동안', '팔자주름', '어흥운동', '노화예방', '선크림', '레티놀']::text[]),
    ('HMAznuRwyKs', 'parkhyojin', '아무것도 하기 싫은데 딱 하나만 해야 한다면 뭘 해야 하나요?', '아무것도 투자하기 싫어도 보톡스만큼은 꼭 하셔야 합니다. 시기를 놓쳐버리면 되돌릴 수 없는 게 근육에 의한 주름이기 때문이에요. 보톡스는 가장 저렴하면서도 효과가 확실한 시술로, 이마·미간·눈가 주름이 깊게 자리 잡기 전에 예방적으로 맞으면 장기적으로 훨씬 동안을 유지할 수 있습니다. 그 외에 집에서 꼭 챙겨야 할 성분으로는 레티놀(비타민A)이 있는데, 피부 턴오버를 빠르게 해서 잔주름과 각질을 줄여주는 바르는 써마지 같은 역할을 합니다. 다만 레티놀은 자극감이 강하기 때문에 소량으로 천천히 적응하면서 사용해야 피부가 뒤집어지지 않아요. 비타민C 앰플도 활성산소를 잡아 콜라겐 파괴를 막아주므로 같이 쓰면 노화 예방에 도움이 됩니다. 보톡스 하나와 레티놀·비타민C를 습관으로 만들면 최소한의 투자로 최대한의 결과를 얻을 수 있습니다.', '최소 투자로 노화를 막는 보톡스와 레티놀 활용법을 피부과 전문의 박효진이 안내합니다.', array['보톡스', '레티놀', '비타민C', '노화예방', '피부턴오버', '안티에이징', '주름']::text[]),
    ('WfrR9vbgbyM', 'kimsoohyung', '얼굴 PT 하면 오히려 팔자주름이 더 깊어지는 거 아닌가요?', '중안부 PT를 할 때 팔자주름이 접히는 것은 일시적인 현상이며, 실제로 주름이 깊어지는 게 아닙니다. 나이가 들면 근육이 빠지면서 피부를 지지하는 힘이 약해지고 팔자주름이 깊어지게 되는데, 중안부 운동을 꾸준히 하면 근육이 천연 필러처럼 자연스러운 볼륨을 만들어줘요. 텐트의 지지대처럼 근육이 피부를 받쳐주는 원리라고 보시면 됩니다. 운동 중 접히는 게 신경 쓰인다면 볼살을 손으로 잡고 어흥 동작을 해보세요. 팔자주름이 접히지 않으면서도 근육 운동 효과를 얻을 수 있어요. 5초간 윗입술 올리기, 5초간 입안에 바람 넣어 주름 펴주기를 시간 날 때마다 3세트 반복하면 효과적이고, 거울을 보면서 윗입술만 올리는 근육을 정확히 쓰는 연습이 중요합니다.', '중안부 PT 시 팔자주름이 깊어지는 것은 일시적 현상이며 꾸준히 하면 천연 필러 효과가 있다고 피부과 전문의 김수형이 설명합니다', array['팔자주름', '중안부PT', '얼굴운동', '볼륨', '리프팅', '근육운동', '홈케어', '동안', '입가주름']::text[]),
    ('WfrR9vbgbyM', 'kimsoohyung', '팔자주름 예방하려면 집에서 뭘 할 수 있나요?', '집에서 할 수 있는 팔자주름 예방법으로 입안 마사지, 레티놀 사용, 수면 자세 교정 세 가지를 추천드립니다. 먼저 깨끗이 씻은 손가락을 입술 안쪽에 넣어 팔자주름 부위를 펴주면 근육 긴장도를 풀어주는 데 도움이 돼요. 팔자주름을 따라 생기는 잔주름에는 레티놀이나 레티날 같은 비타민A 유도체를 발라 피부의 각질 턴오버(피부 재생 주기)를 빠르게 해주시는 게 좋습니다. 특히 중요한 습관은 옆으로 누워 자지 않는 것인데, 옆으로 누워 자는 자세가 팔자주름을 깊어지게 만드는 데 한몫하기 쉬워요. 한쪽 팔자주름만 더 심한 비대칭이 있는 분들은 한쪽으로만 누워 자는 경우가 많습니다. 골판지를 여러 번 접었다 폈다 하면 자국이 생기는 것처럼 매일 반복되는 압력이 주름을 만드는 원리이니, 팔자주름이 신경 쓰이시는 분들은 똑바로 누워 자는 습관을 꼭 들여보세요.', '팔자주름 예방을 위한 입안 마사지, 레티놀, 똑바로 누워 자는 습관 세 가지 홈케어를 피부과 전문의 김수형이 안내합니다', array['팔자주름', '예방', '레티놀', '수면자세', '홈케어', '잔주름', '비타민A', '마사지', '입가주름']::text[]),
    ('WfrR9vbgbyM', 'parkhyojin', '다이어트 하면 팔자주름이 더 심해질 수 있다는 게 진짜예요?', '급격하게 살을 빼면 팔자주름이 깊어질 수 있습니다. 체중이 빠지면 얼굴 전체 볼륨이 꺼지면서 팔자주름을 위로 들어 올려주던 볼살까지 줄어들고, 오히려 살이 아래로 내려오는 효과가 생기거든요. 실제로 체중 감량을 가장 많이 했을 때 이전 영상보다 팔자주름이 훨씬 깊어 보여서 충격을 받은 적이 있었어요. 앞볼의 볼륨까지 사라지면서 팔자주름을 지지해주는 힘이 약해진 거죠. 그래서 다이어트를 할 때는 너무 급격히 빼지 않는 것이 중요하고, 체중 감량 기간에는 중안부 PT를 더 열심히 해서 근육으로 볼륨을 보완해 주시길 권합니다. 무리한 다이어트는 건강뿐 아니라 얼굴 노화에도 영향을 줄 수 있으니 천천히 감량하세요. 얼굴 볼륨을 유지하면서 체중을 관리하는 것이 팔자주름 예방의 핵심입니다.', '급격한 다이어트가 얼굴 볼륨 감소로 팔자주름을 깊어지게 할 수 있는 이유를 피부과 전문의 박효진이 설명합니다', array['팔자주름', '다이어트', '볼륨', '체중감량', '중안부PT', '노화', '처짐', '리프팅']::text[]),
    ('WfrR9vbgbyM', 'kimsoohyung', '팔자주름 시술 종류가 너무 많은데 내 타입에 뭐가 맞나요?', '팔자주름은 생기는 원인에 따라 크게 세 가지 타입으로 나뉘며, 각각 적합한 시술이 다릅니다. 첫째, 얼굴 볼륨이 부족해서 생기는 경우에는 필러나 스컬트라로 팔자주름 부위와 앞볼에 볼륨을 채워주는 것이 근본적인 해결책이 될 수 있어요. 둘째, 얼굴이 전체적으로 빵빵한데 살이 밀려 내려오면서 팔자주름만 깊은 경우에는 지방 분해 주사로 국소적인 지방을 줄여주는 게 효과적입니다. 셋째, 무표정일 때는 괜찮은데 웃을 때만 팔자주름이 깊어지는 분들은 피부 자체가 얇아진 것이 원인이라 하이드로 리프팅으로 진피층을 단단하게 지지해주면 좋아요. 하이드로 리프팅은 필러를 피부 진피 바로 밑에 소량 깔아서 탄력을 만들어주는 시술로 효과가 1년 반에서 2년 정도 유지됩니다. 50~60대에 가만히 있어도 골진 주름이 있는 경우에는 쥬브젠(자가 진피 재생술)이 도움이 될 수 있어요.', '팔자주름을 볼륨 부족형, 지방 과다형, 피부 얇아진 형으로 나눠 시술법을 피부과 전문의 김수형이 설명합니다', array['팔자주름', '필러', '스컬트라', '지방분해주사', '하이드로리프팅', '쥬브젠', '리프팅', '볼륨', '입가주름']::text[]),
    ('JcFbCaf11sE', 'leedoyoung', '외국인들이 한국까지 와서 피부과 시술 받는 이유가 뭔가요?', '한국 피부과 시술이 가격 대비 기술력에서 압도적이기 때문입니다. 작년 한국에 와서 피부과를 방문한 외국인이 117만 명을 넘었는데, 이 중 60% 이상이 피부과 시술을 목적으로 방문했어요. 브라질의 경우 슈링크(울트라포머) 한 번에 220~368만 원인데 한국에서는 50~100만 원이면 받을 수 있고, 볼뉴머도 브라질은 368만 원이지만 한국은 70~100만 원 수준입니다. 대만도 한국 가격의 3배 정도를 받는다고 해요. 비행기 타고 와서 호텔에 머물며 시술받고 가도 자국에서 받는 것보다 저렴한 셈이죠. 가격뿐 아니라 자국 의사들보다 한국 의사들의 시술 경험이 훨씬 많다는 인식도 강합니다. 대만에서만 한국 피부과 방문 외국인이 550% 늘었을 정도로 K-뷰티 시술에 대한 수요가 폭발적이에요.', '외국인이 한국 피부과에 몰리는 이유와 해외 시술 가격 차이를 피부과 전문의 이도영이 설명합니다.', array['K-뷰티', '의료관광', '슈링크', '볼뉴머', '울쎄라', '시술비용', '피부과']::text[]),
    ('JcFbCaf11sE', 'jeonghanmi', '해외 피부과 의사들이 한국에서 꼭 배워가고 싶은 시술이 뭔가요?', '한국만의 ''시술 레이어링'', 즉 여러 시술을 한 번에 겹쳐서 하는 기법이 해외 의사들에게 가장 큰 관심사입니다. 레바논에서 온 의사는 자국에서는 시술 하나 하고 결과를 본 뒤 다음 시술을 하는데, 한국에서는 하루에 울쎄라+써마지+티타늄+스킨부스터까지 겹쳐서 한다는 점이 궁금해서 왔다고 했어요. 한국의 빨리빨리 문화 덕분에 빨리 좋아져야 하니까 콤보 시술이 발전한 거죠. 이스라엘에서 온 의사는 콕 찍어서 리쥬란을 배우러 왔다고 했는데, 리쥬란이 한국 원산지 제품이고 한국에서 가장 많이 시술하기 때문입니다. 중국 의사가 울쎄라와 써마지를 같은 날에 해도 되냐고 질문한 적도 있는데, 한국에서는 그게 루틴이라 무서울 수 있지만 부작용 없이 잘 운용되고 있어요. 해외 의사 2000명이 이런 노하우를 배우러 코리아더마 학회에 참석했을 정도입니다.', '해외 의사들이 한국에서 배워가는 시술 레이어링과 리쥬란 기법을 피부과 전문의 정한미가 정리합니다.', array['시술레이어링', '울쎄라', '써마지', '리쥬란', '스킨부스터', 'K-뷰티', '의료관광']::text[]),
    ('JcFbCaf11sE', 'jeonghanmi', '외국인들 사이에서 제일 핫한 한국 화장품 브랜드가 어딘가요?', '미국에서는 아누아, 조선미녀, 닥터디퍼런트가 특히 인기이고, 브라질에서는 미샤가 엄청난 사랑을 받고 있습니다. 한국 스킨케어는 2025년 미국 시장에서 프랑스를 추월해 1위에 올랐어요. 원래 유리아쥬, 아벤느, 라로슈포제 같은 프랑스 더마코스메틱이 원조였는데 K-뷰티가 넘어선 겁니다. 코리아더마 학회에서 인터뷰한 외국 의사들은 아누아 PDRN 크림, 조선미녀 선크림, 닥터디퍼런트 레티놀과 비타민C, 리쥬란 마스크팩까지 구체적으로 사용 중이라고 답했어요. 평생 하나만 바른다면 선크림을 고르겠다는 대답도 나왔습니다. 브라질에서 33시간을 날아와서까지 한국 제품을 사가는 이유는 한국 화장품의 과학적 성분 조합과 가성비가 압도적이기 때문이에요.', '외국인들이 사랑하는 한국 화장품 브랜드와 인기 비결을 피부과 전문의 정한미가 안내합니다.', array['K-뷰티', '아누아', '조선미녀', '미샤', 'PDRN', '리쥬란', '선크림']::text[]),
    ('JcFbCaf11sE', 'leedoyoung', '피부과 의사가 평생 딱 하나만 맞는다면 어떤 시술을 고르나요?', '보톡스를 선택하겠다는 답변이 가장 많았습니다. 코리아더마 학회에서 해외 피부과 의사에게 물어봤을 때도, 국내 원장들에게 물어봤을 때도 답은 같았어요. 보톡스는 예방적인 측면에서 가장 확실한 효과를 주는데, 유명한 쌍둥이 사례에서 한 사람은 보톡스를 계속 맞고 한 사람은 안 맞았더니 완전히 다른 사람이 된 보고가 있을 정도입니다. 보톡스가 단순히 주름만 펴주는 게 아니라 얼굴 라인을 다듬고, 볼륨을 줄이고, 측두부를 정리하는 등 다양한 역할을 하기 때문이에요. 가장 저렴하면서도 꾸준히 맞으면 스킨 퀄리티 유지까지 해주는 시술이니, 아무것도 하기 싫어도 보톡스 하나만큼은 놓치지 마시길 권합니다.', '피부과 의사들이 평생 하나만 고르는 시술로 보톡스를 택한 이유를 피부과 전문의 이도영이 설명합니다.', array['보톡스', '안티에이징', '주름예방', '리프팅', '스킨퀄리티', '피부과시술']::text[]),
    ('dj6hEvBcbjs', 'kwonsuhyun', '40-50대가 피부과에 처음 간다면 뭘 먼저 하는 게 가장 효과적인가요?', '잡티·검버섯·점·편평사마귀 제거를 가장 먼저 하시면 됩니다. 100명이 받으면 100명 다 만족하는 시술이고, 레이저 딱 한 번만 해도 얼굴이 확 깨끗해져요. 나이가 들면서 세월이 쌓이듯 이런 색소 병변도 많이 쌓이는데, 10~20대에는 한두 개였던 것들이 40~50대가 되면 얼굴 전체를 지저분하고 늙어 보이게 만들거든요. 특히 남편분들이 와이프한테 끌려오시다가 딱 받고 나면 만족해서 보톡스까지 하시는 경우도 많습니다. 병원에 여러 번 안 와도 되고, 이것저것 복잡하게 할 필요도 없어서 피부과 입문 시술로 최고예요. 비용이 아깝다는 생각이 절대 안 들 정도로 드라마틱한 변화를 체감하실 수 있습니다.', '40-50대 피부과 첫 시술로 잡티·검버섯 제거를 추천하는 이유를 피부과 전문의 권수현이 설명합니다.', array['검버섯', '잡티제거', '색소레이저', '편평사마귀', '40대', '50대', '피부과시술']::text[]),
    ('dj6hEvBcbjs', 'jeonghanmi', '볼이 꺼지면 채워야 한다는데 얼굴이 더 커지는 거 아닌가요?', '꺼진 곳을 채우면 오히려 얼굴이 더 작아 보이는 효과가 있습니다. 나이가 들면 관자놀이, 눈 밑, 옆볼, 팔자주름, 마리오네트 부위가 공통적으로 꺼지는데, 이건 리프팅을 한다고 해결되지 않아요. 피부 속 볼륨이 줄어든 거라 겉에만 펴주는 건 아무 의미가 없거든요. 히알루론산 필러가 가장 오래된 방법이고, 요즘은 스컬트라나 쥬베룩볼륨 같은 콜라겐 생성 시술도 많이 합니다. 스컬트라는 콜라겐 씨앗을 피부에 뿌려서 내 피부가 직접 콜라겐을 만들게 하는 원리라 훨씬 자연스럽죠. 울퉁불퉁해진 라인을 매끄럽게 채워주면 입체적으로 변하면서 리프팅 효과까지 나타납니다. 5년 전 정도의 뼈대를 되살린다는 개념으로, 적당한 정도만 보강하면 빵빵해지는 게 아니라 젊어 보이게 됩니다.', '꺼진 볼을 채우면 오히려 얼굴이 작아 보이는 원리를 피부과 전문의 정한미가 안내합니다.', array['필러', '스컬트라', '쥬베룩', '볼륨시술', '콜라겐', '팔자주름', '리프팅']::text[]),
    ('dj6hEvBcbjs', 'kwonsuhyun', '울쎄라·써마지 같은 리프팅 장비는 한 번 받으면 효과가 바로 보이나요?', '딱 한 번 받았을 때는 잘 모르지만, 매년 꾸준히 받으면 5년쯤 뒤에 주변에서 왜 안 늙냐는 소리를 듣게 됩니다. 울쎄라·써마지 같은 장비는 피부에 열을 넣어 콜라겐 재생을 유도하는 원리인데, 드라마틱하게 한 번에 나타나는 게 아니라 적금처럼 쌓이는 시술이에요. 콜라겐이 빠져서 얇아지고 탄력 떨어진 피부가 탄탄하고 반질반질해지는 효과가 서서히 나타납니다. 비용이 부담이라면 울쎄라 대신 슈링크, 써마지 대신 텐써마나 올리지오 같은 장비를 본인 예산에 맞게 골라 1년 주기로 받는 게 더 중요해요. 한국이 리프팅 강국인 만큼 다양한 좋은 장비들이 있기 때문에, 비싼 장비 한 번보다 적당한 장비를 꾸준히 하는 전략이 효과적입니다.', '울쎄라·써마지의 효과가 나타나는 시점과 예산별 대안을 피부과 전문의 권수현이 정리합니다.', array['울쎄라', '써마지', '리프팅', '슈링크', '텐써마', '콜라겐', '노화예방']::text[]),
    ('dj6hEvBcbjs', 'jeonghanmi', '나이 들면서 얼굴이 넙대대해지는데 보톡스로 줄일 수 있나요?', '네, 보톡스로 가장자리 근육을 정리해주면 얼굴을 깎아낸 듯한 효과를 볼 수 있습니다. 나이가 들면서 턱과 옆 근육이 세지면 얼굴이 점점 넙대대해지는데, 보톡스로 옆라인을 줄여 갸름하게 만들어주는 것이 그 사람의 5년 전 모습으로 돌아가는 방법이에요. 확 갸름해지지는 않지만 나이를 덜 먹어 보이고 얼굴이 세련돼 보이는 느낌을 줍니다. 반대로 땅콩형 얼굴은 접근법이 다른데요. 측두근·광대·사각턱을 많이 쓰면 이쪽은 커지고 옆볼은 상대적으로 패여서 땅콩형이 되거든요. 이 경우 보톡스로 과하게 쓰는 근육은 줄이고 안 쓰는 근육은 밸런스를 맞춰주면 얼굴형이 가다듬어집니다. 넙대대한 얼굴은 많이 깎아내는 목적, 땅콩형은 라인을 예쁘게 연결하는 목적으로 보톡스를 활용하시면 됩니다.', '보톡스로 넙대대한 얼굴과 땅콩형 얼굴을 각각 다듬는 방법을 피부과 전문의 정한미가 설명합니다.', array['보톡스', '사각턱', '땅콩형얼굴', '윤곽', '리프팅', '교근', '얼굴축소']::text[]),
    ('MlUm3JCWWe4', 'parkhyojin', '성인인데 볼에만 자꾸 좁쌀 여드름이 나는 이유가 뭔가요?', '화장을 겹겹이 하거나, 모공을 막는 제품을 쓰고 있을 가능성이 높습니다. 프라이머로 모공 가리고, 파운데이션 바르고, 파우더까지 겹쳐 바르면 모공이 막혀 피지가 배출되지 않으면서 좁쌀 여드름이 생겨요. 진한 화장을 지우려고 이중 세안을 열심히 하면 피부 장벽이 무너지고, 무너진 장벽에서 각질이 떡져서 나면서 모공을 또 막는 악순환이 반복됩니다. 특히 파데프리 선크림이 뻑뻑하고 매트해서 피부가 뒤집어져 오시는 분들이 작년 여름에 정말 많았어요. 쿠션도 비추인데, 썼던 퍼프를 계속 쓰면 세균이 번식해서 염증성 여드름의 원인이 됩니다. 쓰고 있는 화장품이 논코메도제닉(모공을 막지 않는 제품)인지 인터넷에 검색해보시고, 모공을 막는 제품이라면 교체하는 것만으로도 개선을 체감할 수 있어요.', '볼에 반복되는 좁쌀 여드름의 원인과 화장품 점검법을 피부과 전문의 박효진이 안내합니다.', array['좁쌀여드름', '성인여드름', '논코메도제닉', '모공', '파운데이션', '클렌징', '피부장벽']::text[]),
    ('MlUm3JCWWe4', 'kimsoohyung', '클렌징 오일 쓰면 오히려 트러블이 폭발하는데 뭘로 지워야 하나요?', '클렌징 밀크를 1차 세안제로 쓰는 걸 가장 추천합니다. 클렌징 오일이나 밤은 매트한 화장을 잘 녹여내지만, 헹굴 때 오일을 제대로 씻어내지 못하면 그 기름이 모공을 막아서 트러블 파티가 열려요. 클렌징 밀크·로션·크림은 오일과 물이 섞여 나온 제형이라 얼굴에 약간 남아있더라도 모공을 막지 않는다는 장점이 있습니다. 크리미한 제형이라 보습 효과까지 있어 피부 장벽도 덜 손상시키죠. 더 나은 방법은 애초에 촉촉한 파운데이션을 써서 화장을 가볍게 하는 건데, 그러면 1차 세안만으로도 충분히 씻겨서 이중 세안 자체가 필요 없어집니다. 퍼프 대신 손으로 바르는 것도 중요해요. 화장을 바꾸기 어렵다면 최소한 클렌징 밀크로 1차 세안 후, 약산성 폼클렌저로 마무리하는 순서를 지켜보세요.', '클렌징 오일 대신 밀크를 써야 트러블이 줄어드는 이유를 피부과 전문의 김수형이 설명합니다.', array['클렌징밀크', '클렌징오일', '성인여드름', '이중세안', '모공', '피부장벽', '세안']::text[]),
    ('MlUm3JCWWe4', 'parkhyojin', '생리 때만 턱 주변에 여드름이 나는데 어떻게 해야 하나요?', '호르몬 변동 때문에 생기는 여드름이라 근본적으로는 경구 피임약으로 호르몬을 안정시키는 게 가장 효과적입니다. 배란기 때쯤 호르몬이 들쭉날쭉 바뀌면서 피지샘이 자극받아 입·턱 주변에 한두 개씩 나는 패턴인데, 많은 환자분들이 여드름 1~2개 때문에 피임약까지 먹어야 하나 고민하시죠. 트러블이 심하지 않다면 크기가 크거나 깊은 건 피부과에서 트리암시놀론 주사를 맞고, 얕은 건 집에서 소독된 면봉으로 짜서 관리하거나 약국 여드름 연고를 발라볼 수 있습니다. 항상 같은 자리에만 반복해서 나는 분은 아그네스라는 시술이 효과적인데, 그 피지선만 콕 찔러 지져주면 같은 자리에 다시 안 나는 경우도 있어요. 생리주기 여드름이 너무 심하다면 항생제를 그 시기에만 복용하는 방법도 있으니 피부과 상담을 받아보세요.', '생리주기마다 턱에 나는 여드름의 원인과 해결 방법을 피부과 전문의 박효진이 정리합니다.', array['생리여드름', '호르몬여드름', '턱여드름', '피임약', '아그네스', '성인여드름', '피지']::text[]),
    ('MlUm3JCWWe4', 'kimsoohyung', '성인 여드름 홈케어만 바꿔도 정말 80% 이상 좋아질 수 있나요?', '네, 홈케어만 점검해서 잘 고쳐줘도 성인 여드름의 80~90%는 많이 개선됩니다. 가장 흔한 실수가 보습제 안 바르고 수분크림만 쓰면서 피부 장벽이 회복되지 않아 여드름이 반복되는 경우예요. 수분크림 위에 세라마이드·콜레스테롤·지방산이 든 보습제로 막을 씌워줘야 합니다. 당과 유제품이 함께 든 음식(초콜릿 등)도 피지를 폭발적으로 자극하는데, GI 지수를 갑자기 높이는 음식이 여드름을 유발하므로 턱 주변에 반복해서 나시는 분은 식습관 점검이 필수예요. 수면도 중요한데, 밤늦게 자면 코르티졸 호르몬이 증가해 피지샘을 자극합니다. 2시에 자서 10시에 일어나는 건 양질의 수면이 아니에요. 밤 10~11시 전에 잠드는 생체리듬을 지키고, 클렌징·보습·식습관·수면 네 가지를 교정하면 시술 없이도 상당한 호전을 기대할 수 있습니다.', '성인 여드름 80% 이상을 개선하는 홈케어 교정 핵심 4가지를 피부과 전문의 김수형이 안내합니다.', array['성인여드름', '홈케어', '보습', '피부장벽', '식습관', '수면', '코르티졸']::text[]),
    ('lewYp5cktgg', 'jeonghanmi', '건성·수부지가 겨울에 추천할 만한 히알루론산 세럼이 있을까요?', '아누아 PDRN 히알루론산 캡슐 세럼처럼 저·중·고분자 히알루론산이 모두 들어간 제품이 좋습니다. 히알루론산은 분자 크기에 따라 역할이 다른데, 저분자는 깊이 스며들어 수분 공급을 하고 고분자는 피부 표면을 수분으로 막아주는 역할을 해요. 세 가지가 다 든 제품이 여러 역할을 동시에 해줘서 겨울 보습에 효과적입니다. 제형이 물처럼 엄청 가벼운데 막상 얼굴에 발라보면 촉촉하고 광이 도는 느낌이라 메이크업 전에 쓰기 좋아요. 그 위에 세타필 시카 카밍 페이스 크림처럼 너무 무겁지 않은 크림을 얹으면 화장이 안 무너집니다. 세타필 시카 크림에는 세라마이드가 들어있어 피부 장벽 강화에도 도움이 되고, 홍조나 민감 피부 분들도 데일리로 부담 없이 쓸 수 있어요. 앰플 바르고 크림 바르고 선크림까지 하면 겨울 루틴으로 충분합니다.', '건성·수부지 겨울 보습용 히알루론산 세럼(저·중·고분자) 추천을 피부과 전문의 정한미가 정리합니다.', array['히알루론산', '겨울보습', '세럼', 'PDRN', '수부지', '건성', '아누아']::text[]),
    ('lewYp5cktgg', 'kwonsuhyun', '지성인데 겨울에 건조해지기 시작했어요, 뭘 발라야 하나요?', '세라마이드·콜레스테롤·지방산이 든 산뜻한 로션이나 크림을 보습제로 쓰시면 됩니다. 지성 피부도 나이가 들면 건조함을 느끼기 시작하는데, 여름에 쓰던 가벼운 크림만으로는 겨울에 부족할 수 있어요. 에스트라 아토베리어 AI 크림이 여름용으로 좋았다면, 겨울에는 제로이드 수딩크림 정도로 보습력을 올려보세요. 그것도 부족하면 에스트라 아토베리어 365 로션까지 시도할 수 있지만, 지성에게는 꽤 꾸덕할 수 있으니 본인 피부에 테스트해보고 결정하는 게 좋습니다. 핵심은 세콜지(세라마이드·콜레스테롤·지방산) 성분이 들어간 제품이면 어떤 브랜드든 OK라는 점이에요. 피지를 날리고 싶을 때는 클레이 성분이 든 팩클렌저로 피지 흡착 후 씻어내는 방법도 있는데, 필링젤보다 자극이 적어 사계절 내내 쓸 수 있습니다.', '겨울에 건조해진 지성 피부를 위한 보습제 선택법을 피부과 전문의 권수현이 안내합니다.', array['지성피부', '겨울보습', '세라마이드', '에스트라', '제로이드', '피지조절', '수부지']::text[]),
    ('lewYp5cktgg', 'kwonsuhyun', '지성 피부인데 나이아신아마이드 20% 제품 써도 괜찮나요?', '피부가 민감하지 않고 기름이 많은 지성 피부라면 나이아신아마이드 20% 제품이 아주 좋습니다. 나이아신아마이드가 유수분 밸런스를 잡아줘서 피지 조절에 효과적이고, 피부 톤과 결을 정돈하는 데도 도움을 줘요. 실제로 지성 피부 원장이 바르고 잤더니 다음 날 피지가 확연히 줄었다는 경험을 공유하기도 했습니다. 다만 처음 바를 때 살짝 따가운 느낌이 있을 수 있는데, 적응되면 괜찮아져요. 주의할 점은 민감하거나 예민한 피부라면 뒤집어질 수 있다는 것이니 소량부터 테스트해보시는 게 좋습니다. 보통 나이아신아마이드 앰플이 5% 정도 들어간 제품이 많은데, 20%는 상당히 고농도이므로 다른 자극 성분과 섞어 바르기보다 단독으로 사용하는 걸 권합니다. 피지 고민이 심한 지성분들에게는 확실한 차이를 체감하실 수 있는 성분이에요.', '나이아신아마이드 20%가 지성 피부에 효과적인 이유와 주의점을 피부과 전문의 권수현이 설명합니다.', array['나이아신아마이드', '지성피부', '피지조절', '피부톤', '피부결', '앰플', '유수분밸런스']::text[]),
    ('lewYp5cktgg', 'jeonghanmi', '피부과 의사도 입술 관리를 따로 하나요? 뭘 바르세요?', '네, 입술 라인이 칙칙해지면 나이 들어 보이기 때문에 따로 관리합니다. PHA가 들어간 디오디너리 엑스폴리에이팅 립 세럼으로 입술 각질을 자극 없이 정리해주는데, PHA는 물분자를 머금고 있어 각질 제거와 수분 보충을 동시에 해줘요. 그 위에 미백 기능이 있는 세럼을 한 겹 더 바르고, 마무리로 라네즈 립 슬리핑 마스크를 입술 라인까지 듬뿍 발라 자면 다음 날 각질 하나 없이 통통한 입술이 됩니다. 라네즈 립 슬리핑 마스크는 바세린보다 쫀득쫀득한 제형이라 막을 더 잘 씌워주는데, 미국에서도 유명한 한국 화장품으로 꼽힐 정도예요. 입술이 사계절 건조하고 각질이 일어나는 분들에게 강력 추천합니다. 한 달 정도 꾸준히 하면 입술 색과 질감 모두 눈에 띄게 달라집니다.', '피부과 의사의 입술 관리 루틴과 추천 제품을 피부과 전문의 정한미가 공유합니다.', array['입술관리', '립세럼', '라네즈', 'PHA', '각질제거', '입술건조', '립슬리핑마스크']::text[]),
    ('Bn9XC9zQwwM', 'kimsoohyung', '수분크림만 열심히 바르는데 왜 계속 건조한 걸까요?', '수분크림만 바르는 건 시멘트 없는 벽에 물만 계속 들이붓는 것과 같아서, 피부 장벽을 강화하는 보습제를 발라야 합니다. 피부 각질층은 벽돌과 시멘트 구조인데, 건조한 분들은 벽돌 사이 시멘트(세라마이드, 콜레스테롤, 지질) 역할이 부족한 상태예요. 여기에 수분만 넣으면 증발해서 날아가버리죠. 시멘트 칠에 해당하는 세콜지 성분이 잘 구성된 보습제를 발라야 수분이 빠져나가지 않습니다. 겨울에는 차갑고 건조한 바람에 피부 장벽이 무너지기 더 쉬워지기 때문에 재생크림을 추가로 바르는 게 도움이 돼요. 전성분표에서 판테놀(비타민 B5 전구체)이 들어있는 재생크림을 고르시면 장벽 손상을 빠르게 회복시켜줍니다. 수분크림이 아니라 장벽을 세워주는 보습제가 건조함의 진짜 해결책이에요.', '수분크림과 보습제의 차이와 겨울 건조 해결법을 피부과 전문의 김수형이 설명합니다.', array['보습제', '수분크림', '피부장벽', '세라마이드', '건조', '겨울보습', '세콜지']::text[]),
    ('Bn9XC9zQwwM', 'parkhyojin', '판테놀이 겨울 건조함에 진짜 효과 있나요?', '네, 판테놀은 리쥬란으로도 개선되지 않던 건조감을 홈케어만으로 해결한 사례가 있을 정도로 겨울 보습에 효과적입니다. 판테놀은 피부에 발라주면 비타민 B5로 변환돼 피부 재생을 도와주는 성분이에요. 비판텐 연고의 주성분이 바로 이 판테놀이고, 아토피 환자에게 스테로이드 1% 크림과 비슷한 효과를 보였다는 연구도 있습니다. 다만 판테놀에는 D판테놀과 L판테놀 두 종류가 있는데, 피부 재생에 유효한 건 D판테놀(덱스판테놀)이에요. 화장품 구매 시 전성분표에 덱스판테놀이라고 적혀 있는지 확인하시는 게 좋습니다. D/L 판테놀이라고 적힌 제품은 실제 유효 성분 함량이 낮을 수 있어 조심하세요. 겨울철 건조가 심할 때 기존 보습제에 판테놀 앰플을 2~3방울 섞어 바르시면 건조감 개선에 도움이 됩니다.', '겨울 건조함에 효과적인 판테놀의 종류와 올바른 사용법을 피부과 전문의 박효진이 안내합니다.', array['판테놀', '덱스판테놀', '비타민B5', '겨울건조', '비판텐', '재생크림', '보습']::text[]),
    ('Bn9XC9zQwwM', 'kimsoohyung', '지성 피부인데 판테놀 앰플 발라도 트러블 안 나요?', '스킨스탠다드 75% 덱스판테놀 세럼을 지성 피부에 직접 테스트해봤는데 트러블이 하나도 안 생기고 모공도 막히지 않았습니다. 이 제품은 덱스판테놀 75%에 정제수 25%를 섞은 구조라 꾸덕꾸덕한 제형이에요. 단독으로 바르면 너무 진득하기 때문에 평소 쓰는 크림에 2~3방울 떨어뜨려 섞어 바르는 방식을 추천합니다. 비판텐 연고에는 라놀린이라는 밀폐 성분이 있어 모공을 막을 수 있지만, 이 앰플은 성분이 심플해서 지성 피부도 안전하게 쓸 수 있어요. 지성인데 속건조가 있는 분이라면 바이오더마 세비엄 하이드라 크림에 판테놀 앰플을 믹스해서 사용해보세요. 세비엄은 피지를 잡아주는 특허 성분이 있으면서도 보습감이 충분한 제품이라 조합이 잘 맞습니다. 지성 피부도 건조함을 느낄 수 있으니 본인 제형에 맞게 섞어 쓰시면 됩니다.', '지성 피부가 판테놀 앰플을 안전하게 쓰는 방법을 피부과 전문의 김수형이 정리합니다.', array['판테놀', '지성피부', '덱스판테놀', '트러블', '세비엄', '바이오더마', '속건조']::text[]),
    ('Bn9XC9zQwwM', 'parkhyojin', '겨울에 한 가지 보습제로 끝내고 싶으면 뭘 발라야 하나요?', '한 큐에 끝내고 싶으신 분은 제로이드 인텐시브 리치크림처럼 판테놀이 보습제에 이미 포함된 제품을 추천합니다. 이 제품은 기존 인텐시브 크림에 판테놀이 추가돼서 겨울철 재생까지 한 번에 해결할 수 있어요. 전성분표에서 판테놀이 꽤 앞쪽에 있어 함량이 높은 편이고, 실제로 건조한 환자분들이 일반 인텐시브 크림보다 리치 크림을 훨씬 선호하시더라고요. 만약 시카 성분까지 원하신다면 라로슈포제 시카플라스트 멀티 리페어 크림도 좋은 선택입니다. 덱스판테놀 5%에 시카 성분이 함께 들어 있어 재생에 도움이 되고, 크림 제형이라 지성 피부도 트러블 없이 바를 수 있어요. 이런 보습제로도 건조하다면 판테놀 앰플을 섞어 바르는 단계로 올라가시면 됩니다. 본인 피부 타입과 건조 정도에 따라 제형을 골라보세요.', '겨울 보습을 한 가지로 끝낼 수 있는 판테놀 보습제 추천을 피부과 전문의 박효진이 안내합니다.', array['제로이드', '판테놀', '보습제', '시카플라스트', '라로슈포제', '겨울보습', '재생크림']::text[]),
    ('Cyo-EMaSR3k', 'kimjongsik', '홈케어만으로 피부가 진짜 하얘질 수 있나요?', '네, 검버섯이나 기미처럼 레이저가 필요한 경우를 제외하면 홈케어만으로도 피부가 전반적으로 밝아지고 깨끗해질 수 있습니다. 다만 아이유나 태연처럼 본인의 한계를 넘어 하얘지는 건 불가능해요. 팔 안쪽이 자외선을 거의 안 맞는 부위라 본연의 가장 밝은 피부색을 보여주는데, 그 정도가 여러분이 도달할 수 있는 최대치입니다. 나이아신아마이드를 아침저녁으로 꾸준히 바르면 피부톤이 전체적으로 밝아지고, 레티놀 성분 연고나 화장품도 미백에 도움이 많이 돼요. 레티놀은 햇빛에 분해되니까 밤에만 사용하시고, 아침에는 비타민C를 바르시면 자외선 보호 기능까지 얻을 수 있습니다. 3일만 바르고 포기하지 마시고, 최소 몇 주 이상 꾸준히 발라주셔야 효과를 체감하실 수 있어요.', '홈케어만으로 피부를 밝게 만드는 성분과 올바른 사용법을 피부과 전문의 김종식이 설명합니다.', array['미백', '나이아신아마이드', '레티놀', '비타민C', '홈케어', '피부톤', '피부밝기']::text[]),
    ('Cyo-EMaSR3k', 'kwonsuhyun', '비타민C 발라도 효과를 못 느끼겠는데 왜 그런 걸까요?', '비타민C 효과를 못 느끼시는 건 농도가 본인 피부에 비해 낮기 때문일 가능성이 높습니다. 낮은 농도를 쓰면 효과가 있는둥 없는둥 하는 느낌이 있기 때문에 본인에게 맞는 비타민C 농도를 찾는 게 중요해요. 또 하나 주의할 점은 비타민C 제품은 시간이 지나면 산화돼서 노랗게 변하는데, 이 상태로 바르면 얼굴이 노래질 수 있습니다. 오래된 비타민C 앰플은 폐기하고 새 제품을 사서 바르시는 게 좋아요. 비타민C는 아침에 쓰시면 자외선 보호 기능도 있어서 더 효과적이고, 레티놀과 함께 쓰고 싶다면 레티놀은 밤에, 비타민C는 아침에 나눠 사용하세요. 나이아신아마이드와 번갈아가면서 바르는 것도 피지 조절과 미백을 동시에 챙길 수 있는 좋은 방법입니다.', '비타민C 효과를 제대로 보기 위한 농도와 사용 팁을 피부과 전문의 권수현이 안내합니다.', array['비타민C', '미백', '농도', '산화', '나이아신아마이드', '레티놀', '피부톤']::text[]),
    ('Cyo-EMaSR3k', 'kimjongsik', '글루타치온 주사 맞으면 피부가 정말 하얘지나요?', '글루타치온 주사는 꾸준히 일주일 간격으로 맞아야 효과가 나타나며, 한두 번으로는 어렵습니다. 먹는 글루타치온은 체내 흡수 후 실제로 작용하는 양이 10% 미만으로 굉장히 적어서, 주사로 맞아 바로 흡수시키는 게 훨씬 효과적이에요. 한꺼번에 고용량을 주사로 맞았을 때 효과가 좋고, 횟수 제한은 따로 없어 일주일에 한 번씩 맞으시는 분들도 계십니다. 다만 엄청 많이 맞아야 변화를 느낄 수 있기 때문에 꾸준함이 핵심이에요. 주사 시술 외에도 잡티가 별로 없으면서 전체적으로 어두운 분들에게는 스킨 보톡스로 주름을 펴서 밝아지게 하거나, 힐로웨이브 같은 히알루론산 주사로 맑아지게 하는 방법도 있습니다. 본인의 고민 원인이 색소인지, 결인지, 볼륨인지에 따라 맞는 시술이 달라지니 상담을 받아보시는 게 좋아요.', '글루타치온 주사의 효과와 피부를 밝히는 다양한 시술을 피부과 전문의 김종식이 정리합니다.', array['글루타치온', '미백주사', '스킨보톡스', '힐로웨이브', '피부밝기', '시술', '미백']::text[]),
    ('Cyo-EMaSR3k', 'kwonsuhyun', '써마지 받으면 피부가 밝아진다는데 사실인가요?', '네, 써마지는 리프팅으로 유명하지만 콜라겐 재생 작용으로 피부가 밝아지는 효과도 분명히 있습니다. 콜라겐이 하는 일이 수분을 머금는 것인데, 수분 자체가 투명하기 때문에 수분을 많이 머금은 피부일수록 실제로 밝아 보이고 투명해 보여요. 건조하고 살이 없는 분들은 써마지가 잘 맞고, 지성 피부에 피부가 두꺼운 분들은 티타늄 시술이 더 효과적입니다. 티타늄은 받자마자 확 환해지는 느낌이 있어서 결혼식이나 중요한 행사를 앞둔 분들에게도 좋아요. 그 외에도 모공이 넓은 분들은 바늘 고주파와 쥬베룩 병행이, 피부결 개선이 필요한 분들은 제네시스 레이저가 밝아지는 데 도움이 됩니다. 레이저 토닝보다 오히려 제네시스가 밝아지는 데는 더 효과적이라는 의견도 있으니 본인 피부 상태에 맞게 선택하세요.', '써마지와 티타늄 등 피부를 밝게 만드는 시술의 원리를 피부과 전문의 권수현이 설명합니다.', array['써마지', '콜라겐', '미백', '티타늄', '제네시스', '리프팅', '피부밝기']::text[]),
    ('Cyo-EMaSR3k', 'kimjongsik', '홈케어만으로 진짜 피부가 하얘질 수 있나요?', '네, 홈케어만으로도 피부를 상당히 밝게 만들 수 있습니다. 다만 자신의 팔 안쪽 피부색이 하얘질 수 있는 최대치라는 점은 알아두셔야 해요. 팔 안쪽은 자외선을 거의 안 받아서 본연의 가장 밝은 피부색을 유지하고 있는 부위거든요. 전반적으로 피부가 밝아지고 깨끗해지는 데는 나이아신아마이드를 아침 저녁으로 꾸준히 바르는 게 핵심입니다. 여기에 레티놀 성분이 들어간 연고나 화장품을 저녁에 한 번 깔아주면 미백에 큰 도움이 돼요. 레티놀은 햇빛을 받으면 분해되고 자극감이 생길 수 있어서 반드시 밤에만 사용하셔야 합니다. 검버섯이나 기미처럼 특정 색소 문제는 레이저 치료가 필요하지만, 전반적인 톤 개선은 홈케어만으로 충분히 가능하니 꾸준히 시도해 보세요.', '홈케어만으로 피부 밝아지는 방법과 나이아신아마이드·레티놀 사용법을 피부과 전문의 김종식이 안내합니다.', array['미백', '나이아신아마이드', '레티놀', '홈케어', '피부톤', '비타민C']::text[]),
    ('Cyo-EMaSR3k', 'kwonsuhyun', '비타민C 앰플 발라도 효과를 못 느끼겠는데 뭐가 문제인가요?', '비타민C 효과를 못 느끼신다면 농도가 너무 낮은 제품을 쓰고 계실 가능성이 높습니다. 비타민C는 어느 정도 농도가 돼야 확실한 효과가 나타나고, 낮은 농도에서는 있는둥 없는둥 하는 느낌이 들 수 있어요. 본인 피부에 맞는 비타민C 농도를 찾는 게 중요합니다. 또 하나 주의할 점은 비타민C 앰플이 오래되면 노랗게 변하면서 오히려 얼굴이 노래질 수 있다는 건데요, 변색된 제품은 바로 폐기하고 새 제품으로 교체하세요. 비타민C는 자외선 보호 기능도 있어서 아침에 바르면 효과가 더 좋고, 레티놀과 함께 쓰고 싶다면 레티놀은 밤에, 비타민C는 아침에 나눠 쓰는 방식을 추천드립니다. 임산부도 사용할 수 있을 만큼 안전한 성분이니 꾸준히 활용해 보세요.', '비타민C 앰플 효과를 못 느끼는 원인과 올바른 사용법을 피부과 전문의 권수현이 설명합니다.', array['비타민C', '앰플', '미백', '농도', '레티놀', '임산부', '자외선차단']::text[]),
    ('Cyo-EMaSR3k', 'kimjongsik', '글루타치온 미백 주사 맞으면 피부가 정말 하얘지나요?', '글루타치온 주사는 미백 효과가 있지만, 한두 번으로는 어렵고 꾸준히 맞아야 합니다. 일주일에 한 번씩 맞는 분도 계시고, 한 달에 한 번 정도 맞는 경우도 있어요. 핵심은 주사로 직접 흡수시켜야 효과를 볼 수 있다는 점입니다. 먹는 글루타치온은 간까지 가서 실제로 미백 작용을 하는 양이 10% 미만으로 굉장히 적거든요. 고용량을 주사로 한꺼번에 맞았을 때 훨씬 효과가 좋고, 일주 간격으로 꾸준히 맞아야 변화를 느낄 수 있습니다. 다만 타고난 피부색 자체를 완전히 바꾸기는 어렵기 때문에 아이유 씨처럼 하얘지겠다는 기대보다는 본인 톤을 고르고 깨끗하게 만드는 데 초점을 맞추시는 게 현실적이에요. 이효리 씨처럼 까무잡잡해도 톤이 고르면 깨끗하고 예뻐 보일 수 있습니다.', '글루타치온 주사의 미백 효과와 먹는 제품과의 흡수율 차이를 피부과 전문의 김종식이 정리합니다.', array['글루타치온', '미백주사', '피부톤', '멜라닌', '미백', '주사']::text[]),
    ('Cyo-EMaSR3k', 'kwonsuhyun', '피부과에서 받으면 확실히 환해지는 시술이 뭔가요?', '시술 직후 확실히 밝아지는 걸 느끼고 싶다면 티타늄을 추천드립니다. 웨딩을 앞둔 신부나 중요한 행사 전에 시술 티가 안 나면서 리프팅 효과와 함께 환해지는 느낌을 줘서 만족도가 높아요. 특히 지성 피부는 다른 시술을 받아도 효과를 잘 못 느끼는 경우가 많은데, 티타늄은 확실히 밝아진 느낌이 든다고 합니다. 건조하고 살이 없는 피부라면 써마지가 더 잘 맞는데, 써마지는 콜라겐을 재생시키면서 피부가 수분을 머금게 해 투명하고 밝아 보이는 효과를 줍니다. 모공이 넓어서 피부가 칙칙해 보이는 분이라면 제네시스로 콜라겐 재생을 유도하는 것도 좋은 방법이에요. 레이저 토닝보다 제네시스가 밝아지는 데는 더 도움이 된다는 의견도 있으니, 본인 피부 타입에 맞게 선택하시면 됩니다.', '시술 후 확실히 밝아지는 티타늄·써마지·제네시스 시술 비교를 피부과 전문의 권수현이 안내합니다.', array['티타늄', '써마지', '제네시스', '리프팅', '미백', '콜라겐', '지성피부']::text[]),
    ('mZSOeGxC2KA', 'jeonghanmi', '바세린 바르면 진짜 눈가 주름이 펴지나요?', '바세린 안에 주름을 펴주는 성분이 따로 있는 건 아니고, 밀폐 효과로 수분 증발을 막아줘서 잔주름이 덜 보이게 되는 원리입니다. 바세린의 정체는 석유에서 정제한 퓨어 페트롤리움 젤리로, 기름 덩어리가 피부에 코팅막을 씌워 수분이 날아가는 걸 차단해줘요. 건조해지면 잔주름이 더 잘 생기고 잘 보이기 때문에 바세린으로 밀폐하면 잔주름이 해결된 것처럼 보이는 겁니다. 다만 굉장히 무거운 제형이라 아침에는 바를 수 없고, 저녁 나이트케어 후에 덧바르는 방식으로 사용하세요. 지성 피부라면 눈가와 입술 정도에만 한정해서 쓰시는 게 안전합니다. 잘못 따라 하면 모공이 막혀서 다음 날 여드름이 올라올 수 있거든요. 바세린 대신 바세린 거즈를 잘라서 눈 밑에 붙이면 사이사이 구멍이 있어 덜 답답하면서도 같은 효과를 낼 수 있어요.', '바세린이 잔주름을 펴주는 원리와 올바른 사용법을 피부과 전문의 정한미가 안내합니다.', array['바세린', '눈가주름', '밀폐제', '잔주름', '보습', '바세린거즈', '건조']::text[]),
    ('mZSOeGxC2KA', 'kwonsuhyun', '지성 피부인데 바세린을 어디에 쓸 수 있어요?', '지성 피부는 기름이 많은 부위를 피하고 눈가, 입술, 발뒤꿈치, 팔꿈치처럼 피지선이 없는 곳에만 사용하시면 됩니다. 지성 피부도 피부가 탱탱한 편이지만 눈 밑은 주름이 자글자글해지고, 입술은 쪼글쪼글해지기 쉬운 부위거든요. 크림을 발라도 눈가가 자글자글할 때 그 위에 바세린을 한 번 덧바르거나, 레티놀 바르고 바세린을 덧발라 밀폐시키는 방식으로 쓸 수 있어요. 단, 목 부위는 여드름이 잘 생기는 곳이라 지성 피부분들은 바르지 마세요. 코, 이마, 볼처럼 피지 분비가 많은 T존에도 바르면 모공이 막혀 100% 트러블이 생깁니다. 바세린을 바를 때는 반드시 저녁에, 아침 외출 전에는 절대 바르지 마시고 나이트케어 마지막 단계로 사용하세요. 지성 피부도 부위를 선별하면 바세린의 밀폐 보습 효과를 충분히 누릴 수 있습니다.', '지성 피부가 바세린을 안전하게 활용할 수 있는 부위와 방법을 피부과 전문의 권수현이 정리합니다.', array['바세린', '지성피부', '눈가', '밀폐', '보습', '잔주름', '입술']::text[]),
    ('mZSOeGxC2KA', 'jeonghanmi', '바세린이랑 뭘 섞어 바르면 효과가 더 좋을까요?', '피부 고민에 따라 조합이 달라지는데, 건조하면 히알루론산을 바르고 바세린으로 덮고, 재생이 필요하면 재생크림이나 EGF를 바른 뒤 바세린으로 밀폐하시면 됩니다. 찢어지게 건조한 분들은 꾸덕한 크림을 발라도 건조하다고 하시는데, 크림 바르고 바세린을 덧바르면 수분 증발을 완전히 차단할 수 있어요. 입술이 잘 터서 각질이 달고 사는 분이라면 세콜지 크림을 입술에 먼저 바르고 너무 심할 때 바세린을 덧바르는 방식도 효과적입니다. 발뒤꿈치 각질이 심한 분은 유리아(피부연화제)를 먼저 바르고 바세린을 듬뿍 바른 뒤 랩으로 감고 수면양말을 신으면 다음 날 완전 부들부들해져요. 유리아가 각질을 연화시키고 바세린이 밀폐해주는 시너지로 드라마틱한 효과를 볼 수 있습니다. 본인의 피부 고민에 맞는 성분을 먼저 바르고 바세린으로 덮는 게 핵심이에요.', '바세린과 함께 쓰면 효과가 극대화되는 성분 조합을 피부과 전문의 정한미가 설명합니다.', array['바세린', '밀폐', '히알루론산', '유리아', '발뒤꿈치', '재생크림', '보습']::text[]),
    ('mZSOeGxC2KA', 'kwonsuhyun', '아토피 건조한 피부에 바세린 덧바르면 도움이 되나요?', '네, 아토피 환자분들에게 바세린은 보습제 위에 덧발라 밀폐 효과를 높이는 용도로 도움이 됩니다. 보습제 크림만 발라서 안 될 때 보습제를 바르고 바세린을 덧바르면 훨씬 덜 간지럽고 촉촉한 느낌이 끈적거림을 이길 수 있어요. 다만 바세린만큼의 밀폐 효과를 세라마이드·콜레스테롤·지방산이 든 보습제로 내려면 듬뿍보다 더 많이 발라야 합니다. 실제로 아토피용 보습제를 3개월 동안 충분한 양으로 꾸준히 바르니 아토피가 거의 재발하지 않았다는 경험담도 있어요. 바세린은 그 기간을 줄여주는 보조 역할로 쓸 수 있겠죠. 주의할 점은 바세린 자체가 치료제는 아니라 밀폐제일 뿐이라는 거예요. 아토피가 심해지면 반드시 피부과에서 적절한 처방을 받으시고, 바세린은 보습 보조 수단으로 활용하시는 게 좋습니다.', '아토피 피부에 바세린을 활용하는 방법과 주의점을 피부과 전문의 권수현이 안내합니다.', array['바세린', '아토피', '보습제', '밀폐', '세라마이드', '피부장벽', '건조']::text[]),
    ('D0RXfp-Rf3s', 'kimjongsik', '20~30대인데 눈 밑이 처지는 건 왜 그런 건가요?', '젊은 나이에도 눈 밑이 처지는 건 노화만의 문제가 아닙니다. 눈 밑 구조 자체가 약하게 태어났거나 앞 볼 부위의 뼈 발달이 적은 분들은 10~20대부터 처짐이 나타날 수 있어요. 또 아토피 피부염이나 비염, 결막염이 있어서 눈을 자주 비비는 습관도 큰 원인입니다. 눈 밑 피부는 피지선 발달도 없고 굉장히 얇아서 자극에 쉽게 손상되고, 한번 늘어나면 원래대로 되돌리기 어려운 부위거든요. 계속 긁다 보면 살이 축 처지고 흐물흐물해지면서 잔주름과 어두운 느낌이 함께 생깁니다. 그래서 가려워서 눈을 비비는 분이라면 피부과에서 약 처방을 받아 가려움부터 해결하는 게 우선이에요. 눈 비비는 습관만 고쳐도 처짐 예방에 큰 효과가 있습니다.', '20~30대에도 눈 밑이 처지는 다양한 원인과 예방법을 피부과 전문의 김종식이 설명합니다.', array['눈밑처짐', '눈밑꺼짐', '다크서클', '아토피', '눈비비기', '20대', '30대']::text[]),
    ('D0RXfp-Rf3s', 'kimjongsik', '눈 밑이 꺼져 보이는데 간단하게 개선할 수 있는 방법이 있나요?', '눈 밑이 꺼져 보이는 분 중 상당수는 실제로 눈 밑이 아니라 앞 광대가 꺼진 경우가 많습니다. 광대 볼륨이 부족하면 주변이 상대적으로 볼록해 보여서 눈 밑이 처진 것처럼 느끼게 되는 거죠. 이런 분들은 앞 볼에 볼륨을 조금만 채워줘도 눈 밑 처짐이 신경 쓰이지 않을 정도로 개선됩니다. 필러, 쥬베룩 볼륨, 스컬트라 같은 시술이 대표적이에요. 반면 앞 광대는 있는데 눈 밑만 꺼진 분이라면 눈 밑에 직접 채워주면 되는데, 쥬베룩 아이가 입자가 더 고와서 콜라겐 생성 반응이 잘 일어나 효과가 괜찮습니다. 많이 심하지 않은 분이라면 수술 없이도 충분히 개선될 수 있으니, 원인이 앞 광대인지 눈 밑 자체인지 먼저 확인해 보세요.', '눈 밑 꺼짐이 앞 광대 볼륨 부족 때문일 수 있는 이유와 시술 방법을 피부과 전문의 김종식이 안내합니다.', array['눈밑꺼짐', '앞광대', '필러', '쥬베룩', '스컬트라', '볼륨', '리프팅']::text[]),
    ('D0RXfp-Rf3s', 'kwonsuhyun', '눈 밑 지방 재배치 수술, 정말 해볼 만한 건가요?', '눈 밑 지방이 볼록하게 튀어나온 분이라면 수술이 가장 확실한 해결책입니다. 눈 밑 지방 재배치는 정말 드라마틱한 수술로, 사람 인상이 바뀌고 10년은 젊어 보일 정도의 효과가 있어요. 수술 시간도 오래 걸리지 않고 다운타임도 그렇게 길지 않습니다. 30대 젊은 분들도 많이 하고 만족도도 높아요. 다만 수술이 무서워서 최대한 늦추고 싶다면 실을 넣거나 울트라콜, 필러를 살짝 깔아서 덜 보이게 만드는 방법이 있습니다. 이런 시술은 수술을 뒤로 미루기 위한 버티기 용도이지 근본적인 해결은 아니에요. 아그네스로 지방을 살짝 녹여 부피를 줄이는 방법도 있지만, 진짜 심한 분은 결국 수술이 필요하게 됩니다.', '눈 밑 지방 재배치 수술의 효과와 수술 전 대안 시술을 피부과 전문의 권수현이 정리합니다.', array['눈밑지방재배치', '눈밑처짐', '눈밑수술', '아그네스', '필러', '울트라콜']::text[]),
    ('D0RXfp-Rf3s', 'kimjongsik', '눈 밑 다크서클이 심한데 집에서라도 관리할 수 있나요?', '네, 다크서클이 색소 침착 때문이라면 집에서 나이아신아마이드, 레티놀, 비타민C를 꾸준히 발라주는 것만으로도 많이 좋아질 수 있습니다. 큰 돈 들이지 않고 꾸준히만 하셔도 진짜 효과가 있어요. 병원에서는 멜라닌 색소를 지우는 토닝을 10~20번 정도 하면 거의 다 좋아지고, 혈관이 넓어져서 푸르게 보이는 경우에는 브이빔 레이저를 병행합니다. 눈 밑 잔주름만 많은 분이라면 보톡스는 효과가 없고, 아이 리쥬란이나 필러 같은 주사 시술을 고려해야 해요. 예방이 가장 중요한데 눈 밑 보습만 충분히 해줘도 잔주름 예방에 큰 도움이 됩니다. 비싼 아이크림이 아니어도 바세린이나 일반 보습제로 꾸준히 관리해 주시면 병원에 올 시간을 늦출 수 있어요.', '다크서클 색소 침착의 홈케어 관리법과 병원 시술을 피부과 전문의 김종식이 설명합니다.', array['다크서클', '색소침착', '나이아신아마이드', '레티놀', '토닝', '아이리쥬란', '보습']::text[]),
    ('D0RXfp-Rf3s', 'kimjongsik', '20~30대인데 눈 밑이 처지는 건 왜 그런 거예요?', '눈 밑 처짐은 노화뿐 아니라 눈 밑 구조가 선천적으로 약하거나 앞 볼 뼈 발달이 부족해도 10~20대부터 생길 수 있습니다. 아토피, 비염, 결막염으로 눈 밑을 계속 긁으면 원래 약한 눈 밑 피부가 더 빨리 손상되면서 살이 축 처져요. 눈 밑은 피지선 발달이 없고 피부가 굉장히 얇아서 자극에 상처가 쉽게 생기고 원래대로 되돌리기 힘든 부위거든요. 병원에 다크서클 때문에 왔다고 하시는 분들 중 실제로는 눈 밑 꺼짐이나 처짐인 경우가 많습니다. 원인에 따라 크게 두 가지로 나뉘는데, 앞 광대가 꺼져서 상대적으로 눈 밑이 볼록해 보이는 경우와 실제 눈 밑 지방이 불룩한 경우예요. 앞 광대가 꺼진 거라면 볼륨만 조금 채워줘도 간단히 개선되니 한번 확인해보시는 걸 추천합니다. 젊다고 방심하지 마시고 눈 비비는 습관부터 교정하는 게 가장 중요해요.', '젊은 나이에도 눈 밑이 처지는 원인과 유형별 해결법을 피부과 전문의 김종식이 설명합니다.', array['눈밑처짐', '눈밑꺼짐', '다크서클', '광대', '필러', '쥬베룩', '눈밑지방']::text[]),
    ('D0RXfp-Rf3s', 'kwonsuhyun', '눈 밑 지방 볼록한 거 수술 말고 해결할 방법 없나요?', '눈 밑 지방이 볼록한 분들은 궁극적으로 수술이 가장 효과적이지만, 수술을 미루고 싶다면 실 삽입이나 울트라콜, 필러로 버틸 수는 있습니다. 다만 이런 시술들은 수술을 뒤로 미루기 위한 임시 방편이지 근본 해결은 아니에요. 30~40대에 눈 밑 지방이 약간 있는 정도라면 아그네스의 지방 녹이는 팁으로 부피를 줄여볼 수 있고, 탄력이 좋아지면서 살짝 녹이는 정도는 효과가 있습니다. 하지만 정말 심하신 분들은 결국 언젠가 수술하게 돼 있어요. 눈 밑 지방 재배치 수술은 정말 드라마틱하게 인상이 바뀌고 10년은 젊어 보이는 효과가 있습니다. 수술 시간이 오래 걸리지도 않고 다운타임도 그렇게 길지 않아서, 피부과 시술을 여러 번 반복하는 것보다 한 방에 해결하고 싶다면 성형외과 상담을 고려해보세요. 나이가 젊어도 만족도가 높은 수술 중 하나입니다.', '눈 밑 지방 볼록을 수술 없이 관리하는 방법과 한계를 피부과 전문의 권수현이 안내합니다.', array['눈밑지방', '눈밑처짐', '지방재배치', '아그네스', '수술', '필러', '리프팅']::text[]),
    ('D0RXfp-Rf3s', 'kimjongsik', '눈 밑 다크서클이 홈케어로 좋아질 수 있나요?', '네, 색소 침착에 의한 다크서클은 나이아신아마이드, 레티놀, 비타민C를 꾸준히 발라주면 큰 돈 들이지 않고도 많이 좋아질 수 있습니다. 아토피 등으로 눈을 계속 비벼서 색소가 침착된 경우라면 눈 비비는 습관을 먼저 멈춰야 해요. 피부과에서는 멜라닌 색소를 지우는 토닝이나, 혈관이 넓어져서 푸르게 보이는 경우 브이빔 레이저를 사용합니다. 토닝을 10~20번 하면 거의 다 좋아지지만 병원 올 여력이 없다면 집에서 미백 성분을 꾸준히 바르셔도 진짜 효과가 있어요. 눈 밑 피부가 푸석하고 잔주름이 많은 경우라면 아이 리쥬란 같은 시술을 병행하면 더 좋습니다. 가려워서 눈을 비비시는 분들은 피부과에서 약 처방을 받으면 가려움이 해결되니 위험한 약이 아니라 꼭 드시는 게 좋아요. 예방이 치료보다 쉬우니 보습을 충분히 하고 눈을 안 비비는 습관이 핵심입니다.', '눈 밑 다크서클을 홈케어와 시술로 개선하는 방법을 피부과 전문의 김종식이 정리합니다.', array['다크서클', '색소침착', '나이아신아마이드', '레티놀', '토닝', '눈밑', '미백']::text[]),
    ('D0RXfp-Rf3s', 'kwonsuhyun', '눈 밑 처짐을 미리 예방하는 방법이 있을까요?', '가장 중요한 예방법은 눈을 안 비비는 것이며, 가려워서 비비시는 분들은 피부과에서 약을 처방받으면 간단히 해결됩니다. 눈 밑은 피부가 굉장히 얇아서 계속 비비면 피부가 약해지는 것은 물론 다크서클까지 심해지고 처져 보이게 돼요. 밤 늦게 깨어있거나 야식, 술을 먹으면 아침에 퉁퉁 붓는데, 붓기가 반복되면서 눈 밑이 점점 늘어날 수 있습니다. 자외선 차단도 중요한데, 눈 주변은 일반 선크림이 눈에 들어가 따가울 수 있으니 무기자차로 꼼꼼하게 발라주세요. 비싼 아이크림이 아니어도 괜찮고 바세린이나 얼굴 보습제로 눈 밑을 꾸준히 보습해주는 것만으로도 잔주름 예방이 됩니다. 레티놀 앰플로 피부 재생을 해주면 병원에 올 시간을 점점 늦출 수 있어요. 미리미리 관리하면 눈가만으로도 10~20년은 어려 보일 수 있습니다.', '눈 밑 처짐을 예방하는 생활 습관과 홈케어 팁을 피부과 전문의 권수현이 안내합니다.', array['눈밑처짐', '예방', '보습', '선크림', '무기자차', '레티놀', '눈비비기']::text[]),
    ('DGusfDat2UY', 'kimjongsik', '30대인데 마리오네트 주름이 벌써 생기기 시작했어요, 왜 그런 거죠?', '마리오네트 주름은 노화뿐 아니라 잘못된 습관만으로도 30대에 충분히 생길 수 있습니다. 입에 힘을 많이 주거나 입꼬리를 내리는 습관이 있으면 젊은 나이에도 빠르게 주름이 자리잡게 돼요. 40~50대에 많이 나타나는 건 옆 볼 볼륨이 밑으로 처지면서 처진 살이 불룩해지고 주름처럼 보이는 케이스가 대부분입니다. 또 마리오네트 주름 쪽이 많이 꺼지면서 깊어지는 경우도 있어요. 습관적으로 입꼬리를 내리고 살아온 분이라면 입가 주변에 힘을 빼주는 보톡스를 맞으면 생각보다 쉽게 좋아지는 경우가 있습니다. 얼굴살이 많은 분은 살이 처지면서 마리오네트가 더 잘 생기는 타입이니 미리 관리하시는 게 좋아요.', '30대부터 생기는 마리오네트 주름의 습관적 원인과 보톡스 개선법을 피부과 전문의 김종식이 안내합니다.', array['마리오네트', '입꼬리주름', '보톡스', '30대', '주름', '리프팅']::text[]),
    ('DGusfDat2UY', 'kwonsuhyun', '"은" 운동으로 마리오네트 주름이 진짜 개선되나요?', '아직 심하지 않은 분이라면 "은" 운동만으로도 입꼬리가 올라가고 마리오네트 주름이 개선될 수 있습니다. 입꼬리를 올리는 근육을 높은 음으로 "은~" 하면서 사용하면 광대가 올라가고 리프팅 효과까지 나타나요. 입가 주변에는 올리는 근육, 옆으로 찢는 근육, 밑으로 내리는 근육 등 다양한 근육이 있는데, "은" 운동은 올리는 근육을 집중적으로 쓰는 방법이죠. 낮은 음이 아니라 높은 음으로 해야 효과가 제대로 나타납니다. 시술할 때 집중하느라 얼굴이 경직되면 문 열고 나오면서 "은~" 해줄 정도로 일상에서 수시로 하는 게 좋아요. 다만 이미 깊게 자리잡은 마리오네트 주름은 홈케어나 운동만으로 개선하기 어렵기 때문에 시술의 도움이 필요합니다.', '"은" 운동으로 마리오네트 주름을 개선하는 원리와 한계를 피부과 전문의 권수현이 설명합니다.', array['은운동', '마리오네트', '입꼬리', '리프팅', '홈케어', '표정근육']::text[]),
    ('DGusfDat2UY', 'kwonsuhyun', '마리오네트 주름에 쥬브젠이 좋다던데 어떤 원리인가요?', '쥬브젠은 CO2 가스와 필러가 교차로 들어가면서 접혀 있던 주름을 재생시키고 채워주는 시술입니다. 바늘이 피부를 찢으면서 CO2 가스가 들어가 피부 재생을 유도하고, 그 사이로 소량의 필러가 주름에 볼륨을 올려주는 원리예요. 보톡스로 아무리 펴도 남아있는 이마, 미간의 고정 주름까지 쥬브젠으로 펴지는 걸 실제로 확인했다고 합니다. 한 번 재생된 부분은 영구적으로 유지된다고 보면 되기 때문에 유지기간도 긴 편이에요. 마리오네트 주름 외에도 팔자주름, 여드름 흉터에도 많이 쓰이고 있습니다. 깊은 볼륨은 스컬트라로 자연스럽게 채우고, 얇게 접힌 주름은 쥬브젠으로 펴주는 조합이 효과적이에요.', '쥬브젠의 CO2 가스·필러 재생 원리와 마리오네트 주름 개선 효과를 피부과 전문의 권수현이 정리합니다.', array['쥬브젠', '마리오네트', '팔자주름', '스컬트라', '콜라겐', '주름', '필러']::text[]),
    ('DGusfDat2UY', 'kimjongsik', '불독살 때문에 마리오네트가 심한데 볼륨 채우면 되는 거 아닌가요?', '불독살이 원인인 마리오네트 주름에 무작정 볼륨을 채우면 오히려 불독살이 더 커질 수 있어 주의가 필요합니다. 얼굴에 전체적으로 살이 있고 무거운 분들은 밑으로 내려오는 볼륨이 크기 때문에 필러나 스컬트라를 넣으면 역효과가 나요. 이런 케이스는 살을 붙이는 게 아니라 줄이거나 눌러서 덜 보이게 만드는 방식이 맞습니다. 울쎄라나 티타늄 같은 리프팅 기기, 실리프팅으로 처진 살을 들어주거나 스킨보톡스, 엘주사, CL주사 같은 볼륨 줄이는 시술을 조합해서 쓰게 돼요. 실제로 "잘라내면 안 되냐"고 하시는 분 중 절반 이상이 볼륨을 줄이는 시술을 했다간 오히려 큰일 나는 케이스입니다. 원인에 따라 시술이 완전히 달라지니 반드시 피부과 전문의와 상의 후 결정하세요.', '불독살이 원인인 마리오네트 주름에 볼륨 시술이 역효과를 낼 수 있는 이유를 피부과 전문의 김종식이 안내합니다.', array['불독살', '마리오네트', '울쎄라', '실리프팅', '스킨보톡스', '리프팅']::text[]),
    ('kki2TkHKRnU', 'kwonsuhyun', '지성 피부인데 모공 줄이려면 집에서 뭘 해야 하나요?', '피지를 줄이고 모공을 비워주는 루틴이 핵심입니다. 모공은 피지가 나오는 구멍이라 기름이 많으면 피지가 쌓여 점점 넓어지게 돼요. 가장 쉬운 홈케어는 클렌징 오일로 코 주변을 문질러 안쪽 피지를 녹여내는 것이고, 그 다음 BHA(살리실산) 성분이 든 토너를 솜에 적셔 살짝 얹어두면 피지가 녹아 올라옵니다. 다만 피부 장벽이 손상되지 않도록 일주일에 1-2회만 하시고, 여름엔 2-3회까지 늘려도 괜찮아요. 평소 바르는 앰플도 나이아신아마이드처럼 피지 조절과 피부 결 정돈에 도움 되는 성분 위주로 선택하는 게 좋습니다. 마무리는 모공을 막지 않는 산뜻한 수분크림으로 가볍게 덮어주세요. 이렇게 꾸준히 피지를 비워주면 화장할 때 오돌토돌한 느낌이 확실히 줄어듭니다.', '지성 피부의 모공을 줄이는 홈케어 루틴과 BHA 사용법을 피부과 전문의 권수현이 안내합니다.', array['모공', '피지', 'BHA', '홈케어', '지성피부', '클렌징오일', '나이아신아마이드']::text[]),
    ('kki2TkHKRnU', 'jeonghanmi', '건성 피부도 나이 들면 모공이 늘어날 수 있나요?', '네, 건성 피부는 탄력 저하로 모공이 벌어져 보일 수 있습니다. 지성처럼 피지가 원인은 아니지만 피부 콜라겐이 줄어들면 모공 주변이 늘어져 보이게 되죠. 이런 타입은 비타민C 앰플을 꾸준히 발라 항산화와 콜라겐 합성을 도와주는 게 효과적이에요. 레티놀이나 레티날 같은 성분도 광노화를 되돌리고 콜라겐 합성을 증가시켜 줍니다. 일주일 발랐다고 바로 모공이 줄진 않지만 6개월에서 1-2년 꾸준히 쓰면 피부 탄력이 관리되면서 모공도 함께 정돈됩니다. 지성 피부처럼 복잡한 루틴이 필요 없고 비타민C와 레티놀 두 가지만 꾸준히 바르는 게 핵심이에요. 간단하지만 오래 지속하는 것이 건성 피부 모공 관리의 비결입니다.', '건성 피부의 모공이 넓어지는 원인과 비타민C·레티놀 관리법을 피부과 전문의 정한미가 설명합니다.', array['모공', '건성피부', '비타민C', '레티놀', '콜라겐', '탄력', '광노화']::text[]),
    ('kki2TkHKRnU', 'kwonsuhyun', '모공 줄이는 시술 중에 가성비 좋은 건 뭔가요?', '스킨보톡스가 가성비 면에서 가장 추천할 만한 모공 시술입니다. 피지를 줄여주면서 모공도 쪼아주고, 비용 부담이 크지 않은데 드라마틱하게 효과가 나타나는 시술이에요. 그 전 단계로 가장 기본인 압출 스케일링도 있는데, 뭉쳐진 피지를 뽑아내고 BHA 같은 산 성분으로 피지를 녹여주는 방식이라 지속적으로 받으면 확실히 좋아집니다. 비용이 좀 더 들어도 괜찮다면 골드 PTT나 아그네스처럼 피지선 자체를 줄이는 시술도 고려해볼 수 있어요. 이 시술들은 여드름 치료의 대표 주자이기도 해서 피지 과다인 분들에게 모공까지 같이 잡아줍니다. 지성 피부는 결국 피지를 줄여야 모공이 줄어드는 구조이기 때문에 본인 예산에 맞춰 단계별로 선택하시면 됩니다.', '모공 축소에 효과적인 가성비 시술 추천을 피부과 전문의 권수현이 정리합니다.', array['모공', '스킨보톡스', '스케일링', '골드PTT', '아그네스', '피지', '가성비']::text[]),
    ('kki2TkHKRnU', 'jeonghanmi', '써마지 같은 고주파 시술이 늘어난 모공에도 효과 있나요?', '네, 탄력 저하로 벌어진 모공에는 고주파 시술이 매우 효과적입니다. 써마지, 텐써마, 올리지오 같은 고주파는 피부에 열을 줘서 콜라겐을 재생시키고 진피를 탄탄하게 만들어 벌어진 모공을 쪼아주는 작용을 해요. 실제로 정기적으로 받으면 모공이 짱짱하게 조여지는 효과를 느낄 수 있습니다. 고주파 외에도 리쥬란, 쥬베룩 같은 스킨부스터를 병행하면 콜라겐 생성을 유도해 피부 자체를 탄탄하게 만들어주죠. 다만 이 시술들은 주로 탄력 저하형 모공에 적합하고, 피지 과다로 인한 모공은 스킨보톡스나 스케일링이 더 맞습니다. 본인 모공이 피지형인지 탄력형인지를 먼저 구분하고 시술을 선택하시는 게 중요해요.', '고주파 시술이 모공 축소에 효과적인 원리와 적합한 피부 타입을 피부과 전문의 정한미가 안내합니다.', array['모공', '써마지', '고주파', '리프팅', '스킨부스터', '쥬베룩', '콜라겐']::text[]),
    ('kki2TkHKRnU', 'kwonsuhyun', '지성 피부 모공은 도대체 어떻게 관리해야 줄어드나요?', '지성 피부의 모공은 피지가 핵심 원인이라 기름을 줄이는 관리가 가장 중요합니다. 모공에 피지가 쌓이면 점점 넓어지고, 넓어진 모공에 피지가 또 쌓이는 악순환이 반복되거든요. 클렌징 오일로 코 블랙헤드의 피지를 녹여낸 뒤, BHA 성분이 든 토너를 솜에 묻혀 살짝 얹어주면 피지가 깊게 녹아 어느 정도 해결됩니다. 세게 닦아내는 게 아니라 불려서 녹이는 느낌으로 해주시면 돼요. 다만 너무 자주 하면 자극이 되니까 일주일에 1~2회, 여름철에는 2~3회 정도로 횟수를 조절하세요. 피지 연화제를 솜에 적셔 올려두면 녹은 피지가 하얗게 올라오는데, 면봉으로 살살 닦아내면 화장할 때 오돌토돌한 것도 확실히 줄어듭니다.', '지성 피부 모공의 피지 관리법과 BHA 토너 사용 팁을 피부과 전문의 권수현이 안내합니다.', array['모공', '피지', 'BHA', '클렌징오일', '블랙헤드', '지성피부', '홈케어']::text[]),
    ('kki2TkHKRnU', 'jeonghanmi', '건성 피부인데 탄력 떨어지면 모공이 넓어질 수 있나요?', '네, 건성 피부도 피부 탄력이 떨어지면 모공이 넓어져 보일 수 있습니다. 지성 피부와는 원인이 다른데, 건성 피부의 모공은 피지가 아니라 탄력 저하가 문제거든요. 그래서 관리 방향도 탄력을 올리는 데 집중해야 합니다. 비타민C 앰플을 꾸준히 바르면 항산화 작용과 함께 콜라겐 합성을 도와주고, 레티놀은 콜라겐 합성을 증가시키고 광노화를 되돌려주는 역할을 해요. 일주일 바른다고 단기간에 모공이 사라지는 건 아니지만, 6개월에서 1~2년 꾸준히 바르면 피부 탄력 관리가 되면서 모공도 개선됩니다. 시술로는 써마지, 올리지오 같은 고주파로 콜라겐을 재생시켜 벌어진 모공을 쪼아주는 방법이 효과적이에요.', '건성 피부 모공이 넓어지는 원인과 비타민C·레티놀 관리법을 피부과 전문의 정한미가 설명합니다.', array['모공', '건성피부', '비타민C', '레티놀', '써마지', '콜라겐', '탄력']::text[]),
    ('kki2TkHKRnU', 'kwonsuhyun', '모공 줄이는 시술 중에 가성비 좋은 건 뭔가요?', '가장 가성비 좋은 모공 시술은 스킨보톡스입니다. 피지도 줄여주고 모공도 쪼아주는데 비용이 별로 비싸지 않아서 드라마틱하게 효과가 나는 시술이에요. 그 전 단계로는 압출 스케일링이 있는데, 안에 뭉쳐진 피지를 뽑아내고 BHA 같은 산성분으로 피지를 녹여주는 방식이죠. 이걸 지속적으로 하면 진짜 좋아집니다. 피지가 많아서 모공이 넓어진 분이라면 골드 PTT나 아그네스 같은 시술로 피지선 자체를 줄이는 방법도 있어요. 건성 피부라면 써마지, 올리지오 같은 고주파로 피부에 열을 줘서 콜라겐을 재생시키고 모공을 쪼아주는 방식이 맞고, 스킨부스터인 리투오나 쥬베룩도 피부 자체를 짱짱하게 만들어 모공 탄력에 도움이 됩니다.', '모공 축소에 가성비 좋은 스킨보톡스와 피부 타입별 시술을 피부과 전문의 권수현이 정리합니다.', array['스킨보톡스', '모공', '압출스케일링', '골드PTT', '아그네스', '쥬베룩', '써마지']::text[]),
    ('kki2TkHKRnU', 'kwonsuhyun', '여드름 많이 나면 피지 조절제를 꼭 먹어야 하나요?', '심한 여드름은 치료가 어려운 모공을 만들기 때문에, 피지 조절제 복용을 적극 추천드립니다. 여드름이 안 생겨야 모공도 안 넓어지는데, 이미 넓어진 모공은 관리가 훨씬 어렵거든요. 고등학교 때 피부가 안 좋았던 시절에 피지 조절제를 먹을 걸 하는 후회를 마흔이 다 된 나이에도 한다는 게 경험자로서의 진심이에요. 약 복용에 대해 부정적인 분도 분명히 많을 텐데, 피검사를 하면서 부작용을 체크하고 의사 처방 아래 복용하면 안전합니다. 만약 자녀가 자신과 같은 피부 타입이라면 피검사를 시키고 무조건 먹이겠다고 할 정도로 예방 효과가 크다고 해요. 지금 여드름이 고민인 20대 초반이라면 모공이 돌이킬 수 없이 넓어지기 전에 한번 고려해 보세요.', '여드름과 모공 예방을 위한 피지 조절제 복용의 중요성을 피부과 전문의 권수현이 안내합니다.', array['피지조절제', '여드름', '모공', '피지', '20대', '예방', '처방']::text[]),
    ('uUfAXNk2A2c', 'kimsoohyung', '토닝 10회 패키지 끊었는데 효과가 없어요, 호구된 건가요?', '색소 종류에 따라 토닝 10회가 필요 없는 경우가 많아서, 진단 없이 패키지를 끊었다면 호구가 됐을 수 있습니다. 주근깨처럼 피부 표면에 있는 색소는 1~3번만 해도 싹 없앨 수 있는 색소거든요. 반면 양쪽 뺨에 넓게 퍼진 후천성 양측성 오타모반처럼 깊이 있는 색소는 반복적으로 토닝해서 멜라닌을 깨부숴야 합니다. 같은 토닝이라도 병변마다 레이저 세기, 머무는 시간, 쏘는 횟수가 전부 달라야 해요. 공장형 피부과에서 모든 환자에게 똑같이 안전한 세기로만 하면 강하게 치료해야 할 색소는 개선되지 않습니다. 피코 토닝이라고 무조건 좋은 것도 아니고, 어떤 색소에 어떤 레이저를 어떻게 사용하느냐가 핵심이에요. 진단을 정확히 하고 거기에 맞는 치료를 받는 게 호구를 피하는 첫걸음입니다.', '토닝 패키지를 끊기 전에 색소 진단이 반드시 필요한 이유를 피부과 전문의 김수형이 설명합니다.', array['토닝', '피코토닝', '색소', '주근깨', '기미', '레이저', '진단']::text[]),
    ('uUfAXNk2A2c', 'kimsoohyung', '리프팅 시술 좋다는 거 다 받으면 효과가 더 좋지 않나요?', '울쎄라, 써마지, 티타늄을 한꺼번에 다 받는 건 가성비가 떨어지고 호구가 되기 쉽습니다. 본인 얼굴에 맞는 시술이 아니라 남들이 좋다는 걸 무작정 받는 게 문제예요. 예를 들어 살이 있고 피부가 두꺼운 분은 울쎄라 효과가 가장 좋지만, 피부가 얇고 볼륨감이 없는 분은 울쎄라를 맞으면 볼 패임이 생길 수 있어 써마지가 더 적합합니다. 친구 얼굴과 내 얼굴은 다르기 때문에 친구에게 좋았던 시술이 나에게도 좋다는 보장이 없어요. 한정적인 예산 안에서 본인에게 잘 맞는 시술 하나를 제대로 받는 게 훨씬 만족도가 높습니다. 제대로 상담을 못 받고 효과 떨어지는 시술을 받다가 돈만 낭비하시는 분들이 정말 많으니 꼭 의사와 직접 상담하세요.', '리프팅 시술을 몰아서 받으면 호구되기 쉬운 이유와 피부 타입별 선택법을 피부과 전문의 김수형이 안내합니다.', array['울쎄라', '써마지', '티타늄', '리프팅', '가성비', '피부타입']::text[]),
    ('uUfAXNk2A2c', 'parkhyojin', '리쥬란 받으면 다 좋아진다던데 왜 저는 효과가 없었을까요?', '리쥬란이 모든 피부에 효과적인 건 아니라서, 본인 피부 타입에 안 맞았을 가능성이 높습니다. 피부 장벽이 무너져 있거나 피부가 얇고 자그마한 자극에도 피부염이 올 수 있는 분에게는 리쥬란이 정말 효과가 좋아요. 반면 기름기가 많고 건강한 피부는 리쥬란을 맞아도 건조함 개선을 못 느끼고 그냥 아프기만 할 수 있습니다. 모공이 도드라지는 피부라면 리쥬란보다 리투오나 쥬베룩이 모공 결을 좁아지게 하는 데 훨씬 잘 맞아요. 스킨부스터가 호구되기 쉬운 이유는 환자가 리쥬란 받으러 왔다고 하면 그냥 해드리는 게 편하기 때문입니다. 효과까지 생각하는 곳이라면 왜 리쥬란을 원하는지 물어보고 피부 타입에 맞게 상담해 줄 거예요.', '리쥬란이 모든 피부에 효과적이지 않은 이유와 대안 스킨부스터를 피부과 전문의 박효진이 설명합니다.', array['리쥬란', '스킨부스터', '쥬베룩', '리투오', '피부장벽', '건조', '모공']::text[]),
    ('uUfAXNk2A2c', 'kimsoohyung', '피부과에서 호구 안 되려면 제일 중요한 게 뭔가요?', '상담 실장이 아니라 시술하는 의사에게 직접 상담받고 치료를 결정하는 게 가장 중요합니다. 상담실에서 시술을 정하고 시술실에서 의사를 처음 만나는 구조에서는 본인 피부에 안 맞는 시술이 진행될 수 있어요. 주근깨를 없애고 싶어서 갔는데 상담 실장이 토닝 10회 패키지를 권유하고, 의사는 누워있는 환자를 보고서야 이걸 왜 토닝으로 치료하지 하는 상황이 실제로 벌어집니다. 의사는 자부심과 사명감을 가지고 치료 결과에 책임을 지기 때문에 내가 줄 수 있는 효과, 내가 책임질 수 있는 치료만 제공하게 돼요. 여드름 치료도 마찬가지인데, 무작정 시술만 할 게 아니라 잘못된 홈케어나 생활 습관을 먼저 교정해야 합니다. 의사와 적극적으로 소통하면서 원인부터 파악하는 곳을 선택하세요.', '피부과에서 호구 안 되려면 의사 직접 상담이 핵심인 이유를 피부과 전문의 김수형이 정리합니다.', array['피부과상담', '진단', '의사상담', '호구', '상담실장', '시술', '여드름']::text[]),
    ('uUfAXNk2A2c', 'kimsoohyung', '토닝 10회 받았는데 색소가 안 없어지면 호구된 건가요?', '정확한 진단 없이 무작정 토닝 횟수만 채웠다면 돈을 낭비했을 가능성이 높습니다. 주근깨 같은 표면 색소는 1-3번만으로도 싹 없앨 수 있는데, 이걸 10회 토닝 패키지로 치료하고 있다면 진단이 잘못된 거예요. 색소는 겉에 있는지 속에 있는지에 따라 치료 전략이 완전히 달라집니다. 겉에 있는 건 강하게 한두 번 쏘면 끝이지만, 깊은 곳에 있는 기미나 오타모반은 반복 토닝으로 멜라닌을 깨부숴야 해요. 공장형 피부과에서 모든 환자에게 같은 세기로 레이저를 쏘면 당연히 개선이 안 됩니다. 피코 토닝이라고 무조건 좋은 것도 아니고, 어떤 장비를 누가 어떻게 사용하느냐가 더 중요합니다. 색소 치료야말로 경험 많은 의사에게 정확한 진단부터 받으셔야 해요.', '주근깨는 1~3번이면 끝나는데 10회 토닝을 받고 있다면 진단이 잘못된 거입니다. 겉·속 색소별 치료 전략이 다른 이유를 피부과 전문의 김수형이 설명합니다.', array['토닝', '색소', '기미', '주근깨', '피코토닝', '진단', '레이저']::text[]),
    ('uUfAXNk2A2c', 'kimsoohyung', '리프팅 시술 여러 개 한꺼번에 받으면 효과 더 좋은 거 아닌가요?', '아닙니다. 본인 얼굴에 맞지 않는 시술을 몰아서 받으면 오히려 효과를 못 느끼고 돈만 날릴 수 있어요. 예를 들어 살이 있고 피부가 두꺼운 분은 울쎄라가 효과적이지만, 피부가 얇고 볼륨감이 없는 분은 울쎄라를 받으면 볼 패임이 생길 수 있습니다. 써마지, 올리지오를 받고 효과가 없었다고 하시는 분들 대부분이 본인에게 필요한 시술이 아닌 걸 받은 경우예요. 친구가 좋았다는 시술도 내 얼굴과는 맞지 않을 수 있습니다. 한정적인 예산 안에서 가성비를 따지려면 내 얼굴 타입에 맞는 시술 하나를 제대로 받는 게 훨씬 낫습니다. 남들이 좋다는 거 다 받지 마시고, 의사 상담을 통해 본인에게 가장 잘 맞는 것부터 선택하세요.', '내 얼굴에 안 맞는 리프팅을 여러 개 받으면 돈만 날립니다. 피부 두께·볼륨별로 울쎄라·써마지 중 하나를 제대로 선택하는 기준을 피부과 전문의 김수형이 정리합니다.', array['리프팅', '울쎄라', '써마지', '올리지오', '가성비', '얼굴형', '피부타입']::text[]),
    ('uUfAXNk2A2c', 'kimsoohyung', '리쥬란 받으면 건조한 피부 좋아지는 거 맞나요?', '모든 건조한 피부에 리쥬란이 효과적인 건 아닙니다. 리쥬란이 효과를 보려면 피부 장벽이 무너져 있거나 재생 시 수분을 가둬두는 능력이 올라가야 개선을 느끼는 피부여야 해요. 피부가 얇고 자극에 민감해서 피부염이 잘 오는 타입에는 확실히 좋습니다. 하지만 기름기가 많고 건강한 피부라면 리쥬란을 해도 건조함 개선을 못 느끼고 그냥 아프기만 할 수 있어요. 이런 피부에는 오히려 모공 결을 좁혀주는 리쥬란 대신 쥬베룩이나 리투오 같은 스킨부스터가 훨씬 잘 맞습니다. 좋다는 말만 듣고 가서 받으면 효과가 떨어질 수밖에 없으니, 본인 피부 타입에 맞는 스킨부스터가 뭔지 의사와 상담 후 결정하세요.', '리쥬란은 장벽이 무너진 민감 피부에 효과적이지만 기름진 건강 피부엔 안 맞습니다. 쥬베룩·리투오 등 피부 타입별 스킨부스터 선택법을 피부과 전문의 김수형이 안내합니다.', array['리쥬란', '스킨부스터', '건조', '피부장벽', '쥬베룩', '피부타입', '민감성']::text[]),
    ('uUfAXNk2A2c', 'parkhyojin', '피부과에서 호구 안 되려면 어떻게 해야 해요?', '상담 실장님이 아닌 시술할 의사에게 직접 상담을 받는 게 가장 확실한 방법입니다. 상담 실장님이 시술을 결정하고 의사는 누워있는 환자만 보는 구조에서는 정확한 진단이 이뤄지기 어려워요. 실제로 주근깨를 없애러 갔는데 상담 실장이 토닝 10회 패키지를 끊어서 효과 없이 돈만 쓴 경우가 흔합니다. 의사는 직접 치료하고 결과에 책임을 지기 때문에 본인이 줄 수 있는 효과 범위 안에서만 치료를 제안하게 돼요. 색소든 리프팅이든 스킨부스터든, 정확한 진단 후 본인에게 맞는 치료 계획을 세울 수 있는 곳에서 받으셔야 합니다. 의사와 소통하면서 치료 방향을 함께 이끌어갈 수 있는 곳을 찾는 게 호구를 피하는 핵심입니다.', '상담 실장이 아닌 시술할 의사에게 직접 상담받는 게 호구 방지의 핵심입니다. 정확한 진단 후 맞춤 치료 계획을 세우는 피부과 선택법을 피부과 전문의 박효진이 설명합니다.', array['피부과상담', '진단', '의사상담', '시술선택', '상담실장', '호구방지']::text[]),
    ('xKFQsT6ZNbM', 'kimsoohyung', '눈밑 다크서클에 필러 넣으면 진짜 좋아져요?', '눈밑은 필러를 가장 많이 녹이러 오시는 부위라 신중해야 합니다. 잘못 넣으면 불룩해 보이거나 햇빛에 푸르딩딩하게 비치는 틴들 현상이 심하게 나타날 수 있어요. 눈밑이 꺼져 보이는 근본 원인은 피부를 지지하는 볼 쪽 볼륨이 부족한 경우가 많습니다. 이런 분들은 눈밑보다 앞볼에 먼저 깊게 넣어서 지지대를 만들어줘야 피곤해 보이는 것까지 개선돼요. 앞볼 지지 없이 눈밑에만 넣으면 같이 처지면서 오히려 눈밑 지방이 튀어나온 것처럼 보일 수 있습니다. 눈밑은 볼까지 이어지는 자연스러운 굴곡 라인이 중요한 부위라서, 한 곳만 채우는 게 답이 아닙니다. 눈밑 필러를 고민하신다면 앞볼 볼륨 상태부터 먼저 확인해보세요.', '눈밑 필러가 위험한 이유와 앞볼 먼저 채워야 하는 원리를 피부과 전문의 김수형이 설명합니다.', array['필러', '눈밑', '다크서클', '틴들현상', '앞볼', '볼륨', '지지대']::text[]),
    ('xKFQsT6ZNbM', 'kimsoohyung', '코 높이려고 필러 넣는 건 왜 비추천하는 건가요?', '코 필러는 시간이 지나면 옆으로 퍼지고, 실명 위험까지 있어 비추천합니다. 코는 원래 얇은 부위라 필러가 피부에 눌려 조금만 퍼져도 주변 사람들 눈에 확 띄게 이상해 보여요. 본인은 매일 거울을 보니까 변화를 모르지만 점점 뭉뚱해지는 거죠. 더 큰 문제는 안전성인데, 코를 가로지르는 혈관이 눈 안쪽 동맥과 연결되어 있어 잘못 주입하면 실명 사고가 발생할 수 있습니다. 실제 응급실에서 코 필러 후 실명된 20대 환자를 본 적도 있어요. 코는 수술로 드라마틱하고 안전하게 영구적인 결과를 얻을 수 있는 부위이기 때문에, 반복적으로 해야 하고 점점 퍼지는 필러보다 수술이 훨씬 나은 선택입니다.', '코 필러가 퍼지는 이유와 실명 위험성을 피부과 전문의 김수형이 안내합니다.', array['코필러', '실명', '코수술', '필러부작용', '혈관', '비추천']::text[]),
    ('xKFQsT6ZNbM', 'parkhyojin', '미간 주름 깊게 패였는데 필러 말고 다른 방법 없나요?', '깊게 패인 미간 주름에는 쥬브젠이 필러보다 안전한 대안이 될 수 있습니다. 미간은 코와 마찬가지로 실명 위험이 있는 부위라서 필러를 넣을 때 각별히 조심해야 하는 곳이에요. 보톡스로 예방을 못 해서 흉터처럼 주름이 패어버린 50-60대 분들이 필러를 고려하시는데, 필러가 즉각적 효과는 좋지만 위험도를 감수해야 합니다. 쥬브젠은 기계로 정확한 깊이를 설정해 히알루론산과 탄산가스를 함께 넣어주는 시술이에요. 탄산가스가 피부 재생을 촉진하기 때문에 깊은 주름이나 흉터 같은 주름에 효과가 드라마틱합니다. 얕은 칼주름이라면 쥬베룩으로도 콜라겐 재생 효과를 기대할 수 있어요. 급한 행사가 아니라면 위험한 필러보다 쥬브젠이나 쥬베룩을 먼저 고려해보세요.', '깊은 미간 주름에 필러 대신 쥬브젠이 안전한 이유를 피부과 전문의 박효진이 정리합니다.', array['미간주름', '쥬브젠', '쥬베룩', '필러', '보톡스', '콜라겐', '주름']::text[]),
    ('xKFQsT6ZNbM', 'kimsoohyung', '필러 맞기 딱 좋은 부위가 있다면 어디예요?', '이마와 턱은 소량 필러로 드라마틱한 변화를 낼 수 있는 대표적인 추천 부위입니다. 이마 필러는 대체제가 마땅히 없으면서 소량만 넣어도 얼굴 인상이 여성스럽게 바뀌고 5-10년까지 유지되는 게 큰 장점이에요. 턱은 1cc 정도의 소량만으로도 들어간 턱을 앞으로 빼거나 짧은 턱을 밑으로 내려 세련된 라인을 만들 수 있습니다. 코에서 턱까지 라인이 일자로 맞춰지면 확 예뻐지고, 무엇보다 턱은 안전한 부위예요. 팔자주름도 코 옆 뼈 안쪽에 쏙 넣어주면 만족도가 높은 부위 중 하나입니다. 핵심은 대체제가 없는 부위에 소량을 넣어 교정하는 것이지, 많은 양을 넣거나 대안이 있는 곳에 굳이 필러를 선택할 필요는 없다는 점입니다.', '이마·턱 등 필러 대체 불가 부위와 소량 시술 효과를 피부과 전문의 김수형이 안내합니다.', array['필러', '이마필러', '턱필러', '팔자주름', '소량', '대체불가', '필러추천']::text[]),
    ('Kl19SoFEJI8', 'parkhyojin', '목 가로주름은 왜 생기고 어떻게 예방해요?', '목 가로주름은 타고난 부분이 크지만 생활 습관으로 훨씬 깊어질 수 있습니다. 스마트폰을 내려다보는 자세, 높은 베개를 베고 자는 습관이 목을 구부러지게 만들어 주름을 악화시키거든요. 이미 깊게 생긴 가로주름은 자외선 차단제를 지금 바른다고 개선되지 않기 때문에 어릴 때부터 예방하는 게 핵심이에요. 아이가 유튜브를 볼 때 눈높이에 맞춰 보게 하고, 높은 베개 대신 낮은 베개를 쓰게 해주는 것만으로도 큰 차이를 만듭니다. 30대부터라도 지금 시작하면 더 깊어지는 건 막을 수 있어요. 생활 습관으로 생긴 주름은 나중에 교정하기가 정말 어렵기 때문에, 예방이 최선의 치료라고 생각하시면 됩니다.', '스마트폰 내려다보기·높은 베개가 목 가로주름을 깊게 만듭니다. 한번 생기면 교정이 어려워 어릴 때부터 예방해야 하는 이유를 피부과 전문의 박효진이 설명합니다.', array['목주름', '가로주름', '생활습관', '베개', '자세', '예방', '스마트폰']::text[]),
    ('Kl19SoFEJI8', 'kimsoohyung', '깊게 패인 목 가로주름에는 어떤 시술이 효과 있나요?', '깊은 목 가로주름에는 필러로 한 땀 한 땀 채우고 위아래에 보톡스로 근육을 풀어주면 쫙 펴집니다. 다만 목 필러는 몇 가지 단점이 있어요. 진주 목걸이처럼 볼록한 엠보가 오래 가고, 유지 기간이 1-2년도 안 되는 분들이 꽤 많습니다. 목은 얼굴보다 지방량이 적어서 말랑한 필러를 넣을 수밖에 없고, 그래서 분해가 빨라요. 멍도 2주 정도 가서 보통 겨울철에 많이 받으시죠. 요즘은 쥬브젠이라는 장비로 탄산가스와 미세한 소량의 히알루론산을 정확하게 넣어줄 수 있는데, 일반 필러보다 유지 기간이 훨씬 길어서 좋은 대안이 됩니다. 멍과 엠보 걱정을 줄이고 싶다면 쥬브젠도 고려해보세요.', '목 필러는 엠보가 오래 가고 유지 기간이 짧은 단점이 있습니다. 쥬브젠으로 탄산가스와 히알루론산을 정밀 주입하면 유지 기간이 더 긴 이유를 피부과 전문의 김수형이 안내합니다.', array['목주름', '필러', '쥬브젠', '보톡스', '가로주름', '엠보', '멍']::text[]),
    ('Kl19SoFEJI8', 'parkhyojin', '목에 자글자글한 잔주름은 왜 생기고 뭘 바르면 되나요?', '목의 자글자글한 잔주름은 탄력 저하와 건조가 원인이라 보습과 자외선 차단으로 예방 가능합니다. 목은 얼굴에 비해 피지샘이 적어서 원래 건조하기 쉬운 부위인데, 우리가 목 피부 건조를 잘 인식하지 못해 보습제를 안 바르죠. 거기에 자외선이 계속 쌓이면 콜라겐이 파괴되면서 자글자글한 주름이 생깁니다. 보습제를 얼굴에 바를 때 목까지 챙기고, 선크림도 반드시 발라주세요. 레티놀도 목에 발라볼 수 있는데, 목은 피지선이 적어 각질 들뜸이 쉽게 생기므로 반드시 로션을 3-4배 정도로 묽게 희석해서 사용해야 합니다. 얼굴에 레티놀을 1 바른다면 목에는 그 1을 로션으로 3-4배 희석하셔야 자극 없이 효과를 볼 수 있어요.', '목은 피지샘이 적어 건조하고 자외선에 콜라겐이 파괴되며 잔주름이 생깁니다. 레티놀을 로션에 3~4배 희석해 목에 바르는 방법을 피부과 전문의 박효진이 정리합니다.', array['목주름', '잔주름', '보습', '레티놀', '자외선차단제', '피지샘', '건조']::text[]),
    ('Kl19SoFEJI8', 'kimsoohyung', '목에 세로줄 주름이 생겼는데 보톡스로 없앨 수 있나요?', '네, 목 세로주름은 보톡스만으로 금방 개선할 수 있어 가장 쉽게 해결 가능한 목주름입니다. 세로주름은 목을 감싸는 플라티즈마라는 넓은 근육의 긴장도가 세지면서 부각되는 거예요. 피부 탄력 문제가 아니라 근육 문제이기 때문에, 긴장도를 풀어주는 보톡스를 놓으면 쫙 풀어집니다. 이 기법은 네페르티티 기법이라고 불리는데, 이집트 여왕 네페르티티의 매끈한 목 라인에서 이름을 따왔어요. 보톡스 두 방 정도만 맞으면 세로 밴드가 풀려서 효과가 간단하게 나타납니다. 가로주름이나 잔주름에 비하면 훨씬 해결이 쉬운 편이니, 목에 세로줄이 신경 쓰인다면 보톡스 시술을 고려해보세요.', '목 세로주름은 플라티즈마 근육 긴장이 원인이라 보톡스 두 방이면 쫙 풀립니다. 네페르티티 기법으로 매끈한 목 라인을 만드는 원리를 피부과 전문의 김수형이 설명합니다.', array['목주름', '세로주름', '보톡스', '네페르티티', '플라티즈마', '근육', '리프팅']::text[]),
    ('Kl19SoFEJI8', 'parkhyojin', '목 가로주름은 왜 생기는 건데 예방할 수 있나요?', '목 가로주름은 타고난 요소가 크지만 생활 습관의 영향도 굉장히 많이 받습니다. 스마트폰을 내려다보는 자세나 높은 베개를 베는 습관이 목을 구부리게 만들면서 가로주름을 깊어지게 해요. 이미 아기한테도 가로주름이 있을 정도로 선천적인 부분이 있지만, 생활 습관 교정으로 예방이 가능합니다. 아이가 유튜브를 볼 때 내려놓고 못 보게 하고 눈높이에 맞춰서 보게 해야 하며, 잘 때도 높은 베개 대신 낮은 베개를 써야 해요. 생활 습관으로 생긴 주름은 교정하기가 진짜 어렵기 때문에 30대부터라도 지금 바로 관리를 시작하셔야 합니다. 이미 너무 깊어진 주름은 개선이 쉽지 않으니 예방이 가장 중요해요.', '목 가로주름이 생기는 원인과 생활 습관 교정으로 예방하는 방법을 피부과 전문의 박효진이 안내합니다.', array['목주름', '가로주름', '생활습관', '베개', '스마트폰자세', '예방']::text[]),
    ('Kl19SoFEJI8', 'kimsoohyung', '이미 깊어진 목 가로주름은 어떤 시술로 펴야 하나요?', '깊게 패인 목 가로주름은 필러로 한 땀 한 땀 채워주고 위아래로 보톡스를 놔서 근육을 풀어주면 쫙 펴집니다. 다만 목 필러의 가장 큰 단점은 유지 기간이 길지 않다는 점이에요. 목은 얼굴에 비해 지방이 적어서 단단한 필러를 넣으면 그대로 티가 나기 때문에 물 같은 부드러운 필러를 쓸 수밖에 없고, 그래서 1~2년도 유지되지 않는 분이 꽤 많습니다. 진주 목걸이처럼 볼록한 엠보가 오래 갈 수 있는 점도 단점이에요. 요즘은 쥬브젠이라는 장비가 나와서 탄산가스로 콜라겐 재생을 유도하면서 미세한 소량의 히알루론산을 정확하게 넣어주는 시술이 가능합니다. 일반 필러보다 유지 기간이 훨씬 길고 멍과 엠보 걱정도 적으니 쥬브젠도 추천드려요.', '깊은 목 가로주름에 필러와 쥬브젠 시술의 장단점을 피부과 전문의 김수형이 비교합니다.', array['목주름', '필러', '쥬브젠', '보톡스', '가로주름', '콜라겐', '히알루론산']::text[]),
    ('Kl19SoFEJI8', 'parkhyojin', '목에 자글자글한 잔주름이 생겼는데 보습제만 발라도 될까요?', '목에 자글자글한 잔주름은 탄력 저하와 건조가 원인이라 보습제와 자외선 차단제를 꾸준히 바르면 예방할 수 있습니다. 목은 얼굴에 비해 피지샘이 적어서 원래 건조한 부위인데, 보습제를 안 바르다가 40대가 돼서 보면 얼굴과 차이가 크게 나게 되죠. 보습제를 얼굴에 바를 때 꼭 목까지 챙겨주는 습관이 중요하고, 레티놀도 목에 발라볼 수 있습니다. 단 목은 피지선이 적어서 레티놀을 얼굴에 1만큼 바를 때 로션을 3~4 정도로 굉장히 묽게 희석해서 발라야 각질 폭발을 막을 수 있어요. 시술로는 바늘 고주파가 피부에 콜라겐 생성을 촉진해서 잔주름을 펴는 데 효과적이고, 레디어스나 쥬베룩 같은 스킨부스터를 목에 직접 넣어주는 방법도 도움이 됩니다.', '목 잔주름 예방을 위한 보습·레티놀 사용법과 시술 방법을 피부과 전문의 박효진이 설명합니다.', array['목주름', '잔주름', '보습', '레티놀', '바늘고주파', '레디어스', '자외선차단']::text[]),
    ('Kl19SoFEJI8', 'kimsoohyung', '목에 세로로 생긴 줄은 뭔가요? 없앨 수 있나요?', '목 세로주름은 근육의 긴장 때문에 생기는 거라 보톡스 몇 방이면 금방 개선됩니다. 목을 감싸고 있는 플라티즈마라는 넓적한 근육이 있는데, 이 근육의 긴장도가 세지면서 표정을 지을 때 세로로 줄이 드러나는 거예요. 피부 탄력 자체는 괜찮은데 근육만 강하게 쓰여서 부각되는 거라 보톡스로 긴장도를 풀어주면 쫙 풀어집니다. 이걸 네페르티티 기법이라고 부르는데, 이집트 여왕 네페르티티의 매끈한 목에서 이름을 따온 시술이에요. 세 가지 목주름 중 개선하기 가장 쉬운 편이니 스트레스 받지 마시고 시술 받아보세요. 목은 지나치기 쉬운 부위지만 얼굴이 아무리 동안이어도 목주름이 심하면 나이가 드러나기 때문에 평소 관리가 중요합니다.', '목 세로주름을 보톡스 네페르티티 기법으로 간단히 개선하는 방법을 피부과 전문의 김수형이 안내합니다.', array['목주름', '세로주름', '보톡스', '네페르티티', '플라티즈마', '리프팅']::text[]),
    ('nfDb7993nEc', 'gohyerim', '세안 후 뽀득거리는 게 깨끗하게 씻긴 거 아닌가요?', '아닙니다. 뽀득거림은 오히려 피부 장벽이 깨졌다는 SOS 신호입니다. 세안제가 노폐물만 씻어낸 게 아니라 피부를 보호하는 천연 보호막인 피지까지 다 씻겨 나간 거거든요. 피부 위의 피지는 지저분하기만 한 게 아니라 막을 씌워서 피부를 보호하고 항산화 역할까지 하고 있어요. 세정력이 강한 클렌저로 이걸 다 벗겨내면 피부에 문제가 생길 수 있습니다. 확인 방법은 간단한데, 세안 후 1분 동안 아무것도 안 바르고 피부가 너무 당기거나 건조하다면 지금 쓰는 세안제를 점검해 봐야 해요. 피부가 튼튼하고 기름이 많은 분에게는 괜찮을 수 있지만, 피부가 민감하거나 습진이 있는 분한테는 정말 안 좋을 수 있으니 본인 피부 상태에 맞는 세안제를 선택하세요.', '뽀득거림은 보호 피지까지 씻겨 나간 SOS 신호인 이유와 세안 후 1분 테스트법을 피부과 전문의 고혜림이 안내합니다.', array['클렌징', '세안', '피부장벽', '뽀득거림', '민감성피부', '클렌저']::text[]),
    ('nfDb7993nEc', 'gohyerim', '민감성·아토피 피부는 클렌저를 뭘 써야 하나요?', '민감성 피부라면 향이 없고 씻은 후 촉촉한 느낌이 나는 클렌징 밀크가 가장 안전합니다. 아토피가 있는 피부는 향이 진한 제품부터 피하고, 뽀득거림보다 보습이 약간 되는 느낌의 세안제를 선택하는 게 좋아요. 아침에는 성분이 10개 정도밖에 안 들어서 자극이 가장 적은 클렌징 젤로 세안하고, 저녁에는 크림 제형에서 폼으로 바뀌는 촉촉한 타입의 클렌저를 쓰는 방식을 추천합니다. 기본 세안제가 다 약산성이고 각질 제거 능력이 뛰어나진 않기 때문에 일주일에 1~2회 효소 클렌저로 각질을 부드럽게 정리해 주면 화장이 뜨는 것도 방지할 수 있어요. 효소 클렌저는 알갱이 있는 스크럽처럼 물리적 자극을 주지 않아서 예민한 피부도 부담 없이 사용 가능합니다.', '민감성·아토피 피부에 안전한 클렌징 밀크 선택법과 효소 클렌저 루틴을 피부과 전문의 고혜림이 설명합니다.', array['민감성피부', '클렌징밀크', '약산성', '효소클렌저', '아토피', '세안', '보습']::text[]),
    ('nfDb7993nEc', 'jeonghanmi', '클렌징 티슈가 기미를 악화시킬 수 있다는 게 사실인가요?', '네, 클렌징 티슈나 클렌징 패드로 매일 얼굴을 닦아내면 자극으로 기미가 악화될 수 있습니다. 실제로 진료실에서 선크림도 잘 바르고 특별히 기미가 생길 이유가 없는데 기미가 심한 환자분이 있었는데, 확인해 보니 20년 동안 클렌징 티슈로만 세안을 해온 거였어요. 매일매일 닦아내다 보면 피부가 빨개지고 간지럽기도 하면서 자극이 쌓여 기미를 유발하거나 악화시킬 수 있습니다. 잘 닦이는 느낌 때문에 쓰게 되지만, 기미가 있거나 피부가 예민하거나 건조한 분에게는 가장 안 좋은 클렌징 방법이에요. 기름기 많고 피부가 튼튼한 분이 가끔 쓰는 건 괜찮지만, 기미 환자라면 클렌징 밀크로 교체하시는 게 좋습니다.', '20년간 클렌징 티슈 마찰로 기미가 심해진 실제 사례와 밀크 클렌저 대안을 피부과 전문의 정한미가 정리합니다.', array['클렌징티슈', '기미', '색소침착', '클렌징밀크', '자극', '민감성피부']::text[]),
    ('nfDb7993nEc', 'jeonghanmi', '결국 세안제는 뭘 사야 하나요? 쉽게 알려주세요.', '화장을 지울 때는 어떤 피부 타입이든 클렌징 밀크가 가장 무난하고, 지성 피부라면 클렌징 오일도 괜찮습니다. 이중 세안할 때 거품 나는 클렌저는 약산성 클렌저라고 써 있는 걸 고르시면 가장 안전해요. 세정력이 좀 더 필요한 지성 피부라면 BHA, PHA 성분이 들어간 약산성 제품을 선택하면 기름기를 자극 없이 잘 씻어낼 수 있습니다. 오일을 쓰고 싶은 지성 피부 분이라면 논코메도제닉, 즉 여드름 유발이 적다고 표기된 제품을 고르세요. 민감하거나 여드름이 많은 분은 에센셜 오일이 알러지를 일으킬 확률이 있어서 오일보다 밀크가 더 안전하고, 꼭 오일을 쓰고 싶다면 호호바 오일 기반이 가장 안전합니다. "화해" 같은 성분 검색 앱으로 향료나 알러지 유발 성분을 확인해 보면 실패할 확률이 줄어들어요.', '화장 지울 땐 클렌징 밀크, 지성 피부엔 BHA 약산성 클렌저가 기본입니다. 민감·지성·여드름 피부별 클렌저 성분 선택 기준을 피부과 전문의 정한미가 안내합니다.', array['클렌저', '약산성', '클렌징밀크', '클렌징오일', 'BHA', '지성피부', '민감성피부']::text[]),
    ('nfDb7993nEc', 'gohyerim', '세안 후 뽀득거리는 느낌이 좋은 건 줄 알았는데 아닌가요?', '아닙니다. 뽀득거림은 피부 장벽이 깨졌다는 SOS 신호입니다. 세안제가 기름을 잘 씻어냈다는 뜻이긴 하지만, 피부 위의 기름 성분은 단순히 지저분한 게 아니라 천연 보호막 역할을 하고 있어요. 피지가 방패처럼 수분 증발을 막고 항산화 역할까지 하는데, 세정력이 강한 클렌저를 쓰면 이게 전부 씻겨 나가버리는 거죠. 확인하는 방법은 세안 후 1분 테스트입니다. 세안하고 1분 동안 아무것도 안 발랐을 때 피부가 너무 당기고 건조한 느낌이 들면 지금 쓰는 세안제를 바꿔야 합니다. 피부가 튼튼하고 기름이 많은 분은 괜찮을 수 있지만, 습진이 있거나 민감한 피부라면 세정력 강한 클렌저는 피부를 더 망가뜨릴 수 있어요.', '뽀득거림은 피지 보호막까지 벗겨진 경고 신호입니다. 세안 후 1분간 아무것도 안 발랐을 때 당김이 심하면 세안제를 바꿔야 하는 이유를 피부과 전문의 고혜림이 설명합니다.', array['클렌저', '세안', '피부장벽', '뽀득거림', '세정력', '민감성피부', '약산성']::text[]),
    ('nfDb7993nEc', 'gohyerim', '민감성 피부는 어떤 클렌저를 써야 하나요?', '민감성·아토피 피부는 씻고 나서 촉촉하고 보습감이 느껴지는 약산성 클렌저를 선택하셔야 합니다. 향이 진한 제품은 피하고, 거품이 많이 나지 않아도 자극이 적은 제형을 고르는 게 핵심이에요. 아침에는 성분이 10개 정도로 단순한 제품으로 자극 없이 세안하고, 저녁에는 크림 제형에서 폼으로 바뀌는 촉촉한 클렌저로 이중 세안을 하면 됩니다. 약산성 클렌저들은 세정력이나 각질 제거가 뛰어난 건 아니라서, 일주일에 1-2회 정도 효소 클렌저로 부드럽게 각질을 정리해주는 게 좋아요. 효소 클렌저는 알갱이 있는 스크럽과 달리 물리적 자극 없이 순하게 각질을 정리해주기 때문에 예민한 피부도 부담 없이 사용 가능합니다.', '민감성·아토피 피부는 향 없고 보습감 있는 약산성 클렌저가 안전합니다. 아침·저녁 다른 제형 조합과 주 1~2회 효소 클렌저 각질 관리법을 피부과 전문의 고혜림이 안내합니다.', array['민감성피부', '클렌저', '약산성', '아토피', '효소클렌저', '세안', '각질']::text[]),
    ('nfDb7993nEc', 'jeonghanmi', '기미 있으면 클렌징 티슈 쓰면 안 되나요?', '네, 기미가 있는 분들은 클렌징 티슈나 패드로 닦아내는 세안을 절대 피하셔야 합니다. 매일 닦아내는 마찰이 피부를 빨갛게 자극하고 그 자극이 기미를 악화시킬 수 있거든요. 실제로 선크림도 잘 바르고 기미가 생길 이유가 없는데 기미가 심했던 환자분의 원인이 20년간 매일 클렌징 티슈를 쓴 것이었던 사례도 있습니다. 잘 닦이는 느낌이 좋아서 계속 쓰셨는데, 그게 기미를 유발할 줄은 전혀 모르셨던 거죠. 기미뿐 아니라 피부가 예민하거나 건조한 분들에게도 닦아내는 제품은 가장 안 좋습니다. 대신 클렌징 밀크처럼 문지르지 않고 부드럽게 녹여내는 방식을 선택하시면 자극 없이 깨끗하게 세안할 수 있어요.', '매일 클렌징 티슈로 닦는 마찰이 기미를 유발·악화시킬 수 있습니다. 20년간 티슈 세안으로 기미가 심해진 실제 사례와 밀크 클렌저 대안을 피부과 전문의 정한미가 정리합니다.', array['기미', '클렌징티슈', '클렌징패드', '마찰', '자극', '클렌징밀크', '민감성피부']::text[]),
    ('nfDb7993nEc', 'jeonghanmi', '피지 많은 지성 피부는 어떤 클렌저가 맞아요?', '지성 피부는 BHA(살리실릭산)가 들어간 약산성 클렌저로 피지를 녹이면서 세안하는 게 효과적입니다. 세정력이 있으면서도 피부가 많이 건조해지지 않는 제품이 핵심인데, 제로이드 핌프로브 포밍클렌저처럼 살리실산 성분이 피지도 녹여주고 각질도 정리해주는 제품이 추천돼요. 기름이 많고 피부가 튼튼하다면 가끔 알갱이 있는 클레이팩으로 각질과 피지를 정리하는 것도 괜찮습니다. 다만 지성이면서 염증성 여드름이 나고 민감한 복합 피부라면 물리적 스크럽은 조심해야 해요. 클렌징 오일을 쓸 때는 코코넛 오일이나 맥아유가 모공을 막아 여드름을 유발할 수 있으니, 쓰고 싶다면 논코메도제닉 표시가 있는 호호바 오일 기반 제품을 선택하시는 게 안전합니다.', '지성 피부는 BHA(살리실산) 약산성 클렌저로 피지를 녹이며 세안하는 게 효과적입니다. 논코메도제닉 오일과 호호바 기반 제품 선택법을 피부과 전문의 정한미가 안내합니다.', array['지성피부', '클렌저', 'BHA', '살리실산', '피지', '논코메도제닉', '여드름']::text[]),
    ('5flSWdbFqh8', 'jeonghanmi', '장방형 얼굴인데 울쎄라 받으면 오히려 더 늙어 보일 수 있나요?', '네, 장방형(긴 얼굴)은 울쎄라를 과하게 받으면 볼패임이 생겨 얼굴이 더 길어 보일 수 있습니다. 장방형 얼굴은 나이가 들면 볼과 관자놀이 볼륨이 줄어들면서 앙상하고 피곤한 인상으로 변하기 쉽습니다. 이런 얼굴형은 리프팅으로 당기는 것보다 꺼진 옆라인에 볼륨을 채워 가로폭을 넓혀주는 게 핵심이에요. 필러나 스컬트라로 관자놀이, 옆볼 등 꺼진 부위를 채우면 덜 길어 보이는 착시 효과가 생깁니다. 동시에 피부가 얇아 처지기 쉬우므로 써마지, 텐써마, 덴서티 같은 고주파 타이트닝으로 탄력을 잡아주는 것도 중요합니다. 리프팅이 필요하다면 소프웨이브나 티타늄처럼 과하지 않게 탄력감을 주는 시술을 선택하세요. 채운다는 느낌보다 굴곡진 그림자를 지우는 느낌으로 접근하는 게 장방형 얼굴의 올바른 전략입니다.', '장방형(긴 얼굴)에 울쎄라가 안 맞는 이유와 올바른 볼륨 시술 전략을 피부과 전문의 정한미가 설명합니다.', array['장방형얼굴', '울쎄라', '스컬트라', '필러', '볼패임', '써마지', '리프팅', '관자놀이']::text[]),
    ('5flSWdbFqh8', 'jeonghanmi', '땅콩형 얼굴은 광대를 깎아야 하나요, 채워야 하나요?', '땅콩형 얼굴은 튀어나온 광대를 깎는 게 아니라, 꺼진 주변 부위를 채워서 라인을 매끈하게 만드는 게 정답입니다. 옆광대가 두드러지면서 위아래가 꺼져 보이는 이 얼굴형은 관자놀이와 옆볼에 볼륨을 넣어주면 광대가 상대적으로 들어가 보이는 착시가 생겨요. 주변을 채워주면 자연스럽게 리프팅된 듯한 인상까지 덤으로 얻을 수 있습니다. 중요한 건 30대부터 볼륨 관리를 시작하는 것인데, 살이 다 빠지고 땅콩형이 심해진 뒤에 시술하는 것보다 볼륨이 남아 있을 때 관리하는 게 훨씬 자연스럽습니다. 서양에서는 오히려 광대를 강조하는 메이크업을 할 정도로 매력 포인트가 될 수도 있지만, 한국인은 이목구비가 오밀조밀해서 과도하면 나이 들어 보이기 쉽습니다. 깎는 수술이 아닌 채우는 시술로 충분히 교정이 가능하니 겁먹지 마세요.', '땅콩형 얼굴을 깎지 않고 채워서 교정하는 시술 원리를 피부과 전문의 정한미가 안내합니다.', array['땅콩형얼굴', '광대', '필러', '스컬트라', '볼륨', '관자놀이', '리프팅']::text[]),
    ('5flSWdbFqh8', 'jeonghanmi', '각진 얼굴형은 사각턱 보톡스만 맞으면 되는 거 아닌가요?', '아닙니다, 각진형은 턱만 줄이면 위쪽이 상대적으로 커 보일 수 있어서 전체적으로 다듬어야 합니다. 보톡스 성분을 이용해 아래쪽 교근(저작근)을 갸름하게 잡아주면서, 위쪽 관자놀이 근육도 함께 줄여주는 게 핵심이에요. 아래만 줄이면 비율이 깨져서 오히려 이상해 보일 수 있기 때문입니다. 피부과에서 주사로 간단하게 할 수 있는 시술이라 성형외과 대수술을 떠올릴 필요가 없습니다. 전체적으로 각진 부위의 각을 줄여주고 여백을 최소화하면, 이목구비는 그대로인데 훨씬 또렷하고 부드러운 인상이 됩니다. 한 부분만 비대칭적으로 줄이면 안 되고, 위아래 균형을 보면서 갸름하게 만들어주는 게 자연스러운 결과의 비결이에요. 각진형은 채우는 게 아니라 깎는 얼굴이라는 점을 기억하시면 됩니다.', '각진 얼굴형이 사각턱 보톡스만으로 부족한 이유와 전체 균형 교정법을 피부과 전문의 정한미가 정리합니다.', array['각진형얼굴', '보톡스', '사각턱', '교근', '관자놀이', '갸름', '리프팅']::text[]),
    ('5flSWdbFqh8', 'jeonghanmi', '둥근형 얼굴인데 다이어트해도 볼살이 안 빠지는 이유가 뭔가요?', '둥근형 얼굴은 체중 문제가 아니라 얼굴 자체에 지방이 발달되어 있는 형태라서 다이어트와 크게 연관이 없는 경우가 많습니다. 5kg를 빼도 얼굴에 티가 안 나는 게 이 얼굴형의 특징이에요. 20대엔 동안으로 보이지만 30대를 넘기면 세련됨과 거리가 멀어지고, 40대엔 볼살이 처지면서 불독살이 생기기 쉽습니다. 교정법은 채우는 게 아니라 빼는 것으로, 울쎄라나 온다 같은 리프팅 시술로 지방을 줄이거나, 지방 분해 주사, 또는 직접 지방을 걷어내는 시술을 고려할 수 있어요. 또한 하관 턱뼈가 작은 경우가 많아서 필러로 턱을 살짝 만들어주면 계란형처럼 보이는 효과가 큽니다. 동안은 유지하되 세련미를 한 스푼 더하는 것, 이게 둥근형 교정의 핵심 목표입니다.', '둥근형 얼굴이 다이어트로 안 빠지는 이유와 지방 정리 시술 방법을 피부과 전문의 정한미가 안내합니다.', array['둥근형얼굴', '볼살', '지방분해주사', '울쎄라', '필러', '턱', '동안', '리프팅']::text[]),
    ('w7DyxIga4qw', 'jeonghanmi', '아이크림을 따로 사야 하나요?', '네, 눈가 피부는 얼굴에서 가장 얇고 예민한 부위라 별도의 아이크림을 사용하시는 게 좋습니다. 일반 페이스 크림은 입자가 크고 유분이 많아 눈가에 좁쌀이나 자극을 일으킬 수 있어요. 아이크림은 눈가 흡수에 최적화된 작은 입자와 저자극 성분으로 만들어집니다. 펩타이드·레티놀(저농도)·비타민E·세라마이드가 든 아이크림이 잔주름 예방에 효과적이에요. 30대부터는 항산화·콜라겐 자극 성분이 든 아이크림을 추가하시면 노화 진행을 늦출 수 있습니다. 약지로 가볍게 두드리듯 발라야 자극과 처짐을 막을 수 있어요. 매일 아침·저녁 꾸준히 사용하는 게 비싼 제품 한두 번보다 훨씬 효과적입니다.', '아이크림 따로 살 필요 없는 이유와 눈가 보습·레티노이드로 주름 예방하는 법을 피부과 전문의 정한미가 안내합니다.', array['아이크림', '눈가보습', '레티노이드', '레티놀', '레티날', '아크리프', '눈가주름예방']::text[]),
    ('w7DyxIga4qw', 'gohyerim', '눈가 잔주름에 좋은 시술은 무엇인가요?', '눈가 잔주름엔 보톡스·스킨부스터·아이크림 조합이 가장 효과적입니다. 웃을 때 잡히는 동적 주름엔 보톡스가 효과적이고, 가만히 있어도 보이는 정적 주름엔 리쥬란·쥬베룩 같은 스킨부스터로 콜라겐을 채워주세요. 두 가지를 함께 하면 동적+정적 주름이 동시에 개선돼 만족도가 높아요. LDM 같은 미세 진동 시술도 눈가 결 정돈에 도움이 됩니다. 일상 관리로는 항산화 성분이 든 아이크림 사용과 자외선 차단(선글라스+선크림)이 핵심이에요. 인공눈물을 자주 쓰는 안구건조증 환자는 눈가 주름이 더 잘 생기니 보습에 더 신경 쓰셔야 합니다. 한 번에 펴려 하기보다 6~8주 간격으로 꾸준히 받는 게 자연스럽습니다.', '눈가 잔주름과 탄력에 좋은 시술(아이써마지·리투오 파인·버츄RF)을 피부과 전문의 고혜림이 비교 안내합니다.', array['눈가주름', '아이써마지', '리투오파인', '버츄RF', '아이쉴드', '눈꺼풀시술']::text[]),
    ('w7DyxIga4qw', 'gohyerim', '웃을 때만 잡히는 눈가 주름엔 어떤 시술이 좋나요?', '웃을 때만 잡히는 눈가 주름은 동적 주름이라 보톡스가 가장 효과적입니다. 눈둘레근의 과도한 수축을 줄여 주름이 새겨지지 않게 막아주는 원리예요. 미세한 양을 정교하게 맞으면 표정은 자연스럽게 유지되면서 주름만 펴집니다. 효과는 시술 후 3~5일에 나타나기 시작해 2주차에 가장 자연스럽게 자리잡고, 4~6개월 유지돼요. 너무 자주 맞으면 표정이 어색해질 수 있으니 의사가 권하는 간격을 지키세요. 깊게 자리잡은 주름은 보톡스만으론 한계가 있으니 스킨부스터를 함께 받으면 더 좋습니다. 꾸준히 보톡스로 관리한 분과 안 한 분의 눈가 주름 차이는 5년 후 확연히 드러나요.', '웃을 때 잡히는 눈가 표정 주름에 보톡스 사용법과 첫 시술 주의사항을 피부과 전문의 고혜림이 안내합니다.', array['눈가보톡스', '표정주름', '웃을때주름', '보톡스주름', '안티에이징']::text[]),
    ('w7DyxIga4qw', 'jeonghanmi', '가만히 있어도 패인 눈가 깊은 주름엔 어떤 시술이 좋나요?', '가만히 있어도 패인 정적 주름엔 보톡스보다 스킨부스터·필러 조합이 효과적입니다. 정적 주름은 콜라겐 손실과 피부 처짐이 같이 작용해 새겨진 주름이라, 근육 움직임만 줄인다고 펴지지 않아요. 리쥬란·쥬베룩 같은 콜라겐 부스터로 진피층의 콜라겐을 채워주는 게 우선입니다. 깊게 골진 주름엔 미세 필러로 채우는 게 효과적이지만, 눈가는 필러가 뭉치거나 비치는 부작용이 있어 정말 숙련된 의사에게 받아야 해요. 보톡스를 함께 받으면 새로 생기는 동적 주름까지 예방할 수 있어 시너지가 좋습니다. 한 번에 펴려 하기보다 4~6주 간격으로 3~5회 단계적으로 받는 게 자연스러워요. 평소 항산화 아이크림과 자외선 차단을 병행하시면 결과가 오래 유지됩니다.', '가만히 있어도 패인 깊은 눈가 주름에 쥬브젠(0.001cc 정밀 주입·CO2)이 효과적인 이유를 피부과 전문의 정한미가 설명합니다.', array['눈가깊은주름', '쥬브젠', '히알루론산', 'CO2가스', '서브시전', '정밀주입']::text[]),
    ('Dq5oaIOdwoQ', 'kimsoohyung', '입술 위 바코드 주름은 왜 유독 빨리 생기나요?', '입술 위 인중 부위는 지방층이 거의 없어서 피부와 근육이 바로 붙어 있는 구조입니다. 입은 말하고 먹을 때 얼굴에서 가장 많이 움직이는 부위인데, 중간에 지방이라는 완충제가 없으니 근육의 움직임이 피부에 그대로 전달돼요. 종이를 자꾸 접었다 폈다 하면 자국이 남듯, 입술을 반복적으로 오므리면 그만큼 주름이 새겨지기 쉽습니다. 여기에 빨대를 자주 물거나 담배를 피우는 습관이 더해지면 주름이 빨라지는데, 영어로 스모커스 라인이라고 부르는 것도 이런 이유 때문이에요. 또한 나이가 들면 잇몸뼈가 안쪽으로 흡수되면서 입술을 지지하던 구조가 사라지고, 펴져 있던 피부가 꺼지며 주름이 더 깊어집니다. 빠른 분들은 40대부터 자글자글한 주름이 나타나기 시작하므로 미리 습관을 점검해보세요.', '입술 위 바코드 주름이 생기는 해부학적 원인과 빨대·흡연 등 악화 습관을 피부과 전문의 김수형이 설명합니다', array['입술주름', '바코드주름', '인중주름', '스모커스라인', '노화', '빨대', '담배', '콜라겐']::text[]),
    ('Dq5oaIOdwoQ', 'parkhyojin', '입술 주름 예방하려면 평소에 뭘 발라야 하나요?', '가장 기본은 입가에 자외선 차단제를 꼼꼼히 바르는 것입니다. 인중은 자외선을 직접 받는 부위인데 얼굴 다른 곳만 신경 쓰고 입 주변은 빠뜨리기 쉽거든요. 자외선은 콜라겐 감소의 직격탄이라 SPF가 들어간 립밤을 인중까지 넓게 발라주면 입술 색소침착과 주름 예방에 도움이 됩니다. 레티놀도 효과적인데, 입가는 각질이 잘 생기는 민감한 부위라 로션 3에 레티놀 1 비율로 희석해서 소량부터 천천히 적응시키는 게 좋아요. 처음에는 입가를 빼고 바르다가 다른 부위가 적응된 뒤 농도를 낮춰 입 주변에 함께 바르는 순서를 추천드립니다. 무엇보다 보습이 중요해서 립밤이나 바세린으로 입술이 건조해지지 않도록 평소에 꾸준히 신경 써주세요.', '입술 주름 예방을 위한 SPF 립밤, 레티놀 희석 사용법, 보습 관리법을 피부과 전문의 박효진이 안내합니다', array['입술주름', '자외선차단제', '선크림', '레티놀', '보습', '립밤', 'SPF', '인중주름', '예방']::text[]),
    ('Dq5oaIOdwoQ', 'kimsoohyung', '입술 주름에 보톡스 맞으면 물 새는 부작용이 있다던데 사실인가요?', '입술 주름 시술로 가장 많이 시도되는 건 보톡스인데, 근육 움직임을 줄여 주름을 완화하는 원리입니다. 다만 입 주변 보톡스는 물이나 국물이 새는 부작용이 생길 수 있고, 이번에는 괜찮았어도 다음에는 샐 수 있어서 결과가 일정하지 않은 편이에요. 이미 깊게 자리 잡은 주름을 보톡스만으로 펴기도 어렵습니다. 필러의 경우 입술 볼륨이 빠지면서 생긴 바코드 주름에는 입술 필러로 볼륨감을 살려주면 어느 정도 개선이 가능해요. 나이 들면서 윗입술이 말리는데 그 라인을 따라 볼륨을 주면 바코드 라인과 고양이 주름도 나아질 수 있습니다. 하지만 인중의 가느다란 주름에 손주사로 필러를 정교하게 소량 넣기는 기술적으로 쉽지 않아서 한계가 있는 시술이기도 합니다.', '입술 주름에 보톡스와 필러를 사용할 때 기대할 수 있는 효과와 부작용 한계를 피부과 전문의 김수형이 설명합니다', array['입술주름', '보톡스', '필러', '바코드주름', '입술필러', '부작용', '인중주름']::text[]),
    ('Dq5oaIOdwoQ', 'kimsoohyung', '쥬브젠이 입술 주름에 좋다던데 어떤 원리인가요?', '쥬브젠은 기계를 이용해 필러나 스킨부스터를 피부에 고르게 주입하면서 동시에 탄산가스를 함께 넣어주는 장비입니다. 탄산가스가 피부 안에 들어가면 섬유아세포를 자극해 콜라겐 생성을 유도하기 때문에 볼륨을 바로 채우면서 피부 재생까지 돕는 이중 효과가 있어요. 특히 인중처럼 가느다란 주름은 손주사로 정교하게 소량을 넣기 어려운데, 쥬브젠은 나오는 히알루론산 양이 일정하게 정해져 있어 균일하게 주입할 수 있습니다. 폴리뉴클레오타이드 성분을 넣어 인중에 깔아주면 자글자글한 주름이 전반적으로 탄탄해지는 효과를 느낄 수 있어요. 시술 시 구강 안쪽으로 마취 주사를 놓아 감각이 거의 없기 때문에 통증 걱정은 안 하셔도 됩니다. 1~2회만으로도 만족도가 높은 편이에요.', '쥬브젠의 탄산가스 주입 원리와 입술 주름 치료 효과, 통증 없는 시술 과정을 피부과 전문의 김수형이 설명합니다', array['쥬브젠', '입술주름', '탄산가스', '콜라겐', '스킨부스터', '폴리뉴클레오타이드', '히알루론산', '인중주름']::text[]),
    ('g1yz2wN3tl8', 'jeonghanmi', '스컬트라가 동안 시술로 좋은 이유는 무엇인가요?', '스컬트라는 PLA(폴리락트산) 성분으로 진피층의 콜라겐 생성을 강하게 유도하는 콜라겐 부스터입니다. 시술 후 1~2개월에 걸쳐 점진적으로 효과가 나타나고, 2년 이상 오래 유지된다는 게 가장 큰 장점이에요. 일반 필러처럼 부피로 채우는 게 아니라 내 콜라겐을 직접 만들어내게 유도해 자연스럽습니다. 그래서 광대·관자·볼이 꺼진 얼굴에 동안 볼륨을 만들기에 좋은 시술이에요. 너무 많은 양을 한 번에 넣지 않고 2~3회 나눠 받으면 결절 위험을 줄일 수 있습니다. 시술 후 5일간 5분씩 5번 마사지하는 ''5-5-5 룰'' 지키기는 필수예요. 자연스러운 동안을 원하시는 30~50대께 가장 잘 맞는 시술입니다.', '스컬트라가 동안 시술로 추천되는 이유(자연스러움, 2~3년 유지, FDA 승인 검증)를 피부과 전문의 정한미가 설명합니다.', array['스컬트라', '동안시술', '콜라겐부스터', 'PLLA', 'FDA승인', '결절', '유지기간']::text[]),
    ('g1yz2wN3tl8', 'jeonghanmi', '보톡스 효과가 빠지면 더 처진다는 말이 사실인가요?', '보톡스 효과가 빠지면 처진다는 말은 사실이 아닙니다. 보톡스는 일정 기간 근육의 움직임을 줄여주는 시술이고, 효과가 빠지면 시술 전 상태로 돌아갈 뿐 더 처지는 건 아니에요. 다만 보톡스를 자주 맞다 보면 근육이 약해지면서 일부 부위에선 약간 변화가 생길 수 있긴 합니다. 사각턱 보톡스의 경우 교근이 위축돼 처짐처럼 보일 수 있는데, 이건 자연스러운 노화 과정과 겹쳐 더 그렇게 느껴지는 거예요. 적절한 간격(4~6개월)을 두고 적정량을 맞으면 처짐 부작용 없이 효과만 누릴 수 있습니다. 너무 자주, 너무 많은 양을 받는 게 오히려 문제가 되니 의사 가이드를 따르세요. 시술 후 효과 빠지는 게 두렵다고 안 맞을 이유는 전혀 없어요.', '보톡스 효과가 빠지면 더 처진다는 오해를 피부과 전문의 정한미가 풀어주고, 꾸준한 관리의 누적 효과를 설명합니다.', array['보톡스', '보톡스오해', '주름예방', '동안', '노화방지', '꾸준한관리']::text[]),
    ('g1yz2wN3tl8', 'jeonghanmi', '리투오는 다른 스킨부스터와 무엇이 다른가요?', '리투오는 단일 성분 스킨부스터와 달리 여러 유효 성분이 결합된 멀티 부스터 시술입니다. 히알루론산·아미노산·비타민·항산화 성분이 함께 들어 있어 수분 공급+콜라겐 자극+피부 결 개선을 한 번에 노릴 수 있어요. 일반 물광 주사보다 효과의 폭이 넓고, 결·탄력·톤 개선까지 함께 기대할 수 있습니다. 회복기간이 짧고 일상 복귀가 빨라 직장인분들도 부담 없이 받으실 수 있어요. 4~6주 간격으로 3~5회 받았을 때 효과가 누적됩니다. 본인이 단일 고민이 아니라 종합적인 피부 컨디션 개선을 원할 때 잘 맞는 시술이에요. 시술 후 보습·자외선 차단을 철저히 하시면 결과가 오래 유지됩니다.', '리투오 스킨부스터의 원리(인체 진피 성분 직접 주입)와 다른 스킨부스터와의 차이를 피부과 전문의 정한미가 설명합니다.', array['리투오', '스킨부스터', '콜라겐', '엘라스틴', '리투오파인', '피부재건']::text[]),
    ('LS-s8wXjBRs', 'kwonsuhyun', '경락 마사지 받으면 진짜 효과가 있긴 한 건가요?', '경락은 뭉친 근육을 물리적으로 풀어주면서 붓기와 긴장을 완화하는 원리입니다. 커진 근육을 반복적으로 이완시켜 크기를 줄인다는 점에서 보톡스가 근육의 힘을 줄여 크기를 감소시키는 원리와 비슷하다고 볼 수 있어요. 다만 효과는 일시적이어서 시간이 지나면 근육이 다시 뭉치기 때문에 꾸준히 적당한 간격을 두고 받아야 유지됩니다. 특히 몸이 뻣뻣하게 긴장하는 스타일이거나 근육이 잘 뭉치는 분들은 경락으로 풀어주면 시원하고 개운한 느낌을 받기 쉬워요. 림프 순환을 도와 붓기를 빼주는 역할도 하기 때문에 야식이나 짠 음식을 자주 드시는 분들에게도 도움이 될 수 있습니다. 다만 성형처럼 근본적으로 얼굴이나 몸매를 바꿔주는 시술은 아니라는 점을 기억하시는 게 좋아요.', '경락 마사지의 근육 이완과 림프 순환 원리, 일시적 효과와 유지 관리법을 피부과 전문의 권수현이 안내합니다', array['경락', '경락마사지', '근육이완', '림프순환', '붓기', '보톡스', '근육뭉침', '마사지효과']::text[]),
    ('LS-s8wXjBRs', 'jeonghanmi', '경락 받고 멍들었다는 사람 많던데 부작용 없나요?', '경락은 피부를 지속적으로 문지르는 시술이므로 부작용이 생길 수 있습니다. 턱 부분처럼 예민한 곳을 강하게 밀면 트러블이 날 수 있고, 강도가 과하면 멍이 들기도 해요. 피부 장벽이 약하거나 조금만 자극을 줘도 예민해지는 분들은 경락을 피하시는 게 좋고, 홍조가 있거나 여드름이 잘 나는 피부도 마찬가지로 조심해야 합니다. 적절한 강도의 기준은 아프긴 하지만 풀리는 느낌이 있고 시원하다는 정도인데, 뼈를 부술 것 같은 극심한 통증은 옳지 않아요. 초보자의 경우 부작용이 생기는 경계를 본인이 모를 수 있으니 처음엔 약한 강도부터 시작해보세요. 피부 컨디션이 괜찮을 때 적당한 텀을 두고 받는 것이 안전합니다. 시술 전에 시술자에게 본인 상태를 미리 말씀해두시면 통증 한계를 넘기는 상황을 예방할 수 있어요.', '경락의 멍·트러블 부작용과 예민·홍조 피부가 조심해야 할 주의사항을 피부과 전문의 정한미가 안내합니다', array['경락', '부작용', '멍', '트러블', '피부장벽', '예민피부', '홍조', '여드름', '경락주의사항']::text[]),
    ('LS-s8wXjBRs', 'kwonsuhyun', '경락 마사지 어떤 사람이 받으면 좋고 누가 피해야 하나요?', '스트레스가 많아 근육이 뭉쳐있는 분이나 근육 자체가 경직되기 쉬운 분들에게 추천합니다. 운동을 해도 오히려 더 뭉치는 초보자 분들에게도 도움이 될 수 있어요. 또한 평소 잘 붓는 분들에게 좋은데, 야식이나 매운 음식을 즐기는 생활 습관 때문에 붓기가 쌓일 때 경락으로 림프 순환을 시켜주면 개운함을 느끼기 쉽습니다. 단단하게 뭉친 살을 풀어주는 데에도 효과가 있어서 팔뚝이나 몸의 특정 부위가 경직된 경우에 받으면 조금씩 부드러워질 수 있죠. 반면 홍조가 있거나 피부가 예민하거나 여드름이 잘 나는 분들에게는 자극이 될 수 있어 비추천입니다. 나에게 맞는 강도를 찾는 게 중요하고, 시원하다고 느껴지는 정도가 가장 적절해요. 시술자의 실력에 따라 결과가 달라질 수 있으니 잘 맞는 곳을 찾아보시는 것도 중요합니다.', '경락 마사지가 적합한 사람과 피해야 할 피부 타입을 추천·비추천으로 구분해 피부과 전문의 권수현이 설명합니다', array['경락', '경락추천', '근육경직', '붓기', '림프순환', '스트레스', '예민피부', '경락비추천']::text[]),
    ('LS-s8wXjBRs', 'jeonghanmi', '경락 받으면 얼굴 진짜 작아지나요? 골격도 변하나요?', '타고난 골격 자체를 경락으로 줄이는 것은 어렵습니다. 성형하듯이 얼굴을 확 바꾸거나 반쪽으로 만들겠다는 기대를 갖고 받으시면 실망하실 수 있어요. 다만 근육이 커져 있는 부위는 경락으로 반복적으로 풀어주면 여지가 있는 만큼 들어갈 수 있습니다. 예를 들어 옆 이마처럼 근육이 발달해서 튀어나온 곳은 경락을 통해 근육이 이완되면서 라인이 정돈되는 경험을 하기도 해요. 이 원리는 보톡스로 근육 크기를 줄이는 것과 비슷한 맥락으로, 뼈가 아닌 근육에 작용하는 것이죠. 하지만 뼈대 자체를 줄이는 게 아니라 근육과 붓기를 관리하는 수준이라는 걸 알고 받으셔야 합니다. 경락은 얼굴 축소보다는 컨디션 관리나 붓기 완화 목적으로 접근하시는 게 현실적인 기대치입니다.', '경락으로 얼굴이 작아질 수 있는지, 골격 변화의 한계와 현실적 기대치를 피부과 전문의 정한미가 설명합니다', array['경락', '얼굴축소', '골격', '소안술', '보톡스', '근육이완', '윤곽', '붓기관리']::text[]),
    ('ygdKtURfU8Q', 'jeonghanmi', '피부 결을 좋게 하려면 어떤 시술이 좋나요?', '피부 결 개선엔 스킨부스터와 미세박피 시술이 가장 효과적입니다. 리쥬란·쥬베룩 같은 콜라겐 부스터는 진피층의 콜라겐 생성을 유도해 피부 결 자체를 매끈하게 만들어줘요. 모공·잔주름·피부 톤 개선까지 함께 기대할 수 있어 만족도가 높습니다. 미세박피 시술(LDM·미세더마브레이젼)은 표피 각질층을 부드럽게 정리해 즉각적인 매끈함을 줘요. 두 가지를 병행하면 표면+심층이 동시에 개선돼 결과가 더 좋습니다. 1~2회로 만족하기보다 4~6주 간격으로 3~5회 받으셨을 때 효과가 누적돼요. 시술 후 보습·자외선 차단을 철저히 하시면 결과가 오래 유지됩니다.', '피부 결을 좋게 하는 스킨부스터(리투오·미라젯)와 보습 관리의 중요성을 피부과 전문의 정한미가 설명합니다.', array['피부결', '스킨부스터', '리투오', '미라젯', '콜라겐', '엘라스틴', '모공', '보습']::text[]),
    ('ygdKtURfU8Q', 'kwonsuhyun', '땅콩형 얼굴은 선이 예뻐지려면 어떤 시술이 필요한가요?', '땅콩형 얼굴은 볼·관자 볼륨을 채우고 처진 윤곽을 정돈하는 복합 접근이 필요합니다. 단순히 사각턱 보톡스만 맞으면 오히려 위쪽 볼이 더 꺼져 보이는 부작용이 생길 수 있어요. 광대 옆·관자놀이 꺼짐엔 필러·쥬브젠·스컬트라 같은 볼륨 시술로 채우는 게 가장 효과적입니다. 처진 라인엔 울쎄라·써마지 같은 리프팅으로 들어 올려야 윤곽이 살아나요. 조합으로 받으면 1~2개월 후 자연스럽게 균형 잡힌 얼굴 라인이 만들어집니다. 시술은 한 번에 다 하지 말고 단계적으로 받아야 결과가 자연스러워요. 본인 얼굴이 어디가 부족한지 의사와 정확히 진단받고 받으시는 게 가장 중요합니다.', '땅콩형 얼굴의 꺼진 부위를 채우는 시술 옵션(필러·스컬트라·힐로웨이브·쥬베룩) 비교를 피부과 전문의 권수현이 안내합니다.', array['땅콩형얼굴', '꺼진얼굴', '필러', '스컬트라', '힐로웨이브', '쥬베룩', '볼꺼짐']::text[]),
    ('ygdKtURfU8Q', 'kwonsuhyun', '얼굴이 비대하고 빵빵한 분은 어떻게 라인을 정리하나요?', '얼굴이 비대하고 빵빵한 분은 부기·근육 비대·지방 분포를 동시에 해결하는 접근이 필요합니다. 부기가 주된 원인이라면 림프 마사지·스킨부스터·생활습관 교정으로 개선이 됩니다. 교근(저작근)이 발달해 사각턱이 두드러진다면 사각턱 보톡스가 효과적이에요. 볼살·턱밑 지방이 많다면 지방 분해 주사(카복시·HPL)나 윤곽 리프팅(써마지·울쎄라)을 고려할 수 있습니다. 한 가지 시술로 모두 해결하긴 어렵고, 본인 얼굴 비대의 원인을 정확히 분석한 후 맞춤형 조합으로 접근해야 해요. 식이·수면·짠 음식 줄이기 같은 일상 관리도 부기 감소에 큰 도움이 됩니다. 시술 결과는 일상 관리와 병행할 때 가장 오래 유지돼요.', '비대한 얼굴 라인을 정리하는 시술(사각턱 보톡스·지방분해·HIFU·지방흡입) 가이드를 피부과 전문의 권수현이 정리합니다.', array['얼굴라인', '사각턱보톡스', '지방분해주사', 'HIFU', '울쎄라', '지방흡입', '교근']::text[]),
    ('ygdKtURfU8Q', 'jeonghanmi', '얼굴이 작아 보이게 하려면 어떤 시술이 좋나요?', '얼굴이 작아 보이려면 윤곽 정돈+볼륨 균형+처짐 회복, 세 가지를 함께 가져가야 합니다. 사각턱 보톡스로 라인을 슬림하게 만들고, 광대·턱선 볼륨이 부족하면 필러·쥬브젠으로 채워 균형을 잡아주세요. 턱밑 지방이 많으면 지방 분해나 HPL 같은 시술로 윤곽을 정리할 수 있어요. 처진 조직은 울쎄라·써마지로 들어 올리면 라인이 또렷해집니다. ''작아 보이는 얼굴''은 단순히 사이즈가 작은 게 아니라 비율과 윤곽이 정돈된 얼굴이에요. 한 가지 시술만 받기보다 본인 얼굴형에 맞는 조합으로 단계적으로 진행하는 게 효과적입니다. 시술 후엔 자외선 차단·보습 같은 일상 관리로 결과를 유지하세요.', '작은 얼굴을 만드는 시술(사각턱 보톡스·지방 분해·리프팅)과 얼굴형별 선택 가이드를 피부과 전문의 정한미가 설명합니다.', array['작은얼굴', 'V라인', '사각턱보톡스', '지방분해', '지방흡입', '울쎄라', '올타이트', '리프팅']::text[]),
    ('Ka8LFvx65yU', 'gohyerim', '손등 노화를 막으려면 어떻게 관리해야 하나요?', '손등 노화 예방의 핵심은 자외선 차단과 보습입니다. 손등은 얼굴 다음으로 자외선에 많이 노출되는 부위라 광노화가 빠르게 진행돼요. 외출 시 얼굴 선크림을 손등까지 함께 발라주세요. 핸드크림은 수시로(특히 손 씻은 후 바로) 발라야 수분 증발을 막을 수 있습니다. 설거지·청소 같은 가사일을 할 땐 고무장갑을 끼고, 직후엔 보습제로 케어해 주세요. 잘 때 핸드크림을 두껍게 바르고 면장갑을 끼는 ''나이트 핸드케어''도 효과적입니다. 흡연·과도한 카페인 섭취는 혈관 수축을 일으켜 손등 노화를 가속시키니 줄이시는 게 좋아요. 한 번 생긴 손등 잡티는 회복이 어렵기 때문에 예방이 가장 효과적인 관리법입니다.', '손등 노화 예방 핵심(핸드크림·선크림·레티노이드)과 검버섯 예방을 위한 미리 관리법을 피부과 전문의 고혜림이 안내합니다.', array['손등관리', '핸드크림', '손등선크림', '자외선차단', '아크리프', '레티노이드', '검버섯예방']::text[]),
    ('Ka8LFvx65yU', 'jeonghanmi', '손등에 시술이 가능한 게 있나요? 어떤 시술이 좋은가요?', '네, 손등에도 다양한 시술이 가능하며 가장 추천드리는 건 스킨부스터와 검버섯 레이저입니다. 손등은 피부가 얇고 콜라겐 손실이 빠른 부위라 리쥬란·쥬베룩 같은 콜라겐 부스터로 두께와 탄력을 회복시킬 수 있어요. 손등 잡티·검버섯엔 IPL·토닝·QS 레이저 같은 색소 레이저가 효과적입니다. 핏줄이 두드러져 보이는 분은 필러로 가볍게 채워 자연스럽게 만들 수 있어요. 손등은 얼굴보다 시술 빈도가 적어 1~2회만 받아도 변화가 잘 보입니다. 다만 손등은 일상에서 자극이 많아 회복이 다소 느릴 수 있다는 점은 감안해 주세요. 시술 후엔 자외선 차단과 보습 관리가 결과 유지의 핵심입니다.', '손등 볼륨 회복에 효과적인 레디어스 스킨부스터 시술의 원리와 만족도를 피부과 전문의 정한미가 설명합니다.', array['손등시술', '레디어스', '스킨부스터', '손볼륨', '핏줄', '손등노화']::text[]),
    ('Ka8LFvx65yU', 'gohyerim', '손등에 어떤 핸드크림을 쓰는 게 좋나요?', '손등엔 보습력이 강하면서 끈적임이 적은 핸드크림이 가장 적합합니다. 세라마이드·시어버터·글리세린·판테놀 성분이 든 제품을 추천드려요. 건성 피부엔 유분이 많은 진한 텍스처, 지성·복합성엔 가볍고 흡수가 빠른 제품이 잘 맞습니다. 자외선 차단 성분(SPF)이 든 핸드크림을 외출 전에 사용하면 광노화 예방에도 도움돼요. 한 번에 많이 바르기보다 자주 덧바르는 게 효과적이니 가방·책상에 작은 사이즈로 휴대하시면 좋습니다. 잘 때는 일반 크림보다 두껍고 영양감 있는 핸드밤이나 수면팩 형태를 추천드려요. 손 씻은 후 3분 안에 바르는 습관만 들여도 손등 컨디션이 확연히 달라집니다.', '손등에 좋은 핸드크림 추천(바이오더마 시카비오·MD스픽)과 겨울철 바세린 활용법을 피부과 전문의 고혜림이 안내합니다.', array['핸드크림', '바이오더마', '시카비오', 'MD스픽', '바세린', '손습진', '보습']::text[]),
    ('Ka8LFvx65yU', 'jeonghanmi', '손등 검버섯·잡티가 생겼는데 어떻게 해야 하나요?', '손등 검버섯·잡티엔 색소 레이저 시술이 가장 효과적이며, 평소 자외선 차단을 병행하셔야 합니다. IPL·토닝·QS레이저(루비·알렉산드라이트) 같은 색소 레이저로 멜라닌을 선택적으로 깨뜨리는 방식으로 치료해요. 1~2회 시술로도 눈에 띄는 변화가 있지만, 깊이 있는 검버섯은 3~5회 정도 필요할 수 있습니다. 시술 후 일시적으로 색이 진해졌다가 1~2주에 걸쳐 떨어져 나가요. 시술 직후 자외선에 노출되면 색소가 더 진해질 수 있으니 한 달 이상 철저한 자차 사용이 필수입니다. 트라넥삼산·비타민C 같은 미백 성분 화장품을 보조적으로 쓰면 효과가 좋아요. 한 번 치료 후에도 자외선 노출을 줄이지 않으면 재발하니 평소 관리가 정말 중요합니다.', '손등 검버섯 레이저 치료의 한계와 레티노이드(아크리프)로 관리하는 방법을 피부과 전문의 정한미가 설명합니다.', array['손등검버섯', '잡티', '색소침착', '손등레이저', '아크리프', '레티노이드']::text[]),
    ('k16Np3fZCCs', 'kimjongsik', '같은 보톡스인데 병원마다 가격이 다른 이유는 무엇인가요?', '보톡스 가격 차이의 핵심은 정품 사용 여부, 의사의 숙련도, 사용 단위(유닛) 차이에 있습니다. 정품 보톡스(앨러간·이펙스·메디톡신·나보타 등)는 원가가 정해져 있어 너무 저렴한 곳은 미허가 제품이거나 희석을 많이 한 경우가 많아요. 같은 브랜드라도 시술 부위·필요 유닛에 따라 가격이 달라지기도 합니다. 또 의사가 직접 정확한 위치에 주입하는 곳과 그렇지 않은 곳은 결과 차이가 크기 때문에 가격에 반영돼요. 너무 싼 곳은 시술 시간이 짧고 상담이 형식적인 경우가 많습니다. 가격만 보고 결정하기보다 정품 인증서·의사 직접 시술 여부·후기·재방문율을 확인하시는 게 안전해요. 결국 보톡스는 ''의사 실력값''이 가격에 가장 크게 반영되는 시술입니다.', '병원마다 보톡스 가격이 다른 이유(맞춤 설계, 부작용 대처 비용)와 너무 저렴한 곳의 위험성을 피부과 전문의 김종식이 설명합니다.', array['보톡스가격', '피부과비용', '안전보험', '맞춤설계', '부작용대처']::text[]),
    ('k16Np3fZCCs', 'kimjongsik', '피부과 전문의와 일반 의원·클리닉은 어떻게 구분하나요?', '피부과 전문의는 의대 졸업 후 4년 이상의 피부과 전공 수련을 거쳐 자격을 얻은 의사입니다. 일반 의원·클리닉은 일반의(인턴 후)도 운영할 수 있어 피부과 전공이 아닐 수 있어요. 간판에 ''피부과 의원''이 아닌 ''○○클리닉'' ''○○의원''으로 적혀 있다면 전문의가 아닐 가능성이 높습니다. 정확한 확인은 병원 홈페이지의 ''피부과 전문의'' 표기와 의사 약력에서 ''피부과 전공의 수련''을 확인하시면 됩니다. 또 대한피부과학회 정회원이라면 전문의가 맞아요. 시술의 안전성·정확한 진단·부작용 대처 능력에서 전문의와 일반의는 차이가 큽니다. 같은 가격이라면 피부과 전문의에게 받는 게 안전하고 결과도 더 좋아요.', '피부과 전문의 간판 구분법(빨간 간판·피부과의원 vs 클리닉)과 전문의 트레이닝 과정을 피부과 전문의 김종식이 설명합니다.', array['피부과전문의', '간판법', '빨간간판', '클리닉', '피부과의원', '의료진구분']::text[]),
    ('k16Np3fZCCs', 'kimjongsik', '피부 시술 받기 전 의사에게 꼭 물어봐야 할 질문이 있나요?', '꼭 물어봐야 할 핵심 질문은 사용 약물·시술자·부작용 대처·사후관리 4가지입니다. 첫째, ''사용하는 약물이 정품이고 어떤 브랜드인지'' 확인해 주세요. 정품 인증서·신청 가능 여부를 함께 묻는 게 좋습니다. 둘째, ''실제로 시술하는 의사가 누구인지'' 확인하세요. 상담은 의사가 했는데 시술은 직원이 하는 경우도 있어요. 셋째, ''부작용이 생겼을 때 어떻게 대처하는지'' 물어보세요. 책임 있는 곳이라면 명확한 대응 매뉴얼이 있습니다. 마지막으로 ''시술 후 관리·재방문 일정''을 확인해 결과를 끝까지 책임지는 곳인지 판단하세요.', '시술 전 의사에게 꼭 물어봐야 할 3가지(효과·부작용·대처)와 좋은 의사 판별법을 피부과 전문의 김종식이 안내합니다.', array['시술상담', '부작용', '의사질문', '효과', '회복기간', '책임진료']::text[]),
    ('k16Np3fZCCs', 'kimjongsik', '좋은 피부과를 고르는 핵심 기준은 무엇인가요?', '좋은 피부과 선택의 핵심 기준은 의사 자격·정품 사용·솔직한 상담·꾸준한 사후관리, 이 4가지입니다. 첫째, 피부과 전문의 자격이 확인되는 곳을 선택하세요. 둘째, 사용 약물이 정품이고 인증서를 보여줄 수 있는 곳이 안전합니다. 셋째, ''꼭 받아야 한다''며 과도한 시술을 권유하기보다 본인 피부 상태에 맞는 솔직한 상담을 해주는 곳이 좋아요. 넷째, 시술 후 부작용이나 추가 관리가 필요할 때 책임지고 케어해주는 곳을 선택하세요. 후기도 중요하지만 광고성 후기와 실제 후기를 구분해서 보시는 게 좋습니다. 가격이 가장 싼 곳보다, 가격대가 합리적이면서 위 4가지 기준을 충족하는 곳을 선택하시는 게 안전해요. 평생 피부 주치의를 만난다는 마음으로 신중히 고르시면 됩니다.', '좋은 피부과 고르는 3대 기준(피부과 전문의·의사 상담·패키지 강매 없음)을 피부과 전문의 김종식이 정리합니다.', array['피부과고르는법', '피부과전문의', '의사상담', '패키지', '토탈케어']::text[]),
    ('sko0mYUAWmA', 'jeonghanmi', '힐로웨이브는 어떤 분께 추천하나요?', '힐로웨이브는 30~50대 중 자연스러운 리프팅과 윤곽 정돈을 동시에 원하는 분께 잘 맞습니다. 특히 중안부·턱선 처짐이 시작됐지만 강한 리프팅 시술은 부담스러운 분께 추천드려요. 광대 옆 그림자가 신경 쓰이거나 입꼬리가 처져 보이는 분, 턱선이 무너진 분께 효과가 좋습니다. 일반 필러와 달리 점도가 높아 들어 올리는 힘이 강하기 때문에 즉각적인 윤곽 변화가 보여요. 시술 시간이 짧고 회복도 빨라 직장인분들도 부담 없이 받으실 수 있습니다. 단, 결절 위험을 줄이기 위해 시술자 경험이 많은 곳을 선택하시는 게 중요해요. 본인이 ''처짐''을 정돈하고 싶을 때 좋은 선택지입니다.', '힐로웨이브가 미세 꺼짐과 결절 부담 큰 분께 잘 맞는 이유, 저분자·고분자 히알루론산의 효과를 피부과 전문의 정한미가 설명합니다.', array['힐로웨이브', '스킨부스터', '히알루론산', '가교제', '결절없음', '눈밑꺼짐', '옆볼', '팔자주름']::text[]),
    ('sko0mYUAWmA', 'jeonghanmi', '올타이트 리프팅이 안 아프다고 하는데 정말인가요?', '올타이트는 마취 크림과 진정 시스템 덕분에 일반적인 리프팅보다 통증이 훨씬 덜한 편입니다. 단극 RF(고주파)로 진피 깊은 층까지 열을 전달해 콜라겐 생성을 유도하는 시술이에요. 써마지보다 자극이 적고, 울쎄라보다 통증이 약해 ''아프지 않은 리프팅''으로 알려져 있습니다. 시술 중 약간의 따뜻함이나 따끔함은 있지만 견디기 어려운 정도는 아니에요. 다만 통증 역치는 사람마다 달라 ''전혀 안 아프다''고 단정 짓기는 어렵습니다. 통증에 민감하시다면 마취 크림을 충분히 도포한 후 시술받으시면 더 편해요. 올타이트는 강도를 조절할 수 있어 본인 컨디션에 맞춰 받을 수 있다는 게 장점입니다.', '올타이트 리프팅의 무통·볼꺼짐 없는 원리(표면 냉각 + 진피·근막층 선택 가열)를 피부과 전문의 정한미가 설명합니다.', array['올타이트', '리프팅', '고주파', '냉각', '볼꺼짐없음', '통증없음', '다운타임', '근막층']::text[]),
    ('sko0mYUAWmA', 'jeonghanmi', '고압 산소 치료는 정말 노화를 되돌려주나요?', '고압 산소 치료는 피부 회복·세포 재생에 도움을 주지만 ''노화를 되돌린다''는 표현은 과장에 가깝습니다. 고농도 산소가 혈관을 통해 조직에 공급되면서 콜라겐 합성·세포 재생이 촉진되는 효과는 검증돼 있어요. 시술 후 피부 톤·결이 개선되거나 피부 장벽이 안정되는 변화는 분명 있습니다. 하지만 이미 진행된 노화 자체를 되돌리는 효과까진 기대하기 어려워요. 다른 시술의 회복을 빠르게 도와주는 보조 요법으로 활용하면 만족도가 좋습니다. 1회로 큰 변화를 기대하기보다 꾸준히 받았을 때 효과가 누적되는 시술이에요. 비용·시간 대비 우선순위를 따져 다른 시술과 함께 받으시는 게 효율적입니다.', '고압 산소 치료의 항노화 효과(텔로미어 20% 회복, 항염증)와 다른 시술 시너지를 피부과 전문의 정한미가 설명합니다.', array['고압산소치료', '항노화', '텔로미어', '안티에이징', '인플라메이징', '엑소좀', '회복촉진']::text[]),
    ('sko0mYUAWmA', 'jeonghanmi', '강남에서 요즘 핫한 자연스러운 시술 3가지가 무엇인가요?', '강남에서 요즘 가장 핫한 자연스러운 시술 3가지는 힐로웨이브·리쥬란·쥬베룩입니다. 세 가지 모두 ''시술받은 티가 안 나는 자연스러움''을 추구한다는 공통점이 있어요. 힐로웨이브는 자연스러운 리프팅과 윤곽 정돈에, 리쥬란은 피부 결·잔주름 개선과 회복력 강화에 효과적입니다. 쥬베룩은 콜라겐 부스터 기능으로 진피층의 탄력을 회복시켜줘요. 강한 한 방의 시술보다 여러 가지를 조합해 자연스럽게 가꾸는 게 최근 트렌드입니다. 회복기간이 짧고 일상 복귀가 빠르다는 것도 인기 요인이에요. 본인 피부 상태와 고민에 맞춰 1~2가지를 골라 받으시는 게 가장 효과적입니다.', '강남에서 요즘 인기 있는 자연스러운 시술 3가지(힐로웨이브·올타이트·고압산소)를 피부과 전문의 정한미가 정리합니다.', array['강남시술', '힐로웨이브', '올타이트', '고압산소치료', '자연스러운시술', '안티에이징']::text[]),
    ('174Hw712Q_c', 'jeonghanmi', '볼륨 채우는 힐로웨이브가 필러랑 뭐가 다른 건가요?', '힐로웨이브는 히알루론산 기반 스킨부스터로, 꺼진 볼륨을 자연스럽고 티 안 나게 채워주는 시술입니다. 필러도 히알루론산으로 만들지만, 가교제(결합제)를 많이 써서 단단하게 뭉쳐놓은 형태라 오래 유지되고 모양을 잡아주는 데 적합해요. 반면 힐로웨이브는 가교제를 최소화해서 히알루론산 본연의 부드러운 물성을 살려놓은 제품입니다. 실제로 짜보면 필러는 덩어리처럼 나오는데, 힐로웨이브는 줄줄 흘러내릴 정도로 유동성이 높아요. 그래서 피부 속에 넣었을 때 뭉치지 않고 이물감 없이 고르게 퍼지는 게 특징입니다. 눈 밑, 팔자주름, 옆볼처럼 미세하게 꺼진 부위에 시술하면 받은 티 없이 자연스럽게 어려 보이는 효과를 줄 수 있어요. 30대 중반 이후 볼륨 꺼짐이 신경 쓰이지만 과한 시술은 부담스러운 분들에게 추천드립니다.', '힐로웨이브와 필러의 차이를 가교제 사용량과 부드러운 물성 관점에서 피부과 전문의 정한미가 설명합니다', array['힐로웨이브', '스킨부스터', '필러', '히알루론산', '볼륨채움', '가교제', '눈밑꺼짐', '팔자주름']::text[]),
    ('174Hw712Q_c', 'jeonghanmi', '힐로웨이브 맞으면 결절 걱정 안 해도 되나요?', '힐로웨이브는 구조적으로 결절이 생길 수 없는 시술입니다. 재료 자체가 히알루론산인 데다가, 단단하게 뭉쳐놓은 형태가 아니라 부드럽게 풀어져 있는 상태이기 때문이에요. 콜라겐 부스터(스컬트라, 쥬베룩, 레디어스 등)는 콜라겐 생성을 촉진하는 원리여서, 드물게 한 부위에 콜라겐이 과도하게 뭉치면 결절처럼 될 가능성이 있습니다. 이런 부작용이 걱정돼서 볼륨 시술을 망설이는 분들이 꽤 많은데, 힐로웨이브는 그런 걱정 없이 안전하게 받을 수 있어요. 예뻐지고 싶지만 결절이 무서운 분들에게 부담 없는 선택지가 될 수 있습니다. 콜라겐 부스터 시술의 입문 단계로도 추천드릴 수 있는 시술이기도 해요. 다만 어떤 시술이든 100% 안전한 것은 없으므로, 본인 상태에 맞는 상담을 받아보시는 게 좋습니다.', '힐로웨이브가 결절이 생길 수 없는 구조적 원리와 콜라겐 부스터 대비 안전성을 피부과 전문의 정한미가 설명합니다', array['힐로웨이브', '결절', '콜라겐부스터', '스컬트라', '쥬베룩', '부작용', '안전성', '히알루론산']::text[]),
    ('174Hw712Q_c', 'jeonghanmi', '힐로웨이브가 피부 자체도 좋아지게 해주나요?', '힐로웨이브는 즉각적인 볼륨 채움과 장기적인 피부 개선, 두 가지 효과를 동시에 가진 시술입니다. 힐로웨이브에는 고분자와 저분자 히알루론산이 함께 들어 있는데, 각각 역할이 달라요. 고분자 히알루론산은 피부 속에서 수분을 물리적으로 머금어 즉각적인 보습과 볼륨감을 만들어줍니다. 저분자 히알루론산은 크기가 작아서 조직에 빠르게 침투해 섬유아세포(콜라겐을 만드는 세포)를 자극하고, 콜라겐 생성 신호를 전달하는 역할을 해요. 다만 스컬트라나 쥬베룩처럼 직접적으로 콜라겐 생성을 강하게 촉진하는 수준은 아닙니다. 피부층에 적당히 건강한 자극을 줘서 장기적으로 피부 컨디션을 개선해주는 정도라고 이해하시면 돼요. 시술 당일 바로 효과가 보이면서 피부 건강까지 챙길 수 있다는 게 힐로웨이브의 장점입니다.', '힐로웨이브의 고분자·저분자 히알루론산이 볼륨과 피부 재생을 동시에 돕는 원리를 피부과 전문의 정한미가 설명합니다', array['힐로웨이브', '고분자히알루론산', '저분자히알루론산', '콜라겐', '섬유아세포', '스킨부스터', '보습', '피부개선']::text[]),
    ('174Hw712Q_c', 'jeonghanmi', '힐로웨이브 단점은 뭔가요? 유지 기간이 짧다던데요?', '힐로웨이브의 가장 큰 단점은 유지 기간이 짧다는 점입니다. 가교제를 최소화한 부드러운 성질이라 필러처럼 1년~1년 반 유지되지 않고, 약 3개월에서 6개월 정도 지속돼요. 또한 패임이 심하거나 많이 꺼진 부위에는 적합하지 않습니다. 힐로웨이브가 워낙 무르고 부드러운 물성이라, 깊게 패인 팔자주름이나 심하게 꺼진 볼처럼 단단하게 받쳐줘야 하는 부위는 필러를 써야 해요. 안전하고 자연스러운 시술이지만 만능은 아니라는 점을 알아두시는 게 좋습니다. 필러가 필요한 부위에는 필러나 스컬트라, 쥬베룩 볼륨 같은 시술이 더 적합할 수 있어요. 미세한 볼륨 꺼짐을 티 안 나게 채우고 싶은 분들에게는 좋지만, 본인 상태에 맞는 시술을 선택하시는 게 중요합니다.', '힐로웨이브의 3~6개월 유지 기간 한계와 깊은 패임에 부적합한 이유를 피부과 전문의 정한미가 설명합니다', array['힐로웨이브', '유지기간', '단점', '필러', '볼꺼짐', '팔자주름', '스컬트라', '쥬베룩']::text[]),
    ('vxBll9U2puA', 'jeonghanmi', '지성 피부도 스킨케어를 꼭 해야 하나요?', '네, 지성 피부일수록 오히려 스킨케어가 더 중요합니다. 피지가 많이 나오는 건 사실이지만 그 자체가 충분한 보습은 아니에요. 피부 장벽이 약해지면 오히려 피지 분비가 더 늘어나는 악순환이 생깁니다. 그래서 가벼운 수분 토너와 오일프리 보습제로 수분을 채워주는 게 필수예요. 지성 피부는 클렌징을 너무 강하게 하면 피지를 더 만들게 되니, 약산성·저자극 클렌저를 사용하시는 게 좋습니다. 주 1~2회 가벼운 각질 관리(BHA, PHA)로 모공을 깨끗이 유지하면 트러블 예방에도 도움돼요. 자외선 차단도 빼먹지 마시고, 가벼운 젤 타입 선크림을 추천드립니다.', '지성 피부도 클렌징과 가벼운 보습 두 가지는 꼭 챙겨야 하는 이유와 제품 추천을 피부과 전문의 정한미가 설명합니다.', array['지성피부', '스킨케어', '클렌징', '약알칼리성', '토너', '로션', '보습', '센카', '라로슈포제']::text[]),
    ('vxBll9U2puA', 'jeonghanmi', '건성 피부 기본 스킨케어는 어떻게 해야 하나요?', '건성 피부는 보습이 핵심이며, 피부 장벽 강화에 집중하는 게 가장 중요합니다. 클렌징부터 부드럽게 시작하고, 뜨거운 물은 피부 수분을 빼앗으니 미지근한 물을 사용하세요. 세안 후 3분 안에 보습제를 발라야 수분 증발을 막을 수 있어요. 토너→에센스→크림 순으로 단계적으로 수분과 유분을 더해주시면 좋습니다. 세라마이드·히알루론산·판테놀 성분이 든 보습제가 건성 피부에 잘 맞아요. 밤엔 수면팩이나 오일을 추가해 수분 증발을 막아주시면 다음날 피부가 훨씬 촉촉합니다. 자외선은 건조함을 더 악화시키니 SPF 30 이상 보습성 선크림을 매일 사용해 주세요.', '건성 피부의 3단계 기본 스킨케어(약산성 클렌저·세럼·크림)와 추가 보습 팁을 피부과 전문의 정한미가 안내합니다.', array['건성피부', '스킨케어', '약산성클렌저', '세럼', '크림', '보습', '피부장벽']::text[]),
    ('vxBll9U2puA', 'jeonghanmi', '선크림은 정말 매일 발라야 하나요?', '네, 선크림은 매일 발라야 합니다. 자외선은 흐린 날·실내·겨울에도 피부에 도달해 콜라겐을 파괴하고 색소를 만들어요. 광노화는 전체 노화의 80% 이상을 차지할 정도로 영향이 큽니다. 매일 SPF 30~50 이상의 선크림을 충분히(얼굴 기준 500원 동전 크기) 발라주세요. 외출 전 15분 전에 바르고, 야외 활동 시엔 2~3시간마다 덧발라야 효과가 유지됩니다. 실내에서도 창문으로 들어오는 UVA를 막기 위해 가벼운 자외선 차단이 필요해요. 끈적임이 싫다면 톤업크림이나 무기자차 베이스 선크림을 선택하시면 좋습니다. 매일 바르는 작은 습관이 10년 후 피부 나이를 결정합니다.', '선크림을 매일 발라야 하는 이유와 인중·손등까지 챙겨야 하는 광노화 예방 팁을 피부과 전문의 정한미가 설명합니다.', array['선크림', '자외선차단', '광노화', '콜라겐', 'SPF', '인중', '손등']::text[]),
    ('vxBll9U2puA', 'jeonghanmi', '30대 중반부터 추가해야 할 화장품이 있나요?', '30대 중반부터는 콜라겐·항산화·수분 보충 성분을 단계적으로 추가하시면 좋습니다. 레티놀은 콜라겐 생성을 돕고 잔주름·모공 개선 효과가 검증된 성분이라 야간 루틴에 추가해 보세요. 비타민C는 항산화·미백 효과가 있어 아침에 바르면 자외선 손상 예방에 도움됩니다. 펩타이드 성분의 안티에이징 크림도 피부 탄력 유지에 좋아요. 눈가는 일반 크림보다 흡수력 좋은 아이크림을 따로 사용하시면 잔주름 예방에 효과적입니다. 단, 새 성분은 한 번에 다 추가하지 말고 1~2주 간격으로 천천히 도입해 자극을 확인하세요. 가장 중요한 건 꾸준함이라, 비싼 제품보다 본인이 매일 쓸 수 있는 제품을 선택하시는 게 좋습니다.', '30대 중반부터 시작해야 할 레티노이드(레티놀·레티날·아크리프) 사용법과 효과를 피부과 전문의 정한미가 안내합니다.', array['레티노이드', '레티놀', '레티날', '아크리프', '30대', '콜라겐', '안티에이징', '주름예방']::text[]),
    ('lZ2460EWRgw', 'leedoyoung', '땅콩형 얼굴인데 울쎄라 맞으면 볼이 더 꺼지나요?', '볼과 관자놀이가 꺼진 땅콩형 얼굴에는 울쎄라를 처음부터 권하기 어렵습니다. 울쎄라는 초음파 에너지를 일정 깊이에 집중시키는 시술인데, 4.5mm 깊이의 열점이 피하지방층을 타격하면 지방 세포가 파괴될 수 있기 때문입니다. 이미 볼이 꺼져 있는 분이 받으면 볼 패임이 더 심해질 위험이 큽니다. 절대 못 받는 건 아니지만 에너지 깊이와 타겟 위치 설정이 정밀해야 하므로 신중하게 접근하셔야 합니다. 대안으로는 단극성 고주파(써마지, 세르프, 덴서티 등)가 있는데, 이 장비들은 지방층으로 전기가 잘 흐르지 않아 지방 세포 파괴 가능성이 낮습니다. 탄력 개선 효과는 주면서 볼 패임 걱정이 적어 땅콩형 얼굴에 더 적합한 선택이 될 수 있으니 참고해보세요.', '땅콩형 얼굴에 울쎄라가 볼 패임을 악화시킬 수 있는 이유와 단극성 고주파 대안을 피부과 전문의 이도영이 설명합니다', array['땅콩형얼굴', '울쎄라', '볼패임', '단극성고주파', '써마지', '피하지방', '리프팅', '볼꺼짐', '관자놀이']::text[]),
    ('lZ2460EWRgw', 'leedoyoung', '볼 꺼진 얼굴인데 사각턱 보톡스 맞아도 괜찮나요?', '광대가 있고 볼이 꺼진 땅콩형 얼굴에 사각턱 보톡스를 무턱대고 맞으면 오히려 볼 꺼짐이 심해질 수 있습니다. 사각턱 보톡스는 교근(씹을 때 쓰는 근육)에 주사하는 시술로, 보통 3~4포인트를 놓게 됩니다. 이때 주사 부위를 잘못 설정하면 교근 위쪽의 볼 볼륨까지 줄어들면서 얼굴 전체가 더 꺼져 보이기 쉽습니다. 다만 절대 맞으면 안 되는 건 아니고, 주사 위치를 평소보다 낮추고 용량도 줄여서 맞는 방법이 있습니다. 한 번에 확 빠지게 하는 게 아니라 부드럽게 턱 라인이 잡히도록 조절하는 게 핵심 포인트입니다. 땅콩형 얼굴이라면 사각턱 보톡스 전에 반드시 본인 얼굴형에 맞는 정확한 위치와 용량을 상담받으시길 권합니다.', '땅콩형 얼굴에 사각턱 보톡스를 맞을 때 볼 꺼짐을 방지하는 위치·용량 조절법을 피부과 전문의 이도영이 설명합니다', array['사각턱보톡스', '교근', '볼꺼짐', '땅콩형얼굴', '보톡스', '광대', '볼패임', '사각턱']::text[]),
    ('lZ2460EWRgw', 'leedoyoung', '필러 무서운데 힐로웨이브로 볼륨 채울 수 있나요?', '힐로웨이브는 필러가 부담스러운 분에게 볼륨과 수분감을 동시에 줄 수 있는 히알루론산 제제입니다. 일반 히알루론산 필러는 분자끼리 강하게 엉겨붙어 젤리처럼 단단한 볼륨을 만드는 반면, 힐로웨이브는 가교(엉겨붙는 정도)를 최소화해서 솜사탕처럼 잘 퍼지는 성질을 가지고 있습니다. 그래서 이물감이나 울퉁불퉁함이 적고, 주변 조직에 동화가 잘 되어 자연스러운 볼륨감을 만들어줍니다. 동시에 저분자와 고분자 히알루론산이 함께 들어 있어 수분을 지속적으로 공급하는 스킨부스터 역할도 합니다. 유지 기간은 약 3개월 정도이고, 완전히 녹아서 없어지기 때문에 안전하게 재시술이 가능합니다. 즉각적인 볼륨 개선과 피부 광택, 수분감까지 원하시는 분에게 적합한 선택이니 고려해보세요.', '힐로웨이브의 자연스러운 볼륨 채움과 스킨부스터 수분 공급 이중 효과를 피부과 전문의 이도영이 설명합니다', array['힐로웨이브', '히알루론산', '스킨부스터', '필러', '볼륨', '볼꺼짐', '땅콩형얼굴', '수분감']::text[]),
    ('lZ2460EWRgw', 'leedoyoung', '스컬트라 맞으면 결절 생길까 봐 걱정되는데 괜찮나요?', '스컬트라는 PLLA 성분이 피부 속에서 콜라겐 생성을 유도해 서서히 볼륨을 채워주는 시술로, 결절(뭉침) 위험은 과거에 비해 크게 줄었습니다. 결절은 성분이 고르게 퍼지지 않고 한 곳에 뭉쳤을 때 국소적으로 강한 반응이 생기는 것인데, 이를 예방하려면 준비 과정이 매우 중요합니다. 시술 최소 3일, 가급적 일주일 전에 증류수와 섞어 수화하고, 수화 직후 의료용 초음파 분쇄기로 약 1시간 동안 입자를 작고 고르게 만드는 과정을 거칩니다. 시술 직전에는 롤러 믹서로 다시 균일하게 섞은 뒤 깊은 층에 주입하고, 주입 후에는 스파츌라로 마사지하며 모양을 빚어줍니다. 효과가 나타나기까지 약 6개월이 걸리지만, 자연스럽게 볼륨이 올라오길 원하는 분이라면 적합한 선택이니 상담받아보시길 권합니다.', '스컬트라 결절 위험을 줄이는 수화, 초음파 분쇄, 마사지 등 안전 시술 과정을 피부과 전문의 이도영이 설명합니다', array['스컬트라', 'PLLA', '콜라겐', '결절', '볼륨', '땅콩형얼굴', '수화', '초음파분쇄']::text[]),
    ('MeycbSmQfxs', 'jeonghanmi', '입 주변 팔자주름이 깊은데 보톡스로 펼 수 있나요?', '깊게 패인 팔자주름은 보톡스로 펼 수 없습니다. 팔자주름 주변의 자글자글한 잔주름 정도는 보톡스로 개선할 수도 있지만, 깊어진 주름은 피부 탄력이 떨어져 이미 패인 것이기 때문에 보톡스가 펴주지 못합니다. 게다가 입 주변에는 근육이 많이 붙어 있어서 보톡스를 잘못 맞으면 입이 돌아가거나 말할 때 삐뚤어질 수 있는 위험도 있습니다. 나이가 들면 입술 위, 팔자주름, 입 옆 부위는 피부가 얇고 반복적으로 많이 움직이기 때문에 주름이 깊게 패이기 쉽습니다. 근육을 이완시키는 보톡스만으로는 이런 구조적 문제를 해결할 수 없으므로, 패인 부분을 채워주면서 동시에 피부 탄력까지 높여주는 시술이 필요합니다. 대표적으로 쥬브젠 같은 시술이 효과적이니 고려해보세요.', '깊은 팔자주름에 보톡스가 효과 없는 이유와 입 주변 보톡스의 부작용 위험성을 피부과 전문의 정한미가 설명합니다.', array['팔자주름', '보톡스', '주름', '입주변주름', '피부탄력', '잔주름', '쥬브젠']::text[]),
    ('MeycbSmQfxs', 'jeonghanmi', '팔자주름 시술에서 쥬브젠이 필러랑 뭐가 다른 건가요?', '쥬브젠은 히알루론산과 이산화탄소 가스를 함께 피부 속에 주입해서 주름을 채우면서 피부 재생까지 유도하는 시술입니다. 필러도 히알루론산을 사용하지만, 쥬브젠은 이산화탄소 가스가 같이 들어가는 것이 핵심 차이점입니다. 이산화탄소 가스는 피부 속에서 새 살을 돋게 하는 역할을 하기 때문에, 시간이 지나도 주사 맞은 부위가 다시 꺼지지 않고 내 살에 탄력이 생기면서 점점 더 좋아집니다. 기계를 이용해 0.001cc씩 미세하게 주입하므로 필러 1cc와 비교하면 훨씬 균일하고 정밀한 시술이 가능합니다. 특히 50~60대처럼 탄력이 떨어지면서 생긴 깊은 주름에 효과적이고, 패인 주름 채움과 피부 탄력 개선 두 가지를 동시에 해결할 수 있다는 게 가장 큰 장점입니다.', '쥬브젠과 필러의 핵심 차이점인 이산화탄소 가스의 피부 재생 원리와 정밀 주입 방식을 피부과 전문의 정한미가 설명합니다', array['쥬브젠', '필러', '히알루론산', '이산화탄소', '피부재생', '주름필러', '팔자주름', '탄력']::text[]),
    ('MeycbSmQfxs', 'jeonghanmi', '쥬브젠 효과 바로 나타나나요? 얼마나 오래 가요?', '쥬브젠은 시술 직후 바로 효과가 나타나고, 두세 달이 지나면서 더 좋아집니다. 단순히 피부 속을 채워놓고 끝나는 것이 아니라 내 살이 차오르게 하는 시술이기 때문에, 3개월 뒤, 6개월 뒤, 1년 뒤로 갈수록 피부가 더 탄탄해지는 것을 확인할 수 있습니다. 유지 기간은 3년에서 5년 정도이며, 필러나 스킨부스터 같은 시술보다 훨씬 오래 가는 편입니다. 다만 우리 피부는 계속 나이가 들기 때문에 한 번 시술로 영구적이라고 보기는 어렵습니다. 3~5년이 지난 후 상태를 보고 주름이 다시 생겼다면 그때 하시면 되고, 상태가 괜찮다면 굳이 하지 않아도 되니까 정기적으로 반복해야 한다는 부담이 없는 것도 장점입니다. 시술 시간도 5분에서 10분 정도로 짧고 통증도 적어 부담 없이 받으실 수 있습니다.', '쥬브젠의 시술 직후 즉각 효과부터 3~5년 유지되는 장기 개선 과정까지 피부과 전문의 정한미가 설명합니다', array['쥬브젠', '유지기간', '시술효과', '피부탄력', '팔자주름', '스킨부스터', '필러', '주름시술']::text[]),
    ('MeycbSmQfxs', 'jeonghanmi', '쥬브젠 맞고 나서 세수나 운동해도 되나요?', '쥬브젠 시술 후 일상생활은 바로 가능하지만 몇 가지 주의사항이 있습니다. 시술이 끝나면 바늘이 들어간 부위로 균이 들어가지 않도록 재생 테이프를 붙여드리는데, 이 테이프가 방수라서 붙인 채로 세수해도 괜찮습니다. 다만 음주, 흡연, 땀을 많이 흘리는 운동은 3일에서 일주일 정도 피해 주시는 게 좋습니다. 바늘을 사용하는 시술이기 때문에 멍이 생길 수 있으며, 약 일주일 정도면 빠집니다. 멍이 빠진 후 시술 부위가 약간 붉어질 수 있는데, 이는 피부 속에서 새 살이 차오르면서 생기는 정상적인 반응이니 걱정하지 않으셔도 됩니다. 붉은기는 3~4주 정도 지속될 수 있으나 시간이 지나면 자연스럽게 사라집니다. 마취크림을 바르면 통증이 거의 없어서 겁이 많으신 분도 편하게 받으실 수 있으니 부담 갖지 마세요.', '쥬브젠 시술 후 세수·운동 제한, 멍과 붉은기 회복 기간 등 관리법을 피부과 전문의 정한미가 안내합니다', array['쥬브젠', '시술후관리', '멍', '다운타임', '부작용', '재생테이프', '주름시술', '회복기간']::text[])
)
insert into public.qas (video_id, doctor_id, question, answer, meta, keywords, published)
select v.id, d.id, nq.question, nq.answer, nq.meta, nq.keywords, true
from new_qas nq
join public.videos  v on v.youtube_id = nq.youtube_id
join public.doctors d on d.slug = nq.doctor_slug
where not exists (
  select 1 from public.qas q
  where q.video_id = v.id and q.question = nq.question
);
